window.HADITH_CACHE = window.HADITH_CACHE || {};
window.HADITH_CACHE["bukhari_9"] = {"4501":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا إِبْرَاهِيمُ بْنُ نَافِعٍ عَنْ الْحَسَنِ هُوَ ابْنُ مُسْلِمٍ عَنْ صَفِيَّةَ عَنْ عَائِشَةَأَنَّ امْرَأَةً مِنْ الْأَنْصَارِ زَوَّجَتْ ابْنَتَهَا فَتَمَعَّطَ شَعَرُ رَأْسِهَا فَجَاءَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ ذَلِكَ لَهُ فَقَالَتْ إِنَّ زَوْجَهَا أَمَرَنِي أَنْ أَصِلَ فِي شَعَرِهَا فَقَالَ لَا إِنَّهُ قَدْ لُعِنَ الْمُوصِلَاتُ","id":"Telah menceritakan kepada kami [Khallad bin Yahya] Telah menceritakan kepada kami [Ibrahim bin Nafi'] dari [Al Hasan bin Muslim] dari [Shafiyyah] dari [Aisyah] bahwa seorang wanita Anshar menikahkan anak perempuannya, lalu rambut anak itu merontok. Maka wanita itu pun segera mendatangi Nabi shallallahu 'alaihi wasallam dan mengadukan hal itu, ia berkata, \"Suaminya menyuruhku untuk menyambung rambutnya.\" Maka beliau bersabda: \"Tidak. Sesungguhnya Allah telah melaknat Al Muwashilaat (para wanita yang menyambung rambutnya).\""},"4502":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا{ وَإِنْ امْرَأَةٌ خَافَتْ مِنْ بَعْلِهَا نُشُوزًا أَوْ إِعْرَاضًا }قَالَتْ هِيَ الْمَرْأَةُ تَكُونُ عِنْدَ الرَّجُلِ لَا يَسْتَكْثِرُ مِنْهَا فَيُرِيدُ طَلَاقَهَا وَيَتَزَوَّجُ غَيْرَهَا تَقُولُ لَهُ أَمْسِكْنِي وَلَا تُطَلِّقْنِي ثُمَّ تَزَوَّجْ غَيْرِي فَأَنْتَ فِي حِلٍّ مِنْ النَّفَقَةِ عَلَيَّ وَالْقِسْمَةِ لِي فَذَلِكَ قَوْلُهُ تَعَالَى{ فَلَا جُنَاحَ عَلَيْهِمَا أَنْ يَصَّالَحَا بَيْنَهُمَا صُلْحًا وَالصُّلْحُ خَيْرٌ }","id":"Telah menceritakan kepada kami [Muhammad bin Salam] Telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Hisyam] dari [bapaknya] dari [Aisyah] radliallahu 'anha, yakni terkait dengan firman-Nya: \"WA INIMRA`ATUN KHAAFAT MIN BA'LIHAA NUSYUUZAN AW I'RAADLAN..\" 'Aisyah berkata, \"Ia adalah seorang wanita yang berada di bawah seorang suami. Namun sang suami tak mendapatkan hal banyak darinya, hingga ia pun ingin menceraikannya lalu menikahi wanita lain. Maka sang wanita pun berkata, 'Tahanlah aku, jangan kau ceraikan. Nikahilah wanita lain, kamu halal (untuk tidak memberi) nafkah atasku begitu pula pembagian jatah untukku.' Itulah maksud dari firman Allah Ta'ala: 'FALAA JUNAAHA 'ALAIHIMAA AN YASHSHAALAHAA BAINAHUMAA SHULHAA WASH SHULHU KHAIR.'\""},"4503":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَكُنَّا نَعْزِلُ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ عَمْرٌو أَخْبَرَنِي عَطَاءٌ سَمِعَ جَابِرًا رَضِيَ اللَّهُ عَنْهُ قَالَ كُنَّا نَعْزِلُ وَالْقُرْآنُ يَنْزِلُ وَعَنْ عَمْرٍو عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَ كُنَّا نَعْزِلُ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْقُرْآنُ يَنْزِلُ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij] dari [Atha`] dari [Jabir] ia berkta; \"Pada masa Nabi shallallahu 'alaihi wasallam, kami pernah melakukan 'Azl (mencabut penis saat ejakulasi).\" Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] Telah berkata [Amru] Telah mengabarkan kepadaku [Atha`] Ia mendengar [Jabir] radliallahu 'anhu berkata; Kami melakukan 'Azl, sedangkan Al Qur`an juga turun. Dan dari [Amru] dari [Atha`] dari [Jabir] ia berkata; Kami melakukan 'Azl di masa Nabi shallallahu 'alaihi wasallam dan Al Qur`an juga turun.\""},"4504":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ الزُّهْرِيِّ عَنْ ابْنِ مُحَيْرِيزٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَأَصَبْنَا سَبْيًا فَكُنَّا نَعْزِلُ فَسَأَلْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَوَإِنَّكُمْ لَتَفْعَلُونَ قَالَهَا ثَلَاثًا مَا مِنْ نَسَمَةٍ كَائِنَةٍ إِلَى يَوْمِ الْقِيَامَةِ إِلَّا هِيَ كَائِنَةٌ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Asma`] Telah menceritakan kepada kami [Juwairiyah] dari [Malik bin Anas] dari [Az Zuhri] dari [Ibnu Muhairiz] dari [Abu Sa'id Al Khudri] ia berkata; Kami mendapatkan tawanan, lalu kami pun melakukan 'Azl, maka kami menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Apakah kalian benar-benar melakukannya?\" beliau mengatakannya sebanyak tiga kali. Beliau meelanjutkan: \"Tidak ada sesuatupun yang telah ditetapkan terjadi hingga datangnya hari kiamat, kecuali ia pasti terjadi.\""},"4505":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ أَيْمَنَ قَالَ حَدَّثَنِي ابْنُ أَبِي مُلَيْكَةَ عَنْ الْقَاسِمِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا خَرَجَ أَقْرَعَ بَيْنَ نِسَائِهِ فَطَارَتْ الْقُرْعَةُ لِعَائِشَةَ وَحَفْصَةَ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ بِاللَّيْلِ سَارَ مَعَ عَائِشَةَ يَتَحَدَّثُ فَقَالَتْ حَفْصَةُ أَلَا تَرْكَبِينَ اللَّيْلَةَ بَعِيرِي وَأَرْكَبُ بَعِيرَكِ تَنْظُرِينَ وَأَنْظُرُ فَقَالَتْ بَلَى فَرَكِبَتْ فَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى جَمَلِ عَائِشَةَ وَعَلَيْهِ حَفْصَةُ فَسَلَّمَ عَلَيْهَا ثُمَّ سَارَ حَتَّى نَزَلُوا وَافْتَقَدَتْهُ عَائِشَةُ فَلَمَّا نَزَلُوا جَعَلَتْ رِجْلَيْهَا بَيْنَ الْإِذْخِرِ وَتَقُولُ يَا رَبِّ سَلِّطْ عَلَيَّ عَقْرَبًا أَوْ حَيَّةً تَلْدَغُنِي وَلَا أَسْتَطِيعُ أَنْ أَقُولَ لَهُ شَيْئًا","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Abdul Wahid bin Aiman] ia berkata; Telah menceritakan kepadaku [Ibnu Abu Mulaikah] dari [Al Qasim] dari [Aisyah] bahwasanya; Apabila Nabi shallallahu 'alaihi wasallam hendak keluar mengadakan perjalanan, beliau mengadakan undian antara isteri-isterinya, lalu undian itu pun jatuh pada Aisyah dan Hafshah. Dan pada malam hari, biasanya Nabi shallallahu 'alaihi wasallam berjalan bersama Aisyah dan berbincang-bincang dengannya. Maka Hafshah berkata, \"Maukah malam kamu menaiki kendaraanku dan aku menaiki kendaraanmu kemudian kamu melihat dan pun juga dapat melihat?\" Aisyah menjawab, \"Ya.\" Akhirnya ia pun menaikinya. Kemudian datanglah Nabi shallallahu 'alaihi wasallam pada kendaraan Aisyah, sementara yang berada di atasnya adalah Hafshah. Beliau pun mengucapkan salam kepadanya, lalu beliau berjalan hingga mereka singgah disuatu tempat, dan ternyata ia kelihangan Aisyah. Saat singgah, Aisyah meletakkan kedua kakinya di antara semak-semak tumbuhan, lalu ia pun berkata, \"Wahai Rabbi, binasakanlah kalajengking dan ular yang menyengatku.\" Maka aku tidak bisa berkata apa-apa pada beliau."},"4506":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا زُهَيْرٌ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ سَوْدَةَ بِنْتَ زَمْعَةَ وَهَبَتْ يَوْمَهَا لِعَائِشَةَ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْسِمُ لِعَائِشَةَ بِيَوْمِهَا وَيَوْمِ سَوْدَةَ","id":"Telah menceritakan kepada kami [Malik bin Isma'il] Telah menceritakan kepada kami [Zuhair] dari [Hisyam] dari [bapaknya] dari [Aisyah] bahwasanya; \"Saudah binti Zam'ah, menghibahkan giliran harinya kepada Aisyah. Karena itu, Nabi shallallahu 'alaihi wasallam membagi harinya untuk Aisyah dan giliran Saudah juga untuknya.\""},"4507":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرٌ حَدَّثَنَا خَالِدٌ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُوَلَوْ شِئْتُ أَنْ أَقُولَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَكِنْ قَالَ السُّنَّةُ إِذَا تَزَوَّجَ الْبِكْرَ أَقَامَ عِنْدَهَا سَبْعًا وَإِذَا تَزَوَّجَ الثَّيِّبَ أَقَامَ عِنْدَهَا ثَلَاثًا","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Bisyr] Telah menceritakan kepada kami [Khalid] dari [Abu Qilabah] dari [Anas] radliallahu 'anhu, -jika aku mau, akan kukatakan; \"Nabi shallallahu 'alaihi wasallam bersabda. Akan tetapi- ia berkata; Termasuk perkara sunnah adalah bila seseorang menikahi gadis hendaklah ia bermukim ditempatnya selama tujuh hari, dan bila ia menikahi seorang janda, maka hendaklah ia bermukim ditempatnya selama tiga hari.\""},"4508":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ رَاشِدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ سُفْيَانَ حَدَّثَنَا أَيُّوبُ وَخَالِدٌ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ قَالَمِنْ السُّنَّةِ إِذَا تَزَوَّجَ الرَّجُلُ الْبِكْرَ عَلَى الثَّيِّبِ أَقَامَ عِنْدَهَا سَبْعًا وَقَسَمَ وَإِذَا تَزَوَّجَ الثَّيِّبَ عَلَى الْبِكْرِ أَقَامَ عِنْدَهَا ثَلَاثًا ثُمَّ قَسَمَ قَالَ أَبُو قِلَابَةَ وَلَوْ شِئْتُ لَقُلْتُ إِنَّ أَنَسًا رَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَقَالَ عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنْ أَيُّوبَ وَخَالِدٍ قَالَ خَالِدٌ وَلَوْ شِئْتُ قُلْتُ رَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yusuf bin Rasyid] Telah menceritakan kepada kami [Abu Usamah] dari [Sufyan] Telah menceritakan kepada kami [Ayyub] dan [Khalid] dari [Abu Qilabah] dari [Anas] ia berkata; Termasuk perbuatan sunnah apabilah seseorang menikahi seorang gadis adalah bermukim di tempatnya selama tujuh hari, baru kemudian ia membagi hari-harinya. Dan bila ia menikahi seorang janda atas gadis, maka ia boleh tinggal di tempat wanita itu selama tiga hari, baru kemudian ia membagi-bagi harinya.\" Abu Qilabah berkata; Jika aku mau, niscaya aku akan mengatakan bahwa Anas telah memarfu'kannya kepada Nabi shallallahu 'alaihi wasallam. [Abdurrazzaq] berkata; Telah mengabarkan kepada kami [Sufyan] dari [Ayyub] dan [Khalid] ia berkata; Khalid berkata; Jika aku mau, aku akan mengatakan; Ia memarfu'kannya kepada Nabi shallallahu 'alaihi wasallam."},"4509":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُمْأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَطُوفُ عَلَى نِسَائِهِ فِي اللَّيْلَةِ الْوَاحِدَةِ وَلَهُ يَوْمَئِذٍ تِسْعُ نِسْوَةٍ","id":"Telah menceritakan kepada kami [Abdul A'la bin Hammad] Telah menceritakan kepada kami [Yazid bin Zurai'] Telah menceritakan kepada kami [Sa'id] dari [Qatadah] bahwa [Anas bin Malik] Telah menceritakan kepada mereka, bahwa Nabi shallallahu 'alaihi wasallam pernah menggilir semua isterinya dalam satu malam, padahal pada hari itu, beliau mempunyai sembilan isteri."},"4510":{"ar":"حَدَّثَنَا فَرْوَةُ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا انْصَرَفَ مِنْ الْعَصْرِ دَخَلَ عَلَى نِسَائِهِ فَيَدْنُو مِنْ إِحْدَاهُنَّ فَدَخَلَ عَلَى حَفْصَةَ فَاحْتَبَسَ أَكْثَرَ مِمَّا كَانَ يَحْتَبِسُ","id":"Telah menceritakan kepada kami [Farwah] Telah menceritakan kepada kami [Ali bin Mushir] dari [Hisyam] dari [bapaknya] dari [Aisyah] radliallahu 'anha; \"Biasanya Rasulullah shallallahu 'alaihi wasallam jika beranjak dari shalat Ashar, maka beliau menemui para isteri-isterinya. Lalu beliau mendekat pada salah seorang dari mereka. Beliau masuk ke rumah Hafshah lalu beliau berdiam di situ lebih lama.\""},"4511":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي سُلَيْمَانُ بْنُ بِلَالٍ قَالَ هِشَامُ بْنُ عُرْوَةَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسْأَلُ فِي مَرَضِهِ الَّذِي مَاتَ فِيهِ أَيْنَ أَنَا غَدًا أَيْنَ أَنَا غَدًا يُرِيدُ يَوْمَ عَائِشَةَ فَأَذِنَ لَهُ أَزْوَاجُهُ يَكُونُ حَيْثُ شَاءَ فَكَانَ فِي بَيْتِ عَائِشَةَ حَتَّى مَاتَ عِنْدَهَا قَالَتْ عَائِشَةُ فَمَاتَ فِي الْيَوْمِ الَّذِي كَانَ يَدُورُ عَلَيَّ فِيهِ فِي بَيْتِي فَقَبَضَهُ اللَّهُ وَإِنَّ رَأْسَهُ لَبَيْنَ نَحْرِي وَسَحْرِي وَخَالَطَ رِيقُهُ رِيقِي","id":"Telah menceritakan kepada kami [Isma'il] ia berkata; Telah menceritakan kepadaku [Sulaiman bin Bilal] Telah berkata [Hisyam bin Urwah] Telah mengabarkan kepadaku [bapakku] dari [Aisyah] radliallahu 'anha, bahwa Rasulullah shallallahu 'alaihi wasallam bertanya di saat beliau sakit yang menyebabkan kematiannya, \"Di mana aku esok hari, dimana aku esok hari?\" Rupanya beliau menginginkan hari esoknya adalah untuk Aisyah, maka para isteri-isterinya pun mengizinkan untuk memilih siapa saja yang dikehendakinya, maka ia memilih di rumah Aisyah hingga meninggal di tempat di sisinya. Aisyah berkata, \"Beliau meninggal tepat di hari yang beliau inginkan untuk berada di rumahku. Allah mewafatkannya sementara kepala beliau berada antara dada dan paru-paruku dan air liurnya bercampur dengan air liurku.\""},"4512":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُلَيْمَانُ عَنْ يَحْيَى عَنْ عُبَيْدِ بْنِ حُنَيْنٍ سَمِعَ ابْنَ عَبَّاسٍ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُمْدَخَلَ عَلَى حَفْصَةَ فَقَالَ يَا بُنَيَّةِ لَا يَغُرَّنَّكِ هَذِهِ الَّتِي أَعْجَبَهَا حُسْنُهَا حُبُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِيَّاهَا يُرِيدُ عَائِشَةَ فَقَصَصْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَبَسَّمَ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] Telah menceritakan kepada kami [Sulaiman] dari [Yahya] dari [Ubaid bin Hunais] ia mendengar [Ibnu Abbas] dari [Umar] radliallahu 'anhum, bahwa ia menemui Hafshah dan berkata, \"Wahai anakku, janganlah kamu sampai terperdaya. Wanita inilah yang memang membuatnya cinta Rasulullah shallallahu 'alaihi wasallam ta'ajub lantaran kecantikan wajahnya.\" Maksudnya adalah Aisyah. Lalu aku pun menceritakannya pada Rasulullah shallallahu 'alaihi wasallam, dan beliau pun tersenyum."},"4513":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ هِشَامٍ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ حَدَّثَتْنِي فَاطِمَةُ عَنْ أَسْمَاءَأَنَّ امْرَأَةً قَالَتْ يَا رَسُولَ اللَّهِ إِنَّ لِي ضَرَّةً فَهَلْ عَلَيَّ جُنَاحٌ إِنْ تَشَبَّعْتُ مِنْ زَوْجِي غَيْرَ الَّذِي يُعْطِينِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُتَشَبِّعُ بِمَا لَمْ يُعْطَ كَلَابِسِ ثَوْبَيْ زُورٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Hammad bin Zaid] dari [Hisyam] dari [Fathimah] dari [Asma`] dari Nabi shallallahu 'alaihi wasallam. - dalam riwayat lain- Telah menceritakan kepadaku [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Yahya] dari [Hisyam] dari [Fathimah] dari [Asma`] bahwa seroang wanita bertanya, \"Wahai Rasulullah, sesungguhnya aku memiliki madu (isteri lain dari suaminya), karena itu apakah aku akan mendapat dosa, bila aku menampak-nampakkan kepuasan dari suamiku dengan suatu hal yang tak diberikannya kepadaku?\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang yang menampakkan kepuasan dengan sesuatu yang tidak diberikan kepadanya adalah seperti halnya seorang yang memakai pakaian kepalsuan.\""},"4514":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ أَحَدٍ أَغْيَرُ مِنْ اللَّهِ مِنْ أَجْلِ ذَلِكَ حَرَّمَ الْفَوَاحِشَ وَمَا أَحَدٌ أَحَبَّ إِلَيْهِ الْمَدْحُ مِنْ اللَّهِ","id":"Telah menceritakan kepada kami [Umar bin Hafsh] Telah menceritakan kepada kami [bapakku] Telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada yang lebih cemburu melebihi Allah. Karena itulah, Dia mengharamkan kekejian. Dan tidak ada pula yang lebih senang terhadap pujian melebihi diri-Nya.\""},"4515":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا أُمَّةَ مُحَمَّدٍ مَا أَحَدٌ أَغْيَرَ مِنْ اللَّهِ أَنْ يَرَى عَبْدَهُ أَوْ أَمَتَهُ تَزْنِي يَا أُمَّةَ مُحَمَّدٍ لَوْ تَعْلَمُونَ مَا أَعْلَمُ لَضَحِكْتُمْ قَلِيلًا وَلَبَكَيْتُمْ كَثِيرًا","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Hisyam] dari [bapaknya] dari [Aisyah] radliallahu 'anha, bahwasanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai ummat Muhammad, tidak ada yang lebih cemburu daripada Allah saat Dia melihat hambanya atau hamba perempuannya berzina. Wahai U'mmat Muhamamd, sekiranya kalian tahu apa yang aku ketahui, niscaya kalian akan sedikit tertawa dan kalian akan banyak menangis.\""},"4516":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا هَمَّامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ أَنَّ عُرْوَةَ بْنَ الزُّبَيْرِ حَدَّثَهُ عَنْ أُمِّهِ أَسْمَاءَ أَنَّهَاسَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا شَيْءَ أَغْيَرُ مِنْ اللَّهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] Telah menceritakan kepada kami [Hammam] dari [Yahya] dari [Abu Salamah] bahwa [Urwah bin Az Zubair] Telah menceritakan kepadanya dari [Ibunya] yakni Asma`, bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada yang lebih pencemburu daripada Allah.\""},"4517":{"ar":"وَعَنْ يَحْيَى أَنَّ أَبَا سَلَمَةَ حَدَّثَهُ أَنَّ أَبَا هُرَيْرَةَ حَدَّثَهُ أَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنَّ اللَّهَ يَغَارُ وَغَيْرَةُ اللَّهِ أَنْ يَأْتِيَ الْمُؤْمِنُ مَا حَرَّمَ اللَّهُ","id":"Dan dari [Yahya] bahwa [Abu Salamah] Telah meceritakan kepadanya bahwa [Abu Hurairah] Telah menceritakan kepadanya, bahwa ia mendengar Nabi shallallahu 'alaihi wasallam bersabda. -Dalam riwayat lain- Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] bahwa ia mendengar [Abu Hurairah] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Sesungguhnya Allah itu cemburu. Dan kecemburuan Allah datang, bilamana seorang mukmin melakukan hal yang diharamkan Allah.\""},"4518":{"ar":"حَدَّثَنَا مَحْمُودٌ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا هِشَامٌ قَالَ أَخْبَرَنِي أَبِي عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَتْتَزَوَّجَنِي الزُّبَيْرُ وَمَا لَهُ فِي الْأَرْضِ مِنْ مَالٍ وَلَا مَمْلُوكٍ وَلَا شَيْءٍ غَيْرَ نَاضِحٍ وَغَيْرَ فَرَسِهِ فَكُنْتُ أَعْلِفُ فَرَسَهُ وَأَسْتَقِي الْمَاءَ وَأَخْرِزُ غَرْبَهُ وَأَعْجِنُ وَلَمْ أَكُنْ أُحْسِنُ أَخْبِزُ وَكَانَ يَخْبِزُ جَارَاتٌ لِي مِنْ الْأَنْصَارِ وَكُنَّ نِسْوَةَ صِدْقٍ وَكُنْتُ أَنْقُلُ النَّوَى مِنْ أَرْضِ الزُّبَيْرِ الَّتِي أَقْطَعَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَأْسِي وَهِيَ مِنِّي عَلَى ثُلُثَيْ فَرْسَخٍ فَجِئْتُ يَوْمًا وَالنَّوَى عَلَى رَأْسِي فَلَقِيتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ نَفَرٌ مِنْ الْأَنْصَارِ فَدَعَانِي ثُمَّ قَالَ إِخْ إِخْ لِيَحْمِلَنِي خَلْفَهُ فَاسْتَحْيَيْتُ أَنْ أَسِيرَ مَعَ الرِّجَالِ وَذَكَرْتُ الزُّبَيْرَ وَغَيْرَتَهُ وَكَانَ أَغْيَرَ النَّاسِ فَعَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنِّي قَدْ اسْتَحْيَيْتُ فَمَضَى فَجِئْتُ الزُّبَيْرَ فَقُلْتُ لَقِيَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَى رَأْسِي النَّوَى وَمَعَهُ نَفَرٌ مِنْ أَصْحَابِهِ فَأَنَاخَ لِأَرْكَبَ فَاسْتَحْيَيْتُ مِنْهُ وَعَرَفْتُ غَيْرَتَكَ فَقَالَ وَاللَّهِ لَحَمْلُكِ النَّوَى كَانَ أَشَدَّ عَلَيَّ مِنْ رُكُوبِكِ مَعَهُ قَالَتْ حَتَّى أَرْسَلَ إِلَيَّ أَبُو بَكْرٍ بَعْدَ ذَلِكَ بِخَادِمٍ تَكْفِينِي سِيَاسَةَ الْفَرَسِ فَكَأَنَّمَا أَعْتَقَنِي","id":"Telah menceritakan kepada kami [Mahmud] Telah menceritakan kepada kami [Abu Usamah] Telah menceritakan kepada kami [Hisyam] ia berkata; Telah mengabarkan kepadaku [bapakku] dari [Asma` binti Abu Bakar radliallahu 'anhuma] ia berkata; Az Zubair bin Awwam menikahiku. Saat itu, ia tidak memiliki harta dan tidak juga memiliki budak serta tidak memiliki apa-apa kecuali alat penyiram lahan dan seekor kuda. Maka akulah yang memberi makan dan minum kudanya, menjahit timbanya serta membuatkan adonan roti. Padahal aku bukanlah seorang yang pandai membuat roti. Karena itu, para tetanggaku dari kaum Anshar-lah yang membuatkan roti. Aku memindahkan biji kurma dari kebun Az Zubair yang telah ditetapkan oleh Rasulullah shallallahu 'alaihi wasallam di atas kepalaku. Tanah itu dariku atas duapertiga Farsakh. Suatu hari aku datang sementara biji kurma ada di atas kepalaku. Lalu aku berjumpa dengan Rasulullah shallallahu 'alaihi wasallam yang sedang bersama beberapa orang dari kaum Anshar. Beliau kemudian memanggilku dan bersabda: \"Hei, hei, rupanya beliau berhasrat untuk menaikkanku diatas kendaraan di belakangnya. Namun, aku malu untuk berjalan bersama para lelaki dan aku ingat akan kecemburuan Az Zubair, ia adalah orang yang paling pencemburu. Maka Rasulullah shallallahu 'alaihi wasallam pun tahu bahwa aku malu, hingga beliau pun berlalu. Setelah itu, aku pun menemui Az Zubair dan berkata, \"Rasulullah shallallahu 'alaihi wasallam menemuiku sementara di atas kepalaku ada biji kurma. Sedangkan beliau sedang bersama beberapa orang dari kalangan Anshar, lalu beliau mempersilahkan agar aku naik kendaraan, namun aku malu dan juga tahu akan kecemburuanmu.\" Maka Az Zubair pun berkata, \"Demi Allah, kamu membawa biji kurma itu adalah lebih besar bagiku daripada engkau naik kendaraan bersama beliau.\" Akhirnya Abu Bakar pun mengutuskan seorang khadim yang dapat mencukupi pekerjaanku untuk mengurusi kuda. Dan seolah-olah ia telah membebaskanku."},"4519":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ بَعْضِ نِسَائِهِ فَأَرْسَلَتْ إِحْدَى أُمَّهَاتِ الْمُؤْمِنِينَ بِصَحْفَةٍ فِيهَا طَعَامٌ فَضَرَبَتْ الَّتِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِهَا يَدَ الْخَادِمِ فَسَقَطَتْ الصَّحْفَةُ فَانْفَلَقَتْ فَجَمَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِلَقَ الصَّحْفَةِ ثُمَّ جَعَلَ يَجْمَعُ فِيهَا الطَّعَامَ الَّذِي كَانَ فِي الصَّحْفَةِ وَيَقُولُ غَارَتْ أُمُّكُمْ ثُمَّ حَبَسَ الْخَادِمَ حَتَّى أُتِيَ بِصَحْفَةٍ مِنْ عِنْدِ الَّتِي هُوَ فِي بَيْتِهَا فَدَفَعَ الصَّحْفَةَ الصَّحِيحَةَ إِلَى الَّتِي كُسِرَتْ صَحْفَتُهَا وَأَمْسَكَ الْمَكْسُورَةَ فِي بَيْتِ الَّتِي كَسَرَتْ","id":"Telah menceritakan kepada kami [Ali] telah menceritakan kepada kami [Ibnu Ulayyah] dari [Humaid] dari [Anas] ia berkata; Suatu ketika Nabi shallallahu 'alaihi wasallam berada di tempat isterinya. Lalu salah seorang Ummahatul Mukminin mengirimkan hidangan berisi makanan. Maka isteri Nabi yang beliau saat itu sedang berada dirumahnya memukul piring yang berisi makanan, maka beliau pun segera mengumpulkan makanan yang tercecer ke dalam piring, lalu beliau bersabda: \"Ibu kalian rupanya sedang terbakar cemburu.\" Kemudian beliau menahan sang Khadim (pembantu) hingga didatangkan piring yang berasal dari rumah isteri yang beliau pergunakan untuk bermukim. Lalu beliau menyerahkan piring yang bagus kepada isteri yang piringnya pecah, dan membiarkan piring yang pecah di rumah isteri yang telah memecahkannya."},"4520":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا مُعْتَمِرٌ عَنْ عُبَيْدِ اللَّهِ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ دَخَلْتُ الْجَنَّةَ أَوْ أَتَيْتُ الْجَنَّةَ فَأَبْصَرْتُ قَصْرًا فَقُلْتُ لِمَنْ هَذَا قَالُوا لِعُمَرَ بْنِ الْخَطَّابِ فَأَرَدْتُ أَنْ أَدْخُلَهُ فَلَمْ يَمْنَعْنِي إِلَّا عِلْمِي بِغَيْرَتِكَ قَالَ عُمَرُ بْنُ الْخَطَّابِ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي يَا نَبِيَّ اللَّهِ أَوَعَلَيْكَ أَغَارُ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakr Al Muqaddami] Telah menceritakan kepada kami [Mu'tamir] dari [Ubaidullah] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] radliallahu 'anhuma, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku memasuki surga, -atau- aku mendatangi surga, lalu aku melihat sebuah istana, maka aku pun bertanya, 'Untuk siapa ini? ' mereka menjawab, 'Untuk Umar bin Al Khaththab.' Lalu aku ingin memasukinya, dan tidak ada yang menghalangiku kecuali pengetahuanku terhadap kecemburuanmu yang besar.\" Umar bin Al Khaththab berkata, \"Wahai Rasulullah, demi bapak, Anda dan ibuku, wahai Nabiyullah apakah kepada Anda aku merasa cemburu?\""},"4521":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي ابْنُ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَبَيْنَمَا نَحْنُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جُلُوسٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَمَا أَنَا نَائِمٌ رَأَيْتُنِي فِي الْجَنَّةِ فَإِذَا امْرَأَةٌ تَتَوَضَّأُ إِلَى جَانِبِ قَصْرٍ فَقُلْتُ لِمَنْ هَذَا قَالُوا هَذَا لِعُمَرَ فَذَكَرْتُ غَيْرَتَكَ فَوَلَّيْتُ مُدْبِرًا فَبَكَى عُمَرُ وَهُوَ فِي الْمَجْلِسِ ثُمَّ قَالَ أَوَعَلَيْكَ يَا رَسُولَ اللَّهِ أَغَارُ","id":"Telah menceritakan kepada kami [Abdan] Telah mengabarkan kepada kami [Abdullah] dari [Yunus] dari [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [Ibnul Musayyab] dari [Abu Hurairah] ia berkata; Ketika aku duduk-duduk di sisi Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika aku tidur, diperlihatkanlah surga padaku, dan aku pun melihat seorang wanita yang sedang berwudlu di samping istana. Lalu aku pun bertanya, 'Siapakah ini? ' mereka menjawab, 'Mereka menjawab, ini adalah untuk si Umar.' Kemudian aku teringat akan kecemburuanmu, lalu wanita itu pun berpaling pergi.\" Maka Umar pun menangis di majelis itu dan bertanya, \"Apakah kepadamu aku cemburu wahai Rasulullah?\""},"4522":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَعْلَمُ إِذَا كُنْتِ عَنِّي رَاضِيَةً وَإِذَا كُنْتِ عَلَيَّ غَضْبَى قَالَتْ فَقُلْتُ مِنْ أَيْنَ تَعْرِفُ ذَلِكَ فَقَالَ أَمَّا إِذَا كُنْتِ عَنِّي رَاضِيَةً فَإِنَّكِ تَقُولِينَ لَا وَرَبِّ مُحَمَّدٍ وَإِذَا كُنْتِ عَلَيَّ غَضْبَى قُلْتِ لَا وَرَبِّ إِبْرَاهِيمَ قَالَتْ قُلْتُ أَجَلْ وَاللَّهِ يَا رَسُولَ اللَّهِ مَا أَهْجُرُ إِلَّا اسْمَكَ","id":"Telah menceritakan kepada kami [Ubaid bin Isma'il] Telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [bapaknya] dari [Aisyah] radliallahu 'anha, ia berkata; Rasulullah shallallahu 'alaihi wasallam perna bersabda kepadaku: \"Sesungguhnya aku benar-benar tahu saat kamu ridla padaku dan saat kamu tidak ridla denganku.\" Aisyah berkata; Aku bertanya, \"Dari mana Anda mengetahui hal itu?\" maka beliau pun menjawab: \"Jika kamu ridla terhadapku maka engkau berkata, 'Demi Rabb Muhammad.' Namun bila kamu sedang marah denganku, maka kamu berkata, 'Tidak. Demi Rabb Ibrahim.'\" Aku pun berkata, \"Demi Allah wahai Rasulullah, aku tidak meninggalkan namamu.\""},"4523":{"ar":"حَدَّثَنِي أَحْمَدُ ابْنُ أَبِي رَجَاءٍ حَدَّثَنَا النَّضْرُ عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ أَنَّهَا قَالَتْمَا غِرْتُ عَلَى امْرَأَةٍ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا غِرْتُ عَلَى خَدِيجَةَ لِكَثْرَةِ ذِكْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِيَّاهَا وَثَنَائِهِ عَلَيْهَا وَقَدْ أُوحِيَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُبَشِّرَهَا بِبَيْتٍ لَهَا فِي الْجَنَّةِ مِنْ قَصَبٍ","id":"Telah menceritakan kepadaku [Ahmad bin Abu Raja`] Telah menceritakan kepada kami [An Nadlr] dari [Hisyam] ia berkata; Telah mengabarkan kepadaku [bapakku] dari [Aisyah] bahwa ia pernah berkata, \"Aku tidak pernah merasa cemburu terhadap isteri-isteri Rasulullah shallallahu 'alaihi wasallam, melebihi rasa cemburuku kepada Khadijah, yang demikian karena begitu seringnya Rasulullah shallallahu 'alaihi wasallam menyebut-nyebut dan memuji kebaikannya. Dan sesungguhnya telah diwahyukan kepada Rasulullah shallallahu 'alaihi wasallam untuk memberi kabar gembira kepadanya dengan rumah yang dipersembahkan untuknya di dalam surga yang terbuat dari marmer.\""},"4524":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَهُوَ عَلَى الْمِنْبَرِ إِنَّ بَنِي هِشَامِ بْنِ الْمُغِيرَةِ اسْتَأْذَنُوا فِي أَنْ يُنْكِحُوا ابْنَتَهُمْ عَلِيَّ بْنَ أَبِي طَالِبٍ فَلَا آذَنُ ثُمَّ لَا آذَنُ ثُمَّ لَا آذَنُ إِلَّا أَنْ يُرِيدَ ابْنُ أَبِي طَالِبٍ أَنْ يُطَلِّقَ ابْنَتِي وَيَنْكِحَ ابْنَتَهُمْ فَإِنَّمَا هِيَ بَضْعَةٌ مِنِّي يُرِيبُنِي مَا أَرَابَهَا وَيُؤْذِينِي مَا آذَاهَا هَكَذَا قَالَ","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Al Laits] dari [Abu Mulaikah] dari [Al Miswar bin Makhramah] ia berkata; AKu mendengar Rasulullah shallallahu 'alaihi wasallam bersabda sedangkan beliau berada di atas mimbar: \"Sesungguhnya bani Hisyam bin Al Mughirah meminta izin kepadaku agar aku menikahkan anak wanita mereka dengan Ali bin Abu Thalib, namun aku tidak mengizinkan kepada mereka, kecuali jika Ali bin Abu Thalib menceraikan anakku lalu menikahi anak wanita mereka. Sesungguhnya anakku (Fathimah) adalah bagian dariku, aku merasa senang dengan apa saja yang menyenangkannya dan aku merasa tersakiti atas semua yang menyakitinya.\""},"4525":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ الْحَوْضِيُّ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَأُحَدِّثَنَّكُمْ حَدِيثًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُحَدِّثُكُمْ بِهِ أَحَدٌ غَيْرِي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ مِنْ أَشْرَاطِ السَّاعَةِ أَنْ يُرْفَعَ الْعِلْمُ وَيَكْثُرَ الْجَهْلُ وَيَكْثُرَ الزِّنَا وَيَكْثُرَ شُرْبُ الْخَمْرِ وَيَقِلَّ الرِّجَالُ وَيَكْثُرَ النِّسَاءُ حَتَّى يَكُونَ لِخَمْسِينَ امْرَأَةً الْقَيِّمُ الْوَاحِدُ","id":"Telah menceritakan kepada kami [Hafsh bin Umar Al Haudli] Telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas] radliallahu 'anhu, ia berkata; Aku benar-benar akan menceritakan suatu hadits yang telah aku dengar dari Rasulullah shallallahu 'alaihi wasallam, yang selain diriku tidak akan menceritakannya kepada kalian. Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Diantara tanda hari kiamat datang adalah ilmu diangkat, banyaknya kebodohan, merajalelanya perzinahan, banyaknya orang yang meminum khamer dan sedikitnya kaum laki-laki serta banyaknya kaum wanita hingga jika ada lima puluh orang wanita namun hanya ada satu orang laki-laki dari mereka.\""},"4526":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِيَّاكُمْ وَالدُّخُولَ عَلَى النِّسَاءِ فَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ يَا رَسُولَ اللَّهِ أَفَرَأَيْتَ الْحَمْوَ قَالَ الْحَمْوُ الْمَوْتُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Laits] dari [Yazid bin Abu Habib] dari [Abul Khair] dari [Uqbah bin Amir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian masuk ke dalam tempat kaum wanita.\" Lalu seorang laki-laki dari Anshar berkata, \"Wahai Rasulullah, bagaimana pendapat Anda mengenai ipar?\" beliau menjawab: \"Ipar adalah maut.\""},"4527":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو عَنْ أَبِي مَعْبَدٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَخْلُوَنَّ رَجُلٌ بِامْرَأَةٍ إِلَّا مَعَ ذِي مَحْرَمٍ فَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ امْرَأَتِي خَرَجَتْ حَاجَّةً وَاكْتُتِبْتُ فِي غَزْوَةِ كَذَا وَكَذَا قَالَ ارْجِعْ فَحُجَّ مَعَ امْرَأَتِكَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Amru] dari [Abu Ma'bad] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah sekali-kali seorang laki-laki berduaan dengan perempuan kecuali dengan ditemani muhrimnya.\" Lalu seorang laki-laki bangkit seraya berkata, \"Wahai Rasulullah, isteriku berangkat hendak menunaikan haji sementara aku diwajibkan untuk mengikuti perang ini dan ini.\" beliau bersabda: \"Kalau begitu, kembali dan tunaikanlah haji bersama isterimu.\""},"4528":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ هِشَامٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَتْ امْرَأَةٌ مِنْ الْأَنْصَارِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَلَا بِهَا فَقَالَ وَاللَّهِ إِنَّكُنَّ لَأَحَبُّ النَّاسِ إِلَيَّ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] Telah menceritakan kepada kami [Ghundar] Telah menceritakan kepada kami [Syu'bah] dari [Hisyam] ia berkata; Aku mendengar [Anas bin Malik] radliallahu 'anhu berkata; Seorang wanita datang kepada Nabi shallallahu 'alaihi wasallam, lalu beliau pun menyendiri dan bersabda: \"Demi Allah, kalian adalah manusia yang paling aku cintai.\""},"4529":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ عِنْدَهَا وَفِي الْبَيْتِ مُخَنَّثٌ فَقَالَ الْمُخَنَّثُ لِأَخِي أُمِّ سَلَمَةَ عَبْدِ اللَّهِ بْنِ أَبِي أُمَيَّةَ إِنْ فَتَحَ اللَّهُ لَكُمْ الطَّائِفَ غَدًا أَدُلُّكَ عَلَى بِنْتِ غَيْلَانَ فَإِنَّهَا تُقْبِلُ بِأَرْبَعٍ وَتُدْبِرُ بِثَمَانٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدْخُلَنَّ هَذَا عَلَيْكُنَّ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] Telah menceritakan kepada kami [Abdah] dari [Hisyam bin Urwah] dari [bapaknya] dari [Zainab binti Ummu Salamah] dari [Ummu Salamah] bahwasanya; Suatu ketika Nabi shallallahu 'alaihi wasallam berada di rumahnya. Sementara di dalam rumah ada Mukhannats (seorang laki-laki yang bertingkah laku seperti perempuan, waria). Sang Mukhannats berkata kepada saudara laki-laki Ummu Salamah yakni Abdullah bin Abu Umayyah, \"Jika Allah memberi kekuatan pada kalian untuk menaklukkan Tha`if esok hari, maka aku akan menunjukkan padamu anak wanita Ghailan, sesungguhnya ia akan menerima dengan empat dan akan berpaling dengan delapan.\" Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Janganlah sekali-kali orang ini menemui kepada kalian.\""},"4530":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ عَنْ عِيسَى عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتُرُنِي بِرِدَائِهِ وَأَنَا أَنْظُرُ إِلَى الْحَبَشَةِ يَلْعَبُونَ فِي الْمَسْجِدِ حَتَّى أَكُونَ أَنَا الَّتِي أَسْأَمُفَاقْدُرُوا قَدْرَ الْجَارِيَةِ الْحَدِيثَةِ السِّنِّ الْحَرِيصَةِ عَلَى اللَّهْوِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] dari [Isa] dari [Al Auza'i] dari [Az Zuhri] dari [Urwah] dari [Aisyah] radliallahu 'anha, ia berkata; \"Aku melihat Nabi shallallahu 'alaihi wasallam menutupiku dengan pakaiannya, sementara aku melihat ke arah orang-orang Habasyah yang sedang bermain di dalam Masjid sampai aku sendirilah yang merasa puas. Karenanya, sebisa mungkin kalian bisa seperti gadis belia yang suka bercanda.\""},"4531":{"ar":"حَدَّثَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْخَرَجَتْ سَوْدَةُ بِنْتُ زَمْعَةَ لَيْلًا فَرَآهَا عُمَرُ فَعَرَفَهَا فَقَالَ إِنَّكِ وَاللَّهِ يَا سَوْدَةُ مَا تَخْفَيْنَ عَلَيْنَا فَرَجَعَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ ذَلِكَ لَهُ وَهُوَ فِي حُجْرَتِي يَتَعَشَّى وَإِنَّ فِي يَدِهِ لَعَرْقًا فَأَنْزَلَ اللَّهُ عَلَيْهِ فَرُفِعَ عَنْهُ وَهُوَ يَقُولُ قَدْ أَذِنَ اللَّهُ لَكُنَّ أَنْ تَخْرُجْنَ لِحَوَائِجِكُنَّ","id":"Telah menceritakan kepada kami [Farwah bin Abu Al Maghra`] Telah menceritakan kepada kami [Ali bin Mushir] dari [Hisyam] dari [bapaknya] dari [Aisyah] ia berkata; Pada suatu malam, Saudah binti Zam'ah keluar, lalu Umar pun melihatnya dan mengenalnya, maka ia pun berkata, \"Demi Allah, sesungguhnya kamu wahai Saudah tidak akan samar bagi kami.\" Maka ia pun kembali kepada Nabi shallallahu 'alaihi wasallam dan menuturkan hal itu pada beliau, dan saat itu beliau berada di rumahku dan sedang makan malam, sementara di tangan beliau terdapat keringat, maka Allah menurunkan wahyu kepadanya, lalu keringat itu hilang. Beliau bersabda: \"Sesungguhnya Allah telah mengizin kalian untuk membuang hajat.\""},"4532":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ عَنْ سَالِمٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَأْذَنَتْ امْرَأَةُ أَحَدِكُمْ إِلَى الْمَسْجِدِ فَلَا يَمْنَعْهَا","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Az Zuhri] dari [Salim] dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari isteri kalian meminta izin ke masjid, maka janganlah ia melarangnya.\""},"4533":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْجَاءَ عَمِّي مِنْ الرَّضَاعَةِ فَاسْتَأْذَنَ عَلَيَّ فَأَبَيْتُ أَنْ آذَنَ لَهُ حَتَّى أَسْأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُهُ عَنْ ذَلِكَ فَقَالَ إِنَّهُ عَمُّكِ فَأْذَنِي لَهُ قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا أَرْضَعَتْنِي الْمَرْأَةُ وَلَمْ يُرْضِعْنِي الرَّجُلُ قَالَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ عَمُّكِ فَلْيَلِجْ عَلَيْكِ قَالَتْ عَائِشَةُ وَذَلِكَ بَعْدَ أَنْ ضُرِبَ عَلَيْنَا الْحِجَابُ قَالَتْ عَائِشَةُ يَحْرُمُ مِنْ الرَّضَاعَةِ مَا يَحْرُمُ مِنْ الْوِلَادَةِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] radliallahu 'anha, bahwa ia berkata; Suatu ketika pamanku sesusuan datang dan meminta izin kepadaku, namun aku tidak memperkenankan untuk memberinya izin hingga aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian datanglah Rasulullah shallallahu 'alaihi wasallam dan aku pun bertanya mengenai hal itu, maka beliau bersabda: \"Sesungguhnya ia adalah pamanmu, karena itu izinkanlah ia.\" Aku berkata, \"Wahai Rasulullah, sesunggunguhnya yang menyusuiku hanyalah seorang wanita dan bukan laki-laki.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ia adalah pamanmu, silahkan ia masuk.\" Aisyah berkata, \"Peristiwa itu terjadi setelah turunnya perintah hijab.\" Aisyah berkata, \"Penyusuan itu mengharamkan apa yang diharamkan karena hubungan darah (kekerabatan).\""},"4534":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُبَاشِرُ الْمَرْأَةُ الْمَرْأَةَ فَتَنْعَتَهَا لِزَوْجِهَا كَأَنَّهُ يَنْظُرُ إِلَيْهَا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Abu Wa`il] dari [Abdullah bin Mas'ud] radliallahu 'anhu, ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang isteri menceritakan sifat-sifat wanita lain pada suaminya sehingga ia seolah-olah melihatnya.\""},"4535":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي شَقِيقٌ قَالَ سَمِعْتُ عَبْدَ اللَّهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُبَاشِرْ الْمَرْأَةُ الْمَرْأَةَ فَتَنْعَتَهَا لِزَوْجِهَا كَأَنَّهُ يَنْظُرُ إِلَيْهَا","id":"Telah menceritakan kepada kami [Umar bin Hafsh bin Ghiyats] Telah menceritakan kepada kami [bapakku] Telah menceritakan kepada kami [Al A'masy] ia berkata; Telah menceritakan kepadaku [Syaqiq] ia berkata; Aku mendengar [Abdullah] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang isteri menceritakan ciri-ciri wanita lain pada suaminya sehingga ia seolah-olah melihatnya.\""},"4536":{"ar":"حَدَّثَنِي مَحْمُودٌ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ سُلَيْمَانُ بْنُ دَاوُدَ عَلَيْهِمَا السَّلَام لَأَطُوفَنَّ اللَّيْلَةَ بِمِائَةِ امْرَأَةٍ تَلِدُ كُلُّ امْرَأَةٍ غُلَامًا يُقَاتِلُ فِي سَبِيلِ اللَّهِ فَقَالَ لَهُ الْمَلَكُ قُلْ إِنْ شَاءَ اللَّهُ فَلَمْ يَقُلْ وَنَسِيَ فَأَطَافَ بِهِنَّ وَلَمْ تَلِدْ مِنْهُنَّ إِلَّا امْرَأَةٌ نِصْفَ إِنْسَانٍ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ قَالَ إِنْ شَاءَ اللَّهُ لَمْ يَحْنَثْ وَكَانَ أَرْجَى لِحَاجَتِهِ","id":"Telah menceritakan kepadaku [Mahmud] Telah menceritakan kepada kami [Abdurrazzaq] Telah mengabarkan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [bapaknya] dari [Abu Hurairah] ia berkata; Sulaiman bin Dawud 'Alaihimas Salam berkata, \"Pada malam ini, aku benar-benar akan menggilir seratus orang isteri, sehingga setiap wanita akan melahirkan seroang anak yang berjihad di jalan Allah.\" Lalu Malaikat pun berkata padanya, \"Katakanlah Insya Allah.\" Namun ternyata ia tidak mengatakannya dan lupa. Kemudian ia pun menggilir pada malam itu, namun tak seorang pun dari mereka yang melahirkan, kecuali seorang wanita yang berbentuk setengah manusia. Nabi shallallahu 'alaihi wasallam bersabda: \"Sekiranya ia mengatakan Insya Allah niscaya ia tidak akan membatalkan sumpahnya, dan juga hajatnya akan terkabulkan.\""},"4537":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُحَارِبُ بْنُ دِثَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكْرَهُ أَنْ يَأْتِيَ الرَّجُلُ أَهْلَهُ طُرُوقًا","id":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Muharib bin Ditsar] ia berkata; Aku mendengar [Jabir bin Abdullah] radliallahu 'anhuma berkata; Nabi shallallahu 'alaihi wasallam tak suka bila seseorang mendatangi keluarganya secara tiba-tiba di malam hari."},"4538":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عَاصِمُ بْنُ سُلَيْمَانَ عَنْ الشَّعْبِيِّ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَطَالَ أَحَدُكُمْ الْغَيْبَةَ فَلَا يَطْرُقْ أَهْلَهُ لَيْلًا","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Ashim bin Sulaiman] dari [Asy Sya'bi] bahwa ia mendengar [Jabir bihn Abdullah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian pergi agak lama, maka janganlah ia mendatangi keluarganya secara mendadak di malam hari.\""},"4539":{"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ هُشَيْمٍ عَنْ سَيَّارٍ عَنْ الشَّعْبِيِّ عَنْ جَابِرٍ قَالَكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةٍ فَلَمَّا قَفَلْنَا تَعَجَّلْتُ عَلَى بَعِيرٍ قَطُوفٍ فَلَحِقَنِي رَاكِبٌ مِنْ خَلْفِي فَالْتَفَتُّ فَإِذَا أَنَا بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا يُعْجِلُكَ قُلْتُ إِنِّي حَدِيثُ عَهْدٍ بِعُرْسٍ قَالَ فَبِكْرًا تَزَوَّجْتَ أَمْ ثَيِّبًا قُلْتُ بَلْ ثَيِّبًا قَالَ فَهَلَّا جَارِيَةً تُلَاعِبُهَا وَتُلَاعِبُكَ قَالَ فَلَمَّا قَدِمْنَا ذَهَبْنَا لِنَدْخُلَ فَقَالَ أَمْهِلُوا حَتَّى تَدْخُلُوا لَيْلًا أَيْ عِشَاءً لِكَيْ تَمْتَشِطَ الشَّعِثَةُ وَتَسْتَحِدَّ الْمُغِيبَةُ قَالَ وَحَدَّثَنِي الثِّقَةُ أَنَّهُ قَالَ فِي هَذَا الْحَدِيثِ الْكَيْسَ الْكَيْسَ يَا جَابِرُ يَعْنِي الْوَلَدَ","id":"Telah menceritakan kepada kami [Musaddad] dari [Husyaim] dari [Sayyar] dari [Asy Sya'bi] dari [Jabir] ia berkata; Aku pernah berada bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu peperangan. Ketika perjalanan pulang aku terburu-buru melajukan Untaku, lalu seorang pengendara dari arah belakang menghampiriku. Maka aku memalingkan muka, ternyata ia adalah Rasulullah shallallahu 'alaihi wasallam. Beliau bertanya: \"Apa yang menyebabkanmu untuk tergesa-gesa?\" Aku menjawab, \"Karena sebentar lagi aku akan melaksanakan walimatul 'ursy.\" Beliau bertanya lagi: \"Apakah kamu menikahi seroang gadis ataukah janda?\" Aku menjawab, \"Janda.\" Beliau bersabda: \"Kenapa tidak dengan gadis sehingga kamu dapat bercanda dengannya dan ia pun dapat bercanda denganmu.\" Ketika sudah mendekat dan akan sampai, kami pun pergi untuk segera masuk, maka beliau bersabda: \"Pelan-pelanlah hingga kalian masuk tepat pada malam (yaitu setelah shalat Isya) sehingga yang kusut rambutnya dapat bersisir dan mereka pun bisa mempersiapkan diri.\" Ia berkata; Dan Telah menceritakan kepada kami seorang yang Tsiqqah ia berkata; Di dalam hadits ini terdapat ungkapan: \"Kalau bisa segeralah punya anak, kalau bisa segeralah punya anak wahai Jabir.\" Maksudnya adalah anak."},"4540":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْوَلِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سَيَّارٍ عَنْ الشَّعْبِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلْتَ لَيْلًا فَلَا تَدْخُلْ عَلَى أَهْلِكَ حَتَّى تَسْتَحِدَّ الْمُغِيبَةُ وَتَمْتَشِطَ الشَّعِثَةُ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَيْكَ بِالْكَيْسِ الْكَيْسِتَابَعَهُ عُبَيْدُ اللَّهِ عَنْ وَهْبٍ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْكَيْسِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Walid] Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Sayyar] dari [Asy Sya'bi] dari [Jabir bin Abdullah] radliallahu 'anhuma, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika kalian tiba dari bepergian pada malam hari, maka janganlah kalian temui keluargamu, hingga orang yang ditinggal dapat berdandan dan yang kusut rambutnya bisa bersisir.\" Syu'bah berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah kamu mempercepat punya anak, hendaklah kamu mempercepat punya anak.\" Hadis ini diperkuat oleh [Ubaidullah] dari [Wahb] dari [Jabir], dari Nabi shallallahu 'alaihi wasallam, yakni terkait dengan ucapan 'Hendaklah kamu mempercepat punya anak, Hendaklah kamu mempercepat punya anak,."},"4541":{"ar":"حَدَّثَنِي يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا سَيَّارٌ عَنْ الشَّعْبِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةٍ فَلَمَّا قَفَلْنَا كُنَّا قَرِيبًا مِنْ الْمَدِينَةِ تَعَجَّلْتُ عَلَى بَعِيرٍ لِي قَطُوفٍ فَلَحِقَنِي رَاكِبٌ مِنْ خَلْفِي فَنَخَسَ بَعِيرِي بِعَنَزَةٍ كَانَتْ مَعَهُ فَسَارَ بَعِيرِي كَأَحْسَنِ مَا أَنْتَ رَاءٍ مِنْ الْإِبِلِ فَالْتَفَتُّ فَإِذَا أَنَا بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي حَدِيثُ عَهْدٍ بِعُرْسٍ قَالَ أَتَزَوَّجْتَ قُلْتُ نَعَمْ قَالَ أَبِكْرًا أَمْ ثَيِّبًا قَالَ قُلْتُ بَلْ ثَيِّبًا قَالَ فَهَلَّا بِكْرًا تُلَاعِبُهَا وَتُلَاعِبُكَ قَالَ فَلَمَّا قَدِمْنَا ذَهَبْنَا لِنَدْخُلَ فَقَالَ أَمْهِلُوا حَتَّى تَدْخُلُوا لَيْلًا أَيْ عِشَاءً لِكَيْ تَمْتَشِطَ الشَّعِثَةُ وَتَسْتَحِدَّ الْمُغِيبَةُ","id":"Telah menceritakan kepadaku [Ya'qub bin Ibrahim] Telah menceritakan kepada kami [Husyaim] Telah mengabarkan kepada kami [Sayyar] dari [Asy Sya'bi] dari [Jabir bin Abdullah] ia berkata; Suatu ketika, kami berada bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu peperangan. Saat perjalanan kembali dan telah mendekati kota Madinah, maka aku pun memacu laju Untaku. Lalu seseorang menyusulku dari belakang dan menahan laju Untaku dengan tongkat miliknya hingga Untaku menjadi sangat lamban sebagaimana Unta yang paling yang pernah Anda lihat. Aku menoleh, ternyata orang itu adalah Rasulullah shallallahu 'alaihi wasallam. Aku pun berkata, \"Wahai Rasulullah, sesungguhnya aku punya hajat Walimatul Ursy.\" Beliau bertanya: \"Apakah kamu telah menikahi seorang wanita?\" Aku menjawab: \"Ya.\" Beliau bertanya lagi: \"Dengan gadis ataukah janda?\" Aku menjawab, \"Janda.\" Beliau bersabda: \"Kenapa tidak dengan gadis sehingga kamu dapat bermain-main dengannya dan ia pun dapat bermain-main denganmu?.\" Ketika sudah mendekat dan akan sampai, kami pun pergi untuk segera masuk, maka beliau bersabda: \"Pelan-pelanlah hingga kalian masuk tepat pada malam (yaitu setelah shalat Isya) sehingga yang kusut rambutnya dapat bersisir dan isteri yang ditinggal bisa mempersiapkan diri.\""},"4542":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي حَازِمٍ قَالَاخْتَلَفَ النَّاسُ بِأَيِّ شَيْءٍ دُووِيَ جُرْحُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ فَسَأَلُوا سَهْلَ بْنَ سَعْدٍ السَّاعِدِيَّ وَكَانَ مِنْ آخِرِ مَنْ بَقِيَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ فَقَالَ وَمَا بَقِيَ مِنْ النَّاسِ أَحَدٌ أَعْلَمُ بِهِ مِنِّي كَانَتْ فَاطِمَةُ عَلَيْهَا السَّلَام تَغْسِلُ الدَّمَ عَنْ وَجْهِهِ وَعَلِيٌّ يَأْتِي بِالْمَاءِ عَلَى تُرْسِهِ فَأُخِذَ حَصِيرٌ فَحُرِّقَ فَحُشِيَ بِهِ جُرْحُهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Sufyan] dari [Abu Hazim] ia berkata; Orang-orang berselisih, dengan obat apa luka Rasulullah shallallahu 'alaihi wasallam diobati pada perang Uhud. Mereka bertanya kepada [Sahl bin Sa'd As Sa'idi] -ia termasuk salah seorang sahabat yang paling akhir wafat di Madinah- ia pun berkata; \"Tidak ada seorang pun yang lebih tahu tentangnya melebihi aku. Fathimah 'Alaihas Salam membersihkan luka dari wajah beliau, sementara Ali datang membawakan air dengan menggunakan tameng. Kemudian diambillah sehelai tikar lalu dirobek dan digunakan untuk membalut lukanya.\""},"4543":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاسَأَلَهُ رَجُلٌ شَهِدْتَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعِيدَ أَضْحًى أَوْ فِطْرًا قَالَ نَعَمْ وَلَوْلَا مَكَانِي مِنْهُ مَا شَهِدْتُهُ يَعْنِي مِنْ صِغَرِهِ قَالَ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى ثُمَّ خَطَبَ وَلَمْ يَذْكُرْ أَذَانًا وَلَا إِقَامَةً ثُمَّ أَتَى النِّسَاءَ فَوَعَظَهُنَّ وَذَكَّرَهُنَّ وَأَمَرَهُنَّ بِالصَّدَقَةِ فَرَأَيْتُهُنَّ يَهْوِينَ إِلَى آذَانِهِنَّ وَحُلُوقِهِنَّ يَدْفَعْنَ إِلَى بِلَالٍ ثُمَّ ارْتَفَعَ هُوَ وَبِلَالٌ إِلَى بَيْتِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Sufyan] dari [Abdurrahman bin Abis] Aku mendengar [Ibnu Abbas] radliallahu 'anhuma, bahwa ia pernah ditanya oleh seorang laki-laki, \"Apakah Anda pernah shalat 'Ied Fithri atau Adlha bersama Rasulullah shallallahu 'alaihi wasallam?\" Ia menjawab, \"Ya. Sekiranya bukan karena kedudukanku saat itu, aku tidak mungkin melihatnya.\" Yakni, saat itu ia masih kecil. Ibnu Abbas melanjutkan, \"Saat itu, Rasulullah shallallahu 'alaihi wasallam keluar lalu shalat dan melanjutkannya dengan khuthbah. Beliau tidak menyebutkan adzan dan tidak pula iqamah. Sesudah itu, beliau mendatangi kaum wanita dan memberi peringatan bagi mereka dan memerintahkan mereka untuk bersedekah, maka aku melihat mereka mempreteli perhiasan telinga dan leher mereka lalu menyerahkan (anting dan kalung) mereka kepada Bilal.\" Kemudian ia bersama Bilal mengangkatnya ke rumah beliau."},"4544":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْعَاتَبَنِي أَبُو بَكْرٍ وَجَعَلَ يَطْعُنُنِي بِيَدِهِ فِي خَاصِرَتِي فَلَا يَمْنَعُنِي مِنْ التَّحَرُّكِ إِلَّا مَكَانُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَأْسُهُ عَلَى فَخِذِي","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Abdurrahman bin Al Qasim] dari [bapaknya] dari [Aisyah] ia berkata; Abu Bakar pernah menegurku secara langsung dengan menggunakan tangannya dan menekan lambungku. Dan tidak ada yang menghalangiku untuk bergerak kecuali tempat Rasulullah shallallahu 'alaihi wasallam dimana kepalanya berada di atas pahaku."},"4545":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَ عُمَرُ بْنُ الْخَطَّابِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْهُ فَلْيُرَاجِعْهَا ثُمَّ لِيُمْسِكْهَا حَتَّى تَطْهُرَ ثُمَّ تَحِيضَ ثُمَّ تَطْهُرَ ثُمَّ إِنْ شَاءَ أَمْسَكَ بَعْدُ وَإِنْ شَاءَ طَلَّقَ قَبْلَ أَنْ يَمَسَّ فَتِلْكَ الْعِدَّةُ الَّتِي أَمَرَ اللَّهُ أَنْ تُطَلَّقَ لَهَا النِّسَاءُ","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah] ia berakta; Telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Abdullah bin Umar] radliallahu 'anhuma, bahwa pada masa Rasulullah shallallahu 'alaihi wasallam, ia pernah menceraikan isterinya dalam keadaan haid, maka Umar bin Al Khaththab pun menanyakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perintahkanlah agar ia segera meruju'nya, lalu menahannya hingga ia suci dan haid kembali kemudian suci. Maka pada saat itu, bila ia mau, ia boleh menahannya, dan bila ingin, ia juga boleh menceraikannya. Itulah Al Iddah yang diperintahkan oleh Allah untuk mentalak isteri.\""},"4546":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ أَنَسِ بْنِ سِيرِينَ قَالَ سَمِعْتُ ابْنَ عُمَرَ قَالَطَلَّقَ ابْنُ عُمَرَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَذَكَرَ عُمَرُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِيُرَاجِعْهَا قُلْتُ تُحْتَسَبُ قَالَ فَمَهْوَعَنْ قَتَادَةَ عَنْ يُونُسَ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَ قَالَ مُرْهُ فَلْيُرَاجِعْهَا قُلْتُ تُحْتَسَبُ قَالَ أَرَأَيْتَ إِنْ عَجَزَ وَاسْتَحْمَقَ حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَ قَالَ حُسِبَتْ عَلَيَّ بِتَطْلِيقَةٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Syu'bah] dari [Anas bin Sirin] ia berkata; Aku mendengar [Ibnu Umar] berkata; Ibnu Umar menceraikan isterinya dalam keadaan haidl. Maka Umar pun menuturkan hal itu pada Nabi shallallahu 'alaihi wasallam. Akhirnya beliau bersabda: \"Hendaklah ia merujuknya kembali.\" Aku bertanya, \"Apakah talak itu dihitung?\" ia menjawab, \"Kenapa tidak?\" Dan dari [Qatadah] dari [Yunus bin Jubair] dari [Ibnu Umar] bahwa beliau bersabda: \"Perintahkan padanya, hendaklah ia meruju'nya kembali.\" Aku bertanya, \"Apakah talak itu juga dihitung?\" Ibnu Umar menjawab, \"Bagaimana bila ia tak mampu dan juga pandir?\" Telah menceritakan kepada kami [Abu Ma'mar] Telah menceritakan kepada kami [Abdul Warits] Telah menceritakan kepada kami [Ayyub] dari [Sa'id bin Jubair] dari [Ibnu Umar] ia berkata; Ia pun menghitung masah iddahnya atasku dengan talak satu."},"4547":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ سَأَلْتُ الزُّهْرِيَّأَيُّ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعَاذَتْ مِنْهُ قَالَ أَخْبَرَنِي عُرْوَةُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّ ابْنَةَ الْجَوْنِ لَمَّا أُدْخِلَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدَنَا مِنْهَا قَالَتْ أَعُوذُ بِاللَّهِ مِنْكَ فَقَالَ لَهَا لَقَدْ عُذْتِ بِعَظِيمٍ الْحَقِي بِأَهْلِكِقَالَ أَبُو عَبْد اللَّهِ رَوَاهُ حَجَّاجُ بْنُ أَبِي مَنِيعٍ عَنْ جَدِّهِ عَنْ الزُّهْرِيِّ أَنَّ عُرْوَةَ أَخْبَرَهُ أَنَّ عَائِشَةَ قَالَتْ","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Al Walid] Telah menceritakan kepada kami [Al Auza'i] ia berkata; Aku bertanya kepada [Az Zuhri], \"Siapakah di antara isteri-isteri Nabi shallallahu 'alaihi wasallam yang meminta perlindungan daripada beliau?\" Ia pun berkata; Telah mengabarkan kepadaku [Urwah] dari [Aisyah] Radliayallahu 'Anha, bahwa ketika anak perempuan Al Jaun dihadapkan pada Rasulullah shallallahu 'alaihi wasallam, dan beliau pun mendekat darinya, ia berkata, \"Aku berlindung kepada Allah darimu.\" Maka beliau pun bersabda padanya: \"Sesungguhnya kamu telah berlindung dengan Dzat Yang Maha Agung. Kembalilah kepada keluargamu.\" Abu Abdullah berkata; Hadits itu diriwayatkan oleh [Hajjaj bin Abu Mani'] dari [kakeknya] dari [Az Zuhri] bahwa [Urwah] Telah mengabarkan kepadanya, bahwa [Aisyah] berkata."},"4548":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ غَسِيلٍ عَنْ حَمْزَةَ بْنِ أَبِي أُسَيْدٍ عَنْ أَبِي أُسَيْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَخَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى انْطَلَقْنَا إِلَى حَائِطٍ يُقَالُ لَهُ الشَّوْطُ حَتَّى انْتَهَيْنَا إِلَى حَائِطَيْنِ فَجَلَسْنَا بَيْنَهُمَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْلِسُوا هَا هُنَا وَدَخَلَ وَقَدْ أُتِيَ بِالْجَوْنِيَّةِ فَأُنْزِلَتْ فِي بَيْتٍ فِي نَخْلٍ فِي بَيْتِ أُمَيْمَةَ بِنْتِ النُّعْمَانِ بْنِ شَرَاحِيلَ وَمَعَهَا دَايَتُهَا حَاضِنَةٌ لَهَا فَلَمَّا دَخَلَ عَلَيْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَبِي نَفْسَكِ لِي قَالَتْ وَهَلْ تَهَبُ الْمَلِكَةُ نَفْسَهَا لِلسُّوقَةِ قَالَ فَأَهْوَى بِيَدِهِ يَضَعُ يَدَهُ عَلَيْهَا لِتَسْكُنَ فَقَالَتْ أَعُوذُ بِاللَّهِ مِنْكَ فَقَالَ قَدْ عُذْتِ بِمَعَاذٍ ثُمَّ خَرَجَ عَلَيْنَا فَقَالَ يَا أَبَا أُسَيْدٍ اكْسُهَا رَازِقِيَّتَيْنِ وَأَلْحِقْهَا بِأَهْلِهَاوَقَالَ الْحُسَيْنُ بْنُ الْوَلِيدِ النَّيْسَابُورِيُّ عَنْ عَبْدِ الرَّحْمَنِ عَنْ عَبَّاسِ بْنِ سَهْلٍ عَنْ أَبِيهِ وَأَبِي أُسَيْدٍ قَالَا تَزَوَّجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمَيْمَةَ بِنْتَ شَرَاحِيلَ فَلَمَّا أُدْخِلَتْ عَلَيْهِ بَسَطَ يَدَهُ إِلَيْهَا فَكَأَنَّهَا كَرِهَتْ ذَلِكَ فَأَمَرَ أَبَا أُسَيْدٍ أَنْ يُجَهِّزَهَا وَيَكْسُوَهَا ثَوْبَيْنِ رَازِقِيَّيْنِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْوَزِيرِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ حَمْزَةَ عَنْ أَبِيهِ وَعَنْ عَبَّاسِ بْنِ سَهْلِ بْنِ سَعْدٍ عَنْ أَبِيهِ بِهَذَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Abdurrahman bin Ghasil] dari [Hamzah bin Abu Usaid] dari [Abu Usaid] radliallahu 'anhu, ia berkata; Kami pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam hingga sampai pada suatu dinding yang dinamakan Asy Syauth, kami terus berjalan hingga sampai pada dua dinding dan duduk di antara keduanya. Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Duduklah kalian di sini.\" Beliau pun masuk dan ternyata telah didatangkan seorang perempuan bani Jaun dan ditempatkan di rumah yang ada di kebun kurma yaitu rumahnya Ummayyah binti An-Nu'man bin Syarahil yang saat itu sedang bersama pelayan dan perawatnya. Dan ketika Nabi shallallahu 'alaihi wasallam menemuinya, beliau bersabda: \"Serahkanlah dirimu untukku.\" Wanita itu berkata, \"Apakah seorang permaisuri akan menyerahkan dirinya kepada seorang rakyat jelata?\" maka beliau pun menjulurkan tangannya dan hendak menyentuh dan menenangkan, akan tetapi wanita itu berkata, \"Aku berlindung kepada Allah darimu.\" Maka beliau bersabda: \"Sesungguhnya kamu telah berlindung dengan Dzat Yang Maha Melindungi.\" Setelah itu, beliau keluar dan berkata, \"Wahai Usaid, berilah ia dua helai pakaian dari katun dan kembalikanlah ia kepada keluarganya.\" Dan [Al Husain bin Al Walid An Naisaburi] berkata; dari [Abdurrahman] dari [Abbas bin Sahl] dari [bapaknya] dan [Abu Usaid] keduanya berkata; Nabi shallallahu 'alaihi wasallam menikahi Umayyah binti Syarahil. Dan ketika wanita itu dipertemukan dengan beliau. beliau pun merangkulkan tangan kepada wanita itu, sepertinya wanita itu tak menyukai hal itu. Maka beliau menyuruh Abu Usaid untuk mempersiapkan bekal untuk wanita itu, kemudian memberinya dua helai pakaian dari katun. Telah menceritakan kepada kami [Abdullah bin Muhammad] Telah menceritakan kepada kami [Ibrahim bin Abu Zubair] Telah menceritakan kepada kami [Abdurrahman] dari [Hamzah] dari [bapaknya] dan dari [Abbas bin Sahl bin Sa'd] dari [bapaknya] dengan hadits ini."},"4549":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى عَنْ قَتَادَةَ عَنْ أَبِي غَلَّابٍ يُونُسَ بْنِ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عُمَرَرَجُلٌ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَقَالَ تَعْرِفُ ابْنَ عُمَرَ إِنَّ ابْنَ عُمَرَ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَأَتَى عُمَرُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَأَمَرَهُ أَنْ يُرَاجِعَهَا فَإِذَا طَهُرَتْ فَأَرَادَ أَنْ يُطَلِّقَهَا فَلْيُطَلِّقْهَا قُلْتُ فَهَلْ عَدَّ ذَلِكَ طَلَاقًا قَالَ أَرَأَيْتَ إِنْ عَجَزَ وَاسْتَحْمَقَ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] Telah menceritakan kepada kami [Hammam bin Yahya] dari [Qatadah] dari [Abu Ghallab Yunus bin Jubair] ia berkata; Aku berkata kepada [Ibnu Umar], \"Bagaimana dengan seorang laki-laki yang menceraikan isterinya dalam keadaan haidl?\" Ia pun berkata, \"Apakah kamu kenal Ibnu Umar? Sesungguhnya Ibnu Umar pernah menceraikan isterinya dalam keadaan haidl, lalu Umar pun mendatangi Nabi shallallahu 'alaihi wasallam dan menuturkan hal itu. Maka beliau pun memerintahkannya untuk meruju'nya kembali. Jika wanita itu suci dan ia ingin untuk menceraikannya, maka ia boleh menceraikannya.\" Aku bertanya, \"Apakah itu terhitung talak?\" ia berkata; \"Apakah kamu kira ia tak mampu atau pandir?\""},"4550":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ أَنَّ سَهْلَ بْنَ سَعْدٍ السَّاعِدِيَّ أَخْبَرَهُأَنَّ عُوَيْمِرًا الْعَجْلَانِيَّ جَاءَ إِلَى عَاصِمِ بْنِ عَدِيٍّ الْأَنْصَارِيِّ فَقَالَ لَهُ يَا عَاصِمُ أَرَأَيْتَ رَجُلًا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ فَتَقْتُلُونَهُ أَمْ كَيْفَ يَفْعَلُ سَلْ لِي يَا عَاصِمُ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَ عَاصِمٌ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَرِهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسَائِلَ وَعَابَهَا حَتَّى كَبُرَ عَلَى عَاصِمٍ مَا سَمِعَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَجَعَ عَاصِمٌ إِلَى أَهْلِهِ جَاءَ عُوَيْمِرٌ فَقَالَ يَا عَاصِمُ مَاذَا قَالَ لَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَاصِمٌ لَمْ تَأْتِنِي بِخَيْرٍ قَدْ كَرِهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسْأَلَةَ الَّتِي سَأَلْتُهُ عَنْهَا قَالَ عُوَيْمِرٌ وَاللَّهِ لَا أَنْتَهِي حَتَّى أَسْأَلَهُ عَنْهَا فَأَقْبَلَ عُوَيْمِرٌ حَتَّى أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسْطَ النَّاسِ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ رَجُلًا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ فَتَقْتُلُونَهُ أَمْ كَيْفَ يَفْعَلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَنْزَلَ اللَّهُ فِيكَ وَفِي صَاحِبَتِكَ فَاذْهَبْ فَأْتِ بِهَا قَالَ سَهْلٌ فَتَلَاعَنَا وَأَنَا مَعَ النَّاسِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا فَرَغَا قَالَ عُوَيْمِرٌ كَذَبْتُ عَلَيْهَا يَا رَسُولَ اللَّهِ إِنْ أَمْسَكْتُهَا فَطَلَّقَهَا ثَلَاثًا قَبْلَ أَنْ يَأْمُرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ ابْنُ شِهَابٍ فَكَانَتْ تِلْكَ سُنَّةَ الْمُتَلَاعِنَيْنِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] bahwa [Sahl bin Sa'd As Sa'idi] Telah mengabarkan keadanya bahwa; Uwaimir Al 'Ajlani datang kepada 'Ashim bin Adi Al Anshari dan bertanya, \"Wahai 'Ashim, bagaimana pendapatmu bila seorang laki-laki mendapatkan laki-laki lain bersama isterinya, apakah ia boleh membunuhnya hingga kalian pun juga turut membunuh laki-laki itu? Atau apakah yang mesti dilakukannya? Wahai 'Ashim, tanyakanlah pertanyaanku itu kepada Rasulullah shallallahu 'alaihi wasallam.\" Maka 'Ashim pun menanyakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, dan ternyata Rasulullah shallallahu 'alaihi wasallam membenci persoalan itu dan mencelanya hingga 'Ashim pun merasa keberatan. Ketika ia pulang ke rumah keluarganya, ia pun didatangi oleh 'Uwaimir dan berkata, \"Wahai 'Ashim apa yang telah dikatakan oleh Rasulullah shallallahu 'alaihi wasallam kepadamu?\" Lalu 'Ashim berkata kepada 'Uwaimir, \"Kebaikan belum singgah padaku. Rasulullah shallallahu 'alaihi wasallam sangat membenci persoalan yang aku tanyakan.\" Maka Uwaimir pun berkata, \"Demi Allah, aku tidak akan berhenti sehingga akan aku tanyakan sendiri.\" Akhirnya Uwaimir menghadap Rasulullah shallallahu 'alaihi wasallam di tengah kerumunan orang-orang, ia pun berkata, \"Wahai Rasulullah, bagaimana pendapat Anda, bila seorang laki-laki mendapatkan laki-laki lain bersama isterinya, apakah ia harus membunuhnya sehingga kalian juga akan membunuhnya? Atau apakah yang mesti ia lakukan?\" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya telah diturunkan ayat terkait denganmu dan juga sahabatmu (isterimu). Pergi dan bawalah ia kemari.\" Sahl berkata; Akhirnya kedua orang suami-isteri itu pun saling meli'an, sementara aku berada bersama orang-orang yang ada di sisi Rasulullah shallallahu 'alaihi wasallam. Ketika keduanya usai saling meli'an, maka 'Uwaimir pun berkata, \"Aku telah berdusta atasnya wahai Rasulullah bila aku tetap menahannya (tidak menceraikannya).\" Akhirnya ia pun meceraikannya dengan talak tiga sebelum ia diperintahkan oleh Rasulullah shallallahu 'alaihi wasallam. Ibnu Syihab berkata; Seperti itulah sunnahnya dua orang suami isteri yang saling meli'an (saling menuduh berbuat serong)."},"4551":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ أَخْبَرَتْهُأَنَّ امْرَأَةَ رِفَاعَةَ الْقُرَظِيِّ جَاءَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ رِفَاعَةَ طَلَّقَنِي فَبَتَّ طَلَاقِي وَإِنِّي نَكَحْتُ بَعْدَهُ عَبْدَ الرَّحْمَنِ بْنَ الزُّبَيْرِ الْقُرَظِيَّ وَإِنَّمَا مَعَهُ مِثْلُ الْهُدْبَةِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّكِ تُرِيدِينَ أَنْ تَرْجِعِي إِلَى رِفَاعَةَ لَا حَتَّى يَذُوقَ عُسَيْلَتَكِ وَتَذُوقِي عُسَيْلَتَهُ","id":"Telah menceritakan kepada kami [Sa'id bin Ufair] Ia berkata; Telah menceritakan kepadaku [Al Laits] ia berkata; Telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] ia berkata; Telah mengabarkan kepadaku [Urwah bin Zubair] bahwa [Aisyah] Telah mengabarkan kepadanya bahwa isteri Rifa'ah Al Qurazhi datang menghadap Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya Rifa'ah telah menceraikanku dan mengokohkan perceraian denganku. Setelah itu, aku pun menikah dengan Abdurrahman bin Az Zubair Al Qurazhi, dan ternyata kelelakiannya hanyalah seperti ujung kain.\" Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sepertinya kamu ingin kembali ruju' dengan Rifa'ah, tidak, hingga laki-laki kedua merasakan madumu dan kamu pun merasakan madunya.\""},"4552":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي الْقَاسِمُ بْنُ مُحَمَّدٍ عَنْ عَائِشَةَأَنَّ رَجُلًا طَلَّقَ امْرَأَتَهُ ثَلَاثًا فَتَزَوَّجَتْ فَطَلَّقَ فَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَحِلُّ لِلْأَوَّلِ قَالَ لَا حَتَّى يَذُوقَ عُسَيْلَتَهَا كَمَا ذَاقَ الْأَوَّلُ","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar] Telah menceritakan kepada kami [Yahya] dari [Ubaidullah] ia berkata; Telah menceritakan kepadaku [Al Qasim bin Muhammad] dari [Aisyah] bahwa ada seorang laki-laki menceraikan isterinya dengan talak tiga. Lalu wanita itu menikah dan diceraikan lagi. Maka Nabi shallallahu 'alaihi wasallam pun ditanya, apakah wanita itu telah halal untuk suaminya yang pertama. Maka beliau menjawab: \"Tidak, hingga laki-laki kedua itu merasakan madunya sebagaimana laki-laki pertama telah merasakannya.\""},"4553":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا مُسْلِمٌ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْخَيَّرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاخْتَرْنَا اللَّهَ وَرَسُولَهُ فَلَمْ يَعُدَّ ذَلِكَ عَلَيْنَا شَيْئًا","id":"Telah menceritakan kepada kami [Umar bin Hafsh] Telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Al A'masy] Telah menceritakan kepada kami [Muslim] dari [Masruq] dari [Aisyah] radliallahu 'anha, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah memberikan pilihan kepada kami, maka kami pun memilih Allah dan Rasul-Nya. Dan beliau tidak menganggapnya thalak sama sekali.\""},"4554":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ إِسْمَاعِيلَ حَدَّثَنَا عَامِرٌ عَنْ مَسْرُوقٍ قَالَ سَأَلْتُ عَائِشَةَعَنْ الْخِيَرَةِ فَقَالَتْ خَيَّرَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفَكَانَ طَلَاقًاقَالَ مَسْرُوقٌ لَا أُبَالِي أَخَيَّرْتُهَا وَاحِدَةً أَوْ مِائَةً بَعْدَ أَنْ تَخْتَارَنِي","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Isma'il] Telah menceritakan kepada kami [Amir] dari [Masruq] ia berkata; Aku pernah bertanya kepada [Aisyah] tentang Al Khiyarah (tawaran pilihan). Maka Ia pun menjawab, \"Nabi shallallahu 'alaihi wasallam pernah memberi kami pilihan.\" Apakah itu termasuk talak? Masruq berkata; Aku tak peduli, apakah aku memberi pilihan satu atau seratus kali setelah ia memilihku.\""},"4555":{"ar":"حَدَّثَنَا مُحَمَّدٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْطَلَّقَ رَجُلٌ امْرَأَتَهُ فَتَزَوَّجَتْ زَوْجًا غَيْرَهُ فَطَلَّقَهَا وَكَانَتْ مَعَهُ مِثْلُ الْهُدْبَةِ فَلَمْ تَصِلْ مِنْهُ إِلَى شَيْءٍ تُرِيدُهُ فَلَمْ يَلْبَثْ أَنْ طَلَّقَهَا فَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ زَوْجِي طَلَّقَنِي وَإِنِّي تَزَوَّجْتُ زَوْجًا غَيْرَهُ فَدَخَلَ بِي وَلَمْ يَكُنْ مَعَهُ إِلَّا مِثْلُ الْهُدْبَةِ فَلَمْ يَقْرَبْنِي إِلَّا هَنَةً وَاحِدَةً لَمْ يَصِلْ مِنِّي إِلَى شَيْءٍ فَأَحِلُّ لِزَوْجِي الْأَوَّلِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحِلِّينَ لِزَوْجِكِ الْأَوَّلِ حَتَّى يَذُوقَ الْآخَرُ عُسَيْلَتَكِ وَتَذُوقِي عُسَيْلَتَهُ","id":"Telah menceritakan kepada kami [Muhammad] Telah menceritakan kepada kami [Abu Mu'awiyah] Telah menceritakan kepada kami [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] ia berkata; Ada seorang laki-laki menceraikan isterinya, lalu sang isteri pun menikah dengan laki-laki lain, kemudian laki-laki lain itu juga menceraikannya. Ternyata kemaluan laki-laki itu hanyalah seperti bulu, sehingga wanita itu belum mendapatkan apa yang diinginkan dari laki-laki kedua. Maka wanita itu pun menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya suamiku telah menceraikanku, lalu aku pun menikah dengan laki-laki lain, lalu laki-laki itu memasukiku, namun ia tak memiliki kelelakian kecuali hanya seperti ujung kain, sehingga ia tak mampu mendekatiku, dan juga tak mampu merasakan maduku. Karena itu, halalkanlah suamiku yang pertama.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kamu tidak akan menjadi halal bagi suamimu yang pertama hingga laki-laki itu merasakan madumu dan kamu juga merasakan madunya.\""},"4556":{"ar":"حَدَّثَنِي الْحَسَنُ بْنُ صَبَّاحٍ سَمِعَ الرَّبِيعَ بْنَ نَافِعٍ حَدَّثَنَا مُعَاوِيَةُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ يَعْلَى بْنِ حَكِيمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَنَّهُ أَخْبَرَهُ أَنَّهُ سَمِعَ ابْنَ عَبَّاسٍ يَقُولُإِذَا حَرَّمَ امْرَأَتَهُ لَيْسَ بِشَيْءٍ وَقَالَ{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌ }","id":"Telah menceritakan kepadaku [Al Hasan bin Shabbah] Ia mendengar [Ar Robi' bin Nafi'] Telah menceritakan kepada kami [Mu'awiyah] dari [Yahya bin Abu Katsir] dari [Ya'la bin Hakim] dari [Sa'id bin Jubair] bahwa ia telah mengabarkan kepadanya bahwa ia mendengar [Ibnu Abbas] berkata; \"Bila seseorang mengharamkan isterinya seperti mengatakan 'Engkau sekarang bagiku bukan apa-apanya lagi', maka itu harus membayar kaffarat\", lantas ia membacakan ayat, \"Sesungguhnya pada diri Rasulullah terdapat suri tauladan bagi kalian.\" (QS. AL-Ahzab 21)."},"4557":{"ar":"حَدَّثَنِي الْحَسَنُ بْنُ مُحَمَّدِ بْنِ صَبَّاحٍ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ زَعَمَ عَطَاءٌ أَنَّهُ سَمِعَ عُبَيْدَ بْنَ عُمَيْرٍ يَقُولُ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَمْكُثُ عِنْدَ زَيْنَبَ بِنْتِ جَحْشٍ وَيَشْرَبُ عِنْدَهَا عَسَلًا فَتَوَاصَيْتُ أَنَا وَحَفْصَةُ أَنَّ أَيَّتَنَا دَخَلَ عَلَيْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْتَقُلْ إِنِّي أَجِدُ مِنْكَ رِيحَ مَغَافِيرَ أَكَلْتَ مَغَافِيرَ فَدَخَلَ عَلَى إِحْدَاهُمَا فَقَالَتْ لَهُ ذَلِكَ فَقَالَ لَا بَلْ شَرِبْتُ عَسَلًا عِنْدَ زَيْنَبَ بِنْتِ جَحْشٍ وَلَنْ أَعُودَ لَهُ فَنَزَلَتْ{ يَا أَيُّهَا النَّبِيُّ لِمَ تُحَرِّمُ مَا أَحَلَّ اللَّهُ لَكَ إِلَى إِنْ تَتُوبَا إِلَى اللَّهِ }لِعَائِشَةَ وَحَفْصَةَ{ وَإِذْ أَسَرَّ النَّبِيُّ إِلَى بَعْضِ أَزْوَاجِهِ }لِقَوْلِهِ بَلْ شَرِبْتُ عَسَلًا","id":"Telah menceritakan kepadaku [Al Hasan bin Muhammad bin Shabbah] Telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] ia berkata; [Atha`] berdalih bahwa ia mendengar [Ubaid bin Umair] berkata; Aku mendengar [Aisyah] radliallahu 'anha berkata; Bahwa Nabi shallallahu 'alaihi wasallam pernah singgah di rumah Zainab binti Jahsy dan beliau juga minum madu di situ. Lalu aku dan Hafshah saling berpesan, bahwa siapa saja di antara kita yang ditemu oleh Nabi shallallahu 'alaihi wasallam hendaklah ia berkata, \"Sesungguhnya aku mendapatkan bau Maghafir. Apakah Anda habis makan maghafir?\" akhirnya beliau pun masuk menemui salah seorang dari keduanya dan ia mengungkapkan kalimat itu pada beliau. Akhirnya beliau bersabda: \"Tidak, akan tetapi aku hanya minum madu di tempat Zainab binti Jahsyin dan aku tidak akan mengulanginya lagi.\" Maka turunlah ayat: \"Wahai Nabi, kenapa kamu mengharamkan sesuatu yang telah dihalalkan oleh Allah…\" hingga firman-Nya: \"Jika kalian berdua bertaubat..\" yakni kepada Aisyah dan Hafshah.\".. adapun kutipan ayat \"Dan ketika Nabi berkata rahasia kepada sebagian isterinya...\" yakni terkait dengan sabda beliau: \"Bahkan aku hanya minum madu.\""},"4558":{"ar":"حَدَّثَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ الْعَسَلَ وَالْحَلْوَاءَ وَكَانَ إِذَا انْصَرَفَ مِنْ الْعَصْرِ دَخَلَ عَلَى نِسَائِهِ فَيَدْنُو مِنْ إِحْدَاهُنَّ فَدَخَلَ عَلَى حَفْصَةَ بِنْتِ عُمَرَ فَاحْتَبَسَ أَكْثَرَ مَا كَانَ يَحْتَبِسُ فَغِرْتُ فَسَأَلْتُ عَنْ ذَلِكَ فَقِيلَ لِي أَهْدَتْ لَهَا امْرَأَةٌ مِنْ قَوْمِهَا عُكَّةً مِنْ عَسَلٍ فَسَقَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُ شَرْبَةً فَقُلْتُ أَمَا وَاللَّهِ لَنَحْتَالَنَّ لَهُ فَقُلْتُ لِسَوْدَةَ بِنْتِ زَمْعَةَ إِنَّهُ سَيَدْنُو مِنْكِ فَإِذَا دَنَا مِنْكِ فَقُولِي أَكَلْتَ مَغَافِيرَ فَإِنَّهُ سَيَقُولُ لَكِ لَا فَقُولِي لَهُ مَا هَذِهِ الرِّيحُ الَّتِي أَجِدُ مِنْكَ فَإِنَّهُ سَيَقُولُ لَكِ سَقَتْنِي حَفْصَةُ شَرْبَةَ عَسَلٍ فَقُولِي لَهُ جَرَسَتْ نَحْلُهُ الْعُرْفُطَ وَسَأَقُولُ ذَلِكِ وَقُولِي أَنْتِ يَا صَفِيَّةُ ذَاكِ قَالَتْ تَقُولُ سَوْدَةُ فَوَاللَّهِ مَا هُوَ إِلَّا أَنْ قَامَ عَلَى الْبَابِ فَأَرَدْتُ أَنْ أُبَادِيَهُ بِمَا أَمَرْتِنِي بِهِ فَرَقًا مِنْكِ فَلَمَّا دَنَا مِنْهَا قَالَتْ لَهُ سَوْدَةُ يَا رَسُولَ اللَّهِ أَكَلْتَ مَغَافِيرَ قَالَ لَا قَالَتْ فَمَا هَذِهِ الرِّيحُ الَّتِي أَجِدُ مِنْكَ قَالَ سَقَتْنِي حَفْصَةُ شَرْبَةَ عَسَلٍ فَقَالَتْ جَرَسَتْ نَحْلُهُ الْعُرْفُطَ فَلَمَّا دَارَ إِلَيَّ قُلْتُ لَهُ نَحْوَ ذَلِكَ فَلَمَّا دَارَ إِلَى صَفِيَّةَ قَالَتْ لَهُ مِثْلَ ذَلِكَ فَلَمَّا دَارَ إِلَى حَفْصَةَ قَالَتْ يَا رَسُولَ اللَّهِ أَلَا أَسْقِيكَ مِنْهُ قَالَ لَا حَاجَةَ لِي فِيهِ قَالَتْ تَقُولُ سَوْدَةُ وَاللَّهِ لَقَدْ حَرَمْنَاهُ قُلْتُ لَهَا اسْكُتِي","id":"Telah menceritakan kepada kami [Farwah bin Abu Al Maghra`] Telah menceritakan kepada kami [Ali bin Mushir] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] radliallahu 'anha, ia berkata; Rasulullah shallallahu 'alaihi wasallam adalah seorang yang menyukai madu dan juga manis-manisan. Biasanya, usai menunaikan shalat Ashar, beliau menemui para isteri-isterinya dan akhirnya mendekat dan menginap di tempat salah seorang dari mereka. Namun beliau selalu berdiam agak lama di tempat Hafshah binti Umar, maka aku merasa cemburu. Aku pun bertanya mencari info hal itu, dan dikatakanlah bahwa ada seorang wanita dari kaumnya yang telah memberikan madu padanya, lalu madu itu ia berikan kepada Nabi shallallahu 'alaihi wasallam. Maka aku pun berkata, \"Demi Allah, aku bernar-benar akan berbuat sesuatu untuk beliau (mengerjai beliau).\" Kemudian, kukatakanlah kepada Saudah binti Zam'ah, \"Sesungguhnya beliau akan mendekatimu. Bila beliau hendak mendekatimu, maka tanyakanlah padanya, 'Apakah Anda telah memakan Maghafir? ' dan beliau pasti akan menjawab: 'Tidak.' Karena itu katakanlah pada beliau, 'Lalu bau yang saya dapatkan dari Anda ini bau apa? ' Dan beliau pun pasti akan menjawab: 'Hafshah telah memberiku minuman madu.' Sesudah itu, katakanlah pada beliau, 'Lebah madu itu telah makan pohon bergetah yang baunya menjijikkan.' Dan aku juga akan mengungkapkan seperti itu, dan kamu wahai Shafiyyah ungkapkan pula seperti itu.\" Saudah berkata, \"Demi Allah, tidaklah beliau kecuali berdiri di depan pintu. Dan aku pun ingin mengungkapkan apa yang kamu inginkan karena rasa takutku padamu.\" Maka ketika beliau telah mendekat kepadanya, Saudah pun berkata, \"Wahai Rasulullah, apakah Anda telah makan buah Maghafir?\" beliau menjawab: \"Tidak.\" Saudah bertanya lagi, \"Lalu bau apa yang aku dapatkan dari Anda ini?\" beliau menjawab: \"Hafshah telah memberiku minuman madu.\" Saudah berkata, \"Lebah itu telah makan pohon bergetah yang baunya menjijikkan.\" Dan ketika beliau berkunjung kepadaku, aku pun berkata seperti itu dan begitu pula di tempat Shafiyyah yang juga berkata seperti itu. Maka pada saat beliau menuju ke tempat Hafshah, Hafshah pun berkata, \"Wahai Rasulullah, maukah Anda aku beri minuman madu itu?\" beliau pun menjawab: \"Aku tidak berhajat sedikit pun terhadap madu itu?\" Akhirnya Saudah berkata, \"Demi Allah, kita telah mengharamkannya.\" Aku pun berkata padanya, \"Diamlah kamu.\""},"4559":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ تَجَاوَزَ عَنْ أُمَّتِي مَا حَدَّثَتْ بِهِ أَنْفُسَهَا مَا لَمْ تَعْمَلْ أَوْ تَتَكَلَّمْقَالَ قَتَادَةُ إِذَا طَلَّقَ فِي نَفْسِهِ فَلَيْسَ بِشَيْءٍ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] Telah menceritakan kepada kami [Hisyam] Telah menceritakan kepada kami [Qatadah] dari [Zurarah bin Aufa] dari [Abu Hurairah] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah memaafkan apa yang dikatakan oleh hati mereka, selama tidak melakukan atau pun mengungkapnya.\" Qatadah berkata, \"Bila ia menceraikan dengan suara hatinya saja, maka hal itu tidaklah berpengaruh sedikit pun.\""},"4560":{"ar":"حَدَّثَنَا أَصْبَغُ أَخْبَرَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ جَابِرٍأَنَّ رَجُلًا مِنْ أَسْلَمَ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي الْمَسْجِدِ فَقَالَ إِنَّهُ قَدْ زَنَى فَأَعْرَضَ عَنْهُ فَتَنَحَّى لِشِقِّهِ الَّذِي أَعْرَضَ فَشَهِدَ عَلَى نَفْسِهِ أَرْبَعَ شَهَادَاتٍ فَدَعَاهُ فَقَالَ هَلْ بِكَ جُنُونٌ هَلْ أَحْصَنْتَ قَالَ نَعَمْ فَأَمَرَ بِهِ أَنْ يُرْجَمَ بِالْمُصَلَّى فَلَمَّا أَذْلَقَتْهُ الْحِجَارَةُ جَمَزَ حَتَّى أُدْرِكَ بِالْحَرَّةِ فَقُتِلَ","id":"Telah menceritakan kepada kami [Ashbagh] Telah mengabarkan kepada kami [Ibnu Wahab] dari [Yunus] dari [Ibnu Syihab] ia berkata; Telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] dari [Jabir] bahwa seorang laki-laki dari Bani Aslam mendatangi Nabi shallallahu 'alaihi wasallam yang saat itu sedang berada di dalam Masjid. Laki-laki itu mengatakan bahwa ia telah berzina, namun beliau berpaling darinya. Maka laki-laki itu menghadap ke arah wajah beliau seraya bersaksi atas dirinya dengan empat orang saksi. Akhirnya beliau memanggil laki-laki itu dan bertanya: \"Apakah kamu memiliki penyakit gila?\" ia menjawab, \"Tidak.\" Beliau bertanya lagi: \"Apakah kamu telah menikah?\" ia menjawab, \"Ya.\" Akhirnya beliau memerintahkan untuk merajamnya di lapangan luas. Dan ketika lemparan batu telah mengenainya, ia berlari hingga ditangkap dan dirajam kembali hingga meninggal."},"4561":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ وَسَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ قَالَأَتَى رَجُلٌ مِنْ أَسْلَمَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي الْمَسْجِدِ فَنَادَاهُ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ الْأَخِرَ قَدْ زَنَى يَعْنِي نَفْسَهُ فَأَعْرَضَ عَنْهُ فَتَنَحَّى لِشِقِّ وَجْهِهِ الَّذِي أَعْرَضَ قِبَلَهُ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ الْأَخِرَ قَدْ زَنَى فَأَعْرَضَ عَنْهُ فَتَنَحَّى لِشِقِّ وَجْهِهِ الَّذِي أَعْرَضَ قِبَلَهُ فَقَالَ لَهُ ذَلِكَ فَأَعْرَضَ عَنْهُ فَتَنَحَّى لَهُ الرَّابِعَةَ فَلَمَّا شَهِدَ عَلَى نَفْسِهِ أَرْبَعَ شَهَادَاتٍ دَعَاهُ فَقَالَ هَلْ بِكَ جُنُونٌ قَالَ لَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبُوا بِهِ فَارْجُمُوهُ وَكَانَ قَدْ أُحْصِنَوَعَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي مَنْ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ الْأَنْصَارِيَّ قَالَ كُنْتُ فِيمَنْ رَجَمَهُ فَرَجَمْنَاهُ بِالْمُصَلَّى بِالْمَدِينَةِ فَلَمَّا أَذْلَقَتْهُ الْحِجَارَةُ جَمَزَ حَتَّى أَدْرَكْنَاهُ بِالْحَرَّةِ فَرَجَمْنَاهُ حَتَّى مَاتَ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] dan [Sa'id bin Al Musayyab] bahwa [Abu Hurairah] berkata; Seorang laki-laki dari Bani Aslam mendatangi Rasulullah shallallahu 'alaihi wasallam yang saat itu sedang berada di Masjid. Laki-laki itu pun memanggil beliau dan berkata, \"Wahai Rasulullah, sesungguhnya Al Akhira (maksudnya adalah dirinya sendiri) telah berzina.\" Lalu beliau berpaling darinya. Laki-laki itu kembali menghadap ke wajah beliau seraya berkata, \"Wahai Rasulullah, sesungguhnya Al Akhir telah berzina.\" Beliau berpaling lagi, dan laki-laki itu pun kembali menghadap ke wajah belia dan berkata seperti itu lagi, namun beliau tetap berpaling. Maka pada keempat kalinya, ia kembali menghadap ke wajah beliau dan bersaksi atas diri dengan empat orang saksi, akhirnya beliau memanggilnya dan bertanya: \"Apakah kamu memiliki penyakit jiwa?\" laki-laki itu menjawab, \"Tidak.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Bawalah laki-laki itu pergi dan rajamlah ia.\" Dan memang laki-laki itu telah menikah. Dan dari [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [seorang] yang telah mendengar [Jabir bin Abdullah Al Anshari] berkata; Aku termasuk diantara orang yang merajamnya. Kami merajamnya di lapangan luas di Madinah. Ketika laki-laki itu terkena lemparan batu, ia pun lari dan kami mengejar dan menangkapnya lalu merajamnya kembali hingga meninggal."},"4562":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ جَمِيلٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ امْرَأَةَ ثَابِتِ بْنِ قَيْسٍ أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ ثَابِتُ بْنُ قَيْسٍ مَا أَعْتِبُ عَلَيْهِ فِي خُلُقٍ وَلَا دِينٍ وَلَكِنِّي أَكْرَهُ الْكُفْرَ فِي الْإِسْلَامِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَرُدِّينَ عَلَيْهِ حَدِيقَتَهُ قَالَتْ نَعَمْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْبَلْ الْحَدِيقَةَ وَطَلِّقْهَا تَطْلِيقَةًقَالَ أَبُو عَبْد اللَّهِ لَا يُتَابَعُ فِيهِ عَنْ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Azhar bin Jamil] Telah menceritakan kepada kami [Abdul Wahhab Ats Tsaqafi] Telah menceritakan kepada kami [Khalid] dari [Ikrimah] dari [Ibnu Abbas] bahwasanya; Isteri Tsabit bin Qais datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, tidaklah aku mencela Tsabit bin Qais atas agama atau pun akhlaknya, akan tetapi aku khawatir kekufuran dalam Islam.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kamu mau mengembalikan kebun miliknya itu?\" Ia menjawab, \"Ya.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Terimalah kebun itu, dan ceraikanlah ia dengan talak satu.\" Abu Abdullah berkata; Tidak ada hadis penguat dari Ibnu Abbas."},"4563":{"ar":"حَدَّثَنَا إِسْحَاقُ الْوَاسِطِيُّ حَدَّثَنَا خَالِدٌ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عِكْرِمَةَأَنَّ أُخْتَ عَبْدِ اللَّهِ بْنِ أُبَيٍّ بِهَذَا وَقَالَ تَرُدِّينَ حَدِيقَتَهُ قَالَتْ نَعَمْ فَرَدَّتْهَا وَأَمَرَهُ يُطَلِّقْهَاوَقَالَ إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ خَالِدٍ عَنْ عِكْرِمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَطَلِّقْهَا وَعَنْ أَيُّوبَ بْنِ أَبِي تَمِيمَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ قَالَ جَاءَتْ امْرَأَةُ ثَابِتِ بْنِ قَيْسٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي لَا أَعْتِبُ عَلَى ثَابِتٍ فِي دِينٍ وَلَا خُلُقٍ وَلَكِنِّي لَا أُطِيقُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَرُدِّينَ عَلَيْهِ حَدِيقَتَهُ قَالَتْ نَعَمْ","id":"Telah menceritakan kepada kami [Ishaq Al Wasithi] Telah menceritakan kepada kami [Khalid] dari [Khalid Al Hadzdza`] dari [Ikrimah] bahwa saudara perempuan Abdullah bin Ubay dengan ini beliau berkata, \"Kembalikanlah kebun miliknya.\" Ia berkata, \"Ya.\" Lalu ia pun mengembalikannya, dan beliau memerintahkan agar menceraikannya. Dan Telah berkata [Ibrahim bin Thahman] dari [Khalid] dari [Ikrimah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dan ceraikanlah ia.\" Dan dari [Ayyub bin Abu Tamimah] dari [Ikrimah] dari [Ibnu Abbas] bahwa ia berkata; Isteri Tsabit datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya aku tidak mencela Tsabit atas agama atau pun akhlaknya. Akan tetapi, aku tak kuasa untuk hidup bersamanya.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalau begitu, kembalikanlah kebun miliknya.\" Ia menjawab, \"Ya.\""},"4564":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ الْمُخَرِّمِيُّ حَدَّثَنَا قُرَادٌ أَبُو نُوحٍ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَجَاءَتْ امْرَأَةُ ثَابِتِ بْنِ قَيْسِ بْنِ شَمَّاسٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ مَا أَنْقِمُ عَلَى ثَابِتٍ فِي دِينٍ وَلَا خُلُقٍ إِلَّا أَنِّي أَخَافُ الْكُفْرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَرُدِّينَ عَلَيْهِ حَدِيقَتَهُ فَقَالَتْ نَعَمْ فَرَدَّتْ عَلَيْهِ وَأَمَرَهُ فَفَارَقَهَاحَدَّثَنَا سُلَيْمَانُ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ أَنَّ جَمِيلَةَ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Al Mubarak Al Mukharrimi] Telah menceritakan kepada kami [Qurad Abu Nuh] Telah menceritakan kepada kami [Jarir bin Hazim] dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma, ia berkata; Suatu ketika, isteri Tsabit bin Qais bin Syammas kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, tidaklah aku mencela Tsabit atas agama atau pun akhlaknya, akan tetapi aku khawatirkan akan terjerumus dalam kekufuran.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalau begitu, kembalikanlah kebun miliknya.\" Ia berkata, \"Ya.\" Maka ia pun mengembalikan kebun itu pada Tsabit, sehingga Tsabit meninggalkan wanita itu. Telah menceritakan kami [Sulaiman] Telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Ikrimah] bahwasanya Jamilah..lalu ia pun menyebutkan hadits."},"4565":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَ الزُّهْرِيِّ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ بَنِي الْمُغِيرَةِ اسْتَأْذَنُوا فِي أَنْ يَنْكِحَ عَلِيٌّ ابْنَتَهُمْ فَلَا آذَنُ","id":"Telah menceritakan kepada kami [Abul Walid] Telah menceritakan kepada kami [Al Laits] dari [Abu Mulaikah] dari [Al Miswar bin Makhramah Az Zuhri] ia berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Bani Al Mughirah meminta izin kepada Nabi shallallahu 'alaihi wasallam agar Ali dapat menikahi anak perempuan mereka, namun beliau tidak mengizinkan.\""},"4566":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ فِي بَرِيرَةَ ثَلَاثُ سُنَنٍ إِحْدَى السُّنَنِ أَنَّهَا أُعْتِقَتْ فَخُيِّرَتْ فِي زَوْجِهَا وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَلَاءُ لِمَنْ أَعْتَقَ وَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْبُرْمَةُ تَفُورُ بِلَحْمٍ فَقُرِّبَ إِلَيْهِ خُبْزٌ وَأُدْمٌ مِنْ أُدْمِ الْبَيْتِ فَقَالَ أَلَمْ أَرَ الْبُرْمَةَ فِيهَا لَحْمٌ قَالُوا بَلَى وَلَكِنْ ذَلِكَ لَحْمٌ تُصُدِّقَ بِهِ عَلَى بَرِيرَةَ وَأَنْتَ لَا تَأْكُلُ الصَّدَقَةَ قَالَ عَلَيْهَا صَدَقَةٌ وَلَنَا هَدِيَّةٌ","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah] ia berkata; Telah menceritakan kepadaku [Malik] dari [Rabi'ah bin Abdu Abdurrahman] dari [Al Qasim bin Muhammad] dari [Aisyah] radliallahu 'anha isteri Nabi shallallahu 'alaihi wasallam, ia berkata; Sesungguhnya pada diri Barirah terdapat tiga sunnah. Yang pertama; Bahwa ia telah dimerdekakan dan diberi tawaran untuk memilih terhadap suaminya. Kemudian kedua; Rasulullah shallallahu 'alaihi wasallam pernah bersabda terkait dengannya: \"Sesungguhnya Al Wala` (hak waris budak dan nasab) itu adalah bagi yang telah memerdedakakan.\" Yang ketiga; Suatu ketika Rasulullah shallallahu 'alaihi wasallam masuk, sementara periuk sedang direbus dengan daging. Namun yang disuguhkan kepada beliau saat itu adalah roti dan lauk dari rumah. Maka beliau pun bertanya: \"Bukankah tadi aku melihat periuk yang berisikan daging.\" Maka mereka menjawab, \"Ya, benar, akan tetapi daging itu adalah daging yang disedekahkan kepada Barirah, sementara Anda tidak makan harta sedekah.\" Akhirnya beliau pun bersabda: \"Bagi Barirah adalah sedekah, sementara untukku adalah hadiah.\""},"4567":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ وَهَمَّامٌ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَرَأَيْتُهُ عَبْدًا يَعْنِي زَوْجَ بَر��يرَةَ","id":"Telah menceritakan kepada kami [Abul Walid] Telah menceritakan kepada kami [Syu'bah] dan [Hammam] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Aku pernah melihatnya sebagai seorang budak. Maksudnya, suami Barirah."},"4568":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَذَاكَ مُغِيثٌ عَبْدُ بَنِي فُلَانٍ يَعْنِي زَوْجَ بَرِيرَةَ كَأَنِّي أَنْظُرُ إِلَيْهِ يَتْبَعُهَا فِي سِكَكِ الْمَدِينَةِ يَبْكِي عَلَيْهَا","id":"Telah menceritakan kepada kami [Abdul A'laa bin Hammad] Telah menceritakan kepada kami [Wuhaib] Telah menceritakan kepada kami [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Itu adalah Mughits, seorang budak Bani Fulan. Yakni, suami Barirah. Sepertinya, aku melihat ia mengikutinya (Barirah) di jalan-jalan Madinah seraya menangisinya."},"4569":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ زَوْجُ بَرِيرَةَ عَبْدًا أَسْوَدَ يُقَالُ لَهُ مُغِيثٌ عَبْدًا لِبَنِي فُلَانٍ كَأَنِّي أَنْظُرُ إِلَيْهِ يَطُوفُ وَرَاءَهَا فِي سِكَكِ الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Abdul Wahhab] dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma, ia berkata; Suami Barirah adalah seorang budak yang berkulit hitam dan biasa dipanggil Mughits. Yakni, seorang budak Bani Fulan. Sepertinya aku melihat ia berkeliling di belakangnya di jalan-jalan Madinah."},"4570":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ زَوْجَ بَرِيرَةَ كَانَ عَبْدًا يُقَالُ لَهُ مُغِيثٌ كَأَنِّي أَنْظُرُ إِلَيْهِ يَطُوفُ خَلْفَهَا يَبْكِي وَدُمُوعُهُ تَسِيلُ عَلَى لِحْيَتِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعبَّاسٍ يَا عَبَّاسُ أَلَا تَعْجَبُ مِنْ حُبِّ مُغِيثٍ بَرِيرَةَ وَمِنْ بُغْضِ بَرِيرَةَ مُغِيثًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ رَاجَعْتِهِ قَالَتْ يَا رَسُولَ اللَّهِ تَأْمُرُنِي قَالَ إِنَّمَا أَنَا أَشْفَعُ قَالَتْ لَا حَاجَةَ لِي فِيهِ","id":"Telah menceritakan kepada kami [Muhammad] Telah mengabarkan kepada kami [Abdul Wahhab] Telah menceritakan kepada kami [Khalid] dari [Ikrimah] dari [Ibnu Abbas] bahwa suami Barirah adalah seorang budak yang bernama Mughits. Sepertinya aku melihat ia berthawaf di belakangnya seraya menangis hingga air matanya membasahi jenggot. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Abbas, tidakkah kamu ta'ajub akan kecintaan Mughits terhadap Barirah dan kebencian Barirah terhadap Mughits?\" Akhirnya Nabi shallallahu 'alaihi wasallam pun bersabda: \"Seandainya kamu mau meruju'nya kembali.\" Barirah bertanya, \"Wahai Rasulullah, apakah Anda menyuruhku?\" beliau menjawab, \"Aku hanya menyarankan.\" Akhirnya Barirah pun berkata, \"Sesungguhnya aku tak berhajat sedikit pun padanya.\""},"4571":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ أَخْبَرَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ أَنَّ عَائِشَةَأَرَادَتْ أَنْ تَشْتَرِيَ بَرِيرَةَ فَأَبَى مَوَالِيهَا إِلَّا أَنْ يَشْتَرِطُوا الْوَلَاءَ فَذَكَرَتْ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اشْتَرِيهَا وَأَعْتِقِيهَا فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ وَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَحْمٍ فَقِيلَ إِنَّ هَذَا مَا تُصُدِّقَ بِهِ عَلَى بَرِيرَةَ فَقَالَ هُوَ لَهَا صَدَقَةٌ وَلَنَا هَدِيَّةٌحَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ وَزَادَ فَخُيِّرَتْ مِنْ زَوْجِهَا","id":"Telah menceritakan kepada kami [Abdullah bin Raja`] Telah mengabarkan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari [Al Aswad] bahwa [Aisyah] ingin membeli Barirah, namun walinya tidak mau kecuali dengan mempersyaratkan perwalaannya. Maka ia pun menuturkan hal itu kepada Nabi shallallahu 'alaihi wasallam, sehingga beliau pun bersabda: \"Beli dan bebaskanlah ia. Sesungguhnya Al Wala` (perwalian/hak milik) itu adalah bagi yang membebaskan.\" Kemudian Nabi shallallahu 'alaihi wasallam pernah diberi daging dan dikatakan kepadanya, \"Sesungguhnya ini adalah daging yang disedekahkan kepada Barirah.\" Maka beliau bersabda: \"Baginya adalah sedekah, namun bagi kami adalah hadiah.\" Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Syu'bah] dan ia menambahkan; Maka ia pun diberi Khiyar (pilihan untuk tetap bersama atau bercerai) dengan suaminya."},"4572":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا لَيْثٌ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَكَانَ إِذَا سُئِلَ عَنْ نِكَاحِ النَّصْرَانِيَّةِ وَالْيَهُودِيَّةِ قَالَ إِنَّ اللَّهَ حَرَّمَ الْمُشْرِكَاتِ عَلَى الْمُؤْمِنِينَ وَلَا أَعْلَمُ مِنْ الْإِشْرَاكِ شَيْئًا أَكْبَرَ مِنْ أَنْ تَقُولَ الْمَرْأَةُ رَبُّهَا عِيسَى وَهُوَ عَبْدٌ مِنْ عِبَادِ اللَّهِ","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Laits] dari [Nafi'] bahwa apabila [Ibnu Umar] ditanya tentang hukum menikahi wanita Nashrani dan wanita Yahudi ia menjawab, \"Sesungguhnya Allah telah mengharamkan wanita-wanita musyrik atas orang-orang yang beriman. Dan aku tidak mengetahui adanya kesyirikan yang paling besar daripada seorang wanita yang mengatakan bahwa Rabbnya adalah Isa, padahal ia hanyalah hamba dari hamba-hamba Allah.\""},"4573":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ عَنْ ابْنِ جُرَيْجٍ وَقَالَ عَطَاءٌ عَنْ ابْنِ عَبَّاسٍكَانَ الْمُشْرِكُونَ عَلَى مَنْزِلَتَيْنِ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمُؤْمِنِينَ كَانُوا مُشْرِكِي أَهْلِ حَرْبٍ يُقَاتِلُهُمْ وَيُقَاتِلُونَهُ وَمُشْرِكِي أَهْلِ عَهْدٍ لَا يُقَاتِلُهُمْ وَلَا يُقَاتِلُونَهُ وَكَانَ إِذَا هَاجَرَتْ امْرَأَةٌ مِنْ أَهْلِ الْحَرْبِ لَمْ تُخْطَبْ حَتَّى تَحِيضَ وَتَطْهُرَ فَإِذَا طَهُرَتْ حَلَّ لَهَا النِّكَاحُ فَإِنْ هَاجَرَ زَوْجُهَا قَبْلَ أَنْ تَنْكِحَ رُدَّتْ إِلَيْهِ وَإِنْ هَاجَرَ عَبْدٌ مِنْهُمْ أَوْ أَمَةٌ فَهُمَا حُرَّانِ وَلَهُمَا مَا لِلْمُهَاجِرِينَ ثُمَّ ذَكَرَ مِنْ أَهْلِ الْعَهْدِ مِثْلَ حَدِيثِ مُجَاهِدٍ وَإِنْ هَاجَرَ عَبْدٌ أَوْ أَمَةٌ لِلْمُشْرِكِينَ أَهْلِ الْعَهْدِ لَمْ يُرَدُّوا وَرُدَّتْ أَثْمَانُهُمْوَقَالَ عَطَاءٌ عَنْ ابْنِ عَبَّاسٍ كَانَتْ قَرِيبَةُ بِنْتُ أَبِي أُمَيَّةَ عِنْدَ عُمَرَ بْنِ الخَطَّابِ فَطَلَّقَهَا فَتَزَوَّجَهَا مُعَاوِيَةُ بْنُ أَبِي سُفْيَانَ وَكَانَتْ أُمُّ الْحَكَمِ بِنْتُ أَبِي سُفْيَانَ تَحْتَ عِيَاضِ بْنِ غَنْمٍ الْفِهْرِيِّ فَطَلَّقَهَا فَتَزَوَّجَهَا عَبْدُ اللَّهِ بْنُ عُثْمانَ الثَّقَفِيُّ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] Telah menceritakan kepada kami [Hisyam] dari [Ibnu Juraij] dan telah berkata ['Atha`] dari [Ibnu Abbas] ia berkata: \"Orang-orang musyrik terbagi menjadi dua bila dilihat dari kedudukan mereka dari Nabi shallallahu 'alaihi wasallam dan kaum mukminin. Yang pertama, Ahlul Harb. Yaitu orang-orang musyrik yang Nabi shallallahu 'alaihi wasallam memerangi mereka dan mereka juga memerangi beliau. Dan yang kedua, Ahlu 'Ahd. Yakni, kaum musyrikin yang tidak diperangi oleh Rasulullah dan mereka juga tidak memerangi beliau. Dan apabila ada salah seorang wanita berhijrah dari Ahlul Harb, maka wanita itu tidak boleh dinikahi hingga ia haid hingga suci kembali. Setelah suci, maka menikah dengannya pun menjadi halal. Apabila suaminya juga ikut berhijrah sebelum wanita itu dinikahi, maka wanita itu akan dikembalikan padanya. Kemudian, apabila yang berhijrah adalah seorang hamba sahaya laki-laki atau pun perempuan, maka keduanya akan menjadi merdeka serta berhak untuk mendapatkan hak sebagaimana yang didapatkan oleh kaum muhajirin yang lain.\" Kemudian disebutkan pula Ahlul 'Ahd sebagaimana haditsnya Mujahid: \"Apabila seorang budak yang berhijrah baik laki-laki atau pun perempuan kepada orang-orang musyrik Ahlul 'Ahd, maka mereka tidak akan dikembalikan, namun yang dikembalikan adalah tebusan harga mereka.\" Dan 'Atha` berkata; dari Ibnu Abbas bahwasanya; Qaribah binti Abu Umayyah adalah isteri Umar bin Al Khaththab, lalu ia menceraikannya. Kemudian wanita itu dinikahi oleh Mu'awiyah bin Abu Sufyan, sedangkan Ummul Hakam binti Abu Sufyan adalah isteri dari 'Iyadl bin Ghanm Al Fihri dan kemudian ia pun menceraikannya, lalu dinikahi oleh Abdullah bin Utsman Ats Tsaqafi."},"4574":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ وَقَالَ إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنِي ابْنُ وَهْبٍ حَدَّثَنِي يُونُسُ قَالَ ابْنُ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَتْ الْمُؤْمِنَاتُ إِذَا هَاجَرْنَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْتَحِنُهُنَّ بِقَوْلِ اللَّهِ تَعَالَى{ يَا أَيُّهَا الَّذِينَ آمَنُوا إِذَا جَاءَكُمْ الْمُؤْمِنَاتُ مُهَاجِرَاتٍ فَامْتَحِنُوهُنَّ }إِلَى آخِرِ الْآيَةِ قَالَتْ عَائِشَةُ فَمَنْ أَقَرَّ بِهَذَا الشَّرْطِ مِنْ الْمُؤْمِنَاتِ فَقَدْ أَقَرَّ بِالْمِحْنَةِ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَقْرَرْنَ بِذَلِكَ مِنْ قَوْلِهِنَّ قَالَ لَهُنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْطَلِقْنَ فَقَدْ بَايَعْتُكُنَّ لَا وَاللَّهِ مَا مَسَّتْ يَدُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَ امْرَأَةٍ قَطُّ غَيْرَ أَنَّهُ بَايَعَهُنَّ بِالْكَلَامِ وَاللَّهِ مَا أَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى النِّسَاءِ إِلَّا بِمَا أَمَرَهُ اللَّهُ يَقُولُ لَهُنَّ إِذَا أَخَذَ عَلَيْهِنَّ قَدْ بَايَعْتُكُنَّ كَلَامًا","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dan telah berkata; [Ibrahim Al Mundzir] Telah menceritakan kepadaku [Ibnu Wahab] Telah menceritakan kepadaku [Yunus] Telah berkata [Ibnu Syihab] Telah mengabarkan kepadaku [Urwah bin Zubair] bahwa [Aisyah] radliallahu 'anha isteri Nabi Shallallahu 'Alaihi wa Salla berkata; Ketika para wanita mukminah berhijrah kepada Nabi shallallahu 'alaihi wasallam, maka beliau akan menguji mereka dengan firman Allah Ta'ala: \"Apabila wanita-wanita mukminat datang kepadamu untuk berhijrah, maka ujilah mereka..\" hingga akhir ayat (QS. Almumtahanah 10). Aisyah berkata; Barangsiapa yang beliau tetapkan dari kaum mukminat dengan syarat ini, maka beliau menyatakan bahwa ia telah teruji. Dan biasa bila kaum wanita telah mengikrarkan syarat itu dengan ungkapan mereka, maka Rasulullah shallallahu 'alaihi wasallam akan bersabda kepada mereka: \"Pergilah, sesungguhnya aku telah membai'at kalian dengan ungkapan ikrar.\" Demi Allah, tidaklah Rasulullah shallallahu 'alaihi wasallam berbuat sesuatu pun atas kaum wanita kecuali dengan sesuatu yang telah diperintahkan Allah. Bila beliau mengambil Bai'at dari mereka, maka beliau akan berkata: \"Sesungguhnya aku telah memba'iat kalian dengan ungkapan kata-kata.\""},"4575":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبِي أُوَيْسٍ عَنْ أَخِيهِ عَنْ سُلَيْمَانَ عَنْ حُمَيْدٍ الطَّوِيلِ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُآلَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ نِسَائِهِ وَكَانَتْ انْفَكَّتْ رِجْلُهُ فَأَقَامَ فِي مَشْرُبَةٍ لَهُ تِسْعًا وَعِشْرِينَ ثُمَّ نَزَلَ فَقَالُوا يَا رَسُولَ اللَّهِ آلَيْتَ شَهْرًا فَقَالَ الشَّهْرُ تِسْعٌ وَعِشْرُونَ","id":"Telah menceritakan kepada kami [Isma'il bin Abu Uwais] dari [saudaranya] dari [Sulaiman] dari [Humaid Ath Thawil] bahwa ia mendengar [Anas bin Malik] berkata; Rasulullah shallallahu 'alaihi wasallam pernah bersumpah untuk tidak menemui para isterinya (selama satu bulan). Kemudian kaki beliau berjalan dan berdiri di tempat minum milik beliau tepat pada tanggal dua puluh sembilan, kemudian beliau singgah (di rumah isterinya). Maka para sahabat pun berkata, \"Wahai Rasulullah, sesungguhnya Anda bersumpah untuk satu bulan.\" Maka beliau bersabda: \"Jumlah bulan itu adalah dua puluh Sembilan hari.\""},"4576":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاكَانَ يَقُولُ فِي الْإِيلَاءِ الَّذِي سَمَّى اللَّهُ لَا يَحِلُّ لِأَحَدٍ بَعْدَ الْأَجَلِ إِلَّا أَنْ يُمْسِكَ بِالْمَعْرُوفِ أَوْ يَعْزِمَ بِالطَّلَاقِ كَمَا أَمَرَ اللَّهُ عَزَّ وَجَلَّو قَالَ لِي إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ إِذَا مَضَتْ أَرْبَعَةُ أَشْهُرٍ يُوقَفُ حَتَّى يُطَلِّقَ وَلَا يَقَعُ عَلَيْهِ الطَّلَاقُ حَتَّى يُطَلِّقَ وَيُذْكَرُ ذَلِكَ عَنْ عُثْمَانَ وَعَلِيٍّ وَأَبِي الدَّرْدَاءِ وَعَائِشَةَ وَاثْنَيْ عَشَرَ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Al Laits] dari [Nafi'] bahwa [Ibnu Umar] radliallahu 'anhuma berkata tentang Al `Iila` dimana Allah telah menyebutkan bahwa tidak halal lagi bagi seseroang setelah masa iddah habis kecuali ia menahannya dengan cara yang ma'ruf atau ia menceraikannya sebagaimana yang diperintahkan Allah 'azza wajalla. [Isma'il] berkata kepadaku; Telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Ibnu Umar] ia berkata; Apabila empat bulan telah berlalu, ia dihadapkan hingga ia menceraikannya. Dan perceraian itu tidak sah kecuali setelah ia benar-benar menceraikannya. Hal itu disebutkan dari Utsman, Ali, Abu Darda`, 'Aisyah, dan dua belas orang dari sahabat Nabi shallallahu 'alaihi wasallam."},"4577":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ يَزِيدَ مَوْلَى الْمُنْبَعِثِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ ضَالَّةِ الْغَنَمِ فَقَالَ خُذْهَا فَإِنَّمَا هِيَ لَكَ أَوْ لِأَخِيكَ أَوْ لِلذِّئْبِ وَسُئِلَ عَنْ ضَالَّةِ الْإِبِلِ فَغَضِبَ وَاحْمَرَّتْ وَجْنَتَاهُ وَقَالَ مَا لَكَ وَلَهَا مَعَهَا الْحِذَاءُ وَالسِّقَاءُ تَشْرَبُ الْمَاءَ وَتَأْكُلُ الشَّجَرَ حَتَّى يَلْقَاهَا رَبُّهَا وَسُئِلَ عَنْ اللُّقَطَةِ فَقَالَ اعْرِفْ وِكَاءَهَا وَعِفَاصَهَا وَعَرِّفْهَا سَنَةً فَإِنْ جَاءَ مَنْ يَعْرِفُهَا وَإِلَّا فَاخْلِطْهَا بِمَالِكَقَالَ سُفْيَانُ فَلَقِيتُ رَبِيعَةَ بْنَ أَبِي عَبْدِ الرَّحْمَنِ قَالَ سُفْيَانُ وَلَمْ أَحْفَظْ عَنْهُ شَيْئًا غَيْرَ هَذَا فَقُلْتُ أَرَأَيْتَ حَدِيثَ يَزِيدَ مَوْلَى المُنْبَعِثِ فِي أَمْرِ الضَّالَّةِ هُوَ عَنْ زَيْدِ بْنِ خَالِدٍ قَالَ نَعَمْ قَالَ يَحْيَى وَيَقُولُ رَبِيعَةُ عَنْ يَزِيدَ مَوْلَى الْمُنْبَعِثِ عَنْ زَيْدِ بْنِ خَالِدٍ قَالَ سُفْيَانُ فَلَقِيتُ رَبِيعَةَ فَقُلْتُ لَهُ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] dari [Yahya bin Sa'id] dari [Yazid Maula Al Munba'its] bahwasanya; Nabi shallallahu 'alaihi wasallam pernah ditanya mengenai kambing yang tersesat, maka beliau pun bersabda: \"Sesungguhnya kambing itu adalah milikmu, atau milik saudaramu atau pun milik srigala.\" Kemudian beliau ditanya mengenai Unta yang hilang, maka wajah beliau memerah dan bersabda: \"Kenapa kamu ini, bukankah Unta punya sepatu dan tempat minum yang ia pergunakan untuk mencari minum?. Dan bukankah ia juga dapat makan tumbuh-tumbuhan hingga ia menemui pemiliknya?\" setelah itu, beliau ditanya tentang barang temuan. Maka beliau bersabda: \"Tolong tandai tali dan tutupnya, dan umumkanlah barang itu selama satu tahun. Jika ada seseorang yang datang dan mengetahuinya berikanlah dan jika tidak, maka kamu boleh mencampurkannya dengan hartamu.\" [Sufyan] berkata; Lalu aku menemui [Rabi'ah bin Abu Abdurrahman]. Sufyan berkata; Aku tidak menghafal sesuatu pun darinya selain ini; Aku berkata, \"Bagaimana pendapat Anda mengenai hadits Yazid Maula Al Munba'its terkait dengan barang yang hilang. Hadits itu dari Yazid bin Khalid?\" Ia menjawab; Ya. [Yahya] berkata; [Rabi'ah] berkata; dari [Yazid] budak Al munba'its dari [Zaid bin Khalid]. Sufyan berkata; Maka aku pun menemui Rabi'ah dan bertanya padanya."},"4578":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو عَامِرٍ عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا إِبْرَاهِيمُ عَنْ خَالِدٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَطَافَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى بَعِيرِهِ وَكَانَ كُلَّمَا أَتَى عَلَى الرُّكْنِ أَشَارَ إِلَيْهِ وَكَبَّرَوَقَالَتْ زَيْنَبُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَفُتِحَ مِنْ رَدْمِ يَأْجُوجَ وَمَأْجُوجَ مِثْلُ هَذِهِ وَعَقَدَ تِسْعِينَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] Telah menceritakan kepada kami [Abu Amir Abdul Malik bin Amru] Telah menceritakan kepada kami [Ibrahim] dari [Khalid] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam melakukan thawaf dengan tetap berada di atas untanya. Dan setiap kali beliau sampai di rukun yamani beliau memberi isyarat padanya dan bertakbir. Kemudan Zainab berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Benteng yang menghalangi Ya`juj dan Ma`juj itu dibuka seperti ini.\" lalu beliau membentuk jari-jemarinya dengan angka sembilan puluh."},"4579":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا سَلَمَةُ بْنُ عَلْقَمَةَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْجُمُعَةِ سَاعَةٌ لَا يُوَافِقُهَا عَبْدٌ مُسْلِمٌ قَائِمٌ يُصَلِّي فَسَأَلَ اللَّهَ خَيْرًا إِلَّا أَعْطَاهُ وَقَالَ بِيَدِهِ وَوَضَعَ أُنْمُلَتَهُ عَلَى بَطْنِ الْوُسْطَى وَالْخِنْصِرِ قُلْنَا يُزَهِّدُهَاوَقَالَ الْأُوَيْسِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ شُعْبَةَ بْنِ الْحَجَّاجِ عَنْ هِشَامِ بْنِ زَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَعَدَا يَهُودِيٌّ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى جَارِيَةٍ فَأَخَذَ أَوْضَاحًا كَانَتْ عَلَيْهَا وَرَضَخَ رَأْسَهَا فَأَتَى بِهَا أَهْلُهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ فِي آخِرِ رَمَقٍ وَقَدْ أُصْمِتَتْ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَتَلَكِ فُلَانٌ لِغَيْرِ الَّذِي قَتَلَهَا فَأَشَارَتْ بِرَأْسِهَا أَنْ لَا قَالَ فَقَالَ لِرَجُلٍ آخَرَ غَيْرِ الَّذِي قَتَلَهَا فَأَشَارَتْ أَنْ لَا فَقَالَ فَفُلَانٌ لِقَاتِلِهَا فَأَشَارَتْ أَنْ نَعَمْ فَأَمَرَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُضِخَ رَأْسُهُ بَيْنَ حَجَرَيْنِ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] Telah menceritakan kepada kami [Salamah bin Alqamah] dari [Muhammad bin Sirin] dari [Abu Hurairah] ia berkata; Abul Qasim shallallahu 'alaihi wasallam bersabda: \"Pada hari jum'at terdapat waktu, yang tidaklah seorang hamba muslim shalat dan berdo'a kepada Allah di waktu itu, kecuali Allah akan mengabulkannya.\" Beliau memberi isyarat dengan tangannya dan meletakkan ujung jari-jarinya pada jari tengah dan kelingking. Kami berkata, \"Beliau menyempitkannya.\" [Al Uwisi] berkata; Telah menceritakan kepada kami [Ibrahim] dari [Syu'bah Al Hajjaj] dari [Hisyam bin Zaid] dari [Anas bin Malik] ia berkata; Pada masa Rasulullah shallallahu 'alaihi wasallam, ada seorang Yahudi yang menganiya seorang budak perempuan."},"4580":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْفِتْنَةُ مِنْ هَا هُنَا وَأَشَارَ إِلَى الْمَشْرِقِ","id":"Telah menceritakan kepada kami [Qabishah] Telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Dinar] dari [Ibnu Umar] radliallahu 'anhuma, ia berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya fitnah itu akan muncul dari sisi.\" Beliau sambil menunjuk ke ufuk timur."},"4581":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ أَبِي إِسْحَاقَ الشَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَكُنَّا فِي سَفَرٍ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا غَرَبَتْ الشَّمْسُ قَالَ لِرَجُلٍ انْزِلْ فَاجْدَحْ لِي قَالَ يَا رَسُولَ اللَّهِ لَوْ أَمْسَيْتَ ثُمَّ قَالَ انْزِلْ فَاجْدَحْ قَالَ يَا رَسُولَ اللَّهِ لَوْ أَمْسَيْتَ إِنَّ عَلَيْكَ نَهَارًا ثُمَّ قَالَ انْزِلْ فَاجْدَحْ فَنَزَلَ فَجَدَحَ لَهُ فِي الثَّالِثَةِ فَشَرِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَوْمَأَ بِيَدِهِ إِلَى الْمَشْرِقِ فَقَالَ إِذَا رَأَيْتُمْ اللَّيْلَ قَدْ أَقْبَلَ مِنْ هَا هُنَا فَقَدْ أَفْطَرَ الصَّائِمُ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Jarir bin Abdul Hamid] dari [Abu Ishaq Asy Syaibani] dari [Abdullah bin Abu Aufa] ia berkata; Kami pernah berada dalam suatu perjalanan bersama Rasulullah shallallahu 'alaihi wasallam. Ketika matahari telah tenggelam beliau berkata kepada salah seorang laki-lakir: \"Turun dan siapkanlah makanan untukku.\" Laki-laki itu berkata, \"Wahai Rasulullah, seandainya Anda mau menunggu agak sore lagi.\" Beliau bersabda lagi: \"Turun dan siapkanlah makanan untukku.\" Laki-laki berkomentar lagi, \"Wahai Rasulullah, sekiranya Anda mau menunggu agak sore sedikit, sesungguhnya hari masih terang.\" Beliau bersabda: \"Turun dan siapkanlah makanan.\" Maka laki-laki itu pun turun dan menyiapkan makanan untuk beliau. Rasulullah shallallahu 'alaihi wasallam pun minum. Setelah itu, beliau menunjuk dengan tangannya ke arah timur seraya bersabda: \"Jika kalian telah melihat malam mulai menyingsing dari arah ini, maka seorang yang berpuasa sudah boleh berbuka.\""},"4582":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَمْنَعَنَّ أَحَدًا مِنْكُمْ نِدَاءُ بِلَالٍ أَوْ قَالَ أَذَانُهُ مِنْ سَحُورِهِ فَإِنَّمَا يُنَادِي أَوْ قَالَ يُؤَذِّنُ لِيَرْجِعَ قَائِمَكُمْ وَلَيْسَ أَنْ يَقُولَ كَأَنَّهُ يَعْنِي الصُّبْحَ أَوْ الْفَجْرَ وَأَظْهَرَ يَزِيدُ يَدَيْهِ ثُمَّ مَدَّ إِحْدَاهُمَا مِنْ الْأُخْرَىوَقَالَ اللَّيْثُ حَدَّثَنِي جَعْفَرُ بْنُ رَبِيعَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هُرْمُزَ سَمِعْتُ أَبَا هُرَيْرَةَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَمَثَلُ الْبَخِيلِ وَالْمُنْفِقِ كَمَثَلِ رَجُلَيْنِ عَ��َيْهِمَا جُبَّتَانِ مِنْ حَدِيدٍ مِنْ لَدُنْ ثَدْيَيْهِمَا إِلَى تَرَاقِيهِمَا فَأَمَّا الْمُنْفِقُ فَلَا يُنْفِقُ شَيْئًا إِلَّا مَادَّتْ عَلَى جِلْدِهِ حَتَّى تُجِنَّ بَنَانَهُ وَتَعْفُوَ أَثَرَهُ وَأَمَّا الْبَخِيلُ فَلَا يُرِيدُ يُنْفِقُ إِلَّا لَزِمَتْ كُلُّ حَلْقَةٍ مَوْضِعَهَا فَهُوَ يُوسِعُهَا فَلَا تَتَّسِعُ وَيُشِيرُ بِإِصْبَعِهِ إِلَى حَلْقِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] Telah menceritakan kepada kami [Yazid bin Zurai'] dari [Sulaiman At Taimi] dari [Abu Utsman] dari [Abdullah bin Mas'ud] radliallahu 'anhu, ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah sekali-laki adzan Bilal menghalangi kalian untuk makan dan minum.\" Atau beliau bersabda: \"Adzan Bilal pada waktu sahur. Sesungguhnya ia adzan hanya untuk membangunkan kalian.\" Al Laits berkata; Telah menceritakan kepadaku Ja'far bin Rabi'ah dari Abdurrahman bin Hurmuz Aku mendengar Abu Hurairah berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan orang yang bakhil dengan orang yang suka berinfak adalah seperti dua orang yang padanya terdapat selendang besi yang terbalut dari dada hingga tulang selangkanya. Maka bagi suka berinfak, tidaklah ia berinfak kecuali besi itu akan semakin longgar dari kulitnya hingga dan menutupi kulit serta menghapus bekasnya. Adapun yang bakhil, maka ia tidaklah ia mau berinfak kecuali selendang besi itu akan semakin menempel pada hampir semua bagian lehernya. Ia berusaha meluaskannya, namun juga tidak bisa lapang.\" Beliau memberi isyarat dengan jarinya ke arah lehernya."},"4583":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا لَيْثٌ عَنْ يَحْيَى بْنِ سَعِيدٍ الْأَنْصَارِيِّ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُخْبِرُكُمْ بِخَيْرِ دُورِ الْأَنْصَارِ قَالُوا بَلَى يَا رَسُولَ اللَّهِ قَالَ بَنُو النَّجَّارِ ثُمَّ الَّذِينَ يَلُونَهُمْ بَنُو عَبْدِ الْأَشْهَلِ ثُمَّ الَّذِينَ يَلُونَهُمْ بَنُو الْحَارِثِ بْنِ الْخَزْرَجِ ثُمَّ الَّذِينَ يَلُونَهُمْ بَنُو سَاعِدَةَ ثُمَّ قَالَ بِيَدِهِ فَقَبَضَ أَصَابِعَهُ ثُمَّ بَسَطَهُنَّ كَالرَّامِي بِيَدِهِ ثُمَّ قَالَ وَفِي كُلِّ دُورِ الْأَنْصَارِ خَيْرٌ","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Laits] dari [Yahya bin Sa'id Al Anshari] bahwa ia mendengar [Anas bin Malik] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah aku beritahukan pada kalian akan sebaik-baik rumah kaum Anshar?\" mereka pun menjawab, \"Mau wahai Rasulullah.\" Beliau bersabda: \"Yaitu Banu An Najjar, setelah mereka Banu Abdul Asyhal, setelah mereka Banul Harits bin Al Khazraj, setelah mereka Banu Sa'idah.\" Kemudian beliau bersabda dengan menggenggam jari-jemarinya dan merenggangkannya kembali sebagaimana seorang yang melempar, beliau bersabda: \"Dan pada setiap rumah kaum Anshar terdapat kebaikan.\""},"4584":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ أَبُو حَازِمٍ سَمِعْتُهُ مِنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ صَاحِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُعِثْتُ أَنَا وَالسَّاعَةَ كَهَذِهِ مِنْ هَذِهِ أَوْ كَهَاتَيْنِ وَقَرَنَ بَيْنَ السَّبَّابَةِ وَالْوُسْطَى","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] Telah berkata [Abu Hazim] Aku mendengarnya dari [Sa'hl bin Sa'd As Sa'idi] salah seorang dari sahabat Rasulullah shallallahu 'alaihi wasallam, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku diutus sementara kedatangan hari kiamat adalah seperti ini dari ini.\" beliau memberi isyarat dengan kedua jarinya, jari telunjuk dan jari tengah."},"4585":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا جَبَلَةُ بْنُ سُحَيْمٍ سَمِعْتُ ابْنَ عُمَرَ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ هَكَذَا وَهَكَذَا وَهَكَذَا يَعْنِي ثَلَاثِينَ ثُمَّ قَالَ وَهَكَذَا وَهَكَذَا وَهَكَذَا يَعْنِي تِسْعًا وَعِشْرِينَ يَقُولُ مَرَّةً ثَلَاثِينَ وَمَرَّةً تِسْعًا وَعِشْرِينَ","id":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Jabalah bin Suhaim] Aku mendengar [Ibnu Umar] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Bilangan bulan itu adalah begini dan begini.\" Maksudnya adalah tiga puluh hari. Kemudian beliau bersabda: \"Dan begini, begini dan begini.\" Yakni, dua puluh sembilan. Beliau menyatakan pada kali yang pertama tiga puluh dan pada kali kedua dua puluh sembilan hari."},"4586":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ عَنْ أَبِي مَسْعُودٍ قَالَوَأَشَارَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ نَحْوَ الْيَمَنِ الْإِيمَانُ هَا هُنَا مَرَّتَيْنِ أَلَا وَإِنَّ الْقَسْوَةَ وَغِلَظَ الْقُلُوبِ فِي الْفَدَّادِينَ حَيْثُ يَطْلُعُ قَرْنَا الشَّيْطَانِ رَبِيعَةَ وَمُضَرَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Isma'il] dari [Qais] dari [Abu Mas'ud] ia berkata; Nabi shallallahu 'alaihi wasallam memberi isyarat dengan tangannya seraya bersabda: \"Sesungguhnya iman itu letaknya di sini.\" Beliau mengucapkannya dua kali. Beliau melanjutkan: \"Sesungguhnya keras dan membatunya hati terdapat pada orang-orang yang angkuh lagi sombong, yaitu di tempat tanduk-tanduk syetan muncul yakni pada Rabi'ah dan Mudlar.\""},"4587":{"ar":"حَدَّثَنَا عَمْرُو بْنُ زُرَارَةَ أَخْبَرَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلٍقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا وَكَافِلُ الْيَتِيمِ فِي الْجَنَّةِ هَكَذَا وَأَشَارَ بِالسَّبَّابَةِ وَالْوُسْطَى وَفَرَّجَ بَيْنَهُمَا شَيْئًا","id":"Telah menceritakan kepada kami [Amru bin Zurarah] Telah mengabarkan kepada kami [Abdul Aziz bin Abu Hazim] dari [bapaknya] dari [Sahl] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku akan bersama orang-orang yang mengurusi anak Yatim dalam surga.\" Seperti inilah, beliau memberi isyarat dengan jari telunjuk dan jari tengah lalu beliau membuka sesuatu diantara keduanya."},"4588":{"ar":"حَدَّثَنَا يَحْيَى بْنُ قَزَعَةَ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ وُلِدَ لِي غُلَامٌ أَسْوَدُ فَقَالَ هَلْ لَكَ مِنْ إِبِلٍ قَالَ نَعَمْ قَالَ مَا أَلْوَانُهَا قَالَ حُمْرٌ قَالَ هَلْ فِيهَا مِنْ أَوْرَقَ قَالَ نَعَمْ قَالَ فَأَنَّى ذَلِكَ قَالَ لَعَلَّهُ نَزَعَهُ عِرْقٌ قَالَ فَلَعَلَّ ابْنَكَ هَذَا نَزَعَهُ","id":"Telah menceritakan kepada kami [Yahya bin Quza'ah] Telah menceritakan kepada kami [Malik] dari [Ibnu Abbas] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] bahwa seorang laki-laki mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, isteriku telah melahirkan anak yang berkulit hitam.\" Beliau bertanya: \"Apakah kamu memiliki beberapa ekor Unta?\" laki-laki itu menjawab, \"Ya.\" Beliau melanjutkan bertanya: \"Lalu apa saja warna kulitnya?\" Ia menjawab, \"Merah.\" Beliau bertanya lagi: \"Apakah di antara Unta itu ada yang berkulit keabu-abuan?\" laki-laki itu menjawab, \"Ya.\" Beliau bertanya: \"Kenapa bisa seperti itu?\" laki-laki itu menjawab, \"Mungkin itu berasal karena faktor keturunan.\" Beliau bersabda: \"Mungkin juga anakmu seperti itu (karena factor keturunan).\""},"4589":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا مِنْ الْأَنْصَارِ قَذَفَ امْرَأَتَهُ فَأَحْلَفَهُمَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ فَرَّقَ بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] Telah menceritakan kepada kami [Juwairiyah] dari [Nafi'] dari [Abdullah] radliallahu 'anhu, bahwa seorang laki-laki dari Anshar menuduh isterinya berzina, maka Nabi shallallahu 'alaihi wasallam pun meminta keduanya untuk bersumpah, lalu memisahkan antara keduanya."},"4590":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ هِشَامِ بْنِ حَسَّانَ حَدَّثَنَا عِكْرِمَةُ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ هِلَالَ بْنَ أُمَيَّةَ قَذَفَ امْرَأَتَهُ فَجَاءَ فَشَهِدَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ يَعْلَمُ أَنَّ أَحَدَكُمَا كَاذِبٌ فَهَلْ مِنْكُمَا تَائِبٌ ثُمَّ قَامَتْ فَشَهِدَتْ","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar] Telah menceritakan kepada kami [Ibnu Abu Adi] dari [Hisyam bin Hassan] Telah menceritakan kepada kami [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma, bahwasanya; Hilal bin Umayyah menuduh isterinya berzina, dan ia mengaku menyaksikannya. Dan Nabi shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya Allah tahu bahwa salah seorang dari kalian berdua berdusta. Apakah salah seorang ada yang mau bertaubat?\" Lalu sang isteri berdiri dan bersaksi."},"4591":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ أَنَّ سَهْلَ بْنَ سَعْدٍ السَّاعِدِيَّ أَخْبَرَهُأَنَّ عُوَيْمِرًا الْعَجْلَانِيَّ جَاءَ إِلَى عَاصِمِ بْنِ عَدِيٍّ الْأَنْصَارِيِّ فَقَالَ لَهُ يَا عَاصِمُ أَرَأَيْتَ رَجُلًا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ فَتَقْتُلُونَهُ أَمْ كَيْفَ يَفْعَلُ سَلْ لِي يَا عَاصِمُ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَ عَاصِمٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَكَرِهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسَائِلَ وَعَابَهَا حَتَّى كَبُرَ عَلَى عَاصِمٍ مَا سَمِعَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَجَعَ عَاصِمٌ إِلَى أَهْلِهِ جَاءَهُ عُوَيْمِرٌ فَقَالَ يَا عَاصِمُ مَاذَا قَالَ لَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَاصِمٌ لِعُوَيْمِرٍ لَمْ تَأْتِنِي بِخَيْرٍ قَدْ كَرِهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسْأَلَةَ الَّتِي سَأَلْتُهُ عَنْهَا فَقَالَ عُوَيْمِرٌ وَاللَّهِ لَا أَنْتَهِي حَتَّى أَسْأَلَهُ عَنْهَا فَأَقْبَلَ عُوَيْمِرٌ حَتَّى جَاءَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَطَ النَّاسِ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ رَجُلًا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ فَتَقْتُلُونَهُ أَمْ كَيْفَ يَفْعَلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أُنْزِلَ فِيكَ وَفِي صَاحِبَتِكَ فَاذْهَبْ فَأْتِ بِهَا قَالَ سَهْلٌ فَتَلَاعَنَا وَأَنَا مَعَ النَّاسِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا فَرَغَا مِنْ تَلَاعُنِهِمَا قَالَ عُوَيْمِرٌ كَذَبْتُ عَلَيْهَا يَا رَسُولَ اللَّهِ إِنْ أَمْسَكْتُهَا فَطَلَّقَهَا ثَلَاثًا قَبْلَ أَنْ يَأْمُرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ابْنُ شِهَابٍ فَكَانَتْ سُنَّةَ الْمُتَلَاعِنَيْنِ","id":"Telah menceritakan kepadaku [Isma'il] Ia berkata; Telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] bahwa [Sahl bin Sa'd As Sa'idi] Telah mengabarkan kepadanya bahwa Uwaimir Al 'Ajlani datang kepada 'Ashim bin Adi Al Anshari dan bertanya, \"Wahai 'Ashim, bagaimana pendapatmu bila seorang laki-laki mendapatkan laki-laki lain yang sedang bersama isterinya, apakah ia boleh membunuhnya hingga kalian pun membunuh laki-laki itu?. Atau apakah yang mesti dilakukannya? Wahai 'Ashim, tanyakanlah pertanyaanku itu kepada Rasulullah shallallahu 'alaihi wasallam.\" Maka 'Ashim pun menanyakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, dan ternyata Rasulullah shallallahu 'alaihi wasallam membenci persoalan itu dan mencelanya hingga Ashim pun merasakan keberatan. Ketika ia pulang ke rumah keluarganya, ia pun didatangi oleh 'Uwaimir dan berkata, \"Wahai 'Ashim apa yang telah dikatakan oleh Rasulullah shallallahu 'alaihi wasallam kepadamu?\" Lalu 'Ashim berkata kepada 'Uwaimir, \"Kebaikan belum singgah padaku. Rasulullah shallallahu 'alaihi wasallam sangat membenci persoalan yang aku tanyakan.\" Maka Uwaimir pun berkata, \"Demi Allah, aku tidak akan berhenti hingga aku akan menanyakannya sendiri.\" Akhirnya Uwaimir datang menghadap Rasulullah shallallahu 'alaihi wasallam di tengah kerumunan orang-orang, ia pun berkata, \"Wahai Rasulullah, bagaimana pendapat Anda, bila seorang laki-laki mendapatkan laki-laki lain bersama isterinya, apakah ia harus membunuhnya sehingga kalian juga akan membunuhnya? Atau apakah yang mesti ia lakukan?\" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya telah diturunkan ayat terkait denganmu dan juga sahabatmu (isterimu). Pergi dan bawalah ia kemari.\" Sahl berkata; Akhirnya kedua orang suami-isteri itu pun saling meli'an, sementara aku berada bersama orang-orang yang ada di sisi Rasulullah shallallahu 'alaihi wasallam. Ketika keduanya telah usai saling meli'an, maka 'Uwaimir pun berkata, \"Aku telah berdusta atasnya wahai Rasulullah bila aku tetap menahannya (tidak menceraikannya).\" Akhirnya ia pun menceraikannya dengan talak tiga sebelum ia diperintahkan oleh Rasulullah shallallahu 'alaihi wasallam. Ibnu Syihab berkata; Seperti itulah sunnah dua orang suami isteri yang saling meli'an (saling menuduh berbuat selingkuh)."},"4592":{"ar":"حَدَّثَنَا يَحْيَى أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي ابْنُ شِهَابٍعَنْ الْمُلَاعَنَةِ وَعَنْ السُّنَّةِ فِيهَا عَنْ حَدِيثِ سَهْلِ بْنِ سَعْدٍ أَخِي بَنِي سَاعِدَةَ أَنَّ رَجُلًا مِنْ الْأَنْصَارِ جَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ رَجُلًا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ أَمْ كَيْفَ يَفْعَلُ فَأَنْزَلَ اللَّهُ فِي شَأْنِهِ مَا ذَكَرَ فِي الْقُرْآنِ مِنْ أَمْرِ الْمُتَلَاعِنَيْنِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قَضَى اللَّهُ فِيكَ وَفِي امْرَأَتِكَ قَالَ فَتَلَاعَنَا فِي الْمَسْجِدِ وَأَنَا شَاهِدٌ فَلَمَّا فَرَغَا قَالَ كَذَبْتُ عَلَيْهَا يَا رَسُولَ اللَّهِ إِنْ أَمْسَكْتُهَا فَطَلَّقَهَا ثَلَاثًا قَبْلَ أَنْ يَأْمُرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ فَرَغَا مِنْ التَّلَاعُنِ فَفَارَقَهَا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ذَاكَ تَفْرِيقٌ بَيْنَ كُلِّ مُتَلَاعِنَيْنِ قَالَ ابْنُ جُرَيْجٍ قَالَ ابْنُ شِهَابٍ فَكَانَتْ السُّنَّةُ بَعْدَهُمَا أَنْ يُفَرَّقَ بَيْنَ الْمُتَلَاعِنَيْنِ وَكَانَتْ حَامِلًا وَكَانَ ابْنُهَا يُدْعَى لِأُمِّهِ قَالَ ثُمَّ جَرَتْ السُّنَّةُ فِي مِيرَاثِهَا أَنَّهَا تَرِثُهُ وَيَرِثُ مِنْهَا مَا فَرَضَ اللَّهُ لَهُ قَالَ ابْنُ جُرَيْجٍ عَنْ ابْنِ شِهَابٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ فِي هَذَا الْحَدِيثِ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنْ جَاءَتْ بِهِ أَحْمَرَ قَصِيرًا كَأَنَّهُ وَحَرَةٌ فَلَا أُرَاهَا إِلَّا قَدْ صَدَقَتْ وَكَذَبَ عَلَيْهَا وَإِنْ جَاءَتْ بِهِ أَسْوَدَ أَعْيَنَ ذَا أَلْيَتَيْنِ فَلَا أُرَاهُ إِلَّا قَدْ صَدَقَ عَلَيْهَا فَجَاءَتْ بِهِ عَلَى الْمَكْرُوهِ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Yahya] Telah mengabarkan kepada kami [Abdurrazzaq] Telah mengabarkan kepada kami [Ibnu Juraij] ia berkata; Telah mengabarkan kepadaku [Ibnu Syihab] yakni tentang li'an dan tentang sunnah yang terkait dengannya, dari hadis [Sahl bin Sa'dari] saudara Bani Sa'adah bahwasanya; Seorang laki-laki dari Anshar datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, bagaimana pendapat Anda bilamana seorang laki-laki mendapati laki-laki lain bersama isterinya, bolehkah ia membunuhnya atau apa yang semestinya ia lakukan?\" Maka Allah pun menurunkan ayat yang berkenaan dengan Mutala'inain (dua orang suami isteri yang saling meli'an). Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya Allah telah memberi putusan denganmu terkait dengan isterimu.\" Lalu dua orang suami-isteri itu saling melaknat di dalam masjid, aku menyaksikannya sendiri. Setelah itu, laki-laki itu berkata, \"Aku telah berdusta atasnya wahai Rasulullah bila aku tetap menahannya.\" Akhirnya laki-laki itu pun mentalaqnya dengan talak tiga sebelum Rasulullah shallallahu 'alaihi wasallam menyuruhnya. Maka orang itu pun berpisah dengannya di sisi Nabi shallallahu 'alaihi wasallam, dan beliau bersabda: \"Itulah At Tafriq (pemisahan) bagi setiap dua orang suami-isteri yang saling melaknat.\" Ibnu Juraij berkata; Ibnu Syihab berkata; Maka sunnah setelah itu adalah memisahkan suami isteri yang saling meli'an. Wanita itu sedang hamil dan anaknya pun dipanggil dengan bersandarkan pada ibunya. Begitulah seterusnya. Sang ibu mewarisi anaknya dan anak pun mewarisi ibunya sebagaimana apa yang telah diwajibkan Allah. Ibnu Juraij berkata; Dari Ibnu Syihab dari Sahl bin Sa'd As Sa'idi di dalam hadits ini, Nabi shallallahu 'alaihi wasallam bersabda: \"Jika ia melahirkan anak yang berkulit kemerah-merahan dan berpostur tubuh pendek menyerupai tokek, maka tidak ada dugaan lain, kecuali bahwa wanita itu telah berkata benar. Dan suaminya telah berdusta atasnya. Namun jika ia melahirkan anak yang kedua bola matanya hitam serta pantatnya besar, maka aku tidak pula menduga yang lain kecuali bahwa ia suaminya itu telah benar.\" Lalu wanita itu pun melahirkan anak yang membenarkan pengakuan 'Uwaimir."},"4593":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ ابْنِ عَبَّاسٍأَنَّهُ ذُكِرَ التَّلَاعُنُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَاصِمُ بْنُ عَدِيٍّ فِي ذَلِكَ قَوْلًا ثُمَّ انْصَرَفَ فَأَتَاهُ رَجُلٌ مِنْ قَوْمِهِ يَشْكُو إِلَيْهِ أَنَّهُ قَدْ وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا فَقَالَ عَاصِمٌ مَا ابْتُلِيتُ بِهَذَا الْأَمْرِ إِلَّا لِقَوْلِي فَذَهَبَ بِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِالَّذِي وَجَدَ عَلَيْهِ امْرَأَتَهُ وَكَانَ ذَلِكَ الرَّجُلُ مُصْفَرًّا قَلِيلَ اللَّحْمِ سَبْطَ الشَّعَرِ وَكَانَ الَّذِي ادَّعَى عَلَيْهِ أَنَّهُ وَجَدَهُ عِنْدَ أَهْلِهِ خَدْلًا آدَمَ كَثِيرَ اللَّحْمِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ ��َيِّنْ فَجَاءَتْ شَبِيهًا بِالرَّجُلِ الَّذِي ذَكَرَ زَوْجُهَا أَنَّهُ وَجَدَهُ فَلَاعَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمَا قَالَ رَجُلٌ لِابْنِ عَبَّاسٍ فِي الْمَجْلِسِ هِيَ الَّتِي قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ رَجَمْتُ أَحَدًا بِغَيْرِ بَيِّنَةٍ رَجَمْتُ هَذِهِ فَقَالَ لَا تِلْكَ امْرَأَةٌ كَانَتْ تُظْهِرُ فِي الْإِسْلَامِ السُّوءَقَالَ أَبُو صَالِحٍ وَعَبْدُ اللَّهِ بْنُ يُوسُفَ آدَمَ خَدِلًا","id":"Telah menceritakan kepada kami [Sa'id bin Ufair] ia berkata; Telah menceritakan kepadaku [Al Laits] dari [Yahya bin Sa'id] dari [Abdurrahman bin Al Qasim] dari [Al Qasim bin Muhammad] dari [Ibnu Abbas] bahwasanya; Suatu ketika li'an (suami-isteri menuduh berzina pasangannya) dibahas di sisi Nabi shallallahu 'alaihi wasallam. Maka Ashim bin Adi mengungkapkan sesuatu dalam masalah itu, kemudian ia beranjak pergi. Kemudian seorang laki-laki dari kaumnya datang dan mengadu padanya bahwa ia mendapati seorang laki-laki bersama isterinya. Maka Ashim berkata, \"Aku belum pernah diuji dengan masalah ini kecuali karena kata-kataku sendiri.\" Akhirnya ia dan laki-laki itu pergi menemui Nabi shallallahu 'alaihi wasallam. Lalu laki-laki itu menuturkan apa yang terjadi pada isterinya. Laki-laki itu kurus dan berambut lurus. Sedangkan laki-laki yang dapati bersama isterinya adalah seorang laki-laki yang gemuk dan berkulit sawo matang. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Ya Allah berilah kejelasan.\" Lalu wanita itu melahirkan bayi yang cirinya seperti laki-laki yang dilukiskan suaminya, yang ia temukan bersama isterinya. Maka Nabi shallallahu 'alaihi wasallam meli'an antara keduanya. Seorang laki-laki berkata kepada Ibnu Abbas di dalam majelis; Itukah wanita yang Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekira aku boleh merajam seseorang dengan tanpa Bayyinah (saksi), niscaya aku akan merajam wanita ini?.\" Ibnu Abbas berkata; \"Oh tidak, yang dimaksudkan wanita yang boleh dirajam tanpa bukti adalah wanita yang menyatakan secara terus terang (vulgar) perzinahannya, bukan wanita yang sekedar dituduh berzina\" Abu Shalih dan Abdullah bin Yusuf Adam mengatakan bahwa makna Adam adalah Khadil (gemuk)."},"4594":{"ar":"حَدَّثَنِي عَمْرُو بْنُ زُرَارَةَ أَخْبَرَنَا إِسْمَاعِيلُ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عُمَرَرَجُلٌ قَذَفَ امْرَأَتَهُ فَقَالَ فَرَّقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَخَوَيْ بَنِي الْعَجْلَانِ وَقَالَ اللَّهُ يَعْلَمُ أَنَّ أَحَدَكُمَا كَاذِبٌ فَهَلْ مِنْكُمَا تَائِبٌ فَأَبَيَا وَقَالَ اللَّهُ يَعْلَمُ أَنَّ أَحَدَكُمَا كَاذِبٌ فَهَلْ مِنْكُمَا تَائِبٌ فَأَبَيَا فَقَالَ اللَّهُ يَعْلَمُ أَنَّ أَحَدَكُمَا كَاذِبٌ فَهَلْ مِنْكُمَا تَائِبٌ فَأَبَيَا فَفَرَّقَ بَيْنَهُمَاقَالَ أَيُّوبُ فَقَالَ لِي عَمْرُو بْنُ دِينَارٍ إِنَّ فِي الْحَدِيثِ شَيْئًا لَا أَرَاكَ تُحَدِّثُهُ قَالَ قَالَ الرَّجُلُ مَالِي قَالَ قِيلَ لَا مَالَ لَكَ إِنْ كُنْتَ صَادِقًا فَقَدْ دَخَلْتَ بِهَا وَإِنْ كُنْتَ كَاذِبًا فَهُوَ أَبْعَدُ مِنْكَ","id":"Telah menceritakan kepadaku [Amru bin Zurarah] Telah mengabarkan kepada kami [Isma'il] dari [Ayyub] dari [Sa'id bin Jubair] ia berkata; Aku pernah bertanya kepada [Ibnu Umar], \"Bagaimanakah bilamana seorang laki-laki menuduh isterinya berzina?\" Ia pun menjawab; Nabi shallallahu 'alaihi wasallam telah memisahkan dua orang dari Bani Ajlan dan beliau bersabda: \"Allah mengetahui bahwa salah seorang dari kalian berdua berdusta. Apakah diantara kalian berdua ada yang mau bertaubat?\" namun, keduanya menolak tawaran itu, akhirnya beliau pun memisahkan keduanya. [Ayyub] berkata; Maka [Amru bin Dinar] berkata padaku, \"Sesungguhnya di dalam hadits masih terdapat suatu ungkapan yang aku kira belum kau sebutkan.\" Amru bin Dinar katakana; Laki-laki itu berkata, \"Lalu bagaimana dengan hartaku?\" beliau bersabda: \"Tidak ada harta bagimu. Jika kamu telah memberinya mahar maka kamu juga telah menggaulinya. Dan jika kamu berdusta, maka hal itu tentu akan menjadi lebih jauh.\""},"4595":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ عَمْرٌو سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ قَالَ سَأَلْتُ ابْنَ عُمَرَعَنْ حَدِيثِ الْمُتَلَاعِنَيْنِ فَقَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْمُتَلَاعِنَيْنِ حِسَابُكُمَا عَلَى اللَّهِ أَحَدُكُمَا كَاذِبٌ لَا سَبِيلَ لَكَ عَلَيْهَا قَالَ مَالِي قَالَ لَا مَالَ لَكَ إِنْ كُنْتَ صَدَقْتَ عَلَيْهَا فَهُوَ بِمَا اسْتَحْلَلْتَ مِنْ فَرْجِهَا وَإِنْ كُنْتَ كَذَبْتَ عَلَيْهَا فَذَاكَ أَبْعَدُ لَكَقَالَ سُفْيَانُ حَفِظْتُهُ مِنْ عَمْرٍو وَقَالَ أَيُّوبُ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عُمَرَ رَجُلٌ لَاعَنَ امْرَأَتَهُ فَقَالَ بِإِصْبَعَيْهِ وَفَرَّقَ سُفْيَانُ بَيْنَ إِصْبَعَيْهِ السَّبَّابَةِ وَالْوُسْطَى فَرَّقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَخَوَيْ بَنِي الْعَجْلَانِ وَقَالَ اللَّهُ يَعْلَمُ إِنَّ أَحَدَكُمَا كَاذِبٌ فَهَلْ مِنْكُمَا تَائِبٌ ثَلَاثَ مَرَّاتٍ قَالَ سُفْيَانُ حَفِظْتُهُ مِنْ عَمْرٍو وَأَيُّوبَ كَمَا أَخْبَرْتُكَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] Telah berkata [Amru] Aku mendengar [Sa'id bin Jubair] berkata; Aku pernah bertanya kepada [Ibnu Umar] mengenai hadist Al Mutalaa'inain (suami-isteri yang meli'an), maka ia pun menjawab; Nabi shallallahu 'alaihi wasallam pernah bersabda kepada Al Mutalaa'inain (suami-isteri yang meli'an): \"Hisab kalian berdua terserah pada Allah. Salah seorang dari kalian berdua musti ada yang berdusta, maka tidak ada lagi jalan bagimu (suami) untuk kembali kepada isteri.\" Laki-laki itu bertanya, \"Lalu bagaimana dengan hartaku?.\" Beliau bersabda: \"Tidak ada harta lagi untukmu. Jika kamu telah memberi sesuatu, maka hal itu adalah mahar yang kamu gunakan untuk menghalalkan farjinya, namun jika kamu berdusta atasnya, maka hal itu tentu akan lebih jauh bagimu.\" Sufyan berkata; Aku menghafalnya dari Amru. Dan telah berkata [Ayyub] Aku mendengar [Sa'id bin Jubair] Ia berkata; Aku berkata kepada [Ibnu Umar], \"Ada seorang laki-laki yang melaknat isterinya.\" Maka ia pun menjawab sambil memberi isyarat dengan kedua jarinya, Sufyan memisahkan antara kedua jarinya itu, yaitu jari telunjuk dan jari tengah. Ia melanjutkan; Nabi shallallahu 'alaihi wasallam pernah memisahkan antara dua orang dari Bani Al 'Ajlan dan beliau bersabda: \"Sesungguhnya Allah mengetahui bahwa salah seorang dari kalian berdusta. Adakah salah seorang yang ingin bertaubat?\" beliau mengulanginya hingga tiga kali. Sufyan berkata; Aku menghafalnya dari Amru dan Ayyub sebagaimana yang telah aku kabarkan kepadamu."},"4596":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَّقَ بَيْنَ رَجُلٍ وَامْرَأَةٍ قَذَفَهَا وَأَحْلَفَهُمَا","id":"Telah menceritakan kepadaku [Ibrahim bin Al Mundzir] Telah menceritakan kepada kami [Anas bin Iyadl] dari [Ubaidullah] dari [Nafi'] bahwa [Ibnu Umar] radliallahu 'anhuma telah menganbarkan kepadanya bahwasanya; Rasulullah shallallahu 'alaihi wasallam pernah memisahkan seorang laki-laki dan isterinya yang telah dituduhnya berzina. Dan beliau juga meminta keduanya untuk bersumpah."},"4597":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ قَالَلَاعَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ رَجُلٍ وَامْرَأَةٍ مِنْ الْأَنْصَارِ وَفَرَّقَ بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Ubaidullah] Telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] ia berkata; Nabi shallallahu 'alaihi wasallam pernah meli'an atara seorang laki-laki dengan wanita Anshar, lalu beliau memisahkan antara keduanya."},"4598":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا مَالِكٌ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَاعَنَ بَيْنَ رَجُلٍ وَامْرَأَتِهِ فَانْتَفَى مِنْ وَلَدِهَا فَفَرَّقَ بَيْنَهُمَا وَأَلْحَقَ الْوَلَدَ بِالْمَرْأَةِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Malik] ia berkata; Telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam meli'an antara seorang suami dengan isterinya. Sang suami menolak (tidak mengakui) anak yang dilahirkan isterinya, maka Nabi shallallahu 'alaihi wasallam memisahkan antara keduanya dan menyerahkan anak itu kepada pihak wanita."},"4599":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي سُلَيْمَانُ بْنُ بِلَالٍ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ الْقَاسِمِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ قَالَذُكِرَ الْمُتَلَاعِنَانِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَاصِمُ بْنُ عَدِيٍّ فِي ذَلِكَ قَوْلًا ثُمَّ انْصَرَفَ فَأَتَاهُ رَجُلٌ مِنْ قَوْمِهِ فَذَكَرَ لَهُ أَنَّهُ وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا فَقَالَ عَاصِمٌ مَا ابْتُلِيتُ بِهَذَا الْأَمْرِ إِلَّا لِقَوْلِي فَذَهَبَ بِهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِالَّذِي وَجَدَ عَلَيْهِ امْرَأَتَهُ وَكَانَ ذَلِكَ الرَّجُلُ مُصْفَرًّا قَلِيلَ اللَّحْمِ سَبْطَ الشَّعَرِ وَكَانَ الَّذِي وَجَدَ عِنْدَ أَهْلِهِ آدَمَ خَدْلًا كَثِيرَ اللَّحْمِ جَعْدًا قَطَطًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ بَيِّنْ فَوَضَعَتْ شَبِيهًا بِالرَّجُلِ الَّذِي ذَكَرَ زَوْجُهَا أَنَّهُ وَجَدَ عِنْدَهَا فَلَاعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمَا فَقَالَ رَجُلٌ لِابْنِ عَبَّاسٍ فِي الْمَجْلِسِ هِيَ الَّتِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ رَجَمْتُ أَحَدًا بِغَيْرِ بَيِّنَةٍ لَرَجَمْتُ هَذِهِ فَقَالَ ابْنُ عَبَّاسٍ لَا تِلْكَ امْرَأَةٌ كَانَتْ تُظْهِرُ السُّوءَ فِي الْإِسْلَامِ","id":"Telah menceritakan kepada kami [Isma'il] ia berkata; Telah menceritakan kepadaku [Sulaiman bin Bilal] dari [Yahya bin Sa'id] Telah mengabarkan kepadaku [Abdurrahman bin Al Qasim] dari [Al Qasim bin Muhammad] dari [Ibnu Abbas] bahwa ia berkata; Pernah disebutkan di sisi Rasulullah shallallahu 'alaihi wasallam, yakni dua orang suami isteri yang saling meli'an. Kemudan Ashim bin Adi mengungkapkan sesuatu terkait perkara itu, lalu ia beranjak pergi. Lalu ia didatangi oleh seseorang dari kaumnya dan menuturkan bahwa ia mendapatkan laki-laki lain yang sedang bersama isterinya. Maka Ashim pun berkata, \"Tidaklah aku diuji dengan masalah ini, kecuali karena ungkapanku.\" Maka ia pun segera pergi bersama laki-laki itu kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian ia pun menceritakan mengenai seorang laki-laki yang ia dapatkan sedang bersama isterinya. Laki-laki itu berperawakan kurus dan berambut lurus, sedangkan laki-laki yang dapatkan sedang bersama isterinya adalah berkulit sawo matang dan berperawakan gemuk. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, jelaskanlah perkara ini.\" Maka sang isteri pun melahirkan bayi menyerupai laki-laki yang dilukiskan oleh suaminya, yang ia tuduhkan bersama isterinya. Akhirnya Rasulullah shallallahu 'alaihi wasallam meli'an keduanya. Kemudian seorang laki-laki bertanya kepada Ibnu Abbas di dalam majelis itu; \"Wanita itukah yang dimaksud oleh sabda Rasulullah shallallahu 'alaihi wasallam: 'Seandainya aku boleh merajam seseorang tanpa Bayyinah (bukti), niscaya aku akan merajam wanita ini?.'\" Maka Ibnu Abbas menjawab, \"Tidak, wanita yang dimaksud adalah wanita yang secara vulgar (terang-terangan) menyatakan perselingkuhannya dalam Islam.\" "},"4600":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى حَدَّثَنَا هِشَامٌ قَالَ حَدَّثَنِي أَبِي عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رِفَاعَةَ الْقُرَظِيَّ تَزَوَّجَ امْرَأَةً ثُمَّ طَلَّقَهَا فَتَزَوَّجَتْ آخَرَ فَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ لَهُ أَنَّهُ لَا يَأْتِيهَا وَأَنَّهُ لَيْسَ مَعَهُ إِلَّا مِثْلُ هُدْبَةٍ فَقَالَ لَا حَتَّى تَذُوقِي عُسَيْلَتَهُ وَيَذُوقَ عُسَيْلَتَكِ","id":"Telah menceritakan kepada kami [Amru bin Ali] Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Hisyam] ia berkata; Telah menceritakan kepadaku [bapakku] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam. -Dalam riwayat lain- Telah menceritakan kepada kami [Utsman bin Abu Syaibah] Telah menceritakan kepada kami [Abdah] dari [Hisyam] dari [bapaknya] dari [Aisyah] radliallahu 'anha, bahwasanya; Rifa'ah Al Qurazhi menikahi seorang wanita lalu ia menceraikannya. Kemudian wanita itu menikah dengan laki-laki lain. Maka wanita itu datang mengadukan kepada Nabi shallallahu 'alaihi wasallam dan menuturkan bahwa suaminya itu belum menggaulinya, dan tidaklah kejantanan yang ada padanya kecuali seperti ujung kain.\" Maka beliau bersaba: \"Tidak boleh (kamu kembali) hingga kamu merasakan madunya dan ia pun merasakan madumu.\""},"4601":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هُرْمُزَ الْأَعْرَجِ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ أَخْبَرَتْهُ عَنْ أُمِّهَا أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ امْرَأَةً مِنْ أَسْلَمَ يُقَالُ لَهَا سُبَيْعَةُ كَانَتْ تَحْتَ زَوْجِهَا تُوُفِّيَ عَنْهَا وَهِيَ حُبْلَى فَخَطَبَهَا أَبُو السَّنَابِلِ بْنُ بَعْكَكٍ فَأَبَتْ أَنْ تَنْكِحَهُ فَقَالَ وَاللَّهِ مَا يَصْلُحُ أَنْ تَنْكِحِيهِ حَتَّى تَعْتَدِّي آخِرَ الْأَجَلَيْنِ فَمَكُثَتْ قَرِيبًا مِنْ عَشْرِ لَيَالٍ ثُمَّ جَاءَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ انْكِحِي","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari [Ja'far bin Rabi'ah] dari [Abdurrahman bin Hurmuz Al A'raj] ia berkata; Telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] bahwa [Zainab binti Abu Salamah] telah mengabarkan kepadanya dari [Ibunya] yakni Ummu Salamah isteri Nabi shallallahu 'alaihi wasallam bahwasanya; Ada seorang wanita dari Bani Aslam yang biasa dipanggil Subai'ah. Ia memiliki suami dan wafat sementara ia dalam keadaan hamil. Lalu ia pun dipinang oleh Abu As Sanabil bin Ba'kak, namun ia menolak untuk menikahinya. Ia berkata, \"Demi Allah, wanita itu tidak boleh menikahinya hingga masa iddah yang terakhir berakhir. (maksudnya empat bulan sepuluh hari, bukan setelah melahirkan). Maka wanita itu pun menunggu selama sepuluh hari, lalu ia datang menemui Nabi shallallahu 'alaihi wasallam, maka beliau bersabda: \"Menikahlah dengannya (maksudnya boleh nikah setelah melahirkan, tidak menunggu empat bulan sepuluh hari)."},"4602":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ عَنْ اللَّيْثِ عَنْ يَزِيدَ أَنَّ ابْنَ شِهَابٍ كَتَبَ إِلَيْهِ أَنَّ عُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ أَخْبَرَهُ عَنْ أَبِيهِ أَنَّهُ كَتَبَ إِلَى ابْنِ الْأَرْقَمِ أَنْ يَسْأَلَ سُبَيْعَةَ الْأَسْلَمِيَّةَكَيْفَ أَفْتَاهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ أَفْتَانِي إِذَا وَضَعْتُ أَنْ أَنْكِحَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] dari [Al Laits] dari [Yazid] bahwa [Ibnu Syihab] pernah menulis kepadanya bahwa [Ubaidullah bin Abdullah] telah mengabarkan kepadanya, dari [bapaknya] bahwa ia telah menulis kepada [Ibnul Arqam] untuk bertanya kepada Subai'ah Al Aslamiyyah tentang fatwa yang telah disampaikan kepada oleh Nabi shallallahu 'alaihi wasallam. Maka [Subai'ah] berkata, \"Beliau berfatwa padaku bahwa jika aku telah melahirkan, maka aku boleh menikah.\""},"4603":{"ar":"حَدَّثَنَا يَحْيَى بْنُ قَزَعَةَ حَدَّثَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَأَنَّ سُبَيْعَةَ الْأَسْلَمِيَّةَ نُفِسَتْ بَعْدَ وَفَاةِ زَوْجِهَا بِلَيَالٍ فَجَاءَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَأْذَنَتْهُ أَنْ تَنْكِحَ فَأَذِنَ لَهَا فَنَكَحَتْ","id":"Telah menceritakan kepada kami [Yahya bin Qaza'ah] Telah menceritakan kepada kami [Malik] dari [Hisyam bin Urwah] dari [bapaknya] dari [Al Miswar bin Makhramah] bahwasanya; Subai'ah Al Aslamiyyah melahirkan beberapa hari setelah suaminya wafat, lalu ia pun menemui Nabi shallallahu 'alaihi wasallam dan meminta izin untuk menikah. Maka beliau pun mengizinkannya."},"4604":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ وَسُلَيْمَانَ بْنِ يَسَارٍ أَنَّهُ سَمِعَهُمَا يَذْكُرَانِأَنَّ يَحْيَى بْنَ سَعِيدِ بْنِ الْعَاصِ طَلَّقَ بِنْتَ عَبْدِ الرَّحْمَنِ بْنِ الْحَكَمِ فَانْتَقَلَهَا عَبْدُ الرَّحْمَنِ فَأَرْسَلَتْ عَائِشَةُ أُمُّ الْمُؤْمِنِيِنَ إِلَى مَرْوَانَ بْنِ الحَكَمِ وَهُوَ أَمِيرُ الْمَدِينَةِ اتَّقِ اللَّهَ وَارْدُدْهَا إِلَى بَيْتِهَا قَالَ مَرْوَانُ فِي حَدِيثِ سُلَيْمَانَ إِنَّ عَبْدَ الرَّحْمَنِ بْنَ الْحَكَمِ غَلَبَنِي وَقَالَ الْقَاسِمُ بْنُ مُحَمَّدٍ أَوَمَا بَلَغَكِ شَأْنُ فَاطِمَةَ بِنْتِ قَيْسٍ قَالَتْ لَا يَضُرُّكَ أَنْ لَا تَذْكُرَ حَدِيثَ فَاطِمَةَ فَقَالَ مَرْوَانُ بْنُ الحَكَمِ إِنْ كَانَ بِكِ شَرٌّ فَحَسْبُكِ مَا بَيْنَ هَذَيْنِ مِنْ الشَّرِّ","id":"Telah menceritakan kepada kami [Isma'il] Telah menceritakan kepada kami [Malik] dari [Yahya bin Sa'id] dari [Al Qasim bin Muhamamd] dan [Sulaiman bin Yasar] bahwa ia mendengar keduanya menyebutkan bahwa Yahya bin Sa'id bin Al 'Ash menceraikan anak wanita Abdurrahman bin Al Hakam, lalu Abdurrahman pun memindahkannya. Maka [Aisyah] Ummul Mukminin mengirim surat kepada Marwan bin Al Hakam yang saat itu sebagai Amir Madinah, \"Bertakwalah kepada Allah dan kembalikanlah ia ke rumahnya.\" Marwan berkata; Di dalam hadits Sulaiman disebutkan: \"Sesungguhnya Abdurrahman bin Al Hakam telah mengalahkanku.\" Al Qasim bin Muhammad berkata, \"Tidakkah sampai kepadamu berita tentang Fathimah binti Qais?\" Wanita itu berkata, \"Tidaklah akan mencelakaimu, kalau kamu tidak menyebutkan hadits Fathimah.\" Maka Marwan bin Al Hakam berkata, \"Sesungguhnya pada dirimu terdapat keburukan. Karena itu, cukuplah keburukanmu antara dua hal itu.\""},"4605":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْمَا لِفَاطِمَةَ أَلَا تَتَّقِي اللَّهَ يَعْنِي فِي قَوْلِهَا لَا سُكْنَى وَلَا نَفَقَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] Telah menceritakan kepada kami [Ghundar] Telah menceritakan kepada kami [Syu'bah] dari [Abdurrahman bin Al Qasim] dari [bapaknya] dari [Aisyah] bahwa ia berkata, \"Ada apa dengan Fathimah, tidakkah kamu takut kepada Allah.\" Yakni terkait dengan ungkapannya, \"Tidak ada tempat tinggal dan tidak pula nafkah.\""},"4606":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبَّاسٍ حَدَّثَنَا ابْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ قَالَ عُرْوَةُ بْنُ الزُّبَيْرِ لِعَائِشَةَأَلَمْ تَرَيْ إِلَى فُلَانَةَ بِنْتِ الْحَكَمِ طَلَّقَهَا زَوْجُهَا الْبَتَّةَ فَخَرَجَتْ فَقَالَتْ بِئْسَ مَا صَنَعَتْ قَالَ أَلَمْ تَسْمَعِي فِي قَوْلِ فَاطِمَةَ قَالَتْ أَمَا إِنَّهُ لَيْسَ لَهَا خَيْرٌ فِي ذِكْرِ هَذَا الْحَدِيثِوَزَادَ ابْنُ أَبِي الزِّنَادِ عَنْ هِشَامٍ عَنْ أَبِيهِ عَابَتْ عَائِشَةُ أَشَدَّ الْعَيْبِ وَقَالَتْ إِنَّ فَاطِمَةَ كَانَتْ فِي مَكَانٍ وَحْشٍ فَخِيفَ عَلَى نَاحِيَتِهَا فَلِذَلِكَ أَرْخَصَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Amru bin Abbas] Telah menceritakan kepada kami [Ibnu Mahdi] Telah menceritakan kepada kami [Sufyan] dari [Abdurrahman bin Al Qasim] dari [bapaknya] bahwa [Urwah bin Az Zubair] berkata kepada Aisyah, \"Tidakkah kamu melihat Fulanah binti Hakam yang telah diceraikan oleh suaminya.\" Maka Aisyah pun keluar seraya berkata, \"Alangkah buruk apa yang telah diperbuatnya.\" Urwah bin Zubair berkata, \"Tidakkah Anda mendengar ungkapan Fathimah?\" Ia berkata, \"Sesungguhnya dalam ungkapan itu tidak ada kebaikan baginya.\" [Ibnu Abu Zinad] menambahkan dari [Hisyam], dari [bapaknya]; [Aisyah] mencela dengan celaan yang sangat dan berkata, \"Sesungguhnya Fathimah saat itu berada di tempat yang tandus, lalu keberadaannya pun dikhawatirkan. Karena itu, Nabi shallallahu 'alaihi wasallam memberikan rukhshah padanya.\""},"4607":{"ar":"حَدَّثَنِي حِبَّانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ أَنَّ عَائِشَةَأَنْكَرَتْ ذَلِكَ عَلَى فَاطِمَةَ","id":"Telah menceritakan kepadaku [Hibban] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Ibnu Juraij] dari [Ibnu Syihab] dari [Urwah] bahwa [Aiysah] mengingkari hal itu atas Fathimah."},"4608":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمَّا أَرَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَنْفِرَ إِذَا صَفِيَّةُ عَلَى بَابِ خِبَائِهَا كَئِيبَةً فَقَالَ لَهَا عَقْرَى أَوْ حَلْقَى إِنَّكِ لَحَابِسَتُنَا أَكُنْتِ أَفَضْتِ يَوْمَ النَّحْرِ قَالَتْ نَعَمْ قَالَ فَانْفِرِي إِذًا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] radliallahu 'anha, ia berkata; Rasulullah shallallahu 'alaihi wasallam hendak nafar (kembali dari Muzdalifah ke Madinah), dan tiba-tiba Shafiyya berdiri di depan pintu tendanya dengan penuh kesedihan. Maka beliau pun bersabda padanya: \"Uhh,,, sesungguhnya kamu benar-benar telah menahan kami. Apakah kamu telah melakukan thawaf di hari kurban?\" Ia menjawab, \"Ya.\" Beliau bersabda: \"Kalau begitu, maka berangkatlah.\""},"4609":{"ar":"حَدَّثَنِي مُحَمَّدٌ أَخْبَرَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ قَالَزَوَّجَ مَعْقِلٌ أُخْتَهُ فَطَلَّقَهَا تَطْلِيقَةً","id":"Telah menceritakan kepadaku [Muhammad] Telah mengabarkan kepada kami [Abdul Wahhab] Telah menceritakan kepada kami [Yunus] dari [Al Hasan] ia berkata; Ma'qil telah menikahkan saudara perempuannya, lalu sang suami menceraikannya dengan talak satu."},"4610":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ حَدَّثَنَا الْحَسَنُأَنَّ مَعْقِلَ بْنَ يَسَارٍ كَانَتْ أُخْتُهُ تَحْتَ رَجُلٍ فَطَلَّقَهَا ثُمَّ خَلَّى عَنْهَا حَتَّى انْقَضَتْ عِدَّتُهَا ثُمَّ خَطَبَهَا فَحَمِيَ مَعْقِلٌ مِنْ ذَلِكَ أَنَفًا فَقَالَ خَلَّى عَنْهَا وَهُوَ يَقْدِرُ عَلَيْهَا ثُمَّ يَخْطُبُهَا فَحَالَ بَيْنَهُ وَبَيْنَهَا فَأَنْزَلَ اللَّهُ{ وَإِذَا طَلَّقْتُمْ النِّسَاءَ فَبَلَغْنَ أَجَلَهُنَّ فَلَا تَعْضُلُوهُنَّ }إِلَى آخِرِ الْآيَةِ فَدَعَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَ عَلَيْهِ فَتَرَكَ الْحَمِيَّةَ وَاسْتَقَادَ لِأَمْرِ اللَّهِ","id":"Dan Telah menceritakan kepadaku [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Abdul A'la] Telah menceritakan kepada kami [Sa'id] dari [Qatadah] Telah menceritakan kepada kami [Al Hasan] bahwa saudara perempuan Ma'qil bin Yasar berada di bawah seorang laki-laki, lalu laki-laki itu pun menceraikannya dan berpisah dengannya hingga masa iddahnya habis. Kemudian laki-laki itu meminangnya kembali. Maka Ma'qil pun marah dan menolak pinangan itu dan berkata, \"Ia menceraikannya padahal ia mampu. Lalu ia mengkhithbahnya kembali.\" Akhirnya ia menghalangi ruju' antara keduanya. Maka Allah menurunkan ayat: \"WA IDZAA THALLAQTUMUN NISAA` FABALAGHNA AJALAHUNNA FALAA TA'DLULUUHUNNA..\" (QS. Albaqarah 232), hingga akhir ayat. Lalu Rasulullah shallallahu 'alaihi wasallam pun memanggilnya dan membacakan ayat itu kepadanya. Akhirnya ia pun meninggalkan keangkuhannya dan meneriman ketentuan Allah."},"4611":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُمَاطَلَّقَ امْرَأَةً لَهُ وَهِيَ حَائِضٌ تَطْلِيقَةً وَاحِدَةً فَأَمَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُرَاجِعَهَا ثُمَّ يُمْسِكَهَا حَتَّى تَطْهُرَ ثُمَّ تَحِيضَ عِنْدَهُ حَيْضَةً أُخْرَى ثُمَّ يُمْهِلَهَا حَتَّى تَطْهُرَ مِنْ حَيْضِهَا فَإِنْ أَرَادَ أَنْ يُطَلِّقَهَا فَ��ْيُطَلِّقْهَا حِينَ تَطْهُرُ مِنْ قَبْلِ أَنْ يُجَامِعَهَا فَتِلْكَ الْعِدَّةُ الَّتِي أَمَرَ اللَّهُ أَنْ تُطَلَّقَ لَهَا النِّسَاءُ وَكَانَ عَبْدُ اللَّهِ إِذَا سُئِلَ عَنْ ذَلِكَ قَالَ لِأَحَدِهِمْ إِنْ كُنْتَ طَلَّقْتَهَا ثَلَاثًا فَقَدْ حَرُمَتْ عَلَيْكَ حَتَّى تَنْكِحَ زَوْجًا غَيْرَكَوَزَادَ فِيهِ غَيْرُهُ عَنْ اللَّيْثِ حَدَّثَنِي نَافِعٌ قَالَ ابْنُ عُمَرَ لَوْ طَلَّقْتَ مَرَّةً أَوْ مَرَّتَيْنِ فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَنِي بِهَذَا","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Al Laits] dari [Nafi'] bahwa [Ibnu Umar bin Al Khaththab] radliallahu 'anhuma menceraikan isterinya dalam keadaan haidl dengan talak satu. Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan agar ia meruju'nya kembali lalu menahannya hingga ia suci, kemudian haid lagi dan menunggunya hingga ia suci kembali dari haidlnya. Maka bila ia mau menceraikannya, maka hendaklah ia menceraikannya saat dalam keadaan suci dan sebelum menjima'nya. Itulah Al 'Iddah yang diperintahkan Allah, agar para wanita diceraikan pada masa itu. Dan apabila Abdullah ditanya tentang hal itu, maka ia kan berkata kepada salah seorang dari mereka, \"Jika kamu menceraikannya dengan talak tiga, maka sungguh wanita itu telah diharamkan atasmu hingga ia menikah dengan laki-laki lain selainmu.\" Dan selainnya menambahkan; Dari Al Laits Telah menceritakan kepadaku Nafi' Telah berkata Ibnu Umar; \"Bila kamu menceraikan dengan sekali atau dua kali talak, maka Nabi shallallahu 'alaihi wasallam telah memerintahkanku seperti itu.\""},"4612":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا يَزِيدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا مُحَمَّدُ بْنُ سِيرِينَ حَدَّثَنِي يُونُسُ بْنُ جُبَيْرٍ سَأَلْتُ ابْنَ عُمَرَ فَقَالَطَلَّقَ ابْنُ عُمَرَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَسَأَلَ عُمَرُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُ أَنْ يُرَاجِعَهَا ثُمَّ يُطَلِّقَ مِنْ قُبُلِ عِدَّتِهَا قُلْتُ فَتَعْتَدُّ بِتِلْكَ التَّطْلِيقَةِ قَالَ أَرَأَيْتَ إِنْ عَجَزَ وَاسْتَحْمَقَ","id":"Telah menceritakan kepada kami [Hajjaj] Telah menceritakan kepada kami [Yazid bin Ibrahim] Telah menceritakan kepada kami [Muhammad bin Sirin] Telah menceritakan kepadaku [Yunus bin Jubair] Aku bertanya kepada [Ibnu Umar], maka ia pun berkata; \"Ibnu Umar pernah menceraikan isterinya dalam keadaan haid. Maka Umar pun menanyakannya kepada Nabi shallallahu 'alaihi wasallam. Dan akhirnya beliau memerintahkannya agar ia meruju'nya kembali dan menceraikannya di permulaan masa iddahnya.\" Aku bertanya, \"Apakah ia (isteri Ibnu Umar) menunggu masa iddah dari perceraian itu?\" ia menjawab, \"Bagaimana pendapatmu, bila ia memang benar-benar bodoh atau pandir (tak tahu)?\""},"4613":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ حُمَيْدِ بْنِ نَافِعٍ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ أَنَّهَا أَخْبَرَتْهُ هَذِهِ الْأَحَادِيثَ الثَّلَاثَةَ قَالَتْ زَيْنَبُ دَخَلْتُ عَلَى أُمِّ حَبِيبَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحِينَ تُوُفِّيَ أَبُوهَا أَبُو سُفْيَانَ بْنُ حَرْبٍ فَدَعَتْ أُمُّ حَبِيبَةَ بِطِيبٍ فِيهِ صُفْرَةٌ خَلُوقٌ أَوْ غَيْرُهُ فَدَهَنَتْ مِنْهُ جَارِيَةً ثُمَّ مَسَّتْ بِعَارِضَيْهَا ثُمَّ قَالَتْ وَاللَّهِ مَا لِي بِالطِّيبِ مِنْ حَاجَةٍ غَيْرَ أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ تُحِدَّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثِ لَيَالٍ إِلَّا عَلَى زَوْجٍ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Abdullah bin Abu Bakr bin Muhammad bin Amru bin Hazm] dari [Humaid bin Nafi'] dari [Zainab binti Abu Salamah] bahwa ia telah mengabarkan tiga hadits ini kepadanya. Zainab berkata; Aku menemui [Ummu Habibah] isteri Nabi shallallahu 'alaihi wasallam saat bapaknya, Abu Sufyan bin Harb, wafat. Lalu Ummu Habibah meminta wewangian yang di dalamnya terdapat minyak wangi kuning yang sudah usang. Kemudian dari wewangian itu, ia meminyaki seorang budak wanita lalu memegang kedua belah pipinya seraya berkata, \"Demi Allah, aku tidak berhajat sedikitpun terhadap wewangian, hanya saja aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Tidak halal bagi seorang wanita yang beriman kepada Allah dan hari akhir, untuk berkabung lebih dari tiga hari, kecuali karena kematian suaminya, yaitu selama empat bulan sepuluh hari.'\""},"4614":{"ar":"قَالَتْ زَيْنَبُ فَدَخَلْتُ عَلَى زَيْنَبَ بِنْتِ جَحْشٍحِينَ تُوُفِّيَ أَخُوهَا فَدَعَتْ بِطِيبٍ فَمَسَّتْ مِنْهُ ثُمَّ قَالَتْ أَمَا وَاللَّهِ مَا لِي بِالطِّيبِ مِنْ حَاجَةٍ غَيْرَ أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَلَى الْمِنْبَرِ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ تُحِدَّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثِ لَيَالٍ إِلَّا عَلَى زَوْجٍ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"(Masih dari jalur periwayatan yang sama dengan hadits sebelumnya) [Zainab] berkata; Aku pernah menemui [Zainab binti Jahsy] ketika saudaranya mati. Lalu ia pun megambil wewangian dan memegangnya seraya berkata; Demi Allah, tidaklah aku berhajat sedikitpun terhadap wewangian ini. Selain aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda di atas mimbar: \"Tidak halal bagi seorang wanita yang beriman kepada Allah dan hari akhir untuk berkabung terhadap mayit lebih dari tiga malam, kecuali atas suaminya, yakni selama empat bulan sepuluh hari.\""},"4615":{"ar":"قَالَتْ زَيْنَبُ وَسَمِعْتُ أُمَّ سَلَمَةَتَقُولُ جَاءَتْ امْرَأَةٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ ابْنَتِي تُوُفِّيَ عَنْهَا زَوْجُهَا وَقَدْ اشْتَكَتْ عَيْنَهَا أَفَتَكْحُلُهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا مَرَّتَيْنِ أَوْ ثَلَاثًا كُلَّ ذَلِكَ يَقُولُ لَا ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا هِيَ أَرْبَعَةُ أَشْهُرٍ وَعَشْرٌ وَقَدْ كَانَتْ إِحْدَاكُنَّ فِي الْجَاهِلِيَّةِ تَرْمِي بِالْبَعْرَةِ عَلَى رَأْسِ الْحَوْلِقَالَ حُمَيْدٌ فَقُلْتُ لِزَيْنَبَ وَمَا تَرْمِي بِالْبَعْرَةِ عَلَى رَأْسِ الْحَوْلِ فَقَالَتْ زَيْنَبُ كَانَتْ الْمَرْأَةُ إِذَا تُوُفِّيَ عَنْهَا زَوْجُهَا دَخَلَتْ حِفْشًا وَلَبِسَتْ شَرَّ ثِيَابِهَا وَلَمْ تَمَسَّ طِيبًا حَتَّى تَمُرَّ بِهَا سَنَةٌ ثُمَّ تُؤْتَى بِدَابَّةٍ حِمَارٍ أَوْ شَاةٍ أَوْ طَائِرٍ فَتَفْتَضُّ بِهِ فَقَلَّمَا تَفْتَضُّ بِشَيْءٍ إِلَّا مَاتَ ثُمَّ تَخْرُجُ فَتُعْطَى بَعَرَةً فَتَرْمِي ثُمَّ تُرَاجِعُ بَعْدُ مَا شَاءَتْ مِنْ طِيبٍ أَوْ غَيْرِهِ سُئِلَ مَالِكٌ مَا تَفْتَضُّ بِهِ قَالَ تَمْسَحُ بِهِ جِلْدَهَا","id":"(Masih dari jalur periwayatan yang sama dengan hadits sebelumnya) [Zainab] berkata; Aku mendengar [Ummu Salamah] berkata; Seorang wanita pernah datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya anak perempuanku ditinggal mati oleh suaminya, sementara matanya juga terasa perih. Bolehkah ia bercelak?\" Maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Tidak.\" Beliau mengulanginya dua atau tiga kali. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Masa berkabungnya adalah empat bulan sepuluh hari. Sesungguhnya pada masa jahiliyah dulu, salah seorang dari kalian melempar kotoran setelah satu tahun.\" Humaid berkata; Aku bertanya kepada Zainab, \"Apa maksud dari pernyataan bahwa, ia melempar kotoran setelah setahun?\" Zainab menjawab, \"Maksudnya, bila seorang wanita ditinggal mati oleh suaminya, ia masuk ke dalam gubuk, dan memakai pakaian yang paling lusuh miliknya. Ia tidak boleh menyentuh wewangian hingga berlalu satu tahun. Kemudian keledai, kambing atau sebangsa burung didatangkan kepada wanita itu agar ia mengusap kulitnya. Dan amat jarang ia mengusap suatu pun kecuali sesuatu itu akan mati. Setelah itu, ia keluar lalu diberi kotoran hewan dan ia lemparkan, setelah itu ia bebas menyentuh kembali sekehendaknya berupa wewangian atau pun yang lainnya.\" Malik ditanya, \"Apa makna Tanfadldlu bihi?\" Ia menjawab, \"Yaitu, mengusap kulitnya dengannya.\""},"4616":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا حُمَيْدُ بْنُ نَافِعٍ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّهَاأَنَّ امْرَأَةً تُوُفِّيَ زَوْجُهَا فَخَشُوا عَلَى عَيْنَيْهَا فَأَتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَأْذَنُوهُ فِي الْكُحْلِ فَقَالَ لَا تَكَحَّلْ قَدْ كَانَتْ إِحْدَاكُنَّ تَمْكُثُ فِي شَرِّ أَحْلَاسِهَا أَوْ شَرِّ بَيْتِهَا فَإِذَا كَانَ حَوْلٌ فَمَرَّ كَلْبٌ رَمَتْ بِبَعَرَةٍ فَلَا حَتَّى تَمْضِيَ أَرْبَعَةُ أَشْهُرٍ وَعَشْرٌوَسَمِعْتُ زَيْنَبَ بِنْتَ أُمِّ سَلَمَةَ تُحَدِّثُ عَنْ أُمِّ حَبِيبَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِامْرَأَةٍ مُسْلِمَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ تُحِدَّ فَوْقَ ثَلَاثَةِ أَيَّامٍ إِلَّا عَلَى زَوْجِهَا أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Humaid bin Nafi'] dari [Zainab binti Ummu Salamah] dari [Ibunya] bahwasanya; Ada seorang wanita yang ditinggal mati oleh suaminya, hingga orang-orang pun mengkhawatir kesehatan kedua matanya. Maka mereka mendatangi Rasulullah shallallahu 'alaihi wasallam dan meminta izin bolehnya mencelak mata. Maka beliau bersabda: \"Janganlah kamu bercelak. Sesungguhnya -pada masa jahiliyah dulu- salah seorang dari kalian berdiam diri dalam rumahnya yang paling lusuh. Setelah setahun berlaku, seekor anjing lewat, dan ia pun melemparinya dengan kotoran. Karena itu, janganlah bercelak hingga empat bulan sepuluh hari telah berlalu.\" Dan aku mendengar [Zainab binti Ummu Salamah] menceritakan dari [Ummu Habibah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seorang wanita muslimah yang beriman kepada Allah dan hari akhir untuk berkabung lebih dari tiga hari kecuali atas suaminya, yakni empat bulan sepuluh hari.\""},"4617":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرٌ حَدَّثَنَا سَلَمَةُ بْنُ عَلْقَمَةَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَتْ أُمُّ عَطِيَّةَنُهِينَا أَنْ نُحِدَّ أَكْثَرَ مِنْ ثَلَاثٍ إِلَّا بِزَوْجٍ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Bisyr] Telah menceritakan kepada kami [Salamah bin 'Alqamah] dari [Muhammaad bin Sirin] bahwa [Ummu 'Athiyyah] berkata, \"Kami dilarang untuk berkabung lebih dari tiga hari kecuali terhadap suami.\""},"4618":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْكُنَّا نُنْهَى أَنْ نُحِدَّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثٍ إِلَّا عَلَى زَوْجٍ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا وَلَا نَكْتَحِلَ وَلَا نَطَّيَّبَ وَلَا نَلْبَسَ ثَوْبًا مَصْبُوغًا إِلَّا ثَوْبَ عَصْبٍ وَقَدْ رُخِّصَ لَنَا عِنْدَ الطُّهْرِ إِذَا اغْتَسَلَتْ إِحْدَانَا مِنْ مَحِيضِهَا فِي نُبْذَةٍ مِنْ كُسْتِ أَظْفَارٍ وَكُنَّا نُنْهَى عَنْ اتِّبَاعِ الْجَنَائِزِ","id":"Telah menceritakan kepadaku [Abdullah bin Abdul Wahb] Telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Hafshah] dari [Ummu 'Athiyyah] ia berkata; \"Kami dilarang untuk berkabung atas mayit lebih dari tiga hari kecuali atas suami, yakni empat bulan sepuluh hari. Kami tidak boleh bercelak, tidak boleh memakai wewangian dan tidak pula memakai pakaian yang berwarna kecuali pakaian yang terbuat dari bahan dedaunan. Pada masa suci kami telah diberi keringanan, yakni ketika salah seorang dari kami telah mandi bersih dari haidnya, maka ia boleh memakai potongan kecil dari dahan yang dipergunakan untuk kemenyan dan obat yang sering dinamakan qusth atau minyak wangi Azhfar.\" Dan kami juga dilarang untuk mengikuti jenazah.\""},"4619":{"ar":"حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ عَنْ هِشَامٍ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ تُحِدَّ فَوْقَ ثَلَاثٍ إِلَّا عَلَى زَوْجٍ فَإِنَّهَا لَا تَكْتَحِلُ وَلَا تَلْبَسُ ثَوْبًا مَصْبُوغًا إِلَّا ثَوْبَ عَصْبٍوَقَالَ الْأَنْصَارِيُّ حَدَّثَنَا هِشَامٌ حَدَّثَتْنَا حَفْصَةُ حَدَّثَتْنِي أُمُّ عَطِيَّةَ نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا تَمَسَّ طِيبًا إِلَّا أَدْنَى طُهْرِهَا إِذَا طَهُرَتْ نُبْذَةً مِنْ قُسْطٍ وَأَظْفَارٍ قَالَ أَبُو عَبْد اللَّهِ الْقُسْطُ وَالْكُسْتُ مِثْلُ الْكَافُورِ وَالْقَافُورِ","id":"Telah menceritakan kepada kami [Al Fadllu bin Dukain] Telah menceritakan kepada kami [Abdus Salam bin Harb] dari [Hisyam] dari [Hafshah] dari [Ummu 'Athiyah] ia berkata; Nabi shallallahu 'alaihi wasallam pernah bersabda kepadaku: \"Tidak halal bagi seorang wanita yang beriman kepada Allah dan hari akhir untuk berkabung lebih dari tiga hari kecuali terhadap suaminya. Maka ia tidak boleh bercelak, tidak boleh memakai pakaian yang berwarna (bercorak) kecuali pakaian yang terbuat dari bahan dedaunan.\" Dan [Al Anshari] berkata; Telah menceritakan kepada kami [Hisyam] Telah menceritakan kepada kami [Hafshah] Telah menceritakan kepadaku [Ummu 'Athiyyah] ia berkata; Nabi shallallahu 'alaihi wasallam melarang: \"Dan janganlah ia memakai wewangian kecuali pada akhir masa sucinya. Dan jika ia telah suci, ia boleh memakai potongan kecil dari dahan yang dibuat kemenyan dan obat yang sering disebut qusth atau minyak wangi azhfar.\" Abu Abdullah berkata; Al Qusth dan Al Kust adalah seperti Al Kafur dan Al Qafur (maksudnya dalam kesesuaian huruf qaf dan kaf)."},"4620":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ مَنْصُورٍ أَخْبَرَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا شِبْلٌ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا }قَالَ كَانَتْ هَذِهِ الْعِدَّةُ تَعْتَدُّ عِنْدَ أَهْلِ زَوْجِهَا وَاجِبًا فَأَنْزَلَ اللَّهُ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا وَصِيَّةً لِأَزْوَاجِهِمْ مَتَاعًا إِلَى الْحَوْلِ غَيْرَ إِخْرَاجٍ فَإِنْ خَرَجْنَ فَلَا جُنَاحَ عَلَيْكُمْ فِيمَا فَعَلْنَ فِي أَنْفُسِهِنَّ مِنْ مَعْرُوفٍ }قَالَ جَعَلَ اللَّهُ لَهَا تَمَامَ السَّنَةِ سَبْعَةَ أَشْهُرٍ وَعِشْرِينَ لَيْلَةً وَصِيَّةً إِنْ شَاءَتْ سَكَنَتْ فِي وَصِيَّتِهَا وَإِنْ شَاءَتْ خَرَجَتْ وَهُوَ قَوْلُ اللَّهِ تَعَالَى{ غَيْرَ إِخْرَاجٍ فَإِنْ خَرَجْنَ فَلَا جُنَاحَ عَلَيْكُمْ }فَالْعِدَّةُ كَمَا هِيَ وَاجِبٌ عَلَيْهَا زَعَمَ ذَلِكَ عَنْ مُجَاهِدٍ وَقَالَ عَطَاءٌ قَالَ ابْنُ عَبَّاسٍنَسَخَتْ هَذِهِ الْآيَةُ عِدَّتَهَا عِنْدَ أَهْلِهَا فَتَعْتَدُّ حَيْثُ شَاءَتْ وَقَوْلُ اللَّهِ تَعَالَى{ غَيْرَ إِخْرَاجٍ }وَقَالَ عَطَاءٌ إِنْ شَاءَتْ اعْتَدَّتْ عِنْدَ أَهْلِهَا وَسَكَنَتْ فِي وَصِيَّتِهَا وَإِنْ شَاءَتْ خَرَجَتْ لِقَوْلِ اللَّهِ{ فَلَا جُنَاحَ عَلَيْكُمْ فِيمَا فَعَلْنَ فِي أَنْفُسِهِنَّ }قَالَ عَطَاءٌ ثُمَّ جَاءَ الْمِيرَاثُ فَنَسَخَ السُّكْنَى فَتَعْتَدُّ حَيْثُ شَاءَتْ وَلَا سُكْنَى لَهَا","id":"Telah menceritakan kepadaku [Ishaq bin Manshur] Telah mengabarkan kepada kami [Rauh bin Ubadah] Telah menceritakan kepada kami [Syibl] dari [Ibnu Najih] dari [Mujahid] terkait dengan firman Allah: Dan orang-orang yang meninggal diantara kalian dan meninggalkan isteri (QS. Albaqarah 240), dahulu iddah yang dilakukan seorang isteri di rumah suaminya adalah wajib, lantas Allah menurunkan ayat; \"WALLADZI YUTAFFAUNA MINKUM WA YADZARUUNA AZWAAJAW WASHIYYATAL LIAZWAAJIHIM MATAA'AN ILAL HAULI GHAIRA IKHRAAJ FAIN KHARAJNA FALAA JUNAAHA 'ALAIKUM FIIMAA FA'ALNAA FII ANFUSIHINNA MIM MA'RUUF.\" \"Dan orang-orang yang meninggal diantara kalian dan meninggalkan isteri, hendaklah menyampaikan wasiat kediaman isteri dan nafkah kepada isterinya selama setahun dengan tidak menyuruh mereka agar keluar, namun jika para isteri yang ditinggal suaminya itu keluar rumah, maka tiada ada dosa bagimu atas perbuatan yang mereka lakukan' (QS. Albaqarah 240). Ia menjelaskan, \"Allah menjadikan kesempurnaan sunnah adalah selama empat bulan dua puluh hari, sebagai wasiat. Bila ia mau, maka oleh boleh tetap pada wasiatnya. Dan jika tidak, ia boleh keluar. Itulah yang dimaksud dengan firman Allah, 'GHAIRA IKHRAAJ, FA`IN KHARAJNA FALAA JUNAHA 'ALAIKUM (dengan tidak menyuruh si isteri untuk pergi, jika isteri itu pergi, maka tidak ada dosa atas kalian), Yakni, masa 'Iddah sebagaimana yang diwajibkan atasnya. ['Atha`] berkata; [Ibnu Abbas] berkata; Ayat ini dinasakh (dihapus) bahwa ia melalui masa iddahnya di rumah suaminya. Karena itu, ia boleh melalui masa iddahnya di mana pun ia mau.\" Dan firman Allah Ta'ala: \"Ghaira Ikharaaj\" Ahta` berkata; Bila ia mau, maka ia boleh melalui masa iddahnya di rumah suaminya atau berdiam pada washiyatnya. Dan bila ia mau, ia boleh keluar karena firman Allah: \"FALAA JUNAAHA 'ALAIKUM FIIMAA FA'ALNA FII ANFUSIHINNA.\" (Maka tak ada dosa atasmu atas perbuatan yang mereka lakukan) Atha` berkata; Kemudian turunlah ayat warisan dan terhapuslah As Sukna (tempat wanita berdiam), hingga ia pun boleh beriddah di mana pun ia suka, dan tidak ada tempat tinggal baginya."},"4621":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ عَمْرِو بْنِ حَزْمٍ حَدَّثَنِي حُمَيْدُ بْنُ نَافِعٍ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ حَبِيبَةَ بِنْتِ أَبِي سُفْيَانَلَمَّا جَاءَهَا نَعِيُّ أَبِيهَا دَعَتْ بِطِيبٍ فَمَسَحَتْ ذِرَاعَيْهَا وَقَالَتْ مَا لِي بِالطِّيبِ مِنْ حَاجَةٍ لَوْلَا أَنِّي سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ تُحِدُّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثٍ إِلَّا عَلَى زَوْجٍ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] dari [Sufyan] dari [Abdullah bin Abu Bakr bin Amru bin Hazm] Telah menceritakan kepadaku [Humaid bin Nafi'] dari [Zainab binti Ummu Salamah] dari [Ummu Habibah binti Abu Sufyan] bahwa ketika berita kematian bapaknya sampai padanya, ia minta diambilnya wewangian dan berkata, \"Aku tak berhajat untuk memakai wewangian sekiranya aku tak mendengar Nabi shallallahu 'alaihi wasallam bersabda: 'Tidak halal bagi seorang wanita yang beriman kepada Allah dan hari akhir untuk berkabung lebih dari tiga hari kecuali terhadap suaminya, maka ia berkabung selama empat bulan sepuluh hari.'\""},"4622":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَمَنِ الْكَلْبِ وَحُلْوَانِ الْكَاهِنِ وَمَهْرِ الْبَغِيِّ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Bakr bin Abdurrahman] dari [Abu Mas'ud] radliallahu 'anhu, ia berkata; Nabi shallallahu 'alaihi wasallam melarang untuk memakan hasil keuntungan dari anjing, dan dukun dan pelacur."},"4623":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَوْنُ بْنُ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ قَالَلَعَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَاشِمَةَ وَالْمُسْتَوْشِمَةَ وَآكِلَ الرِّبَا وَمُوكِلَهُ وَنَهَى عَنْ ثَمَنِ الْكَلْبِ وَكَسْبِ الْبَغِيِّ وَلَعَنَ الْمُصَوِّرِينَ","id":"Telah menceritakan kepada kami [Adam] Telah menceritakan kepada kami [Su'bah] Telah menceritakan kepada kami ['Aun bin Juhaifah] dari [bapaknya] ia berkata; \"Nabi shallallahu 'alaihi wasallam telah melaknat Al Wasyimah (wanita yang mentato) dan Al Mustausyimah (wanita yang meminta untuk ditato), orang yang memakan riba, dan orang yang memberi dari hasil riba. Dan beliau juga melarang untuk memakan hasil keuntungan dari anjing, dan pelacur. Kemudian beliau juga melaknat para tukang gambar.\""},"4624":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْجَعْدِ أَخْبَرَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ جُحَادَةَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كَسْبِ الْإِمَاءِ","id":"Telah menceritakan kepada kami [Ali bin Ja'd] Telah mengabarkan kepada kami [Syu'bah] dari [Muhammad bin Juhadah] dari [Abu Hazim] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam telah melarang untuk mempekerjakan budak wanita."},"4625":{"ar":"حَدَّثَنَا عَمْرُو بْنُ زُرَارَةَ أَخْبَرَنَا إِسْمَاعِيلُ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عُمَرَرَجُلٌ قَذَفَ امْرَأَتَهُ فَقَالَ فَرَّقَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَخَوَيْ بَنِي الْعَجْلَانِ وَقَالَ اللَّهُ يَعْلَمُ أَنَّ أَحَدَكُمَا كَاذِبٌ فَهَلْ مِنْكُمَا تَائِبٌ فَأَبَيَا فَقَالَ اللَّهُ يَعْلَمُ أَنَّ أَحَدَكُمَا كَاذِبٌ فَهَلْ مِنْكُمَا تَائِبٌ فَأَبَيَا فَفَرَّقَ بَيْنَهُمَا قَالَ أَيُّوبُ فَقَالَ لِي عَمْرُو بْنُ دِينَارٍ فِي الْحَدِيثِ شَيْءٌ لَا أَرَاكَ تُحَدِّثُهُ قَالَ قَالَ الرَّجُلُ مَالِي قَالَ لَا مَالَ لَكَ إِنْ كُنْتَ صَادِقًا فَقَدْ دَخَلْتَ بِهَا وَإِنْ كُنْتَ كَاذِبًا فَهُوَ أَبْعَدُ مِنْكَ","id":"Telah menceritakan kepada kami [Amru bin Zurarah] Telah mengabarkan kepada kami [Isma'il] dari [Ayyub] dari [Sa'id bin Jubair] ia berkata; Aku pernah bertanya kepada [Ibnu Umar] mengenai seorang laki-laki yang menuduh isterinya berzina. Maka ia pun menjelaskan; Nabi shallallahu 'alaihi wasallam telah memisahkan antara dua orang Bani 'Ajlan dan beliau bersabda: \"Sesungguhnya Allah mengetahui bahwa salah sorang dari kalian adalah dusta. Apakah di antara kalian ada yang mau bertaubat?\" namun keduanya enggan dan menolak. Beliau bersabda lagi: \"Sesungguhnya Allah mengetahui bahwa salah seorang dari kalian adalah dusta. Apakah di antara kalian ada yang mau bertaubat?\" keduanya tetap engan, maka beliau memisahkan antara keduanya. Ayyub berkata; Amru bin Dinar berkata padaku; Di dalam hadits terdapat sesuatu yang tidak kamu ceritakan. Lalu ia pun menyebutkan; Laki-laki itu berkata, \"Lalu bagaimana dengan hartaku?\" beliau bersabda: \"Jika kamu jujur, kamu telah menggaulinya. Dan jika kamu dusta, maka hal itu tentulah lebih parah lagi.\""},"4626":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْمُتَلَاعِنَيْنِ حِسَابُكُمَا عَلَى اللَّهِ أَحَدُكُمَا كَاذِبٌ لَا سَبِيلَ لَكَ عَلَيْهَا قَالَ يَا رَسُولَ اللَّهِ مَالِي قَالَ لَا مَالَ لَكَ إِنْ كُنْتَ صَدَقْتَ عَلَيْهَا فَهُوَ بِمَا اسْتَحْلَلْتَ مِنْ فَرْجِهَا وَإِنْ كُنْتَ كَذَبْتَ عَلَيْهَا فَذَاكَ أَبْعَدُ وَأَبْعَدُ لَكَ مِنْهَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Sufyan] dari [Amru] dari [Sa'id bin Jubair] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada Al Mutalaa'inaini (dua orang suami-isteri yang saling menuduh berzina kepada satu sama lain): \"Hisab kalian berdua adalah terserah kepada Allah. Salah seorang dari kalian telah berdusta. Karena itu, tidak ada jalan lagi bagimu untuk kembali ruju' padanya.\" Laki-laki itu berkata, \"Wahai Rasulullah, bagaimana dengan hartaku?\" beliau bersabda: \"Tidak ada bagian harta untukmu. Jika kamu berkata benar atasnya, maka mahar yang telah kamu berikan adalah sebagai penghalal farjinya. Dan jika kamu dusta, maka hal itu tentulah lebih parah.\""},"4627":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَ الْأَنْصَارِيَّ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ فَقُلْتُ عَنْ النَّبِيِّ فَقَالَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَنْفَقَ الْمُسْلِمُ نَفَقَةً عَلَى أَهْلِهِ وَهُوَ يَحْتَسِبُهَا كَانَتْ لَهُ صَدَقَةً","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] Telah menceritakan kepada kami [Syu'bah] dari [Adi bin Tsabit] ia berkata; Aku mendengar [Abdullah bin Yazid Al Anshari] dari [Abu Mas'ud Al Anshari] maka aku berkata; Dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika seorang muslim memberi nafkah pada keluarganya dengan niat mengharap pahala, maka baginya hal itu adalah sedekah.\""},"4628":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ أَنْفِقْ يَا ابْنَ آدَمَ أُنْفِقْ عَلَيْكَ","id":"Telah menceritakan kepada kami [Isma'il] ia berkata; Telah menceritakan kepadaku [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya, Allah berilah rezeki. Wahai Ibnu Adam berinfaklah, niscaya kalian juga akan diberi rezeki.\""},"4629":{"ar":"حَدَّثَنَا يَحْيَى بْنُ قَزَعَةَ حَدَّثَنَا مَالِكٌ عَنْ ثَوْرِ بْنِ زَيْدٍ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّاعِي عَلَى الْأَرْمَلَةِ وَالْمِسْكِينِ كَالْمُجَاهِدِ فِي سَبِيلِ اللَّهِ أَوْ الْقَائِمِ اللَّيْلَ الصَّائِمِ النَّهَارَ","id":"Telah menceritakan kepada kami [Yahya bin Qaza'ah] Telah menceritakan kepada kami [Malik] dari [Tsaur bin Zaid] dari [Abul Ghaits] dari [Abu Hurairah] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Orang yang memberi kecukupan kepada para janda dan orang-orang miskin, maka ia seperti halnya seorang mujahid di jalan Allah atau seorang yang berdiri menunaikan qiyamullail dan berpuasa di siang harinya.\""},"4630":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ سَعْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي وَأَنَا مَرِيضٌ بِمَكَّةَ فَقُلْتُ لِي مَالٌ أُوصِي بِمَالِي كُلِّهِ قَالَ لَا قُلْتُ فَالشَّطْرِ قَالَ لَا قُلْتُ فَالثُّلُثِ قَالَ الثُّلُثُ وَالثُّلُثُ كَثِيرٌ أَنْ تَدَعَ وَرَثَتَكَ أَغْنِيَاءَ خَيْرٌ مِنْ أَنْ تَدَعَهُمْ عَالَةً يَتَكَفَّفُونَ النَّاسَ فِي أَيْدِيهِمْ وَمَهْمَا أَنْفَقْتَ فَهُوَ لَكَ صَدَقَةٌ حَتَّى اللُّقْمَةَ تَرْفَعُهَا فِي فِي امْرَأَتِكَ وَلَعَلَّ اللَّهَ يَرْفَعُكَ يَنْتَفِعُ بِكَ نَاسٌ وَيُضَرُّ بِكَ آخَرُونَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah mengabarkan kepada kami [Sufyan] dari [Sa'd bin Ibrahim] dari [Amir bin Sa'd] dari [Sa'd] radliallahu 'anhu ia berkata; Nabi shallallahu 'alaihi wasallam pernah mengunjungiku ketika aku jatuh sakit di Makkah. Kukatakan pada beliau, \"Sesungguhnya aku memiliki harta. Haruskah aku mewasiatkan seluruhnya?\" beliau menjawab: \"Tidak.\" Aku bertanya lagi, \"Ataukah setengah darinya?\" beliau menjawab: \"Tidak.\" Aku bertanya lagi, \"Ataukah sepertiga darinya?\" beliau menjawab: \"Ya, sepertiga. Namun sepertiga adalah sesuatu yang banyak. Lebih baik bila kamu meninggalkan ahli warismu dalam keadaan berkecukupan daripada kamu meninggalkan mereka dalam keadaan miskin dan mengharap-harap apa yang ada di tangan manusia. Dan seagala yang kamu infakkan, maka hal itu adalah sedekah bagimu, bahkan termasuk sesuap makanan yang kamu suapkan pada bibir isterimu. Dan semoga Allah mengangkat derajatmu sehingga banyak orang mengambil manfaat darimu dan yang lain mendapat madharrat.\""},"4631":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا أَبُو صَالِحٍ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ الصَّدَقَةِ مَا تَرَكَ غِنًى وَالْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى وَابْدَأْ بِمَنْ تَعُولُ تَقُولُ الْمَرْأَةُ إِمَّا أَنْ تُطْعِمَنِي وَإِمَّا أَنْ تُطَلِّقَنِي وَيَقُولُ الْعَبْدُ أَطْعِمْنِي وَاسْتَعْمِلْنِي وَيَقُولُ الِابْنُ أَطْعِمْنِي إِلَى مَنْ تَدَعُنِي فَقَالُوا يَا أَبَا هُرَيْرَةَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا هَذَا مِنْ كِيسِ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Umar bin Hafsh] Telah menceritakan kepada kami [bapakku] Telah menceritakan kepada kami [Al A'masy] Telah menceritakan kepada kami [Abu Shalih] ia berkata; Telah menceritakan kepadaku [Abu Hurairah] radliallahu 'anhu, ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sedekah yang paling utama adalah sedekah yang meninggalkan pelakunya dalam kecukupan. Tangan yang di atas adalah lebih baik daripada tangan yang dibawah. Dan mulailah dari orang yang menjadi tanggunganmu.\" Sebab, seorang isteri akan berkata, \"Terserah, kamu memberiku makan, atau kamu menceraikanku.\" Dan seorang budak juga berkata, \"Berilah aku makan dan silahkan engkau menyuruhku bekerja.\" Kemudian seorang anak juga akan berkata, \"Berilah aku makan, kepada siapa lagi engkau meninggalkanku?.\" Mereka bertanya, \"Wahai Abu Hurairah, apakah kamu mendengar hal ini dari Rasulullah shallallahu 'alaihi wasallam?\" ia menjawab, \"Tidak. Hal ini adalah dari Abu Hurairah.\""},"4632":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدِ بْنِ مُسَافِرٍ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ الصَّدَقَةِ مَا كَانَ عَنْ ظَهْرِ غِنًى وَابْدَأْ بِمَنْ تَعُولُ","id":"Telah menceritakan kepada kami [Sa'id bin Ufair] ia berkata; Telah menceritakan kepadaku [Al Laits] ia berkata; Telah menceritakan kepadaku [Abdurrahman bin Khalid bin Musafir] dari [Ibnu Syihab] dari [Ibnul Musayyab] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik sedekah adalah setelah kecukupan terpenuhi. Dan mulailah dari orang yang menjadi tanggunganmu.\""},"4633":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا وَكِيعٌ عَنْ ابْنِ عُيَيْنَةَ قَالَ قَالَ لِي مَعْمَرٌ قَالَ لِي الثَّوْرِيُّ هَلْ سَمِعْتَ فِي الرَّجُلِ يَجْمَعُ لِأَهْلِهِ قُوتَ سَنَتِهِمْ أَوْ بَعْضِ السَّنَةِ قَالَ مَعْمَرٌ فَلَمْ يَحْضُرْنِي ثُمَّ ذَكَرْتُ حَدِيثًا حَدَّثَنَاهُ ابْنُ شِهَابٍ الزُّهْرِيُّ عَنْ مَالِكِ بْنِ أَوْسٍ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَبِيعُ نَخْلَ بَنِي النَّضِيرِ وَيَحْبِسُ لِأَهْلِهِ قُوتَ سَنَتِهِمْ","id":"Telah menceritakan kepadaku [Muhammad bin Salam] Telah mengabarkan kepada kami [Waki'] dari [Ibnu 'Uyainah] ia berkata; Telah berkata kepadaku [Ma'mar] Telah berkata kepadaku Ats Tsauri; \"Apakah kamu pernah mendengar tentang seorang laki-laki yang mengumpulkan makanan untuk persediaan selama satu tahun atau setelah tahun bagi keluarganya atau?\" Ma'mar berkata; Ia tidak menjawabnya. Kemudian aku pun menyebutkan hadits; Telah menceritakan kepada kami [Ibnu Syihab Az Zuhri] dari [Malik bin Aus] dari [Umar] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam menjual pohon kurma Bani Nadlir dan menyimpan makanan untuk persediaan selama setahun bagi keluarganya."},"4634":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي مَالِكُ بْنُ أَوْسِ بْنِ الْحَدَثَانِ وَكَانَ مُحَمَّدُ بْنُ جُبَيْرِ بْنِ مُطْعِمٍذَكَرَ لِي ذِكْرًا مِنْ حَدِيثِهِ فَانْطَلَقْتُ حَتَّى دَخَلْتُ عَلَى مَالِكِ بْنِ أَوْسٍ فَسَأَلْتُهُ فَقَالَ مَالِكٌ انْطَلَقْتُ حَتَّى أَدْخُلَ عَلَى عُمَرَ إِذْ أَتَاهُ حَاجِبُهُ يَرْفَا فَقَالَ هَلْ لَكَ فِي عُثْمَانَ وَعَبْدِ الرَّحْمَنِ وَالزُّبَيْرِ وَسَعْدٍ يَسْتَأْذِنُونَ قَالَ نَعَمْ فَأَذِنَ لَهُمْ قَالَ فَدَخَلُوا وَسَلَّمُوا فَجَلَسُوا ثُمَّ لَبِثَ يَرْفَا قَلِيلًا فَقَالَ لِعُمَرَ هَلْ لَكَ فِي عَلِيٍّ وَعَبَّاسٍ قَالَ نَعَمْ فَأَذِنَ لَهُمَا فَلَمَّا دَخَلَا سَلَّمَا وَجَلَسَا فَقَالَ عَبَّاسٌ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنِي وَبَيْنَ هَذَا فَقَالَ الرَّهْطُ عُثْمَانُ وَأَصْحَابُهُ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنَهُمَا وَأَرِحْ أَحَدَهُمَا مِنْ الْآخَرِ فَقَالَ عُمَرُ اتَّئِدُوا أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ هَلْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ يُرِيدُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفْسَهُ قَالَ الرَّهْطُ قَدْ قَالَ ذَلِكَ فَأَقْبَلَ عُمَرُ عَلَى عَلِيٍّ وَعَبَّاسٍ فَقَالَ أَنْشُدُكُمَا بِاللَّهِ هَلْ تَعْلَمَانِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذَلِكَ قَالَا قَدْ قَالَ ذَلِكَ قَالَ عُمَرُ فَإِنِّي أُحَدِّثُكُمْ عَنْ هَذَا الْأَمْرِ إِنَّ اللَّهَ كَانَ قَدْ خَصَّ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْمَالِ بِشَيْءٍ لَمْ يُعْطِهِ أَحَدًا غَيْرَهُ قَالَ اللَّهُ{ مَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِنْهُمْ فَمَا أَوْجَفْتُمْ عَلَيْهِ مِنْ خَيْلٍ إِلَى قَوْلِهِ قَدِيرٌ }فَكَانَتْ هَذِهِ خَالِصَةً لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ مَا احْتَازَهَا دُونَكُمْ وَلَا اسْتَأْثَرَ بِهَا عَلَيْكُمْ لَقَدْ أَعْطَاكُمُوهَا وَبَثَّهَا فِيكُمْ حَتَّى بَقِيَ مِنْهَا هَذَا الْمَالُ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْفِقُ عَلَى أَهْلِهِ نَفَقَةَ سَنَتِهِمْ مِنْ هَذَا الْمَالِ ثُمَّ يَأْخُذُ مَا بَقِيَ فَيَجْعَلُهُ مَجْعَلَ مَالِ اللَّهِ فَعَمِلَ بِذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيَاتَهُ أَنْشُدُكُمْ بِاللَّهِ هَلْ تَعْلَمُونَ ذَلِكَ قَالُوا نَعَمْ قَالَ لِعَلِيٍّ وَعَبَّاسٍ أَنْشُدُكُمَا بِاللَّهِ هَلْ تَعْلَمَانِ ذَلِكَ قَالَا نَعَمْ ثُمَّ تَوَفَّى اللَّهُ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ أَنَا وَلِيُّ رَسُولِ اللَّهِ فَقَبَضَهَا أَبُو بَكْرٍ يَعْمَلُ فِيهَا بِمَا عَمِلَ بِهِ فِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْتُمَا حِينَئِذٍ وَأَقْبَلَ عَلَى عَلِيٍّ وَعَبَّاسٍ تَزْعُمَانِ أَنَّ أَبَا بَكْرٍ كَذَا وَكَذَا وَاللَّهُ يَعْلَمُ أَنَّهُ فِيهَا صَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّ ثُمَّ تَوَفَّى اللَّهُ أَبَا بَكْرٍ فَقُلْتُ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ فَقَبَضْتُهَا سَنَتَيْنِ أَعْمَلُ فِيهَا بِمَا عَمِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ ثُمَّ جِئْتُمَانِي وَكَلِمَتُكُمَا وَاحِدَةٌ وَأَمْرُكُمَا جَمِيعٌ جِئْتَنِي تَسْأَلُنِي نَصِيبَكَ مِنْ ابْنِ أَخِيكَ وَأَتَى هَذَا يَسْأَلُنِي نَصِيبَ امْرَأَتِهِ مِنْ أَبِيهَا فَقُلْتُ إِنْ شِئْتُمَا دَفَعْتُهُ إِلَيْكُمَا عَلَى أَنَّ عَلَيْكُمَا عَهْدَ اللَّهِ وَمِيثَاقَهُ لَتَعْمَلَانِ فِيهَا بِمَا عَمِلَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِمَا عَمِلَ بِهِ فِيهَا أَبُو بَكْرٍ وَبِمَا عَمِلْتُ بِهِ فِيهَا مُنْذُ وُلِّيتُهَا وَإِلَّا فَلَا تُكَلِّمَانِي فِيهَا فَقُلْتُمَا ادْفَعْهَا إِلَيْنَا بِذَلِكَ فَدَفَعْتُهَا إِلَيْكُمَا بِذَلِكَ أَنْشُدُكُمْ بِاللَّهِ هَلْ دَفَعْتُهَا إِلَيْهِمَا بِذَلِكَ فَقَالَ الرَّهْطُ نَعَمْ قَالَ فَأَقْبَلَ عَلَى عَلِيٍّ وَعَبَّاسٍ فَقَالَ أَنْشُدُكُمَا بِاللَّهِ هَلْ دَفَعْتُهَا إِلَيْكُمَا بِذَلِكَ قَالَا نَعَمْ قَالَ أَفَتَلْتَمِسَانِ مِنِّي قَضَاءً غَيْرَ ذَلِكَ فَوَالَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ لَا أَقْضِي فِيهَا قَضَاءً غَيْرَ ذَلِكَ حَتَّى تَقُومَ السَّاعَةُ فَإِنْ عَجَزْتُمَا عَنْهَا فَادْفَعَاهَا فَأَنَا أَكْفِيَكُمَاهَا","id":"Telah menceritakan kepada kami [Sa'id bin Ufair] ia berkata; Telah menceritakan kepadaku [Al Laits] ia berkata; Telah menceritakan kepadaku [Uqail] dari [Ibnu Syihab] ia berkata; Telah mengabarkan kepadaku [Malik bin Aus bin Al Hadatsan] dan bahwasanya [Muhammad bin Jubair bin Muth'im] menyebutkan suatu hadits padaku. Maka aku pun pergi menemui Malik bin Aus dan bertanya padanya. Maka [Malik] berkata; Aku pergi hingga bertemu dengan [Umar]. Lalu pelayannya pun menemuinya dan berkata pada Umar, \"Apakah Anda mengizinkan [Utsman], [Abdurrahman], [Az Zubair] dan [Sa'dari] untuk masuk?\" Ia menjawab, \"Ya.\" Lalu sang pelayan mengizinkan mereka masuk dan mereka pun mengucapkan salam kemudian duduk. Sang pelayan kembali menutup dan berkata pada Umar, \"Apakah Anda juga mengizinkan pada [Ali] dan [Abbas]\" Umar menjawab, \"Ya.\" Pelayan itu pun mengizinkan keduanya masuk. Dan ketika kedua masuk, keduanya pun mengucapkan salam dan duduk. Kemudian Abbas berkata, \"Wahai Amirul Mukminin, putuskanlah perkara antara aku dan orang ini.\" lalu Utsman berserta kelompoknya berkata, \"Wahai Amirul Mukminin, berilah keputusan antara mereka berdua dan istirahatkanlah yang satu dari yang lainnya.\" Maka Umar berkata, \"Aku menyumpah kalian dengan nama Allah yang dengan-Nya berdirilah langit dan bumi, sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sesungguhnya kami tidaklah mewariskan. Dan apa yang kami tinggalkan adalah harta sedekah.' Yang dimaksud oleh Rasulullah shallallahu 'alaihi wasallam adalah dirinya sendiri. Ar Rahth (sekelompok orang itu) pun berkata, \"Sesungguhnya beliau telah mengatakan hal itu.\" Kemudian Umar menghadap ke arah Ali dan dan Abbas dan berkata, \"Aku menyumpahkah kalian dengan nama Allah, apakah kalian berdua tahu bahwa Rasulullah shallallahu 'alaihi wasallam telah mengatakan hal itu?\" keduanya menjawab, \"Ya, beliau telah mengatakan hal itu.\" Selanjutnya Umar berkata, \"Aku menceritakan kepada kalian mengenai perkara ini. Sesungguhnya Allah telah mengkhususkan untuk Rasulullah shallallahu 'alaihi wasallam di dalam harta ini dengan sesuatu yang belum pernah Dia berikan kepada orang lain selainnya. Allah berfirman: 'MAA AFAA`ALLAHU 'ALAA RASUULIHI MINHUM FAMAA AUJAFTUM 'ALAIHI MIN KHAIL.' (QS. Alhasyr. 6).Hingga firman-Nya: 'QADIIR.' Maka harta ini adalah murni untuk diri Rasulullah shallallahu 'alaihi wasallam. Dan demi Allah, Rasulullah Shallallahu'alaihiwasallam dahulu tidak pernah memberikannya kepada selain kalian (ahlu bait) dan tidak pula beliau lebih mementingkan dirinya sendiri daripadsa kalian. Sesungguhnya beliau telah memberikannya dan menyerahkannya pada kalian, hingga darinya tersisalah harta ini. Dulu, Rasulullah shallallahu 'alaihi wasallam memberi nafkah tahunan kepada keluarganya dari harta ini, kemudian sisanya beliau ambil dan menjadikannya sebagai harta Allah. Begitulah Rasulullah shallallahu 'alaihi wasallam mengisi menjalani kehidupannya. Aku menyumpah kalian dengan nama Allah, apakah kalian mengetahui hal itu?\" Mereka menjawab, \"Ya.\" Umar kemudian berkata kepada Ali dan Abbas, \"Aku menyumpah kalian dengan nama Allah, apakah kalian juga tahu akan hal itu?\" keduanya menjawab: \"Ya.\" Umar melanjutkan, \"Kemudian Nabi shallallahu 'alaihi wasallam wafat dan berkatalah Abu Bakar, 'Aku adalah wali Rasulullah.' Maka Abu Bakar pun menanganinya. Ia mengelolanya sebagaimana yang diperbuat oleh Rasulullah shallallahu 'alaihi wasallam. Dan ada pun kalian berdua -Umar menghadap ke arah Ali dan Abbas- menyangka bahwa Abu Bakar adalah begini dan begitu. Demi Allah, sesungguhnya dala hal itu Abu Bakar adalah telah bertindak benar, berbuat baik dan juga rasyid berada di atas kebenaran. Kemudian setelah Abu Bakar Wafat, aku pun berkata, 'Aku adalah wali Rasulullah shallallahu 'alaihi wasallam dan Abu bakar.' Sehingga aku pun menanganinya selama dua tahun. Aku mengelolanya sebagaimana yang telah diperbuat oleh Rasulullah shallallahu 'alaihi wasallam dan Abu Bakar. Kemudian kalian berdua bersepakat mendatangiku. Kamu (Ibn Abbas) mendatangiku untuk meminta bagianmu dari anak saudaramu (maksudnya Rasulullah), dan yang ini (Ali) juga mendatangiku untuk meminta bagian isterinya dari jalur bapaknya (maksudnya Rasulullah). Maka aku katakan, 'Jika kalian mau, maka aku akan menyerahkannya pada kalian berdua dengan satu catatan, bahwa di atas kalian berdua terdapat janji Allah. Kalian berdua benar-benar sadar akan apa yang telah diperbuat oleh Rasulullah shallallahu 'alaihi wasallam di dalamnya, dan juga apa yang telah diperbuat oleh Abu Bakar serta apa yang aku perbuat sejak aku menanganinya. Kalau tidak, maka janganlah kalian berdua berkata lagi padaku tentang harta itu, 'Berikanlah harta itu pada kami.' Sehingga aku akan menyerahkan harta itu pada kalian berdua. Aku menyumpah kalian berdua dengan nama Allah, apakakah aku menyerahkannya pada keduanya?\" sekelompok orang itu pun menjawab, \"Ya.\" Kemudian Umar berpaling ke arah Ali dan Abbas seraya bertanya, \"Aku menyumpah kalian dengan nama Allah, apakah aku menyerahkannya pada kalian berdua?\" keduanya menjawab, \"Ya.\" Umar berkata lagi, \" Apakah kalian berdua memintaku keputusan selain yang telah kuutarakan tadi? Demi Dzat yang dengan seijin-Nya langit dan bumi tegak, saya tidak akan memutuskan peninggalan Rasulullah tersebut dengan keputusan lain hingga kiamat tiba, seandainya kamu berdua tidak mampu mengelolanya, tolong kalian berdua serahkan, dan saya yang akan menggantikan kalian berdua.\""},"4635":{"ar":"حَدَّثَنَا ابْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْجَاءَتْ هِنْدٌ بِنْتُ عُتْبَةَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ أَبَا سُفْيَانَ رَجُلٌ مِسِّيكٌ فَهَلْ عَلَيَّ حَرَجٌ أَنْ أُطْعِمَ مِنْ الَّذِي لَهُ عِيَالَنَا قَالَ لَا إِلَّا بِالْمَعْرُوفِ","id":"Telah menceritakan kepada kami [Ibnu Muqatil] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Yunus] dari [Ibnu Syihab] Telah mengabarkan kepadaku [Urwah] bahwa [Aisyah] radliallahu 'anha berkata; Hindun binti Utbah datang seraya berkata, \"Wahai Rasulullah, sesungguhnya Abu Shufyan adalah seorang laki-laki yang pelit. Berdosakah aku, bila aku memberi makan keluarga kami dari harta benda miliknya?\" beliau menjawab: \"Tidak. Dan kamu mengambilnya secara wajar.\""},"4636":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَنْفَقَتْ الْمَرْأَةُ مِنْ كَسْبِ زَوْجِهَا عَنْ غَيْرِ أَمْرِهِ فَلَهُ نِصْفُ أَجْرِهِ","id":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Hammam] ia berkata; Aku mendengar [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika seorang wanita menginfakkan sesuatu dari hasil jerih payah suaminya tanpa seizinnya, maka bagi suaminya itu adalah setengah pahala.\""},"4637":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ قَالَ حَدَّثَنِي الْحَكَمُ عَنْ ابْنِ أَبِي لَيْلَى حَدَّثَنَا عَلِيٌّأَنَّ فَاطِمَةَ عَلَيْهِمَا السَّلَام أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَشْكُو إِلَيْهِ مَا تَلْقَى فِي يَدِهَا مِنْ الرَّحَى وَبَلَغَهَا أَنَّهُ جَاءَهُ رَقِيقٌ فَلَمْ تُصَادِفْهُ فَذَكَرَتْ ذَلِكَ لِعَائِشَةَ فَلَمَّا جَاءَ أَخْبَرَتْهُ عَائِشَةُ قَالَ فَجَاءَنَا وَقَدْ أَخَذْنَا مَضَاجِعَنَا فَذَهَبْنَا نَقُومُ فَقَالَ عَلَى مَكَانِكُمَا فَجَاءَ فَقَعَدَ بَيْنِي وَبَيْنَهَا حَتَّى وَجَدْتُ بَرْدَ قَدَمَيْهِ عَلَى بَطْنِي فَقَالَ أَلَا أَدُلُّكُمَا عَلَى خَيْرٍ مِمَّا سَأَلْتُمَا إِذَا أَخَذْتُمَا مَضَاجِعَكُمَا أَوْ أَوَيْتُمَا إِلَى فِرَاشِكُمَا فَسَبِّحَا ثَلَاثًا وَثَلَاثِينَ وَاحْمَدَا ثَلَاثًا وَثَلَاثِينَ وَكَبِّرَا أَرْبَعًا وَثَلَاثِينَ فَهُوَ خَيْرٌ لَكُمَا مِنْ خَادِمٍ","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Yahya] dari [Syu'bah] ia berkata; Telah menceritakan kepadaku [Al Hakam] dari [Ibnu Abu Laila] Telah menceritakan kepada kami [Ali] bahwa Fathimah 'Alaihimas Salam datang menemui Nabi shallallahu 'alaihi wasallam mengadukan tangannya yang mengeras karena menggiling. Fathimah pernah mendengar kabar bahwa nabi pernah mendapatkan budak, sayang, kebetulan ia malah nggak kesana. Fathimah pun menuturkan hal itu pada Aisyah. Ketika Rasulullah shallallahu 'alaihi wasallam datang, maka Aisyah pun menuturkannya. Kemudian beliau mendatangi kami yang pada saat itu kami sudah bersiap-siap untuk tidur, maka kami pun segera beranjak. Beliau bersabda: \"Tetaplah pada tempat kalian.\" Beliau datang lalu duduk tepat antara aku dan Fathimah hingga aku merasakan kesejukan kedua kakinya. Dan beliau bersabda: \"Maukah aku tunjukkan pada sesuatu yang lebih baik daripada apa yang kalian minta? Bila kalian hendak beranjak ke tempat tidur, maka bertasbihlah tiga puluh tiga kali dan bertahmidlah tiga puluh tiga kali serta bertakbir tiga puluh empat kali. Hal itu adalah lebih baik bagi kalian daripada seorang pembantu.\""},"4638":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ سَمِعَ مُجَاهِدًا سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ أَبِي لَيْلَى يُحَدِّثُ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍأَنَّ فَاطِمَةَ عَلَيْهَا السَّلَام أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسْأَلُهُ خَادِمًا فَقَالَ أَلَا أُخْبِرُكِ مَا هُوَ خَيْرٌ لَكِ مِنْهُ تُسَبِّحِينَ اللَّهَ عِنْدَ مَنَامِكِ ثَلَاثًا وَثَلَاثِينَ وَتَحْمَدِينَ اللَّهَ ثَلَاثًا وَثَلَاثِينَ وَتُكَبِّرِينَ اللَّهَ أَرْبَعًا وَثَلَاثِينَ ثُمَّ قَالَ سُفْيَانُ إِحْدَاهُنَّ أَرْبَعٌ وَثَلَاثُونَ فَمَا تَرَكْتُهَا بَعْدُ قِيلَ وَلَا لَيْلَةَ صِفِّينَ قَالَ وَلَا لَيْلَةَ صِفِّينَ","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Ubaidulah bin Abu Yazid] bahwa ia mendengar [Mujahid] berkata; Aku mendengar [Abdurrahman bin Abu Laila] menceritakan dari [Ali bin Abu Thalib] bahwasanya; Fathimah Alaihas Salam datang kepada Nabi shallallahu 'alaihi wasallam untuk meminta Khadim (seorang pembantu), maka beliau bersabda: \"Maukah kamu aku beritahukan sesuatu yang lebih baik darinya? Bertasbihlah kepada Allah saat kamu hendak tidur sebanyak tiga puluh tiga kali, kemudian bertahmid tiga puluh tiga kali dan bertakbir sebanyak tiga puluh empat kali.\" Sufyan berkata; \"Satu diantaranya adalah sebanyak tiga puluh empat kali, maka setelah itu aku tidak pernah meninggalkannya.\" Di tanyakan kepadanya, \"Meskipun pada malam perang Shiffin?\" Ia menjawab, \"Meskipun pada malam perang Shiffin.\""},"4639":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ بْنِ عُتَيْبَةَ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ سَأَلْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَامَا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ فِي الْبَيْتِ قَالَتْ كَانَ يَكُونُ فِي مِهْنَةِ أَهْلِهِ فَإِذَا سَمِعَ الْأَذَانَ خَرَجَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ar'arah] Telah menceritakan kepada kami [Syu'bah] dari [Al Hakam bin Utbah] dari [Ibrahim] dari [Al Aswad bin Yazid] ia berkata; Aku bertanya kepada [Aisyah] radliallahu 'anha mengenai apa saja yang dilakukan Nabi shallallahu 'alaihi wasallam di rumah. Maka ia pun menjawab, \"Beliau turut membantu pekerjaan keluarganya, dan bila beliau mendengar adzan, beliau pun keluar.\""},"4640":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَأَنَّ هِنْدَ بِنْتَ عُتْبَةَ قَالَتْ يَا رَسُولَ اللَّهِ إِنَّ أَبَا سُفْيَانَ رَجُلٌ شَحِيحٌ وَلَيْسَ يُعْطِينِي مَا يَكْفِينِي وَوَلَدِي إِلَّا مَا أَخَذْتُ مِنْهُ وَهُوَ لَا يَعْلَمُ فَقَالَ خُذِي مَا يَكْفِيكِ وَوَلَدَكِ بِالْمَعْرُوفِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Yahya] dari [Hisyam] ia berkata; Telah mengabarkan kepadaku [bapakku] dari [Aisyah] bahwa Hindu binti Utbah berkata, \"Wahai Abu Sufyan adalah seorang laki-laki yang pelit. Ia tidak memberikan kecukupan nafkah padaku dan anakku, kecuali jika aku mengambil dari hartanya dengan tanpa sepengetahuannya.\" Maka beliau bersabda: \"Ambillah dari hartanya sekadar untuk memenuhi kebutuhanmu dan juga anakmu.\""},"4641":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ وَأَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ نِسَاءٍ رَكِبْنَ الْإِبِلَ نِسَاءُ قُرَيْشٍ وَقَالَ الْآخَرُ صَالِحُ نِسَاءِ قُرَيْشٍ أَحْنَاهُ عَلَى وَلَدٍ فِي صِغَرِهِ وَأَرْعَاهُ عَلَى زَوْجٍ فِي ذَاتِ يَدِهِوَيُذْكَرُ عَنْ مُعَاوِيَةَ وَابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Ibnu Thawus] dari [bapaknya] dan [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik wanita yang mengendarai Unta adalah wanita Quraisy.\" Dan yang lain berkata: \"Sebaik-baik wanita Quraisy adalah sifat lembutnya terhadap anak di masa kecilnya, dan kepandaiannya menjaga harta suaminya.\" Dan sisebutkan pula dari Mu'awiyah dan Ibnu Abbas dari Nabi shallallahu 'alaihi wasallam."},"4642":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَبْدُ الْمَلِكِ بْنُ مَيْسَرَةَ قَالَ سَمِعْتُ زَيْدَ بْنَ وَهْبٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ ق��الَآتَى إِلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُلَّةً سِيَرَاءَ فَلَبِسْتُهَا فَرَأَيْتُ الْغَضَبَ فِي وَجْهِهِ فَشَقَّقْتُهَا بَيْنَ نِسَائِي","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] Telah menceritakan kepada kami [Syu'bah] ia berkata; Telah mengabarkan kepadaku [Abdul Malik bin Maisarah] ia berkata; Aku mendengar [Zaid bin Wahb] dari [Ali] radliallahu 'anhu, ia berkata; Nabi shallallahu 'alaihi wasallam memberikan kain sutera padaku, maka aku pun memakainya. Lalu aku melihat kemarahan pada wajah beliau, maka aku pun segera memberikannya kepada isteri-isteriku."},"4643":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرٍو عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَهَلَكَ أَبِي وَتَرَكَ سَبْعَ بَنَاتٍ أَوْ تِسْعَ بَنَاتٍ فَتَزَوَّجْتُ امْرَأَةً ثَيِّبًا فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزَوَّجْتَ يَا جَابِرُ فَقُلْتُ نَعَمْ فَقَالَ بِكْرًا أَمْ ثَيِّبًا قُلْتُ بَلْ ثَيِّبًا قَالَ فَهَلَّا جَارِيَةً تُلَاعِبُهَا وَتُلَاعِبُكَ وَتُضَاحِكُهَا وَتُضَاحِكُكَ قَالَ فَقُلْتُ لَهُ إِنَّ عَبْدَ اللَّهِ هَلَكَ وَتَرَكَ بَنَاتٍ وَإِنِّي كَرِهْتُ أَنْ أَجِيئَهُنَّ بِمِثْلِهِنَّ فَتَزَوَّجْتُ امْرَأَةً تَقُومُ عَلَيْهِنَّ وَتُصْلِحُهُنَّ فَقَالَ بَارَكَ اللَّهُ لَكَ أَوْ قَالَ خَيْرًا","id":"Telah menceritakan kepada kami [Musaddad] Telah menceritakan kepada kami [Hammad bin Zaid] dari [Amru] dari [Jabir bin Abdullah] radliallahu 'anhuma, ia berkata, \"Bapakku wafat dan ia meninggalkan tujuh orang anak wanita, maka aku pun menikah dengan seorang janda.\" Maka Rasulullah shallallahu 'alaihi wasallam bertanya padaku: \"Apakah kamu sudah menikah wahai Jabir?\" Aku menjawab, \"Ya.\" Beliau bertanya lagi: \"Dengan gadits ataukah janda?\" aku menjawab, \"Dengan janda.\" Beliau bersabda: \"Kenapa tidak dengan gadis sehingga kamu dapat bermain-main dengannya dan ia pun dapat bermain-main denganmu. Kamu dapat bergurau dengannya dan ia pun dapat bergurau denganmu?.\" Maka aku pun berkata pada beliau, \"Sesungguhnya Abdullah meninggal, dan ia meninggalkan banyak anak wanita. Dan aku tak suka bila melahirkan anak-anak (yang tak terurus) seperti mereka. Karena itulah, aku menikahi seorang wanita agar dapat mengurus mereka.\" Maka beliau pun bersabda: \"Semoga Allah memberi keberkahan padamu.\" Atau beliau bersabda dengan kebaikan."},"4644":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَقَالَ هَلَكْتُ قَالَ وَلِمَ قَالَ وَقَعْتُ عَلَى أَهْلِي فِي رَمَضَانَ قَالَ فَأَعْتِقْ رَقَبَةً قَالَ لَيْسَ عِنْدِي قَالَ فَصُمْ شَهْرَيْنِ مُتَتَابِعَيْنِ قَالَ لَا أَسْتَطِيعُ قَالَ فَأَطْعِمْ سِتِّينَ مِسْكِينًا قَالَ لَا أَجِدُ فَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَقٍ فِيهِ تَمْرٌ فَقَالَ أَيْنَ السَّائِلُ قَالَ هَا أَنَا ذَا قَالَ تَصَدَّقْ بِهَذَا قَالَ عَلَى أَحْوَجَ مِنَّا يَا رَسُولَ اللَّهِ فَوَالَّذِي بَعَثَكَ بِالْحَقِّ مَا بَيْنَ لَابَتَيْهَا أَهْلُ بَيْتٍ أَحْوَجُ مِنَّا فَضَحِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَدَتْ أَنْيَابُهُ قَالَ فَأَنْتُمْ إِذًا","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] Telah menceritakan kepada kami [Ibrahim bin Sa'd] Telah menceritakan kepada kami [Ibnu Syihab] dari [Humaid bin Abdurrahman] dari [Abu Hurairah] radliallahu 'anhu, ia berkata; Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Aku telah binasa.\" Beliau bertanya: \"Karena apa?\" laki-laki itu berkata, \"Aku telah menggauli isteriku pada siang hari bulan Ramadlan.\" Maka beliau bersabda: \"Kalau begitu, merdekakanlah seorang budak.\" Laki-laki itu berkata, \"Aku tidak punya.\" Beliau bersabda lagi: \"Kalau tak punya, maka berpuasalah dua bulan berturut-turut.\" Laki-laki itu menjawab, \"Aku tak sanggup.\" Beliau bersabda: \"Jika tak mampu, maka berilah makan kepada enam puluh orang miskin.\" Laki-laki itu berkata, \"Aku tidak mendapati sesuatu.\" Sesudah itu, Nabi shallallahu 'alaihi wasallam diberi keranjang berisi kurma. Maka beliau pun bertanya: \"Dimanakah orang yang bertanya tadi?\" laki-laki itu menjawab, \"Ya, ini aku.\" Beliau bersabda: \"Bersedekahlah dengan ini.\" laki-laki itu berkata, \"Apakah ada orang yang paling membutuhkannya dari pada kami wahai Rasulullah? Maka demi Dzat yang telah mengutusmu dengan membawa kebenaran, tidak ada ahlu bait di antara dua bukit itu yang lebih membutuhkannya dari pada kami.\" Akhirnya Nabi shallallahu 'alaihi wasallam tertawa hingga gigi gerahannya terlihat. Beliau bersabda: \"Kalau begitu, sedekahkanlah kepada keluargamu.\""},"4645":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ أَخْبَرَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قُلْتُيَا رَسُولَ اللَّهِ هَلْ لِي مِنْ أَجْرٍ فِي بَنِي أَبِي سَلَمَةَ أَنْ أُنْفِقَ عَلَيْهِمْ وَلَسْتُ بِتَارِكَتِهِمْ هَكَذَا وَهَكَذَا إِنَّمَا هُمْ بَنِيَّ قَالَ نَعَمْ لَكِ أَجْرُ مَا أَنْفَقْتِ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] Telah menceritakan kepada kami [Wuhaib] Telah mengabarkan kepada kami [Hisyam] dari [bapaknya] dari [Zainab binti Abu Salamah] dari [Ummu Salamah], Aku bertanya, \"Wahai Rasulullah, apakah aku mendapatkan pahala bila aku berinfak kepada anak-anak Abu Salamah, dan aku tidak meninggalkan mereka dalam banyak hal. Sesungguhnya mereka adalah anak-anakku.\" Beliau menjawab: \"Ya, kamu akan mendapatkan pahala atas apa yang kamu nafkahkan pada mereka.\""},"4646":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاقَالَتْ هِنْدُ يَا رَسُولَ اللَّهِ إِنَّ أَبَا سُفْيَانَ رَجُلٌ شَحِيحٌ فَهَلْ عَلَيَّ جُنَاحٌ أَنْ آخُذَ مِنْ مَالِهِ مَا يَكْفِينِي وَبَنِيَّ قَالَ خُذِي بِالْمَعْرُوفِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Sufyan] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] radliallahu 'anha, bahwa Hindun berkata, \"Wahai Rasulullah, sesungguhnya Abu Sufyan adalah seorang laki-laki yang pelit. Maka apakah aku berdosa bila mengambil sesuatu dari hartanya yang dapat menutupi kebutuhanku dan juga anakku?\" beliau menjawab: \"Ambillah dengan cara yang wajar.\""},"4647":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُؤْتَى بِالرَّجُلِ الْمُتَوَفَّى عَلَيْهِ الدَّيْنُ فَيَسْأَلُ هَلْ تَرَكَ لِدَيْنِهِ فَضْلًا فَإِنْ حُدِّثَ أَنَّهُ تَرَكَ وَفَاءً صَلَّى وَإِلَّا قَالَ لِلْمُسْلِمِينَ صَلُّوا عَلَى صَاحِبِكُمْ فَلَمَّا فَتَحَ اللَّهُ عَلَيْهِ الْفُتُوحَ قَالَ أَنَا أَوْلَى بِالْمُؤْمِنِينَ مِنْ أَنْفُسِهِمْ فَمَنْ تُوُفِّيَ مِنْ الْمُؤْمِنِينَ فَتَرَكَ دَيْنًا فَعَلَيَّ قَضَاؤُهُ وَمَنْ تَرَكَ مَالًا فَلِوَرَثَتِهِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] dari [Abu Salamah] dari [Abu Hurairah] radliallahu 'anhu, bahwa suatu ketika, pernah didatangkan kepada Rasulullah shallallahu 'alaihi wasallam seorang laki-laki yang meninggal dalam keadaan memiliki hutang. Maka beliau pun menanyakan, apakah laki-laki itu meninggalkan sesuatu untuk membayar hutangnya. Bila diberitakan bahwa bahwa laki-laki itu meninggalkan sesuatu yang dapat melunasi hutangnya, maka beliau menshalatinya. Namun jika tidak, maka beliau bersabda kepada kaum muslimin: \"Shalatilah sahabat kalian ini.\" Ketika Allah telah memberikan kemenangan-kemenangan beliau bersabda: \"Aku adalah lebih utama (lebih berhak) melayani kaum mukminin daripada diri mereka sendiri. Barangsiapa yang meninggal dari kaum mukminin dengan meninggalkan hutang, maka atas dirikulah pelunasannya. Dan barangsiapa yang meninggalkan harta, maka harta itu adalah untuk ahli warisnya.\""},"4648":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ أَنَّ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ أَخْبَرَتْهُ أَنَّ أُمَّ حَبِيبَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ قُلْتُيَا رَسُولَ اللَّهِ انْكِحْ أُخْتِي بِنْتَ أَبِي سُفْيَانَ قَالَ وَتُحِبِّينَ ذَلِكِ قُلْتُ نَعَمْ لَسْتُ لَكَ بِمُخْلِيَةٍ وَأَحَبُّ مَنْ شَارَكَنِي فِي الْخَيْرِ أُخْتِي فَقَالَ إِنَّ ذَلِكِ لَا يَحِلُّ لِي فَقُلْتُ يَا رَسُولَ اللَّهِ فَوَاللَّهِ إِنَّا نَتَحَدَّثُ أَنَّكَ تُرِيدُ أَنْ تَنْكِحَ دُرَّةَ بِنْتَ أَبِي سَلَمَةَ فَقَالَ بِنْتَ أُمِّ سَلَمَةَ فَقُلْتُ نَعَمْ قَالَ فَوَاللَّهِ لَوْ لَمْ تَكُنْ رَبِيبَتِي فِي حَجْرِي مَا حَلَّتْ لِي إِنَّهَا بِنْتُ أَخِي مِنْ الرَّضَاعَةِ أَرْضَعَتْنِي وَأَبَا سَلَمَةَ ثُوَيْبَةُ فَلَا تَعْرِضْنَ عَلَيَّ بَنَاتِكُنَّ وَلَا أَخَوَاتِكُنَّوَقَالَ شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ عُرْوَةُ ثُوَيْبَةُ أَعْتَقَهَا أَبُو لَهَبٍ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] Telah mengabarkan kepadaku [Urwah] bahwa [Zainab binti Abu Salamah] Telah mengabarkan kepadanya bahwa [Ummu Habibah] Isteri Nabi shallallahu 'alaihi wasallam berkata; Aku pernah berkata, \"Wahai Rasulullah, nikahilah saudara perempuanku binti Abu Sufyan.\"Beliau bertanya: \"Apakah kamu menyukai hal itu?\" aku menjawab, \"Ya, aku tak ingin jika kebaikanmu kunikmati sendiri. Aku ingin jika kebaikanmu juga sama-sama dirasakan oleh saudariku.\" Beliau pun bersabda: \"Sesungguhnya hal itu tidaklah halal bagiku.\" Aku berkata lagi, \"Wahai Rasulullah, demi Allah, sesungguhnya kami pernah ngobrol-ngobrol bahwa Anda ingin menikahi Durrah binti Abu Salamah!.\" Beliau balik bertanya: \"Binti Abu Salamah?\" aku menjawb, \"Ya.\" Beliau bersabda: \"Demi Allah, sekiranya ia bukan termasuk anak tiri dalam asuhanku, ia pun tak halal bagiku. Sesungguhnya ia adalah anak perempuan dari saudara sesusuanku. Tsuwaibah telah menyusuiku dan juga Abu Salamah. Karena itu, janganlah kalian menawarkan anak-anak dan saudara-saudara perempuan kalian padaku.\" Syu'aib berkata; Dari Az Zuhri, bahwa telah berkata Urwah; Yang membebaskan Tsuwaibah adalah Abu Lahab."},"4649":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَطْعِمُوا الْجَائِعَ وَعُودُوا الْمَرِيضَ وَفُكُّوا الْعَانِيَقَالَ سُفْيَانُوَالْعَانِي الْأَسِيرُ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah mengabarkan kepada kami [Sufyan] dari [Manshur] dari [Abu Wa`il] dari [Abu Musa Al Asy'ari] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Berilah makan kepada orang yang kelaparan, jenguklah orang sakit dan bebaskanlah Al 'Ani.\" Sufyan berkata; \"Al 'Ani adalah Al Asir (tawanan).\""},"4650":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ عِيسَى حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَمَا شَبِعَ آلُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ طَعَامٍ ثَلَاثَةَ أَيَّامٍ حَتَّى قُبِضَ","id":"Telah menceritakan kepada kami [Yusuf bin Isa] Telah menceritakan kepada kami [Muhamamd bin Fudlail] dari [bapaknya] dari [Abu Hazim] dari [Abu Hurairah] ia berkata; \"Keluarga Nabi Muhammad shallallahu 'alaihi wasallam tidak pernah kenyang dengan makanan selama tiga hari, hingga beliau wafat.\""},"4651":{"ar":"وَعَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَأَصَابَنِي جَهْدٌ شَدِيدٌ فَلَقِيتُ عُمَرَ بْنَ الْخَطَّابِ فَاسْتَقْرَأْتُهُ آيَةً مِنْ كِتَابِ اللَّهِ فَدَخَلَ دَارَهُ وَفَتَحَهَا عَلَيَّ فَمَشَيْتُ غَيْرَ بَعِيدٍ فَخَرَرْتُ لِوَجْهِي مِنْ الْجَهْدِ وَالْجُوعِ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ عَلَى رَأْسِي فَقَالَ يَا أَبَا هُرَيْرَةَ فَقُلْتُ لَبَّيْكَ رَسُولَ اللَّهِ وَسَعْ��َيْكَ فَأَخَذَ بِيَدِي فَأَقَامَنِي وَعَرَفَ الَّذِي بِي فَانْطَلَقَ بِي إِلَى رَحْلِهِ فَأَمَرَ لِي بِعُسٍّ مِنْ لَبَنٍ فَشَرِبْتُ مِنْهُ ثُمَّ قَالَ عُدْ يَا أَبَا هِرٍّ فَعُدْتُ فَشَرِبْتُ ثُمَّ قَالَ عُدْ فَعُدْتُ فَشَرِبْتُ حَتَّى اسْتَوَى بَطْنِي فَصَارَ كَالْقِدْحِ قَالَ فَلَقِيتُ عُمَرَ وَذَكَرْتُ لَهُ الَّذِي كَانَ مِنْ أَمْرِي وَقُلْتُ لَهُ فَوَلَّى اللَّهُ ذَلِكَ مَنْ كَانَ أَحَقَّ بِهِ مِنْكَ يَا عُمَرُ وَاللَّهِ لَقَدْ اسْتَقْرَأْتُكَ الْآيَةَ وَلَأَنَا أَقْرَأُ لَهَا مِنْكَ قَالَ عُمَرُ وَاللَّهِ لَأَنْ أَكُونَ أَدْخَلْتُكَ أَحَبُّ إِلَيَّ مِنْ أَنْ يَكُونَ لِي مِثْلُ حُمْرِ النَّعَمِ","id":"Dan (masih dari jalur periwayatan yang sama dengan hadits sebelumnya) dari [Abu Hazim] dari [Abu Hurairah] ia berkata; Aku pernah tertimpa kesulitan yang sangat, lalu kujumpai Umar bin Al Khaththab dan aku pun memintanya untuk membacakan ayat dari Kitabullah. Maka ia pun masuk ke dalam rumahnya dan membukakan pintu untukku. Kemudian aku berjalan tak jauh dari situ, lalu aku menundukkan wajahku lantaran rasa penat dan lapar. Ternyata Rasulullah shallallahu 'alaihi wasallam berdiri tetap di depan kepalaku. Beliau bersabda: \"Wahai Abu Hurairah.\" Aku menjawab, \"Labbaik ya Rasulullah wa Sa'daik.\" Kemudian beliau menggandeng kedua tanganku dan menegakkanku, dan beliau pun tahu apa yang menimpa diriku. Kemudian beliau membawaku menuju kendaraannya, lalu beliau menyuruhku untuk meminum seteguk susu. Maka aku pun meminumnya. Setelah itu beliau bersabda: \"Ulangilah wahai Abu Hirr.\" Aku pun meminumnya kembali. Kemudian beliau bersabda: \"Ulangilah.\" Akhirnya aku minum hingga perutku kenyang seperti gelas. Setelah itu, aku menemui Umar dan menuturkan apa terjadi denganku. Aku berkata padanya, \"Maka Allah memberikan urusan itu kepada orang yang lebih berhak dari pada Anda wahai Umar. Demi Allah, aku telah meminta Anda untuk membacakan ayat sementara aku adalah lebih bagus bacaannya daripada Anda.\" Umar berkata, \"Demi Allah, aku memasukkanmu kedalam rumahku adalah lebih aku sukai daripada aku memiliki Unta merah.\""},"4652":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ أَخْبَرَنَا سُفْيَانُ قَالَ الْوَلِيدُ بْنُ كَثِيرٍ أَخْبَرَنِي أَنَّهُ سَمِعَ وَهْبَ بْنَ كَيْسَانَ أَنَّهُ سَمِعَ عُمَرَ بْنَ أَبِي سَلَمَةَ يَقُولُكُنْتُ غُلَامًا فِي حَجْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَتْ يَدِي تَطِيشُ فِي الصَّحْفَةِ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا غُلَامُ سَمِّ اللَّهَ وَكُلْ بِيَمِينِكَ وَكُلْ مِمَّا يَلِيكَ فَمَا زَالَتْ تِلْكَ طِعْمَتِي بَعْدُ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah mengabarkan kepada kami [Sufyan] ia berkata; [Al Walid bin Katsir] Telah mengabarkan kepadaku, bahwa ia mendengar [Wahb bin Kaisan] bahwa ia mendengar [Umar bin Abu Salamah] berkata; Waktu aku masih kecil dan berada di bawah asuhan Rasulullah shallallahu 'alaihi wasallam, tanganku bersileweran di nampan saat makan. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Ghulam, bacalah Bismilillah, makanlah dengan tangan kananmu dan makanlah makanan yang ada di hadapanmu.\" Maka seperti itulah gaya makanku setelah itu."},"4653":{"ar":"حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَلْحَلَةَ الدِّيلِيِّ عَنْ وَهْبِ بْنِ كَيْسَانَ أَبِي نُعَيْمٍ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ وَهُوَ ابْنُ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَكَلْتُ يَوْمًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا فَجَعَلْتُ آكُلُ مِنْ نَوَاحِي الصَّحْفَةِ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلْ مِمَّا يَلِيكَ","id":"Telah menceritakan kepadaku [Abdul Aziz bin Abdullah] ia berkata; Telah menceritakan kepadaku [Muhammad bin Ja'far] dari [Muhammad bin Amru bin Halhalah Ad Dili] dari [Wahb bin Kaisan Abu Nu'aim] dari [Amru bin Abu Salamah] ia adalah Ibnu Ummu Salah isteri Nabi shallallahu 'alaihi wasallam, ia berkata; Suatu hari, aku makan makanan bersama Rasulullah shallallahu 'alaihi wasallam, lalu aku menyantap makanan dari ujung nampan, maka Rasulullah shallallahu 'alaihi wasallam bersabda padaku: \"Makanlah makanan yang ada didepanmu.\""},"4654":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ وَهْبِ بْنِ كَيْسَانَ أَبِي نُعَيْمٍ قَالَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِطَعَامٍ وَمَعَهُ رَبِيبُهُ عُمَرُ بْنُ أَبِي سَلَمَةَ فَقَالَ سَمِّ اللَّهَ وَكُلْ مِمَّا يَلِيكَ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Wahb bin Kaisan Abu Nu'aim] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah diberi makanan, dan saat itu beliau bersama anak tirinya Umar bin Abu Salamah, maka beliau pun bersabda: \"Bacalah Basmalah dan ambillah makanan yang ada didekatmu.\""},"4655":{"ar":"حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُإِنَّ خَيَّاطًا دَعَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِطَعَامٍ صَنَعَهُ قَالَ أَنَسٌ فَذَهَبْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَأَيْتُهُ يَتَتَبَّعُ الدُّبَّاءَ مِنْ حَوَالَيْ الْقَصْعَةِقَالَ فَلَمْ أَزَلْ أُحِبُّ الدُّبَّاءَ مِنْ يَوْمِئِذٍ","id":"Telah menceritakan kepada kami [Qutaibah] dari [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] bahwa ia mendengar [Anas bin Malik] berkata; Sesungguhnya Khayyath mengundang Rasulullah shallallahu 'alaihi wasallam untuk menyantap makanan yang dibuatnya. Anas berkata; Maka aku pun pergi bersama Rasulullah shallallahu 'alaihi wasallam, lalu aku melihat beliau mencari-cari labu dari sekitar piring. Maka sejak hari itu, aku pun mulai menyukai labu."},"4656":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا شُعْبَةُ عَنْ أَشْعَثَ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ التَّيَمُّنَ مَا اسْتَطَاعَ فِي طُهُورِهِ وَتَنَعُّلِهِ وَتَرَجُّلِهِ وَكَانَ قَالَ بِوَاسِطٍ قَبْلَ هَذَا فِي شَأْنِهِ كُلِّهِ","id":"Telah menceritakan kepada kami [Abdan] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Syu'bah] dari [Asy'ats] dari [bapaknya] dari [Masruq] dari [Aisyah] radliallahu 'anha, ia berkata; Nabi shallallahu 'alaihi wasallam menyukai sebelah kanan sejauh beliau bisa melakukannya, yakni dalam bersuci, memakai terompah, dan menyisir, dan setiap urusnanya. Syu'bah katakan, Asy'ats di kota Wasith mengucapkan kata-kata lain sebelum ini \"."},"4657":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ أَبُو طَلْحَةَ لِأُمِّ سُلَيْمٍ لَقَدْ سَمِعْتُ صَوْتَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَعِيفًا أَعْرِفُ فِيهِ الْجُوعَ فَهَلْ عِنْدَكِ مِنْ شَيْءٍ فَأَخْرَجَتْ أَقْرَاصًا مِنْ شَعِيرٍ ثُمَّ أَخْرَجَتْ خِمَارًا لَهَا فَلَفَّتْ الْخُبْزَ بِبَعْضِهِ ثُمَّ دَسَّتْهُ تَحْتَ ثَوْبِي وَرَدَّتْنِي بِبَعْضِهِ ثُمَّ أَرْسَلَتْنِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَذَهَبْتُ بِهِ فَوَجَدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ وَمَعَهُ النَّاسُ فَقُمْتُ عَلَيْهِمْ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَكَ أَبُو طَلْحَةَ فَقُلْتُ نَعَمْ قَالَ بِطَعَامٍ قَالَ فَقُلْتُ نَعَمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمَنْ مَعَهُ قُومُوا فَانْطَلَقَ وَانْطَلَقْتُ بَيْنَ أَيْدِيهِمْ حَتَّى جِئْتُ أَبَا طَلْحَةَ فَقَالَ أَبُو طَلْحَةَ يَا أُمَّ سُلَيْمٍ قَدْ جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّاسِ وَلَيْسَ عِنْدَنَا مِنْ الطَّعَامِ مَا نُطْعِمُهُمْ فَقَالَتْ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَانْطَلَقَ أَبُو طَلْحَةَ حَتَّى لَقِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَقْبَلَ أَبُو طَلْحَةَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى دَخَلَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلُمِّي يَا أُمَّ سُلَيْمٍ مَا عِنْدَكِ فَأَتَتْ بِذَلِكَ الْخُبْزِ فَأَمَرَ بِهِ فَفُتَّ وَعَصَرَتْ أُمُّ سُلَيْمٍ عُكَّةً لَهَا فَأَدَمَتْهُ ثُمَّ قَالَ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا شَاءَ اللَّهُ أَنْ يَقُولَ ثُمَّ قَالَ ائْذَنْ لِعَشَرَةٍ فَأَذِنَ لَهُمْ فَأَكَلُوا حَتَّى شَبِعُوا ثُمَّ خَرَجُوا ثُمَّ قَالَ ائْذَنْ لِعَشَرَةٍ فَأَذِنَ لَهُمْ فَأَكَلُوا حَتَّى شَبِعُوا ثُمَّ خَرَجُوا ثُمَّ قَالَ ائْذَنْ لِعَشَرَةٍ فَأَذِنَ لَهُمْ فَأَكَلُوا حَتَّى شَبِعُوا ثُمَّ خَرَجُوا ثُمَّ أَذِنَ لِعَشَرَةٍ فَأَكَلَ الْقَوْمُ كُلُّهُمْ وَشَبِعُوا وَالْقَوْمُ ثَمَانُونَ رَجُلًا","id":"Telah menceritakan kepada kami [Isma'il] ia berkata; Telah menceritakan kepadaku [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] bahwa ia mendengar [Anas bin Malik] berkata; Abu Thalah berkata kepada Ummu Sulaim, \"Aku mendengar suara Rasulullah shallallahu 'alaihi wasallam telah melemah, dan aku tahu bahwa beliau sedang lapar. Apakah kamu mempunyai sesuatu?\" Maka Ummu Sulaim pun mengeluarkan beberapa bulatan gandum, dan mengeluarkan tudungnya lalu menutup roti itu dan meletakkannya di balik pakaianku. Ia juga memberikan sebagiannya padaku lalu mengutusku untuk menemui Rasulullah shallallahu 'alaihi wasallam. Aku pun membawa dan aku dapati Rasulullah shallallahu 'alaihi wasallam sedang berada di dalam masjid yang sedang bersama orang-orang. Aku berdiri di tengah-tengah mereka, maka Rasulullah shallallahu 'alaihi wasallam bertanya padaku: \"Apakah kamu diutus oleh Abu Thalhah?\" Aku menjawab, \"Ya.\" Beliau bertanya lagi: \"Dengan membawa makanan?\" Aku berkata, \"Ya.\" Akhirnya Rasulullah shallallahu 'alaihi wasallam bersabda kepada orang-orang yang saat itu sedang bersamanya: \"Beranjaklah.\" Maka mereka pun segera beranjak pergi (ke tempat Abu Thalhah) dan aku segera bergegas ke hadapan mereka, hingga aku sampai di tempat Abu Thalhah. Maka Abu Thalhah pun berkata, \"Wahai Ummu Sulaim. Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah datang bersama orang-orang sementara kita tidak memiliki persediaan makanan untuk menjamu mereka.\" Ummu Sulaim berkata, \"Allah dan Rasul-Nya yang lebih mengetahui.\" Akhirnya Abu Thalhah pergi hingga bertemu dengan Rasulullah shallallahu 'alaihi wasallam. Maka Abu Thalhah menyambut Rasulullah shallallahu 'alaihi wasallam hingga keduanya masuk. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Ummu Sulaim, keluarkanlah makanan yang kamu punyai.\" Maka Ummu Sulaim pun mengeluarkan roti itu. Lalu Nabi shallallahu 'alaihi wasallam menyuruh untuk diremukkan sementara Ummu Sulaim meremas-remas samin untuk lauk roti. Kemudian Rasulullah Shallallah membacakan sesutu padanya sekehendak Allah. Sesudah itu beliau bersabda: \"Izinkanlah untuk sepuluh orang.\" Lalu ia pun mengizinkan mereka dan mereka pun makan hingga kenyang dan keluar. Beliau bersabda lagi: \"Izinkan untuk sepuluh orang lagi.\" Ia pun mengizinkan mereka hingga mereka makan sampai kenyang dan keluar. Beliau bersabda lagi: \"Izinkan untuk sepuluh orang lagi.\" Ia pun mengizinkan mereka hingga mereka semua makan sampai kenyang lalu keluar. Setelah itu, beliau mengizinkan lagi untuk sepuluh orang. Akhirnya mereka semua makan dan kenyang. Padahal jumlah mereka adalah delapan puluh orang."},"4658":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ قَالَ وَحَدَّثَ أَبُو عُثْمَانَ أَيْضًا عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثِينَ وَمِائَةً فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ مَعَ أَحَدٍ مِنْكُمْ طَعَامٌ فَإِذَا مَعَ رَجُلٍ صَاعٌ مِنْ طَعَامٍ أَوْ نَحْوُهُ فَعُجِنَ ثُمَّ جَاءَ رَجُلٌ مُشْرِكٌ مُشْعَانٌّ طَوِيلٌ بِغَنَمٍ يَسُوقُهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَيْعٌ أَمْ عَطِيَّةٌ أَوْ قَالَ هِبَةٌ قَالَ لَا بَلْ بَيْعٌ قَالَ فَاشْتَرَى مِنْهُ شَاةً فَصُنِعَتْ فَأَمَرَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَوَادِ الْبَطْنِ يُشْوَى وَايْمُ اللَّهِ مَا مِنْ الثَّلَاثِينَ وَمِائَةٍ إِلَّا قَدْ حَزَّ لَهُ حُزَّةً مِنْ سَوَادِ بَطْنِهَا إِنْ كَانَ شَاهِدًا أَعْطَاهَا إِيَّاهُ وَإِنْ كَانَ غَائِبًا خَبَأَهَا لَهُ ثُمَّ جَعَلَ فِيهَا قَصْعَتَيْنِ فَأَكَلْنَا أَجْمَعُونَ وَشَبِعْنَا وَفَضَلَ فِي الْقَصْعَتَيْنِ فَحَمَلْتُهُ عَلَى الْبَعِيرِ أَوْ كَمَا قَالَ","id":"Telah menceritakan kepada kami [Musa] Telah menceritakan kepada kami [Mu'tamir] dari [bapaknya] ia berkata; Dan [Abu Utsman] Telah menceritakan juga dari [Abdurrahman bin Abu Bakar] radliallahu 'anhuma, ia berkata; Suatu ketika kami pernah bersama Nabi shallallahu 'alaihi wasallam dengan seratus tiga puluh orang sahabat. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah salah seorang dari kalian memiliki makanan?\" ternyata ada seorang laki-laki yang mempunyai satu Sha' makanan atau sebanyak itu, lalu makanan itu pun dibuat adonan. Kemudian datanglah seorang laki-laki musyrik berambut kusut dan berpostur tubuh tinggi dengan membawa kambing. Maka Nabi shallallahu 'alaihi wasallam bertanya, \"Apakah kambing itu adalah untuk dijual, diserahkan sebagai pemberian ataukah Hibah?\" laki-laki itu menjawab, \"Untaku dijual.\" Akhirnya beliau membeli satu kambing dari orang itu, lalu kambing itu dimasak. Kemudian Nabi shallallahu 'alaihi wasallam memerintahkan para sahabat agar dipanggangkan. Dan sungguh Maha Besar Allah, tidak seorang pun dari seratus tiga puluh orang itu, kecuali telah memotong daging perut kambing itu. Bila ia hadir, maka beliau akan memberinya langsung, dan jika tidak, maka beliau akan menyimpan untuknya. Kemudian beliau meletakkan sebagian darinya di dalam nampan, lalu kami pun makan di situ semuanya, dan kami pun kenyang. Namun di dalam nampan ternyata masih tersisa, sehingga aku pun membawanya di atas Unta milikku. -Atau sebagaimana yang ia katakan.-"},"4659":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا مَنْصُورٌ عَنْ أُمِّهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاتُوُفِّيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ شَبِعْنَا مِنْ الْأَسْوَدَيْنِ التَّمْرِ وَالْمَاءِ","id":"Telah menceritakan kepada kami [Muslim] Telah menceritakan kepada kami [Wuhaib] Telah menceritakan kepada kami [Manshur] dari [Ibunya] dari [Aisyah] radliallahu 'anha ia berkata; Nabi shallallahu 'alaihi wasallam wafat ketika kami kenyang karena makan kurma dan minum air."},"4660":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ يَحْيَى بْنُ سَعِيدٍ سَمِعْتُ بُشَيْرَ بْنَ يَسَارٍ يَقُولُ حَدَّثَنَا سُوَيْدُ بْنُ النُّعْمَانِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى خَيْبَرَ فَلَمَّا كُنَّا بِالصَّهْبَاءِ قَالَ يَحْيَى وَهِيَ مِنْ خَيْبَرَ عَلَى رَوْحَةٍ دَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِطَعَامٍ فَمَا أُتِيَ إِلَّا بِسَوِيقٍ فَلُكْنَاهُ فَأَكَلْنَا مِنْهُ ثُمَّ دَعَا بِمَاءٍ فَمَضْمَضَ وَمَضْمَضْنَا فَصَلَّى بِنَا الْمَغْرِبَ وَلَمْ يَتَوَضَّأْ قَالَ سُفْيَانُ سَمِعْتُهُ مِنْهُ عَوْدًا وَبَدْءًا","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] Telah berkata [Yahya bin Sa'id] Aku mendengar [Busyair bin Yasar] berkata; Telah menceritakan kepada kami [Suwaid bin An Nu'man] ia berkata; kami pernah keluar ke Khaibar bersama Rasulullah shallallahu 'alaihi wasallam. Ketika kami sampai di Shahba` -Yahya berkata; Dari Khaibar adalah perjalanan semalam- Rasulullah shallallahu 'alaihi wasallam meminta makanan, namun beliau hanya diberi makanan berupa gandum. Maka kami mengunyah dan memakannya. Setelah itu, beliau meminta air, lalu berkumur dan kami pun ikut berkumur-kumur. Kemudian beliau shalat Maghrib bersama kami dengan tanpa berwudlu lagi. Sufyan berkata; Aku mendengarnya darinya ketika pulang dan ketika awal perjalanan."},"4661":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ قَالَ كُنَّا عِنْدَ أَنَسٍوَعِنْدَهُ خَبَّازٌ لَهُ فَقَالَ مَا أَكَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُبْزًا مُرَقَّقًا وَلَا شَاةً مَسْمُوطَةً حَتَّى لَقِيَ اللَّهَ","id":"Telah menceritakan kepada kami [Muhammad bin Sinan] Telah menceritakan kepada kami [Hammam] dari [Qatadah] ia berkata; Suatu kami berada di sisi [Anas] dan saat itu ia mempunyai pembuat roti, maka ia pun berkata, \"Nabi shallallahu 'alaihi wasallam tidak pernah makan roti yang empuk dan tidak pula kambing yang dipanggang.\""},"4662":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ يُونُسَ قَالَ عَلِيٌّ هُوَ الْإِسْكَافُ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَمَا عَلِمْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكَلَ عَلَى سُكْرُجَةٍ قَطُّ وَلَا خُبِزَ لَهُ مُرَقَّقٌ قَطُّ وَلَا أَكَلَ عَلَى خِوَانٍ قَطُّقِيلَ لِقَتَادَةَ فَعَلَامَ كَانُوا يَأْكُلُونَ قَالَ عَلَى السُّفَرِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Mu'adz bin Hisyam] ia berkata;; Telah menceritakan kepadaku [bapakku] dari [Yunus] -Ali berkata; Itu adalah Al Iksaf- dari [Qatadah] dari [Anas] radliallahu 'anhu, ia berkata; Aku tidak pernah mengetahui bahwa Nabi shallallahu 'alaihi wasallam makan di atas piring sekali pun. Dan tidak pernah pula beliau dibuatkan roti yang empuk sekali pun serta beliau juga tak pernah makan di atas meja makan sekali pun. Maka ditanyakan kepada Qatadah, \"Kalau begitu, di atas apa mereka makan?\" ia menjawab, \"Di atas daun kurma.\""},"4663":{"ar":"حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ أَخْبَرَنِي حُمَيْدٌ أَنَّهُ سَمِعَ أَنَسًا يَقُولُقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْنِي بِصَفِيَّةَ فَدَعَوْتُ الْمُسْلِمِينَ إِلَى وَلِيمَتِهِ أَمَرَ بِالْأَنْطَاعِ فَبُسِطَتْ فَأُلْقِيَ عَلَيْهَا التَّمْرُ وَالْأَقِطُ وَالسَّمْنُوَقَالَ عَمْرٌو عَنْ أَنَسٍ بَنَى بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ صَنَعَ حَيْسًا فِي نِطَعٍ","id":"Telah menceritakan kepada kami [Ibnu Abu Maryam] Telah mengabarkan kepada kami [Muhammad bin Ja'far] Telah mengabarkan kepadaku [Humaid] bahwa ia mendengar [Anas] berkata; Nabi shallallahu 'alaihi wasallam bermukim guna menikahi Shafiyyah, lalu aku pun mengundang kaum muslimin untuk menghadiri walimahnya. Beliau memerintahkan untuk menghidangkan hamparan dari kulit yang diberi kurma, keju dan samin. Dan [Amru] berkata; dari [Anas]; Nabi shallallahu 'alaihi wasallam mengadakan walimah dengan makanan itu. Kemudian beliau membuat bubur yang terbuat dari gandum, kurma dan daging, dan meletakkannya dalam hamparan kulit."},"4664":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ وَعَنْ وَهْبِ بْنِ كَيْسَانَ قَالَكَانَ أَهْلُ الشَّأْمِ يُعَيِّرُونَ ابْنَ الزُّبَيْرِ يَقُولُونَ يَا ابْنَ ذَاتِ النِّطَاقَيْنِ فَقَالَتْ لَهُ أَسْمَاءُ يَا بُنَيَّ إِنَّهُمْ يُعَيِّرُونَكَ بِالنِّطَاقَيْنِ هَلْ تَدْرِي مَا كَانَ النِّطَاقَانِ إِنَّمَا كَانَ نِطَاقِي شَقَقْتُهُ نِصْفَيْنِ فَأَوْكَيْتُ قِرْبَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَحَدِهِمَا وَجَعَلْتُ فِي سُفْرَتِهِ آخَرَ قَالَ فَكَانَ أَهْلُ الشَّأْمِ إِذَا عَيَّرُوهُ بِالنِّطَاقَيْنِ يَقُولُ إِيهًا وَالْإِلَهِ تِلْكَ شَكَاةٌ ظَاهِرٌ عَنْكَ عَارُهَا","id":"Telah menceritakan kepada kami [Muhammad] Telah mengabarkan kepada kami [Abu Mu'awiyah] Telah menceritakan kepada kami [Hisyam] dari [bapaknya] dan dari [Wahb bin Kaisan] ia berkata; Para penduduk Syam menjuluki Ibnu Zubair dengan panggilan, \"Wahai Ibnu Dzata An Nithaaqain.\" Maka [Asma'] pun berkata padanya, \"Wahai anakku, sesungguhnya mereka menjulukimu dengan An Nithaaqain. Apakah kamu apakah itu An Nithaaqain. Demikian itu hanyalah karena, ikat pinggangku yang telah aku sobek menjadi dua. Lalu aku mengikat geriba Rasulullah shallallahu 'alaihi wasallam dengan salah satu darinya, sedangkan yang satu lagi aku letakkan untuk mengikat rangsum.\" Di kemudian hari, jika ada orang yang memberinya julukan buruk dengan panggilan 'Nithaqaini', ia jawab ' Hei, demi Allah, itu adalah panggilan yang jelas-jelas tercela.\""},"4665":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ أُمَّ حُفَيْدٍ بِنْتَ الْحَارِثِ بْنِ حَزْنٍ خَالَةَ ابْنِ عَبَّاسٍ أَهْدَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمْنًا وَأَقِطًا وَأَضُبًّا فَدَعَا بِهِنَّ فَأُكِلْنَ عَلَى مَائِدَتِهِ وَتَرَكَهُنَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَالْمُسْتَقْذِرِ لَهُنَّ وَلَوْ كُنَّ حَرَامًا مَا أُكِلْنَ عَلَى مَائِدَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا أَمَرَ بِأَكْلِهِنَّ","id":"Telah menceritakan kepada kami [Abu Nu'man] Telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa Ummu Hufaid binti Al Harits bin Hazn bibi Ibnu Abbas, memberi hadiah kepada Nabi shallallahu 'alaihi wasallam berupa samin, keju dan biawak. Maka beliau pun mengundang orang-orang untuk memakannya, hingga makanan itu pun di makan di atas hidangan beliau. Sedangkan Nabi shallallahu 'alaihi wasallam meninggalkannya seperti seorang yang tak berselera. Dan sekiranya semua makanan itu haram, niscaya semua itu tidak dimakan di tempat hidangan Nabi shallallahu 'alaihi wasallam dan beliau tidak pula beliau menyuruh untuk memakannya."},"4666":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ يَحْيَى عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ سُوَيْدِ بْنِ النُّعْمَانِ أَنَّهُ أَخْبَرَهُأَنَّهُمْ كَانُوا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّهْبَاءِ وَهِيَ عَلَى رَوْحَةٍ مِنْ خَيْبَرَ فَحَضَرَتْ الصَّلَاةُ فَدَعَا بِطَعَامٍ فَلَمْ يَجِدْهُ إِلَّا سَوِيقًا فَلَاكَ مِنْهُ فَلُكْنَا مَعَهُ ثُمَّ دَعَا بِمَاءٍ فَمَضْمَضَ ثُمَّ صَلَّى وَصَلَّيْنَا وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Hammad] dari [Yahya] dari [Busyair binti Yasar] dari [Suwaid bin An Nu'man] bahwa ia telah mengabarkan kepadanya bahwa mereka pernah bersama Nabi shallallahu 'alaihi wasallam di Shahba` -tempat yang berjarak semalam perjalanan Khaibar- kemudian tibalah waktu shalat. Beliau meminta makanan, namun tidak ada makanan kecuali tepung gandum, lalu beliau mengunyahnya dan kami pun ikut mengunyah bersamanya. Setelah itu, beliau meminta air dan berkumur-kumur kemudian shalat dan kami pun shalat sementara beliau tidak berwudlu lagi."},"4667":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَبُو الْحَسَنِ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو أُمَامَةَ بْنُ سَهْلِ بْنِ حُنَيْفٍ الْأَنْصَارِيُّ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُ أَنَّ خَالِدَ بْنَ الْوَلِيدِالَّذِي يُقَالُ لَهُ سَيْفُ اللَّهِ أَخْبَرَهُ أَنَّهُ دَخَلَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَيْمُونَةَ وَهِيَ خَالَتُهُ وَخَالَةُ ابْنِ عَبَّاسٍ فَوَجَدَ عِنْدَهَا ضَبًّا مَحْنُوذًا قَدْ قَدِمَتْ بِهِ أُخْتُهَا حُفَيْدَةُ بِنْتُ الْحَارِثِ مِنْ نَجْدٍ فَقَدَّمَتْ الضَّبَّ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ قَلَّمَا يُقَدِّمُ يَدَهُ لِطَعَامٍ حَتَّى يُحَدَّثَ بِهِ وَيُسَمَّى لَهُ فَأَهْوَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ إِلَى الضَّبِّ فَقَالَتْ امْرَأَةٌ مِنْ النِّسْوَةِ الْحُضُورِ أَخْبِرْنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قَدَّمْتُنَّ لَهُ هُوَ الضَّبُّ يَا رَسُولَ اللَّهِ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ عَنْ الضَّبِّ فَقَالَ خَالِدُ بْنُ الْوَلِيدِ أَحَرَامٌ الضَّبُّ يَا رَسُولَ اللَّهِ قَالَ لَا وَلَكِنْ لَمْ يَكُنْ بِأَرْضِ قَوْمِي فَأَجِدُنِي أَعَافُهُ قَالَ خَالِدٌ فَاجْتَرَرْتُهُ فَأَكَلْ��ُهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْظُرُ إِلَيَّ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil Abul Hasan] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [Abu Umamah bin Sahl bin Hunaif Al Anshari] bahwa [Ibnu Abbas] telah mengabarkan kepadanya bahwa [Khalid bin Al Khalid] yang juga dijuluki sebagai Saifullah telah mengabarkan kepadanya; Bahwa ia dan Rasulullah shallallahu 'alaihi wasallam pernah menemui bibinya yaitu Maimunah yang juga bibi daripada Ibnu Abbas. kemudian ia mendapati biawak yang telah terpanggang yang dibawa oleh saudara bibinya yakni, Hudzaifah bintu Al Harits dari Najed. Maka Maimunah pun menyuguhkan Biawak itu kepada Rasulullah shallallahu 'alaihi wasallam. Jarang sekali beliau memajukan tangannya untuk mengambil makanan hingga beliau dipersilahkan bahwa makanan itu untuk beliau. Saat itu, Rasulullah shallallahu 'alaihi wasallam menggerakkan tangannya ke arah biawak, lalu seorang wanita yang hadir di situ berkata dan memberitahukan kepada beliau tentang makanan yang telah disuguhkan, \"Itu adalah Biawak ya Rasulullah?\" Maka seketika itu, Rasulullah shallallahu 'alaihi wasallam segera menarik tangannya kembali dari daging Biawak sehingga Khalid bin Al Walid pun bertanya, \"Apakah daging Biawak itu haram ya Rasulullah?\" beliau menjawab: \"Tidak, akan tetapi daging itu tidak terdapat di negeri kaumku, karena itu aku tidak memakannya.\" Khalid berkata, \"Lalu aku pun menarik dan memakannya. Sementara Rasulullah shallallahu 'alaihi wasallam melihat ke arahku.\""},"4668":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ ح و حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامُ الِاثْنَيْنِ كَافِي الثَّلَاثَةِ وَطَعَامُ الثَّلَاثَةِ كَافِي الْأَرْبَعَةِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] -dalam riwayat lain- Dan Telah menceritakan kepada kami [Isma'il] ia berkata; Telah menceritakan kepadaku [Malik] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makanan untuk dua orang cukup untuk tiga orang, dan makanan untuk tiga orang cukup untuk empat orang.\""},"4669":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا شُعْبَةُ عَنْ وَاقِدِ بْنِ مُحَمَّدٍ عَنْ نَافِعٍ قَالَ كَانَ ابْنُ عُمَرَلَا يَأْكُلُ حَتَّى يُؤْتَى بِمِسْكِينٍ يَأْكُلُ مَعَهُ فَأَدْخَلْتُ رَجُلًا يَأْكُلُ مَعَهُ فَأَكَلَ كَثِيرًا فَقَالَ يَا نَافِعُ لَا تُدْخِلْ هَذَا عَلَيَّ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْمُؤْمِنُ يَأْكُلُ فِي مِعًى وَاحِدٍ وَالْكَافِرُ يَأْكُلُ فِي سَبْعَةِ أَمْعَاءٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] Telah menceritakan kepada kami [Abdush Shamad] Telah menceritakan kepada kami [Syu'bah] dari [Waqid bin Muhammad] dari [Nafi'] ia berkata; Biasanya [Ibnu Umar] tidak makan hingga didatangnya kepadanya seorang miskin lalu makan bersamanya. Maka aku pun memasukkan seorang laki-laki untuk makan bersamanya, lalu laki-laki itu makan banyak, maka ia pun berkata, \"Wahai Nafi', jangan kamu masukkan orang ini. sesungguhnya aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Seorang mukmin itu makan dengan satu usus, sedangkan orang kafir makan dengan tujuh usus.'\""},"4670":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا عَبْدَةُ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمُؤْمِنَ يَأْكُلُ فِي مِعًى وَاحِدٍ وَإِنَّ الْكَافِرَ أَوْ الْمُنَافِقَ فَلَا أَدْرِي أَيَّهُمَا قَالَ عُبَيْدُ اللَّهِ يَأْكُلُ فِي سَبْعَةِ أَمْعَاءٍوَقَالَ ابْنُ بُكَيْرٍ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] Telah mengabarkan kepada kami [Abdah] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang mukmin itu makan dengan satu usus, sedangkan orang kafir atau munafik -aku tidak tahu mana yang beliau ucapkan diantara keduanya- makan dengan tujuh usus.\" [Ibnu Bukair] berkata; Telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam semisalnya."},"4671":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو قَالَ كَانَ أَبُو نَهِيكٍ رَجُلًا أَكُولًا فَقَالَ لَهُ ابْنُ عُمَرَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْكَافِرَ يَأْكُلُ فِي سَبْعَةِ أَمْعَاءٍ فَقَالَ فَأَنَا أُومِنُ بِاللَّهِ وَرَسُولِهِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Sufyan] dari [Amru] ia berkata; Bahwasnya Abu Nahik adalah seorang yang makannya sedikit, maka [Ibnu Umar] berkata padanya; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Sesungguhnya orang kafir itu makan dengan tujuh usus.\" Maka ia pun berkata, \"Kalau begitu, aku beriman kepada Allah dan Rasul-Nya.\""},"4672":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ الْمُسْلِمُ فِي مِعًى وَاحِدٍ وَالْكَافِرُ يَأْكُلُ فِي سَبْعَةِ أَمْعَاءٍ","id":"Telah menceritakan kepada kami [Isma'il] ia berkata; Telah menceritakan kepadaku [Malik] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang mukmin itu hanya makan dengan satu usus, sedangkan orang kafir makan dengan tujuh usus.\""},"4673":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا كَانَ يَأْكُلُ أَكْلًا كَثِيرًا فَأَسْلَمَ فَكَانَ يَأْكُلُ أَكْلًا قَلِيلًا فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ الْمُؤْمِنَ يَأْكُلُ فِي مِعًى وَاحِدٍ وَالْكَافِرَ يَأْكُلُ فِي سَبْعَةِ أَمْعَاءٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Syu'bah] dari [Adi bin Tsabit] dari [Abu Hazim] dari [Abu Hurairah] bahwa seorang ada seorang laki-laki yang makannya banyak, lalu ia masuk Islam. Setelah itu, makannya menjadi sedikit, maka hal itu pun diceritakan kepada Nabi shallallahu 'alaihi wasallam, maka beliau bersabda: \"Sesungguhnya seorang mukmin itu makan dari satu usus, sedangkan orang kafir makan dengan tujuh usus.\""},"4674":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مِسْعَرٌ عَنْ عَلِيِّ بْنِ الْأَقْمَرِ سَمِعْتُ أَبَا جُحَيْفَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا آكُلُ مُتَّكِئًا","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Mis'ar] dari [Ali bin Al Aqmar] Aku mendengar [Abu Juhaifah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku tidaklah makan sambil bersandar.\""},"4675":{"ar":"حَدَّثَنِي عُثْمَانُ بْنُ أَبِي شَيْبَةَ أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ عَلِيِّ بْنِ الْأَقْمَرِ عَنْ أَبِي جُحَيْفَةَ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِرَجُلٍ عِنْدَهُ لَا آكُلُ وَأَنَا مُتَّكِئٌ","id":"Telah menceritakan kepadaku [Utsman bin Abu Syaibah] Telah mengabarkan kepada kami [Jarir] dari [Manshur] dari [Ali bin Al Aqmar] dari [Abu Juhaifah] ia berkata; Suatu ketika, apa berada di sisi Nabi shallallahu 'alaihi wasallam, kemudian beliau bersabda kepada seorang laki-laki yang ada di sisinya: \"Aku tidak akan makan sambil bersandar.\""},"4676":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنْ ابْنِ عَبَّاسٍ عَنْ خَالِدِ بْنِ الْوَلِيدِ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِضَبٍّ مَشْوِيٍّ فَأَهْوَى إِلَيْهِ لِيَأْكُلَ فَقِيلَ لَهُ إِنَّهُ ضَبٌّ فَأَمْسَكَ يَدَهُ فَقَالَ خَالِدٌ أَحَرَامٌ هُوَ قَالَ لَا وَلَكِنَّهُ لَا يَكُونُ بِأَرْضِ قَوْمِي فَأَجِدُنِي أَعَافُهُ فَأَكَلَ خَالِدٌ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْظُرُقَالَ مَالِكٌ عَنْ ابْنِ شِهَابٍ بِضَبٍّ مَحْنُوذٍ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Hisyam bin Yusuf] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Umamah bin Sahl] dari [Ibnu Abbas] dari [Khalid bin Al Walid] ia berkata; Nabi shallallahu 'alaihi wasallam pernah diberi daging biawak yang terpanggang. Maka beliau pun berselera hendak memakannya, lalu dikatakanlah kepada beliau, \"Itu adalah daging biawak.\" Dengan segera beliau menahan tangannya kembali. Khalid bertanya, \"Apakah daging itu adalah haram?\" beliau bersabda: \"Tidak, akan tetapi daging itu tidak ada di negeri kaumku.\" Beliau tidak melarang. Maka Khalid pun memakannya sementara Rasulullah shallallahu 'alaihi wasallam melihat. [Malik] berkata; Dari [Ibnu Syihab]; BIDLABBIN MAHNUUDZ (Biawak yang dipanggang)."},"4677":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي مَحْمُودُ بْنُ الرَّبِيعِ الْأَنْصَارِيُّ أَنَّ عِتْبَانَ بْنَ مَالِكٍوَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِمَّنْ شَهِدَ بَدْرًا مِنْ الْأَنْصَارِ أَنَّهُ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَنْكَرْتُ بَصَرِي وَأَنَا أُصَلِّي لِقَوْمِي فَإِذَا كَانَتْ الْأَمْطَارُ سَالَ الْوَادِي الَّذِي بَيْنِي وَبَيْنَهُمْ لَمْ أَسْتَطِعْ أَنْ آتِيَ مَسْجِدَهُمْ فَأُصَلِّيَ لَهُمْ فَوَدِدْتُ يَا رَسُولَ اللَّهِ أَنَّكَ تَأْتِي فَتُصَلِّي فِي بَيْتِي فَأَتَّخِذُهُ مُصَلًّى فَقَالَ سَأَفْعَلُ إِنْ شَاءَ اللَّهُ قَالَ عِتْبَانُ فَغَدَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ حِينَ ارْتَفَعَ النَّهَارُ فَاسْتَأْذَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَذِنْتُ لَهُ فَلَمْ يَجْلِسْ حَتَّى دَخَلَ الْبَيْتَ ثُمَّ قَالَ لِي أَيْنَ تُحِبُّ أَنْ أُصَلِّيَ مِنْ بَيْتِكَ فَأَشَرْتُ إِلَى نَاحِيَةٍ مِنْ الْبَيْتِ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَبَّرَ فَصَفَفْنَا فَصَلَّى رَكْعَتَيْنِ ثُمَّ سَلَّمَ وَحَبَسْنَاهُ عَلَى خَزِيرٍ صَنَعْنَاهُ فَثَابَ فِي الْبَيْتِ رِجَالٌ مِنْ أَهْلِ الدَّارِ ذَوُو عَدَدٍ فَاجْتَمَعُوا فَقَالَ قَائِلٌ مِنْهُمْ أَيْنَ مَالِكُ بْنُ الدُّخْشُنِ فَقَالَ بَعْضُهُمْ ذَلِكَ مُنَافِقٌ لَا يُحِبُّ اللَّهَ وَرَسُولَهُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُلْ أَلَا تَرَاهُ قَالَ لَا إِلَهَ إِلَّا اللَّهُ يُرِيدُ بِذَلِكَ وَجْهَ اللَّهِ قَالَ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ قُلْنَا فَإِنَّا نَرَى وَجْهَهُ وَنَصِيحَتَهُ إِلَى الْمُنَافِقِينَ فَقَالَ فَإِنَّ اللَّهَ حَرَّمَ عَلَى النَّارِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ يَبْتَغِي بِذَلِكَ وَجْهَ اللَّهِقَالَ ابْنُ شِهَابٍ ثُمَّ سَأَلْتُ الْحُصَيْنَ بْنَ مُحَمَّدٍ الْأَنْصَارِيَّ أَحَدَ بَنِي سَالِمٍ وَكَانَ مِنْ سَرَاتِهِمْ عَنْ حَدِيثِ مَحْمُودٍ فَصَدَّقَهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] ia berkata; Telah mengabarkan kepadaku [Mahmud bin Ar Rabi' Al Anshari] bahwa ['Itban bin Malik] -ia adalah termasuk salah seorang sahabat Nabi shallallahu 'alaihi wasallam dan termasuk Ahli Badar- bahwasanya; Ia pernah mendatangi Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya aku selalu shalat bersama kaumku, akan tetapi, saat hujan turun dan lembah yang memisahkan antara aku dan kaumku pun membanjir, maka aku tidak bisa lagi mendatangi masjid mereka. Karena itu aku sangat berharap bahwa Anda datang dan shalat di rumahku, hingga aku pun menjadikannya tempat shalat.\" Beliau pun bersabda: \"Aku akan melakukannya Insya Allah.\" 'Utban berkata; Ketika matahari mulai meninggi, Rasulullah shallallahu 'alaihi wasallam pun berangkat bersama Abu Bakar. Kemudian Nabi shallallahu 'alaihi wasallam meminta izin dan aku pun mengizinkannya. Beliau tidak duduk hingga masuk ke dalam rumah dan bertanya padaku: \"Di tempat manakah yang kamu sukai aku shalat?\" Aku pun memberi isyarat pada bagian di rumah itu. Kemudian Nabi shallallahu 'alaihi wasallam bangun dan bertakbir, lalu kami pun membentuk shaf. Beliau shalat dua raka'at dan salam. Sesudah itu, kami menahan beliau dengan bambu yang telah kami buat. Lalu berkumpullah beberapa orang di rumah itu, dan salah seorang dari mereka berkata, \"Di mana Malik bin Ad Dukhsyun?\" sebagian dari mereka menjawab, \"Ia adalah seorang munafik yang tidak menyukai Allah dan Rasul-Nya.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu berbicara seperti itu. Tidakkah kamu lihat ia mengucapkan 'Laa Ilaaha Illallah' dan ia mengucapkan karena wajah Allah?\" laki-laki itu menjawab, \"Allah dan Rasul-Nya yang lebih mengetahui.\" Kami berkata, \"Sesungguhnya kami telah melihat wajah dan nasehatnya kepada orang-orang munafik.\" Maka beliau pun bersabda: \"Sesungguhnya Allah telah mengharamkan neraka atas orang yang mengucapkan Laa Ilaaha Illallah dengan mengharap wajah Allah.\" [Ibnu Syihab] berkata; Lalu aku bertanya kepada [Al Hushain bin Muhammad Al Anshari] -salah seorang Bani Salim- mengenai hadits Mahmud, lalu ia pun membenarkannya."},"4678":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَهْدَتْ خَالَتِي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضِبَابًا وَأَقِطًا وَلَبَنًا فَوُضِعَ الضَّبُّ عَلَى مَائِدَتِهِ فَلَوْ كَانَ حَرَامًا لَمْ يُوضَعْ وَشَرِبَ اللَّبَنَ وَأَكَلَ الْأَقِطَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] Telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id] dari [Ibnu Abbas] Radliayallahu 'Anhuma, ia berkata; Bibiku pernah memberi hadiah kepada Rasulullah shallallahu 'alaihi wasallam berupa daging biawak, keju dan susu. Kemudian daging biawak itu diletakkan di atas hidangan beliau. Sekiranya biawak itu haram, niscaya ia tidak akan diletakkan di situ. Lalu beliau meminum susu dan memakan keju."},"4679":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَإِنْ كُنَّا لَنَفْرَحُ بِيَوْمِ الْجُمُعَةِ كَانَتْ لَنَا عَجُوزٌ تَأْخُذُ أُصُولَ السِّلْقِ فَتَجْعَلُهُ فِي قِدْرٍ لَهَا فَتَجْعَلُ فِيهِ حَبَّاتٍ مِنْ شَعِيرٍ إِذَا صَلَّيْنَا زُرْنَاهَا فَقَرَّبَتْهُ إِلَيْنَا وَكُنَّا نَفْرَحُ بِيَوْمِ الْجُمُعَةِ مِنْ أَجْلِ ذَلِكَ وَمَا كُنَّا نَتَغَدَّى وَلَا نَقِيلُ إِلَّا بَعْدَ الْجُمُعَةِ وَاللَّهِ مَا فِيهِ شَحْمٌ وَلَا وَدَكٌ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Ya'qub bin Abdurrahman] dari [Abu Hazim] dari [Sahl bin Sa'd] ia berkata; Dulu kami benar-benar merasa senang di hari Jum'at. Kami memiliki seorang nenek yang telah tua. Biasanya ia mengambil ubi lalu meletakkannya di dalam periuk miliknya dan menambahkan pula biji-bijian dari gandum. Setelah shalat Jum'at kami selalu mengunjunginya, sehingga sang nenek pun menyuguhkan ubi serta biji-bijian itu untuk kami. Karena itulah hari Jum'at, adalah hari yang sangat menyenangkan bagi kami. Kami tidak pernah menyantap makan siang dan tidak pula tidur, kecuali setelah Jum'at. Demi Allah di situ tak ada lemak, tidak pula bubur tepung mengandung lemak."},"4680":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَتَعَرَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتِفًا ثُمَّ قَامَ فَصَلَّى وَلَمْ يَتَوَضَّأْوَعَنْ أَيُّوبَ وَعَاصِمٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ انْتَشَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَرْقًا مِنْ قِدْرٍ فَأَكَلَ ثُمَّ صَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Abdullah bin Abdul Wahhab] Telah menceritakan kepada kami [Hammad] Telah menceritakan kepada kami [Ayyub] dari [Muhammad] dari [Ibnu Abbas] radliallahu 'anhuma, ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah mengunyah bahu kambing kemudian berdiri dan shalat dengan tidak berwudlu lagi. Dan dari [Ayyub] dan [Ashim] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Nabi shallallahu 'alaihi wasallam pernah menggigit urat dari periuk kemudian beliau memakannya dan shalat dengan tidak berwudlu lagi."},"4681":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنِي عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا فُلَيْحٌ حَدَّثَنَا أَبُو حَازِمٍ الْمَدَنِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَخَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ مَكَّةَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] ia berkata; Telah menceritakan kepadaku [Utsman bin Umar] Telah menceritakan kepada kami [Fulaih] Telah menceritakan kepada kami [Abu Hazim Al Madani] Telah menceritakan kepada kami [Abdullah bin Abu Qatadah] dari [bapaknya] ia berkata; Kami pernah keluar bersama Nabi shallallahu 'alaihi wasallam menuju ke arah Ka'bah."},"4682":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ أَبِي حَازِمٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ السَّلَمِيِّ عَنْ أَبِيهِ أَنَّهُ قَالَكُنْتُ يَوْمًا جَالِسًا مَعَ رِجَالٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَنْزِلٍ فِي طَرِيقِ مَكَّةَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَازِلٌ أَمَامَنَا وَالْقَوْمُ مُحْرِمُونَ وَأَنَا غَيْرُ مُحْرِمٍ فَأَبْصَرُوا حِمَارًا وَحْشِيًّا وَأَنَا مَشْغُولٌ أَخْصِفُ نَعْلِي فَلَمْ يُؤْذِنُونِي لَهُ وَأَحَبُّوا لَوْ أَنِّي أَبْصَرْتُهُ فَالْتَفَتُّ فَأَبْصَرْتُهُ فَقُمْتُ إِلَى الْفَرَسِ فَأَسْرَجْتُهُ ثُمَّ رَكِبْتُ وَنَسِيتُ السَّوْطَ وَالرُّمْحَ فَقُلْتُ لَهُمْ نَاوِلُونِي السَّوْطَ وَالرُّمْحَ فَقَالُوا لَا وَاللَّهِ لَا نُعِينُكَ عَلَيْهِ بِشَيْءٍ فَغَضِبْتُ فَنَزَلْتُ فَأَخَذْتُهُمَا ثُمَّ رَكِبْتُ فَشَدَدْتُ عَلَى الْحِمَارِ فَعَقَرْتُهُ ثُمَّ جِئْتُ بِهِ وَقَدْ مَاتَ فَوَقَعُوا فِيهِ يَأْكُلُونَهُ ثُمَّ إِنَّهُمْ شَكُّوا فِي أَكْلِهِمْ إِيَّاهُ وَهُمْ حُرُمٌ فَرُحْنَا وَخَبَأْتُ الْعَضُدَ مَعِي فَأَدْرَكْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْنَاهُ عَنْ ذَلِكَ فَقَالَ مَعَكُمْ مِنْهُ شَيْءٌ فَنَاوَلْتُهُ الْعَضُدَ فَأَكَلَهَا حَتَّى تَعَرَّقَهَا وَهُوَ مُحْرِمٌقَالَ مُحَمَّدُ بْنُ جَعْفَرٍ وَحَدَّثَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي قَتَادَةَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] Telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Abu Hazim] dari [Abdullah bin Abu Qatadah As Salami] dari [bapaknya] bahwa ia berkata; Pada suatu hari, aku duduk-duduk bersama beberapa orang dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, tepatnya di suatu rumah yang ada di jalan menuju Makkah, sementara Nabi shallallahu 'alaihi wasallam juga singgah di hadapan kami, sedangkan orang-orang dalam keadaan Ihram, kecuali aku. Tiba-tiba mereka melihat keledai liar, sementara aku sedang sibuk menambal sendalku, dan mereka juga tidak memberitahuku. Mereka sangat menginginkan bila aku melihatnya. Aku pun menoleh, lalu melihatnya, maka aku segera beranjak menuju kuda milikku, memasang pelananya dan menaikinya, namun aku lupa untuk membawa cambuk dan tombak. Maka kukatakanlah pada mereka, \"Ambilkan cambuk dan tombak.\" Mereka berkata, \"Tidak, Demi Allah, kami tidak akan membantumu dengan sesuatu pun untuk menangkapnya.\" Aku pun marah dan turun lalu mengambil keduanya lalu segera menuju himar dan menikamnya. Kemudian aku mendatanginya, dan ternyata ia telah mati. Lalu orang-orang yang muhrim pun ikut memakan dagingnya. Sesudah itu, mereka merasa bimbang karena memakannya karena mereka dalam keadaan Muhrim. Kemudian kami pun istirahat dan aku menyimpan daging bagian lengannya. Setelah itu, kami menjumpai Rasulullah shallallahu 'alaihi wasallam dan kami pun menanyakan hal itu pada beliau, maka beliau bersabda: \"Apakah kalian masih mempunyai dagingnya?\" Maka aku menyerahkan bagian lengannya itu pada beliau dan beliau pun memakannya hingga mengunyahnya sementara beliau sedang muhrim. [Muhammad bin Ja'far] berkata; dan Telah menceritakan kepadaku [Zaid bin Aslam] dari ['Atha` bin Yasar] dari [Abu Qatadah] semisalnya."},"4683":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ أَنَّ أَبَاهُ عَمْرَو بْنَ أُمَيَّةَ أَخْبَرَهُأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْتَزُّ مِنْ كَتِفِ شَاةٍ فِي يَدِهِ فَدُعِيَ إِلَى الصَّلَاةِ فَأَلْقَاهَا وَالسِّكِّينَ الَّتِي يَحْتَزُّ بِهَا ثُمَّ قَامَ فَصَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; Telah mengabarkan kepada kami [Ja'far bin Amru bin Umayyah] bahwa [bapaknya] yakni Amru bin Umayyah telah mengabarkan kepadanya bahwa ia pernah melihat Nabi shallallahu 'alaihi wasallam memotong bahu kambing yang ada pada tangannya, lalu masuklah waktu shalat. Maka beliau melepaskannya dan juga meletakkan pisau yang digunakannya memotong kemudian beliau bergegas dan menunaikan shalat dengan tanpa berwudlu lagi."},"4684":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَمَا عَابَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا قَطُّ إِنْ اشْتَهَاهُ أَكَلَهُ وَإِنْ كَرِهَهُ تَرَكَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] Telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Hazim] dari [Abu Hurairah] ia berkata; Nabi shallallahu 'alaihi wasallam tidak pernah mencela makanan sekali pun. Bila beliau berselera, maka beliau memakannya dan bila tak suka, maka beliau meninggalkannya."},"4685":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ أَنَّهُ سَأَلَ سَهْلًاهَلْ رَأَيْتُمْ فِي زَمَانِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّقِيَّ قَالَ لَا فَقُلْتُ فَهَلْ كُنْتُمْ تَنْخُلُونَ الشَّعِيرَ قَالَ لَا وَلَكِنْ كُنَّا نَنْفُخُهُ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] Telah menceritakan kepada kami [Abu Ghassan] ia berkata; Telah menceritakan kepadaku [Abu Hazim] bahwa ia bertanya kepada [Sahl], \"Apakah kamu melihat An Naqiy (sumsum) pada masa Nabi shallallahu 'alaihi wasallam?\" Ia menjawab, \"Tidak.\" Aku bertanya lagi, \"Apakah kalian mengayak gandum?\" Ia menjawab, \"Tidak. Akan tetapi cukup bagi kami meniupnya.\""},"4686":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَبَّاسٍ الْجُرَيْرِيِّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَسَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا بَيْنَ أَصْحَابِهِ تَمْرًا فَأَعْطَى كُلَّ إِنْسَانٍ سَبْعَ تَمَرَاتٍ فَأَعْطَانِي سَبْعَ تَمَرَاتٍ إِحْدَاهُنَّ حَشَفَةٌ فَلَمْ يَكُنْ فِيهِنَّ تَمْرَةٌ أَعْجَبَ إِلَيَّ مِنْهَا شَدَّتْ فِي مَضَاغِي","id":"Telah meceritakan kepada kami [Abu Nu'man] Telah menceritakan kepada kami [Hammad bin Zaid] dari [Abbas Al Jurairi] dari [Abu Utsman An Nahdi] dari [Abu Hurairah] ia berkata; \"Pada suatu hari, Nabi shallallahu 'alaihi wasallam membagikan kurma kepada para sahabatnya. Beliau beri tujuh butir kurma pada setiap orangnya. Maka beliau juga memberiku sebanyak tujuh butir kurma, salah satunya adalah kering, yang tidak ada kurma lainnya yang lebih mengherankan bagiku daripadanya karena sedemikian kerasnya kurma itu harus dikunyah."},"4687":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا شُعْبَةُ عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ عَنْ سَعْدٍ قَالَرَأَيْتُنِي سَابِعَ سَبْعَةٍ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لَنَا طَعَامٌ إِلَّا وَرَقُ الْحُبْلَةِ أَوْ الْحَبَلَةِ حَتَّى يَضَعَ أَحَدُنَا مَا تَضَعُ الشَّاةُ ثُمَّ أَصْبَحَتْ بَنُو أَسَدٍ تُعَزِّرُنِي عَلَى الْإِسْلَامِ خَسِرْتُ إِذًا وَضَلَّ سَعْيِي","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] Telah menceritakan kepada kami [Wahb bin Jarir] Telah menceritakan kepada kami [Syu'bah] dari [Isma'il] dari [Qais] dari [Sa'd] ia berkata; \"Aku melihat bahwa aku adalah salah seorang dari tujuh orang yang bersama Nabi shallallahu 'alaihi wasallam. Saat itu, kami tak punya makanan kecuali dedaunan anggur hingga kami buang kotoran sebagaimana kotoran kambing. Kemudian Banu Asad memuliakanku dengan Islam. Karena itu, aku betul-betul telah rugi dan usahaku pun sia-sia.\""},"4688":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ عَنْ أَبِي حَازِمٍ قَالَ سَأَلْتُ سَهْلَ بْنَ سَعْدٍ فَقُلْتُهَلْ أَكَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّقِيَّ فَقَالَ سَهْلٌ مَا رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّقِيَّ مِنْ حِينَ ابْتَعَثَهُ اللَّهُ حَتَّى قَبَضَهُ اللَّهُ قَالَ فَقُلْتُ هَلْ كَانَتْ لَكُمْ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنَاخِلُ قَالَ مَا رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنْخُلًا مِنْ حِينَ ابْتَعَثَهُ اللَّهُ حَتَّى قَبَضَهُ اللَّهُ قَالَ قُلْتُ كَيْفَ كُنْتُمْ تَأْكُلُونَ الشَّعِيرَ غَيْرَ مَنْخُولٍ قَالَ كُنَّا نَطْحَنُهُ وَنَنْفُخُهُ فَيَطِيرُ مَا طَارَ وَمَا بَقِيَ ثَرَّيْنَاهُ فَأَكَلْنَاهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Ya'qub] dari [Abu Hazim] ia berkata; Aku bertanya kepada [Sahl], \"Apakah Rasulullah shallallahu 'alaihi wasallam makan gandum yang ditapis?\" Sahl menjawab, \"Rasulullah shallallahu 'alaihi wasallam tidak pernah melihat gandum yang ditapis sejak Allah mengutusnya hingga mewafatkannya.\" Aku bertanya lagi, \"Apakah di zaman Rasulullah shallallahu 'alaihi wasallam kalian mempunyai ayakan?\" Ia menjawab, \"Rasulullah shallallahu 'alaihi wasallam tidak pernah melihat ayakan sejak Allah mengutusnya hingga mewafatkannya.\" Aku bertanya lagi, \"Lalu bagaimana kalian memakan gandum yang belum terayak?\" ia menjawab, \"Kami menggiling dan meniupnya hingga terbanglah apa yang dapat terbang, sedangkan yang tersisa kami basahi dan memakannya.\""},"4689":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّهُ مَرَّ بِقَوْمٍ بَيْنَ أَيْدِيهِمْ شَاةٌ مَصْلِيَّةٌ فَدَعَوْهُ فَأَبَى أَنْ يَأْكُلَ وَقَالَ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الدُّنْيَا وَلَمْ يَشْبَعْ مِنْ خُبْزِ الشَّعِيرِ","id":"Telah menceritakan kepadaku [Ishaq bin Ibrahim] Telah mengabarkan kepada kami [Rauh bin Ubadah] Telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Sa'id Al Maqburi] dari [Abu Hurairah] radliallahu 'anhu, bahwa suatu ketika ia melewati suatu kaum yang dihadapan mereka terdapat seekor kambing yang telah terpanggang. Lalu mereka pun mengundangnya, namun ia enggan untuk memakan daging kambing tersebut. Dan Abu Hurairah pun berkata, \"Rasulullah shallallahu 'alaihi wasallam meninggalkan dunia ini, namun beliau belum pernah kenyang memakan roti yang terbuat dari gandum lembut.\""},"4690":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي الْأَسْوَدِ حَدَّثَنَا مُعَاذٌ حَدَّثَنِي أَبِي عَنْ يُونُسَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَمَا أَكَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى خِوَانٍ وَلَا فِي سُكْرُجَةٍ وَلَا خُبِزَ لَهُ مُرَقَّقٌقُلْتُ لِقَتَادَةَ عَلَامَ يَأْكُلُونَ قَالَ عَلَى السُّفَرِ","id":"Telah menceritakan kepada kami [Abdullah bin Abul Aswad] Telah menceritakan kepada kami [Mu'adz] Telah menceritakan kepadaku [bapakku] dari [Yunus] dari [Qatadah] dari [Anas bin Malik] ia berkata; Nabi shallallahu 'alaihi wasallam tidak pernah makan di atas meja dan tidak pula dengan piring. Dan beliau tidak pernah dibuatkan roti empuk.\" Aku bertanya kepada Qatadah, \"Lalu di atas hamparan apa beliau makan?\" ia menjawab, \"Di atas daun kurma.\""},"4691":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَا شَبِعَ آلُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنْذُ قَدِمَ الْمَدِينَةَ مِنْ طَعَامِ الْبُرِّ ثَلَاثَ لَيَالٍ تِبَاعًا حَتَّى قُبِضَ","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] radliallahu 'anha, ia berkata, \"Keluarga Muhammad shallallahu 'alaihi wasallam tidak pernah kenyang dari gandum halus selama tiga malam berturut-turut sejak tiba di Madinah hingga beliau wafat.\""},"4692":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهَا كَانَتْ إِذَا مَاتَ الْمَيِّتُ مِنْ أَهْلِهَا فَاجْتَمَعَ لِذَلِكَ النِّسَاءُ ثُمَّ تَفَرَّقْنَ إِلَّا أَهْلَهَا وَخَاصَّتَهَا أَمَرَتْ بِبُرْمَةٍ مِنْ تَلْبِينَةٍ فَطُبِخَتْ ثُمَّ صُنِعَ ثَرِيدٌ فَصُبَّتْ التَّلْبِينَةُ عَلَيْهَا ثُمَّ قَالَتْ كُلْنَ مِنْهَا فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ التَّلْبِينَةُ مُجِمَّةٌ لِفُؤَادِ الْمَرِيضِ تَذْهَبُ بِبَعْضِ الْحُزْنِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] Telah menceritakan kepada kami ['Uqail] dari [Ibnu Syihab] dari [Urwah] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam bahwasanya; Bila salah seorang dari keluarganya meninggal, dan kaum wanita pun berkumpul lalu bubar kecuali pihak keluarganya, maka ia menyuruh untuk menyediakan periuk berisikan bubur yang dimasak dari gandum lembut. Kemudian ia membuat campuran daging dan roti dan menuangkan gandum lembut. Setelah itu, Aisyah berkata; Makanlah darinya, karena aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bubur gandum lembut bisa menghimpun hati yang sakit yang menghilangkan kesedihan.\""},"4693":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ الْجَمَلِيِّ عَنْ مُرَّةَ الْهَمْدَانِيِّ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَمَلَ مِنْ الرِّجَالِ كَثِيرٌ وَلَمْ يَكْمُلْ مِنْ النِّسَاءِ إِلَّا مَرْيَمُ بِنْتُ عِمْرَانَ وَآسِيَةُ امْرَأَةُ فِرْعَوْنَ وَفَضْلُ عَائِشَةَ عَلَى النِّسَاءِ كَفَضْلِ الثَّرِيدِ عَلَى سَائِرِ الطَّعَامِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] Telah menceritakan kepada kami [Ghundar] Telah menceritakan kepada kami [Syu'bah] dari [Amru bin Murrah Al Jamali] dari [Murrah Al Hamdani] dari [Abu Musa Al Asy'ari] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kaum laki-laki yang sempurna sudah sekian banyak, namun dari kaum wanita tidak ada yang sempurnya kecuali Maryam binti Imran dan Asiyah isteri Fir'aun. Dan keutamaan Aisyah atas seluruh wanita adalah seperti keutamaan bubur atas semua jenis makanan.\""},"4694":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِي طُوَالَةَ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَضْلُ عَائِشَةَ عَلَى النِّسَاءِ كَفَضْلِ الثَّرِيدِ عَلَى سَائِرِ الطَّعَامِ","id":"Telah menceritakan kepada kami [Amru bin 'Aun] Telah menceritakan kepada kami [Khalid bin Abdullah] dari [Abu Thuwalah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Keutamaan Aisyah atas seluruh wanita adalah seperti keutamaan bubur atas semua makanan.\""},"4695":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُنِيرٍ سَمِعَ أَبَا حَاتِمٍ الْأَشْهَلَ بْنَ حَاتِمٍ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ ثُمَامَةَ بْنِ أَنَسٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَدَخَلْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى غُلَامٍ لَهُ خَيَّاطٍ فَقَدَّمَ إِلَيْهِ قَصْعَةً فِيهَا ثَرِيدٌ قَالَ وَأَقْبَلَ عَلَى عَمَلِهِ قَالَ فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَتَبَّعُ الدُّبَّاءَ قَالَ فَجَعَلْتُ أَتَتَبَّعُهُ فَأَضَعُهُ بَيْنَ يَدَيْهِقَالَ فَمَا زِلْتُ بَعْدُ أُحِبُّ الدُّبَّاءَ","id":"Telah menceritakan kepada kami [Abdullah bin Munir] Ia mendengar [Abu Hatim Al Asyhal bin Hatim] Telah menceritakan kepada kami [Ibnu 'Aun] dari [Tsumamah bin Anas] dari [Anas] Radliayallahu 'Anhu, ia berkata; Suatu ketika aku bersama Rasulullah shallallahu 'alaihi wasallam menemui seorang anak kecil yang memiliki penjahit. Kemudian sang penjahit itu menyuguhkan pada beliau hidangan yang berisikan bubur, lalu kembali meneruskan pekerjaannya. Kemudian Nabi shallallahu 'alaihi wasallam mencari-cari labunya dan mengunyahnya, maka aku pun ikut mengambil dan meletakkannya di depan beliau. Sejak itulah, aku menyukai labu."},"4696":{"ar":"حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى عَنْ قَتَادَةَ قَالَ كُنَّا نَأْتِي أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُوَخَبَّازُهُ قَائِمٌ قَالَ كُلُوا فَمَا أَعْلَمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَغِيفًا مُرَقَّقًا حَتَّى لَحِقَ بِاللَّهِ وَلَا رَأَى شَاةً سَمِيطًا بِعَيْنِهِ قَطُّ","id":"Telah menceritakan kepada kami [Hudbah bin Khalid] berkata; telah menceritakan kepada kami [Hammam bin Yahya] dari [Qatadah] ia berkata; \"Kami mendatangi [Anas bin Malik? radliallahu 'anhu] sementara pembuat rotinya berdiri. Ia lalu berkata; 'Makanlah. Sungguh aku tidak mengetahui bahwa Nabi shallallahu 'alaihi wasallam pernah melihat roti berkuah hingga bertemu dengan Allah. Dan beliau tidak pernah merasakan kambing bakar sama sekali.\""},"4697":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيِّ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْتَزُّ مِنْ كَتِفِ شَاةٍ فَأَكَلَ مِنْهَا فَدُعِيَ إِلَى الصَّلَاةِ فَقَامَ فَطَرَحَ السِّكِّينَ فَصَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ja'far bin Amru bin Umayyah Adl Dlamri] dari [Bapaknya] ia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam memotong-motong pundak kambing dan memakannya. Ketika panggilan shalat tiba, beliau langsung meletakkan pisaunya lalu melaksanakan shalat tanpa berwudlu lagi.\""},"4698":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ عَنْ أَبِيهِ قَالَ قُلْتُ لِعَائِشَةَأَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُؤْكَلَ لُحُومُ الْأَضَاحِيِّ فَوْقَ ثَلَاثٍ قَالَتْ مَا فَعَلَهُ إِلَّا فِي عَامٍ جَاعَ النَّاسُ فِيهِ فَأَرَادَ أَنْ يُطْعِمَ الْغَنِيُّ الْفَقِيرَ وَإِنْ كُنَّا لَنَرْفَعُ الْكُرَاعَ فَنَأْكُلُهُ بَعْدَ خَمْسَ عَشْرَةَ قِيلَ مَا اضْطَرَّكُمْ إِلَيْهِ فَضَحِكَتْ قَالَتْ مَا شَبِعَ آلُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خُبْزِ بُرٍّ مَأْدُومٍ ثَلَاثَةَ أَيَّامٍ حَتَّى لَحِقَ بِاللَّهِوَقَالَ ابْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَابِسٍ بِهَذَا","id":"Telah menceritakan kepada kami [Khallad bin Yahya] berkata; telah menceritakan kepada kami [Sufyan] dari ['Abdurrahman bin Abis] dari [Bapaknya] ia berkata; \"Aku bertanya kepada [Aisyah]; 'Apakah Nabi shallallahu 'alaihi wasallam melarang untuk makan daging sembelihan hari raya Adlha lebih dari tiga hari? ' Aisyah menjawab; \"Beliau tidak melakukan itu kecuali pada tahun paceklik (manusia kelaparan), sehingga beliau berharap orang kaya memberi makan kepada yang miskin. Dan sungguh, kami biasa makan lengan kambing setelah lima belas hari.\" Lalu dikatakan; 'Apa yang mendorong kalian melakukan itu? ' Aisyah tertawa, lalu ia berkata; 'Keluarga Muhammad shallallahu 'alaihi wasallam tidak pernah merasa kenyang karena makan roti atau gandum lebih dari tiga hari hingga beliau bertemu dengan Allah.' [Ibnu Katsir] berkata; telah mengabarkan kepada kami [Sufyan] berkata; telah menceritakan kepada kami ['Abdurrahman bin Abis] dengan hadits ini.'"},"4699":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَكُنَّا نَتَزَوَّدُ لُحُومَ الْهَدْيِ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمَدِينَةِتَابَعَهُ مُحَمَّدٌ عَنْ ابْنِ عُيَيْنَةَ وَقَالَ ابْنُ جُرَيْجٍ قُلْتُ لِعَطَاءٍ أَقَالَ حَتَّى جِئْنَا الْمَدِينَةَ قَالَ لَا","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] berkata; telah menceritakan kepada kami [Sufyan] dari [Amru] dari [Atha] dari [Jabir] ia berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam kami pernah berbekal dengan daging hadyu hingga sampai Madinah.\" Hadits ini dikuatkan oleh [Muhammad] dari [Ibnu Uyainah], dan [Ibnu Juraij] berkata; Aku bertanya kepada [Atha]; 'Apakah ia mengatakan; 'Hingga kami tiba Madinah? ' Ia menjawab; 'Tidak.'"},"4700":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو مَوْلَى الْمُطَّلِبِ بْنِ عَبْدِ اللَّهِ بْنِ حَنْطَبٍ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَبِي طَلْحَةَ الْتَمِسْ غُلَامًا مِنْ غِلْمَانِكُمْ يَخْدُمُنِي فَخَرَجَ بِي أَبُو طَلْحَةَ يُرْدِفُنِي وَرَاءَهُ فَكُنْتُ أَخْدُمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلَّمَا نَزَلَ فَكُنْتُ أَسْمَعُهُ يُكْثِرُ أَنْ يَقُولَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْهَمِّ وَالْحَزَنِ وَالْعَجْزِ وَالْكَسَلِ وَالْبُخْلِ وَالْجُبْنِ وَضَلَعِ الدَّيْنِ وَغَلَبَةِ الرِّجَالِ فَلَمْ أَزَلْ أَخْدُمُهُ حَتَّى أَقْبَلْنَا مِنْ خَيْبَرَ وَأَقْبَلَ بِصَفِيَّةَ بِنْتِ حُيَيٍّ قَدْ حَازَهَا فَكُنْتُ أَرَاهُ يُحَوِّي لَهَا وَرَاءَهُ بِعَبَاءَةٍ أَوْ بِكِسَاءٍ ثُمَّ يُرْدِفُهَا وَرَاءَهُ حَتَّى إِذَا كُنَّا بِالصَّهْبَاءِ صَنَعَ حَيْسًا فِي نِطَعٍ ثُمَّ أَرْسَلَنِي فَدَعَوْتُ رِجَالًا فَأَكَلُوا وَكَانَ ذَلِكَ بِنَاءَهُ بِهَا ثُمَّ أَقْبَلَ حَتَّى إِذَا بَدَا لَهُ أُحُدٌ قَالَ هَذَا جَبَلٌ يُحِبُّنَا وَنُحِبُّهُ فَلَمَّا أَشْرَفَ عَلَى الْمَدِينَةِ قَالَ اللَّهُمَّ إِنِّي أُحَرِّمُ مَا بَيْنَ جَبَلَيْهَا مِثْلَ مَا حَرَّمَ بِهِ إِبْرَاهِيمُ مَكَّةَ اللَّهُمَّ بَارِكْ لَهُمْ فِي مُدِّهِمْ وَصَاعِهِمْ","id":"Telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Ismail bin Ja'far] dari [Amru bin Abu Amru] mantan budak Al Muthallib bin Abdullah bin Hanthab, bahwa ia mendengar [Anas bin Malik] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda kepada Abu Thalhah: 'Berilah aku seorang pelayan lelaki dari yang kamu miliki hingga ia bisa membantuku.' Abu Thalhah lalu keluar dengan membawaku di belakang boncengannya. Aku lalu menjadi pelayan Rasulullah shallallahu 'alaihi wasallam. Setiap kali beliau singgah pada suatu tempat, beliau banyak membaca: 'ALLAHUMMA INNI A'UUDZUBIKA MINAL HAMMI WAL HAZANI WAL 'AJZI WAL KASALI WAL BUKHLI WAL JUBNI WA DLALA'ID DAINI WA 'ALAIHI WA GHALABATIR RIJAALI (Ya Allah, aku berlindung kepada-Mu dari keluh kesah dan kesedihan, dari kelemahan dan kemalasan, dari sifat bakhil dan penakut, dan dari lilitan hutang dan penindasan) '. Aku selalu melayani (keperluan) beliau hingga kembali dari Khaibar, beliau kembali dengan membawa (mengiring) Shafiyah binti Huyai. Dan aku lihat beliau menutupinya dengan kain kemudian memboncengkannya di belakang beliau. Sehingga ketika kami tiba di daerah Shahba`, beliau membuat hais dalam bejana dari kulit, kemudian beliau menyuruh agar aku mengundang para sahabat. Lalu mereka menyantap hidangan tersebut, maka itulah awal rumah tangga beliau dengannya. Kemudian beliau melanjutkan perjalanan, hingga ketika tiba di gunung Uhud, beliau bersabda: 'Ini adalah gunung yang kita mencintainya dan dia mencintai kita.' Ketika memasuki kota Madinah beliau mengatakan: 'Ya Allah, sesungguhnya aku mengharamkan apa yang ada di antara dua gunungnya (Madinah), sebagaimana Ibrahim mengharamkan (mensucikan) Makkah. Ya Allah, berkahilah mereka dalam mud dan sha' mereka.' "},"4701":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سَيْفُ بْنُ أَبِي سُلَيْمَانَ قَالَ سَمِعْتُ مُجَاهِدًا يَقُولُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبِي لَيْلَى أَنَّهُمْ كَانُوا عِنْدَ حُذَيْفَةَفَاسْتَسْقَى فَسَقَاهُ مَجُوسِيٌّ فَلَمَّا وَضَعَ الْقَدَحَ فِي يَدِهِ رَمَاهُ بِهِ وَقَالَ لَوْلَا أَنِّي نَهَيْتُهُ غَيْرَ مَرَّةٍ وَلَا مَرَّتَيْنِ كَأَنَّهُ يَقُولُ لَمْ أَفْعَلْ هَذَا وَلَكِنِّي سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَلْبَسُوا الْحَرِيرَ وَلَا الدِّيبَاجَ وَلَا تَشْرَبُوا فِي آنِيَةِ الذَّهَبِ وَالْفِضَّةِ وَلَا تَأْكُلُوا فِي صِحَافِهَا فَإِنَّهَا لَهُمْ فِي الدُّنْيَا وَلَنَا فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata; telah menceritakan kepada kami [Saif bin Abu Sulaiman] ia berkata; aku mendengar [Mujahid] berkata; telah menceritakan kepadaku ['Abdurrahman bin Abu Laila] bahwasanya mereka sedang berada di sisi [Hudzaifah], lalu ia (Hudzaifah) minta minum lantas seorang Majusi memberinya minum. Ketika Majusi tersebut meletakkan gelas pada tangannya, Hudzaifah langsung membuangnya seraya berkata; \"Kalau bukan karena aku telah melarang sekali atau dua kali, \" seakan ia mengatakan; 'Aku tidak akan melakukan ini (membuang gelas). Sungguh, aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: 'Janganlah kalian memakai sutera atau Dibaj (kain bersulam sutera), jangan minum dari bejana emas dan perak, dan jangan makan di baskom mereka, sesungguhnya barang-barang itu adalah untuk mereka di dunia dan untuk kita di akhirat kelak.'"},"4702":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْمُؤْمِنِ الَّذِي يَقْرَأُ الْقُرْآنَ كَمَثَلِ الْأُتْرُجَّةِ رِيحُهَا طَيِّبٌ وَطَعْمُهَا طَيِّبٌ وَمَثَلُ الْمُؤْمِنِ الَّذِي لَا يَقْرَأُ الْقُرْآنَ كَمَثَلِ التَّمْرَةِ لَا رِيحَ لَهَا وَطَعْمُهَا حُلْوٌ وَمَثَلُ الْمُنَافِقِ الَّذِي يَقْرَأُ الْقُرْآنَ مَثَلُ الرَّيْحَانَةِ رِيحُهَا طَيِّبٌ وَطَعْمُهَا مُرٌّ وَمَثَلُ الْمُنَافِقِ الَّذِي لَا يَقْرَأُ الْقُرْآنَ كَمَثَلِ الْحَنْظَلَةِ لَيْسَ لَهَا رِيحٌ وَطَعْمُهَا مُرٌّ","id":"Telah menceritakan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abu Awanah] dari [Qatadah] dari [Anas] dari [Abu Musa Al Asy'ari] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: 'Perumpamaan seorang Mukmin yang suka membaca Al Qur'an seperti buah Utrujah, baunya harum dan rasanya enak. Perumpamaan seorang Mukmin yang tidak suka membaca Al Qur'an seperti buah kurma, tidak berbau namun rasanya manis. Perumpamaan seorang Munafik yang suka membaca Al Qur'an seperti buah raihanah, baunya harum tapi rasanya pahit. Dan Perumpamaan seorang Munafik yang tidak suka membaca Al Qur'an seperti buah hanzhalah, tidak berbau dan rasanya pahit.'"},"4703":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَضْلُ عَائِشَةَ عَلَى النِّسَاءِ كَفَضْلِ الثَّرِيدِ عَلَى سَائِرِ الطَّعَامِ","id":"Telah menceritakan kepada kami [Musaddad] berkata; telah menceritakan kepada kami [Khalid] berkata; telah menceritakan kepada kami [Abdullah bin 'Abdurrahman] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kelebihan Aisyah dibanding dengan semua wanita, seperti kelebihan bubur atas semua makanan.\""},"4704":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مَالِكٌ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ السَّفَرُ قِطْعَةٌ مِنْ الْعَذَابِ يَمْنَعُ أَحَدَكُمْ نَوْمَهُ وَطَعَامَهُ فَإِذَا قَضَى نَهْمَتَهُ مِنْ وَجْهِهِ فَلْيُعَجِّلْ إِلَى أَهْلِهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata; telah menceritakan kepada kami [Malik] dari [Sumayy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Safar itu separuh dari siksaan, seseorang dari kalian akan terhalang untuk tidur dan makan. Jika telah selesai dari keperluannya, hendaklah ia segera kembali pada keluarganya.\""},"4705":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ رَبِيعَةَ أَنَّهُ سَمِعَ الْقَاسِمَ بْنَ مُحَمَّدٍ يَقُولُكَانَ فِي بَرِيرَةَ ثَلَاثُ سُنَنٍ أَرَادَتْ عَائِشَةُ أَنْ تَشْتَرِيَهَا فَتُعْتِقَهَا فَقَالَ أَهْلُهَا وَلَنَا الْوَلَاءُ فَذَكَرَتْ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَوْ شِئْتِ شَرَطْتِيهِ لَهُمْ فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ قَالَ وَأُعْتِقَتْ فَخُيِّرَتْ فِي أَنْ تَقِرَّ تَحْتَ زَوْجِهَا أَوْ تُفَارِقَهُ وَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا بَيْتَ عَائِشَةَ وَعَلَى النَّارِ بُرْمَةٌ تَفُورُ فَدَعَا بِالْغَدَاءِ فَأُتِيَ بِخُبْزٍ وَأُدْمٍ مِنْ أُدْمِ الْبَيْتِ فَقَالَ أَلَمْ أَرَ لَحْمًا قَالُوا بَلَى يَا رَسُولَ اللَّهِ وَلَكِنَّهُ لَحْمٌ تُصُدِّقَ بِهِ عَلَى بَرِيرَةَ فَأَهْدَتْهُ لَنَا فَقَالَ هُوَ صَدَقَةٌ عَلَيْهَا وَهَدِيَّةٌ لَنَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata; telah menceritakan kepada kami [Ismail bin Ja'far] dari [Rabi'ah] bahwasanya ia mendengar [Al Qasim bin Muhammad] berkata; \"Pada diri Barirah ada tiga sifat yang Aisyah ingin membeli lalu memerdekakannya. Keluarganya lalu berkata; 'Tetapi perwaliannya tetap untuk kami.' Maka [Aisyah] pun melaporkan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, beliau lalu bersabda: 'Jika mau, kamu bisa membuat persyaratan bagi mereka. Sesungguhnya perwalian itu adalah bagi orang yang memerdekakannya.' Al Qasim berkata; 'Kemudian Barirah dimerdekakan dan diberi pilihan untuk kembali kepada suaminya atau berpisah. Suatu ketika Rasulullah shallallahu 'alaihi wasallam masuk ke dalam rumah Aisyah, sementara di atas tungku ada periuk yang sedang mendidih. Beliau kemudian minta untuk disiapkan makanan pagi. Maka beliau pun diberi hidangan roti dan makanan pendampingnya (semacam kuah), lalu beliau pun bersabda: 'Sepertinya aku melihat daging? ' Mereka (yang ada di rumah) menjawab; 'Benar, wahai Rasulullah. Tetapi itu adalah daging yang disedekahkah kepada Barirah, lalu olehnya diberikan kepada kita! ' Beliau lantas bersabda: 'Daging itu bagi Barirah adalah sedekah, sedangkan untuk kita adalah hadiah.'"},"4706":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ عَنْ أَبِي أُسَامَةَ عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ الْحَلْوَاءَ وَالْعَسَلَ","id":"Telah menceritakan kepadaku [Ishaq bin Ibrahim Al Hanzhali] dari [Abu Usamah] dari [Hisyam] ia berkata; telah mengabarkan kepadaku [Bapakku] dari [Aisyah] radliallahu 'anha, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam menyukai manisan dan madu.\" "},"4707":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ شَيْبَةَ قَالَ أَخْبَرَنِي ابْنُ أَبِي الْفُدَيْكِ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَكُنْتُ أَلْزَمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِشِبَعِ بَطْنِي حِينَ لَا آكُلُ الْخَمِيرَ وَلَا أَلْبَسُ الْحَرِيرَ وَلَا يَخْدُمُنِي فُلَانٌ وَلَا فُلَانَةُ وَأُلْصِقُ بَطْنِي بِالْحَصْبَاءِ وَأَسْتَقْرِئُ الرَّجُلَ الْآيَةَ وَهِيَ مَعِي كَيْ يَنْقَلِبَ بِي فَيُطْعِمَنِي وَخَيْرُ النَّاسِ لِلْمَسَاكِينِ جَعْفَرُ بْنُ أَبِي طَالِبٍ يَنْقَلِبُ بِنَا فَيُطْعِمُنَا مَا كَانَ فِي بَيْتِهِ حَتَّى إِنْ كَانَ لَيُخْرِجُ إِلَيْنَا الْعُكَّةَ لَيْسَ فِيهَا شَيْءٌ فَنَشْتَقُّهَا فَنَلْعَقُ مَا فِيهَا","id":"Telah menceritakan kepada kami ['Abdurrahman bin Syaibah] ia berkata; telah mengabarkan kepadaku [Ibnu Abu Al Fudaik] dari [Ibnu Dzi'b] dari [Al Maqburi] dari [Abu Hurairah] ia berkata; \"Aku selalu menemani Nabi shallallahu 'alaihi wasallam dalam keadaan perut kenyang (merasa kenyang meskipun lapar, pent), sehingga aku tidak dapat makan roti, tidak bisa mengenakan kain sutera dan tidak memiliki pelayan yang bisa membantuku. Bahkan aku mengganjal perutku dengan kerikil, dan aku minta orang lain agar aku bisa membacakan ayat kepadanya sehingga ia bisa memberiku sesuatu yang aku makan. Dan sebaik-baik manusia bagi orang miskin adalah Ja'far bin Abu Thalib, ia pulang ke rumah dengan mengajak kami lalu memberi kami makan dengan apa yang ada di dalam rumahnya. Sampai-sampai ia mengeluarkan 'Ukkah (tempat air terbuat dari kulit) yang sudah tidak ada isinya lagi, kami lalu membelah dan menjilati apa yang ada di dalamnya.\""},"4708":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا أَزْهَرُ بْنُ سَعْدٍ عَنْ ابْنِ عَوْنٍ عَنْ ثُمَامَةَ بْنِ أَنَسٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى مَوْلًى لَهُ خَيَّاطًا فَأُتِيَ بِدُبَّاءٍ فَجَعَلَ يَأْكُلُهُ فَلَمْ أَزَلْ أُحِبُّهُ مُنْذُ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُهُ","id":"Telah menceritakan kepada kami [Amru bin Ali] berkata; telah menceritakan kepada kami [Azhar bin Sa'd] dari [Ibnu Aun] dari [Tsumamah bin Anas] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam mendatangi seorang penjahit pernah menjadi budaknya. Beliau lalu diberi buah labu yang kemudian memakannya, maka aku selalu menyukainya semenjak aku melihat beliau memakannya.\""},"4709":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَكَانَ مِنْ الْأَنْصَارِ رَجُلٌ يُقَالُ لَهُ أَبُو شُعَيْبٍ وَكَانَ لَهُ غُلَامٌ لَحَّامٌ فَقَالَ اصْنَعْ لِي طَعَامًا أَدْعُو رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَامِسَ خَمْسَةٍ فَدَعَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَامِسَ خَمْسَةٍ فَتَبِعَهُمْ رَجُلٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكَ دَعَوْتَنَا خَامِسَ خَمْسَةٍ وَهَذَا رَجُلٌ قَدْ تَبِعَنَا فَإِنْ شِئْتَ أَذِنْتَ لَهُ وَإِنْ شِئْتَ تَرَكْتَهُ قَالَ بَلْ أَذِنْتُ لَهُقَالَ مُحَمَّدُ بْنُ يُوسُفَ سَمِعْتُ مُحَمَّدَ بْنَ إِسْمَاعِيْلَ يَقُولُ إِذَا كَانَ الْقَوْمُ عَلَى الْمَائِدَةِ لَيْسَ لَهُمْ أَنْ يُنَاوِلُوا مِنْ مَائِدَةٍ إِلَى مَائِدَةٍ أُخْرَى وَلَكِنْ يُنَاوِلُ بَعْضُهُمْ بَعْضًا فِي تِلْكَ الْمَائِدَةِ أَوْ يَدَعُ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] berkata; telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Wail] dari [Abu Mas'ud Al Anshari] ia berkata; \"Ada seorang laki-laki yang bernama Abu Syu'aib dari kalangan Anshar, ia mempunyai seorang budak yang pandai memasak daging, ia lalu berkata kepada budaknya; 'Buatlah makanan dengan lima porsi, aku ingin mengundang Rasulullah shallallahu 'alaihi wasallam.' Ia lalu mengundang Rasulullah shallallahu 'alaihi wasallam dengan sejumlah lima porsi tersebut. Lalu ada seorang laki-laki yang mengikuti beliau, maka Nabi shallallahu 'alaihi wasallam pun bersabda: 'Engkau mengundang kami dengan lima porsi, padahal ini ada seorang laki-laki (lain) yang ingin ikut. Sekarang terserah kamu, memberi izin atau tidak.' Abu Syu'aib menjawab; 'Aku memberinya izin.' Muhammad bin Yusuf berkata; Aku mendengar Muhammad bin Ismail berkata; 'Jika suatu kaum berada dalam suatu meja makan, maka mereka tidak memindahkannya ke meja makan yang lainnya. Namun, sebagian mereka mengambilkan untuk sebagian yang lain dalam satu meja tersebut, atau mereka tidak mengambilnya.'"},"4710":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُنِيرٍ سَمِعَ النَّضْرَ أَخْبَرَنَا ابْنُ عَوْنٍ قَالَ أَخْبَرَنِي ثُمَامَةُ بْنُ عَبْدِ اللَّهِ بْنِ أَنَسٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ غُلَامًا أَمْشِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى غُلَامٍ لَهُ خَيَّاطٍ فَأَتَاهُ بِقَصْعَةٍ فِيهَا طَعَامٌ وَعَلَيْهِ دُبَّاءٌ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَتَبَّعُ الدُّبَّاءَ قَالَ فَلَمَّا رَأَيْتُ ذَلِكَ جَعَلْتُ أَجْمَعُهُ بَيْنَ يَدَيْهِ قَالَ فَأَقْبَلَ الْغُلَامُ عَلَى عَمَلِهِقَالَ أَنَسٌ لَا أَزَالُ أُحِبُّ الدُّبَّاءَ بَعْدَ مَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَنَعَ مَا صَنَعَ","id":"Telah menceritakan kepadaku [Abdullah bin Munir]; ia mendengar [An Nadlr]; telah mengabarkan kepada kami [Ibnu Aun] ia berkata; telah mengabarkan kepadaku [Tsumamah bin Abdullah bin Anas] dari [Anas] radliallahu 'anhu, ia berkata; \"Aku berjalan bersama Rasulullah shallallahu 'alaihi wasallam, padahal aku masih seorang bocah. Beliau lalu menemui budaknya yang tukang jahit, budak itu kemudian menghidangkan kepada beliau makanan dalam sebuah bejana yang di antaranya adalah buah labu. Beliau lalu memilih-milih buah tersebut (untuk dimakan).\" Anas berkata, \"Ketika aku melihat beliau seperti itu, maka aku pun mengambil dan meletakkannya di hadapannya. Sementara budak tersebut kembali mengerjakan pekerjaannya.\" Anas berkata, \"Maka aku sangat menyukai buah labu semenjak aku melihat Rasulullah shallallahu 'alaihi wasallam melakukan hal tersebut.\""},"4711":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍأَنَّ خَيَّاطًا دَعَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِطَعَامٍ صَنَعَهُ فَذَهَبْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَّبَ خُبْزَ شَعِيرٍ وَمَرَقًا فِيهِ دُبَّاءٌ وَقَدِيدٌ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَتَبَّعُ الدُّبَّاءَ مِنْ حَوَالَيْ الْقَصْعَةِفَلَمْ أَزَلْ أُحِبُّ الدُّبَّاءَ بَعْدَ يَوْمِئِذٍ","id":"Telah menceritakan kepada kami [Abdullah bin Salamah] dari [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] Bahwasanya ia mendengar [Anas bin Malik] berkata, \"Seorang tukang jahit mengundang Nabi shallallahu 'alaihi wasallam untuk menghadiri jamuan yang ia masak. Aku lalu pergi bersama Nabi shallallahu 'alaihi wasallam memenuhi undangan tersebut, penjahit itu lalu menyodorkan roti gandum dan kuah yang di dalamnya ada labu dan daging yang telah dikeringkan. Aku melihat Nabi shallallahu 'alaihi wasallam memilih-milih buah labu di dalam bejana tersebut, maka setelah hari itu aku sangat menyukai buah labu.\""},"4712":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِمَرَقَةٍ فِيهَا دُبَّاءٌ وَقَدِيدٌ فَرَأَيْتُهُ يَتَتَبَّعُ الدُّبَّاءَ يَأْكُلُهَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Ishaq bin Abdullah] dari [Anas] radliallahu 'anhu, ia berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam diberi hidangan kuah yang di dalamnya ada buah labu dan daging yang telah dikeringkan, dan aku lihat beliau memilih-milih buah labu lalu memakannya.\""},"4713":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَا فَعَلَهُ إِلَّا فِي عَامٍ جَاعَ النَّاسُ أَرَادَ أَنْ يُطْعِمَ الْغَنِيُّ الْفَقِيرَ وَإِنْ كُنَّا لَنَرْفَعُ الْكُرَاعَ بَعْدَ خَمْسَ عَشْرَةَ وَمَا شَبِعَ آلُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خُبْزِ بُرٍّ مَأْدُومٍ ثَلَاثًا","id":"Telah menceritakan kepada kami [Qabishah] berkata, telah menceritakan kepada kami [Sufyan] dari ['Abdurrahman bin Abis] dari [Bapaknya] dari [Aisyah] radliallahu 'anhuma, ia berkata, \"Beliau tidak pernah melakukannya kecuali di saat paceklik yang manusia semuanya dalam keadaan lapar, beliau ingin orang kaya memberi makan kepada yang miskin. Dan sungguh, kami memakan kaki kambing setelah lima belas hari, dan keluarga Muhammad shallallahu 'alaihi wasallam tidak pernah merasa kenyang dengan roti gandum berkuah selama tiga hari terturut-turut.\""},"4714":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُإِنَّ خَيَّاطًا دَعَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِطَعَامٍ صَنَعَهُ قَالَ أَنَسٌ فَذَهَبْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى ذَلِكَ الطَّعَامِ فَقَرَّبَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُبْزًا مِنْ شَعِيرٍ وَمَرَقًا فِيهِ دُبَّاءٌ وَقَدِيدٌ قَالَ أَنَسٌ فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَتَبَّعُ الدُّبَّاءَ مِنْ حَوْلِ الصَّحْفَةِفَلَمْ أَزَلْ أُحِبُّ الدُّبَّاءَ مِنْ يَوْمِئِذٍ وَقَالَ ثُمَامَةُ عَنْ أَنَسٍ فَجَعَلْتُ أَجْمَعُ الدُّبَّاءَ بَيْنَ يَدَيْهِ","id":"Telah menceritakan kepada kami [Ismail] ia berkata; telah menceritakan kepadaku [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] Bahwasanya ia mendengar [Anas bin Malik] berkata, \"Seorang tukang jahit mengundang Rasulullah shallallahu 'alaihi wasallam menghadiri jamuan makan yang ia buat. Aku lalu berangkat bersama Nabi shallallahu 'alaihi wasallam memenuhi undangan tersebut. Penjahit itu kemudian menyodorkan roti gandum dan kuah yang di dalamnya terdapat buah labu dan daging yang telah dikeringkan kepada Rasulullah shallallahu 'alaihi wasallam.\" Anas berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam memilih-milih buah labu dalam bejana tersebut, maka aku selalu menyukai labu setelah hari itu.\" [Tsumamah] menyebutkan dari [Anas], \"Aku lalu mengumpulkan buah labu ke hadapan beliau.\""},"4715":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرِ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ الرُّطَبَ بِالْقِثَّاءِ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] ia berkata; telah menceritakan kepadaku [Ibrahim bin Sa'd] dari [Bapaknya] dari [Abdullah bin Ja'far bin Abu Thalib] radliallahu 'anhuma, ia berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam makan buah kurma segar dengan qitsa` (semacam mentimun).\""},"4716":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَبَّاسٍ الْجُرَيْرِيِّ عَنْ أَبِي عُثْمَانَ قَالَ تَضَيَّفْتُ أَبَا هُرَيْرَةَسَبْعًا فَكَانَ هُوَ وَامْرَأَتُهُ وَخَادِمُهُ يَعْتَقِبُونَ اللَّيْلَ أَثْلَاثًا يُصَلِّي هَذَا ثُمَّ يُوقِظُ هَذَا وَسَمِعْتُهُ يَقُولُ قَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَصْحَابهِ تَمْرًا فَأَصَابَنِي سَبْعُ تَمَرَاتٍ إِحْدَاهُنَّ حَشَفَةٌ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Abbas Al Jurairi] dari [Abu Utsman] ia berkata, \"Aku bertamu ke rumah [Abu Hurairah] selama tujuh hari. Dia bersama istri dan pembantunya membagi malam menjadi tiga bagian, shalat di sebagian waktu dan tidur di sebagian waktu. Dan aku mendengar ia berkata, \"Rasulullah shallallahu 'alaihi wasallam membagi-bagikan kurma kepada para sahabatnya, aku lalu mendapat bagian tujuh butir yang satu diantaranya sudah rusak (busuk).\""},"4717":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا إِسْمَاعِيلُ بْنُ زَكَرِيَّاءَ عَنْ عَاصِمٍ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُقَسَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَنَا تَمْرًا فَأَصَابَنِي مِنْهُ خَمْسٌ أَرْبَعُ تَمَرَاتٍ وَحَشَفَةٌ ثُمَّ رَأَيْتُ الْحَشَفَةَ هِيَ أَشَدُّهُنَّ لِضِرْسِي","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah] berkata, telah menceritakan kepada kami [Ismail bin Zakaria] dari [Ashim] dari [Abu Utsman] dari [Abu Hurairah] radliallahu 'anhu, bahwa Rasulullah shallallahu 'alaihi wasallam membagi-bagikan kurma kepada kami, lalu aku mendapat bagian lima biji, empat masih dalam keadaan bagus dan satu telah rusak. Maka, satu biji itulah yang membuat gigiku susah untuk mengunyahnya.\""},"4718":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْن أَبِي رَبِيعَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ بِالْمَدِينَةِ يَهُودِيٌّ وَكَانَ يُسْلِفُنِي فِي تَمْرِي إِلَى الْجِدَادِ وَكَانَتْ لِجَابِرٍ الْأَرْضُ الَّتِي بِطَرِيقِ رُومَةَ فَجَلَسَتْ فَخَلَا عَامًا فَجَاءَنِي الْيَهُودِيُّ عِنْدَ الْجَدَادِ وَلَمْ أَجُدَّ مِنْهَا شَيْئًا فَجَعَلْتُ أَسْتَنْظِرُهُ إِلَى قَابِلٍ فَيَأْبَى فَأُخْبِرَ بِذَلِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِأَصْحَابِهِ امْشُوا نَسْتَنْظِرْ لِجَابِرٍ مِنْ الْيَهُودِيِّ فَجَاءُونِي فِي نَخْلِي فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَلِّمُ الْيَهُودِيَّ فَيَقُولُ أَبَا الْقَاسِمِ لَا أُنْظِرُهُ فَلَمَّا رَأَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فَطَافَ فِي النَّخْلِ ثُمَّ جَاءَهُ فَكَلَّمَهُ فَأَبَى فَقُمْتُ فَجِئْتُ بِقَلِيلِ رُطَبٍ فَوَضَعْتُهُ بَيْنَ يَدَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكَلَ ثُمَّ قَالَ أَيْنَ عَرِيشُكَ يَا جَابِرُ فَأَخْبَرْتُهُ فَقَالَ افْرُشْ لِي فِيهِ فَفَرَشْتُهُ فَدَخَلَ فَرَقَدَ ثُمَّ اسْتَيْقَظَ فَجِئْتُهُ بِقَبْضَةٍ أُخْرَى فَأَكَلَ مِنْهَا ثُمَّ قَامَ فَكَلَّمَ الْيَهُودِيَّ فَأَبَى عَلَيْهِ فَقَامَ فِي الرِّطَابِ فِي النَّخْلِ الثَّانِيَةَ ثُمَّ قَالَ يَا جَابِرُ جُدَّ وَاقْضِ فَوَقَفَ فِي الْجَدَادِ فَجَدَدْتُ مِنْهَا مَا قَضَيْتُهُ وَفَضَلَ مِنْهُ فَخَرَجْتُ حَتَّى جِئْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَشَّرْتُهُ فَقَالَ أَشْهَدُ أَنِّي رَسُولُ اللَّهِ عُرُوشٌ وَعَرِيشٌ بِنَاءٌ وَقَالَ ابْنُ عَبَّاسٍ{ مَعْرُوشَاتٍ }مَا يُعَرَّشُ مِنْ الْكُرُومِ وَغَيْرِ ذَلِكَ يُقَالُ عُرُوشُهَا أَبْنِيَتُهَا","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] berkata, telah menceritakan kepada kami [Abu Ghassan] ia berkata; telah menceritakan kepadaku [Abu Hazim] dari [Ibrahim bin 'Abdurrahman bin Abdullah bin Abu Rabi'ah] dari [Jabir bin Abdullah] radliallahu 'anhuma, ia berkata, \"Di Madinah ada seorang Yahudi yang meminjamiku setandan kurma-dan Jabir sendiri memiliki kebun yang ada di jalan menuju Ruumah (nama tempat), namun tidak berbuah selama setahun-, orang Yahudi itu kemudian datang kepadaku meminta pembayaran kurma, namun aku tidak mendapatkannya. Maka aku minta tenggang waktu hingga tahun mendatang tetapi ia menolak. Maka aku mengabarkan hal itu kepada Nabi shallallahu 'alaihi wasallam, beliau lalu bersabda kepada para sahabatnya: \"Berjalanlah. Kita minta penangguhan kepada Yahudi itu untuk Jabir.\" Mereka kemudian mendatangiku di kebun milikku, beliau lalu berbicara dengan Yahudi tersebut hingga Yahudi itu pun berkata, \"Wahai Abul Qasim, aku tidak akan memberinya tenggang waktu.\" Ketika Nabi shallallahu 'alaihi wasallam melihat hal itu, beliau lalu bangkit dan mengelilingi kebun kurma tersebut, kemudian beliau mendatangi Yahudi itu dan bernegosisasi, namun Yahudi itu tetap tidak mau (memberi penangguhan). Aku lalu berdiri dan membawakan sedikit kurma dan meletakkan di depan Nabi shallallahu 'alaihi wasallam, lalu beliau pun memakannya. Setelah itu beliau bersabda: \"Wahai Jabir, dimana tenda tempat kamu berteduh?\" Aku lalu mengabarkannya. Beliau berkata lagi: \"Siapkanlah untukku.\" Maka aku pun menyiapkan tenda tersebut untuk beliau, beliau kemudian masuk dan tidur. Setelah bangun, aku kembali menemui beliau dengan membawa segenggam kurma, beliau lalu memakannya. Kemudian beliau berdiri dan bernegoisasi dengan orang Yahudi tersebut namun ia tetap menolak. Kemudian beliau kembali mengelilingi kebun kurma tersebut dan berkata: \"Wahai Jabir, goyangkanlah (pohon kurma) dan gantilah untuknya.\" Aku lalu menghampiri batang kurma dan menggoyangnya dan mengambil sesuatu yang akan aku gunakan untuk menggantinya. Dan ternyata lebih, aku lalu keluar dan menemui Nabi shallallahu 'alaihi wasallam untuk mengabarkan kepadanya. Beliau lalu bersabda: \"Sesungguhnya aku bersaksi bahwa aku adalah utusan Allah. lafazh 'Urusy dan 'Arisy bisa berarti sebuah bangunan. Ibnu Abbas berkata mengenai firman Allah: MA'RUSYAAT, (Al An'am: 141): apa saja yang bisa menaungi dari pepohonan."},"4719":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي مُجَاهِدٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَبَيْنَا نَحْنُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جُلُوسٌ إِذَا أُتِيَ بِجُمَّارِ نَخْلَةٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ الشَّجَرِ لَمَا بَرَكَتُهُ كَبَرَكَةِ الْمُسْلِمِ فَظَنَنْتُ أَنَّهُ يَعْنِي النَّخْلَةَ فَأَرَدْتُ أَنْ أَقُولَ هِيَ النَّخْلَةُ يَا رَسُولَ اللَّهِ ثُمَّ الْتَفَتُّ فَإِذَا أَنَا عَاشِرُ عَشَرَةٍ أَنَا أَحْدَثُهُمْ فَسَكَتُّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هِيَ النَّخْلَةُ","id":"Telah menceritakan kepada kami [Umar bin Hafsh bin Ghiyats] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Al A'masy] ia berkata; telah menceritakan kepadaku [Mujahid] dari [Abdullah bin Umar] radliallahu 'anhuma, ia berkata, \"Ketika kami sedang duduk di sisi Nabi shallallahu 'alaihi wasallam, lalu dihidangkanlah kurma yang sudah kering. Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Sesungguhnya di antara pepohonan itu ada satu jenis pohon yang keberkahannya seperti seorang Muslim.\" Lalu aku mempunyai perkiraan bahwa pohon itu adalah pohon kurma, aku berkeinginan menjawab; 'Wahai Rasulullah, itu adalah pohon kurma', namun aku melihat bahwa di antara sepuluh orang yang ada aku adalah yang paling muda. Maka aku pun diam. Nabi shallallahu 'alaihi wasallam kemudian bersabda: \"Yaitu pohon kurma.\""},"4720":{"ar":"حَدَّثَنَا جُمْعَةُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مَرْوَانُ أَخْبَرَنَا هَاشِمُ بْنُ هَاشِمٍ أَخْبَرَنَا عَامِرُ بْنُ سَعْدٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَصَبَّحَ كُلَّ يَوْمٍ سَبْعَ تَمَرَاتٍ عَجْوَةً لَمْ يَضُرَّهُ فِي ذَلِكَ الْيَوْمِ سُمٌّ وَلَا سِحْرٌ","id":"Telah menceritakan kepada kami [Jum'ah bin Abdullah] berkata, telah menceritakan kepada kami [Marwan] berkata, telah mengabarkan kepada kami [Hasyim bin Hasyim] berkata, telah mengabarkan kepada kami [Amir bin Sa'd] dari [Bapaknya] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa setiap pagi mengkonsumsi tujuh butir kurma 'Ajwah, maka pada hari itu ia akan terhindar dari racun dan sihir.\""},"4721":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا جَبَلَةُ بْنُ سُحَيْمٍ قَالَأَصَابَنَا عَامُ سَنَةٍ مَعَ ابْنِ الزُّبَيْرِ فَرَزَقَنَا تَمْرًا فَكَانَ عَبْدُ اللَّهِ بْنُ عُمَرَ يَمُرُّ بِنَا وَنَحْنُ نَأْكُلُ وَيَقُولُ لَا تُقَارِنُوا فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْقِرَانِ ثُمَّ يَقُولُ إِلَّا أَنْ يَسْتَأْذِنَ الرَّجُلُ أَخَاهُقَالَ شُعْبَةُ الْإِذْنُ مِنْ قَوْلِ ابْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Syu'bah] berkata, telah menceritakan kepada kami [Jabalah bin Suhaim] ia berkata, \"Kami mengalami kesulitan (paceklik) bersama Ibnu Zubair, Abdullah bin Umar lalu memberikan kami kurma. Saat kami makan [Abdullah bin Umar] lewat di hadapan kami, maka ia pun berkata; \"Janganlah kalian berserikat (menggabungkan kurma saat makan). Sesungguhnya Nabi shallallahu 'alaihi wasallam melarang untuk berserikat.\" Kemudian ia mengatakan lagi, \"Kecuali jika ia minta izin kepada temannya.\" Syu'bah berkata, \"Lafadz 'izin' ini adalah ucapan Ibnu Umar.\""},"4722":{"ar":"حَدَّثَنِي إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ جَعْفَرٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ الرُّطَبَ بِالْقِثَّاءِ","id":"Telah menceritakan kepadaku [Isma'il bin Abdullah] ia berkata; telah menceritakan kepadaku [Ibrahim bin Sa'd] dari [Bapaknya] ia berkata, \"Aku mendengar [Abdullah bin Ja'far] berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam makan kurma segar dengan qitsa` (sejenis mentimun).\""},"4723":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مُحَمَّدُ بْنُ طَلْحَةَ عَنْ زُبَيْدٍ عَنْ مُجَاهِدٍ قَالَ سَمِعْتُ ابْنَ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ الشَّجَرِ شَجَرَةً تَكُونُ مِثْلَ الْمُسْلِمِ وَهِيَ النَّخْلَةُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Muhammad bin Thalhah] dari [Zubaid] dari [Mujahid] ia berkata, \"Aku mendengar [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya di antara jenis pohon ada yang seperti seorang Muslim (keberkahannya), yaitu pohon kurma.\""},"4724":{"ar":"حَدَّثَنَا ابْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ الرُّطَبَ بِالْقِثَّاءِ","id":"Telah menceritakan kepada kami [Ibnu Muqatil] berkata, telah mengabarkan kepada kami [Abdullah] berkata, telah mengabarkan kepada kami [Ibrahim bin Sa'd] dari [Bapaknya] dari [Abdullah bin Ja'far] radliallahu 'anhuma, ia berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam makan kurma segar dengan qitsa` (sejenis mentimun).\""},"4725":{"ar":"حَدَّثَنَا الصَّلْتُ بْنُ مُحَمَّدٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ الْجَعْدِ أَبِي عُثْمَانَ عَنْ أَنَسٍ ح وَعَنْ هِشَامٍ عَنْ مُحَمَّدٍ عَنْ أَنَسٍ وَعَنْ سِنَانٍ أَبِي رَبِيعَةَ عَنْ أَنَسٍأَنَّ أُمَّ سُلَيْمٍ أُمَّهُ عَمَدَتْ إِلَى مُدٍّ مِنْ شَعِيرٍ جَشَّتْهُ وَجَعَلَتْ مِنْهُ خَطِيفَةً وَعَصَرَتْ عُكَّةً عِنْدَهَا ثُمَّ بَعَثَتْنِي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُهُ وَهُوَ فِي أَصْحَابِهِ فَدَعَوْتُهُ قَالَ وَمَنْ مَعِي فَجِئْتُ فَقُلْتُ إِنَّهُ يَقُولُ وَمَنْ مَعِي فَخَرَجَ إِلَيْهِ أَبُو طَلْحَةَ قَالَ يَا رَسُولَ اللَّهِ إِنَّمَا هُوَ شَيْءٌ صَنَعَتْهُ أُمُّ سُلَيْمٍ فَدَخَلَ فَجِيءَ بِهِ وَقَالَ أَدْخِلْ عَلَيَّ عَشَرَةً فَدَخَلُوا فَأَكَلُوا حَتَّى شَبِعُوا ثُمَّ قَالَ أَدْخِلْ عَلَيَّ عَشَرَةً فَدَخَلُوا فَأَكَلُوا حَتَّى شَبِعُوا ثُمَّ قَالَ أَدْخِلْ عَلَيَّ عَشَرَةً حَتَّى عَدَّ أَرْبَعِينَ ثُمَّ أَكَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَامَ فَجَعَلْتُ أَنْظُرُ هَلْ نَقَصَ مِنْهَا شَيْءٌ","id":"Telah menceritakan kepada kami [Ash Shalt bin Muhammad] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Al Ja'd Abu Utsman] dari [Anas]. (dalam jalur lain disebutkan) dan dari [Hisyam] dari [Muhammad] dari [Anas] dari [Sinan Abu Rabi'ah] dari [Anas] bahwa Ummu Sulaim, ibunya, membuat makanan dengan satu mud gandum dan membuatnya semacam adonan, lalu ia memerah susu satu bejana (kecil dari kulit). Kemudian ia menyuruhku menemui Nabi shallallahu 'alaihi wasallam, aku lalu mendatangi beliau yang saat itu sedang bersama para sahabatnya. Kemudian aku mengundangnya. Beliau bertanya: \"Bersama semua (orang) yang bersamaku ini?\" aku lalu kembali dan menyampaikan, \"Sesungguhnya beliau mengatakan 'Bersama semua orang yang bersamaku? ' Abu Thalhah kemudian keluar menemui Rasulullah, ia berkata, \"Wahai Rasulullah, itu hanyalah sesuatu (makanan ala kadarnya) yang dibuat oleh Ummu Sulaim.\" Beliau lalu masuk dan makanan tersebut dibawa ke hadapan beliau, lalu beliau bersabda: \"Suruhlah sepuluh orang untuk masuk bersamaku.\" Mereka lalu masuk dan makan hingga kenyang. Beliau lalu bersabda lagi: \"Suruhlah sepuluh orang untuk masuk bersamaku.\" Mereka lalu masuk dan makan hingga kenyang. Beliau bersabda lagi: \"Suruhlah sepuluh orang untuk masuk bersamaku.\" Sehingga jumlah mereka mencapai empat puluh orang. Nabi shallallahu 'alaihi wasallam kemudian makan dan setelah itu beliau pergi. Maka aku pun melihat, tapi kenapa tidak ada yang berkurang darinya sedikitpun.\""},"4726":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ قَالَ قِيلَ لِأَنَسٍمَا سَمِعْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي الثُّومِ فَقَالَ مَنْ أَكَلَ فَلَا يَقْرَبَنَّ مَسْجِدَنَا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abdul Warits] dari [Abdul Aziz] ia berkata; Ditanyakan kepada [Anas], \"Apakah kamu pernah mendengar Nabi shallallahu 'alaihi wasallam menyebutkan tentang buah bawang?\" Beliau mengatakan: \"Barangsiapa memakannya, maka jangan sekali-kali ia mendekati tempat shalat kami.\""},"4727":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو صَفْوَانَ عَبْدُ اللَّهِ بْنُ سَعِيدٍ أَخْبَرَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي عَطَاءٌ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَازَعَمَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَكَلَ ثُومًا أَوْ بَصَلًا فَلْيَعْتَزِلْنَا أَوْ لِيَعْتَزِلْ مَسْجِدَنَا","id":"Telah menceritakan kepada kami [Ali bin Abdullah] berkata, telah menceritakan kepada kami [Abu Shafwan Abdullah bin Sa'id] berkata, telah mengabarkan kepada kami [Yunus] dari [Ibnu Syihab] ia berkata; telah menceritakan kepadaku [Atha] bahwa [Jabir bin Abdullah] radliallahu 'anhuma menyakini dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa makan bawang merah atau bawang putih, hendaklah ia menjauhi kami, atau beliau mengatakan, \"Hendaklah ia menjauhi tempat shalat kami.\""},"4728":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ قَالَ أَخْبَرَنِي جَابِرُ بْنُ عَبْدِ اللَّهِ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَرِّ الظَّهْرَانِ نَجْنِي الْكَبَاثَ فَقَالَ عَلَيْكُمْ بِالْأَسْوَدِ مِنْهُ فَإِنَّهُ أَيْطَبُ فَقَالَ أَكُنْتَ تَرْعَى الْغَنَمَ قَالَ نَعَمْ وَهَلْ مِنْ نَبِيٍّ إِلَّا رَعَاهَا","id":"Telah menceritakan kepada kami [Sa'id bin Ufair] berkata, telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] ia berkata; telah mengabarkan kepadaku [Abu Salamah] ia berkata; telah mengabarkan kepadaku [Jabir bin Abdullah] ia berkata, \"Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam di Marru Azh Zhahran memetik biji pohon Arok (pohon siwak), beliau lalu bersabda: \"Hendaklah kalian mengambil biji hitam buah itu, sebab ia sangat bagus.\" Jabir lalu bertanya; \"Apakah engkau mengembala kambing?\" Beliau menjawab: \"Ya. Tidak ada seorang Nabi kecuali ia mengembala.\""},"4729":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ سَمِعْتُ يَحْيَى بْنَ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ سُوَيْدِ بْنِ النُّعْمَانِ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى خَيْبَرَ فَلَمَّا كُنَّا بِالصَّهْبَاءِ دَعَا بِطَعَامٍ فَمَا أُتِيَ إِلَّا بِسَوِيقٍ فَأَكَلْنَا فَقَامَ إِلَى الصَّلَاةِ فَتَمَضْمَضَ وَمَضْمَضْنَاقَالَ يَحْيَى سَمِعْتُ بُشَيْرًا يَقُولُ حَدَّثَنَا سُوَيْدٌ خَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى خَيْبَرَ فَلَمَّا كُنَّا بِالصَّهْبَاءِ قَالَ يَحْيَى وَهِيَ مِنْ خَيْبَرَ عَلَى رَوْحَةٍ دَعَا بِطَعَامٍ فَمَا أُتِيَ إِلَّا بِسَوِيقٍ فَلُكْنَاهُ فَأَكَلْنَا مَعَهُ ثُمَّ دَعَا بِمَاءٍ فَمَضْمَضَ وَمَضْمَضْنَا مَعَهُ ثُمَّ صَلَّى بِنَا الْمَغْرِبَ وَلَمْ يَتَوَضَّأْ وَقَالَ سُفْيَانُ كَأَنَّكَ تَسْمَعُهُ مِنْ يَحْيَى","id":"Telah menceritakan kepada kami [Ali] berkata, telah menceritakan kepada kami [Sufyan] aku mendengar [Yahya bin Sa'id] dari [Busyair bin Yasar] dari [Suwaid bin An Nu'man] ia berkata, \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam menuju Khaibar, ketika sampai di Shahba`, beliau minta disiapkan makanan. Dan beliau tidak diberi kecuali hanya sawiq (tepung gandum yang dicampur dengan air), kami lalu memakannya. Beliau kemudian berdiri untuk melaksanakan shalat, beliau berkumur lalu kami pun ikut berkumur.\" Yahya berkata; Aku mendengar Busyair berkata; telah menceritakan kepada kami Suwaid berkata, \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam menuju Khaibar, ketika kami sampai di Shahba` -Yahya berkata; jaraknya dengan Khaibar hanya beberapa mil-, beliau minta untuk disiapkan makanan. Dan beliau tidak diberi hidangan kecuali hanya sawiq, kami lalu makan bersama beliau. Kemudian beliau minta diambilkan air, beliau lalu berkumur dan kami pun mengikutinya berkumur, kemudian beliau mengimami kami shalat Maghrib dan tidak berwudlu lagi.\" Sufyan berkata, \"Sepertinya kamu mendengarnya dari Yahya.\""},"4730":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَكَلَ أَحَدُكُمْ فَلَا يَمْسَحْ يَدَهُ حَتَّى يَلْعَقَهَا أَوْ يُلْعِقَهَا","id":"Telah menceritakan kepada kami [Ali bin Abdullah] berkata, telah menceritakan kepada kami [Sufyan] dari [Amru bin Dinar] dari [Atha] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian makan, maka janganlah ia mengelap tangannya hingga ia menjilatinya.\""},"4731":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ فُلَيْحٍ قَالَ حَدَّثَنِي أَبِي عَنْ سَعِيدِ بْنِ الْحَارِثِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ سَأَلَهُ عَنْ الْوُضُوءِ مِمَّا مَسَّتْ النَّارُ فَقَالَ لَا قَدْ كُنَّا زَمَانَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَجِدُ مِثْلَ ذَلِكَ مِنْ الطَّعَامِ إِلَّا قَلِيلًا فَإِذَا نَحْنُ وَجَدْنَاهُ لَمْ يَكُنْ لَنَا مَنَادِيلُ إِلَّا أَكُفَّنَا وَسَوَاعِدَنَا وَأَقْدَامَنَا ثُمَّ نُصَلِّي وَلَا نَتَوَضَّأُ","id":"Telah menceritakan kepada kami [Ibrahim Ibnul Mundzir] berkata; telah menceritakan kepadaku [Muhammad bin Fulaih] berkata; telah menceritakan kepadaku [Bapakku] dari [Sa'id Ibnul Harits] dari [Jabir bin Abdullah] radliallahu 'anhuma, Bahwasanya ia bertanya kepadanya tentang wudlu karena memakan sesuatu yang terkena api (dibakar). Ia menjawab, \"Tidak. Pada masa Nabi shallallahu 'alaihi wasallam kami tidak menemui makanan seperti itu kecuali sedikit. Jika kami mendapatkannya (makan) dan tidak memiliki sapu tangan untuk mengelap telapak tangan, betis dan telapak kaki, maka kami shalat dan tidak berwudlu lagi.\""},"4732":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ ثَوْرٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ أَبِي أُمَامَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا رَفَعَ مَائِدَتَهُ قَالَ الْحَمْدُ لِلَّهِ كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ غَيْرَ مَكْفِيٍّ وَلَا مُوَدَّعٍ وَلَا مُسْتَغْنًى عَنْهُ رَبَّنَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Sufyan] dari [Tsaur] dari [Khalid] dari [Abu Umamah] bahwa Nabi shallallahu 'alaihi wasallam jika mengangkat lambungnya (selesai makan), beliau membaca: 'ALHAMDULILLAHI KATSIIRAN THAYYIBAN MUBAARAKAN FIIHI GHAIRA MAKFIYIN WA LAA MUWADDA'IN WA LAA MUSTAGHNAN 'ANHU RABBANAA (Segala puji bagi Allah dengan pujian yang banyak, yang baik dan yang mengandung keberkahan di dalamnya, bukan pujian yang tidak dianggap dan tidak dibutuhkan oleh Tuhan) '.\""},"4733":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ثَوْرِ بْنِ يَزِيدَ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ أَبِي أُمَامَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا فَرَغَ مِنْ طَعَامِهِ وَقَالَ مَرَّةً إِذَا رَفَعَ مَائِدَتَهُ قَالَ الْحَمْدُ لِلَّهِ الَّذِي كَفَانَا وَأَرْوَانَا غَيْرَ مَكْفِيٍّ وَلَا مَكْفُورٍ وَقَالَ مَرَّةً الْحَمْدُ لِلَّهِ رَبِّنَا غَيْرَ مَكْفِيٍّ وَلَا مُوَدَّعٍ وَلَا مُسْتَغْنًى رَبَّنَا","id":"Telah menceritakan kepada kami [Abu Ashim] dari [Tsaur bin Yazid] dari [Khalid bin Ma'dan] dari [Abu Umamah] bahwa Nabi shallallahu 'alaihi wasallam jika selesai dari makan, sekali waktu dengan lafadz, 'jika mengangkat lambungnya, beliau mengucapkan: \"ALHAMDULILLAHILADZII KAFAANAA WA ARWAANAA GHAIRA MAKFIYIN WA LAA MAKFUURIN (Segala puji hanya milik Allah yang telah memberi kecukupan kami dan menghilangkan rasa haus, bukan nikmat yang tidak dianggap atau dikufuri) ', dilain waktu dengan lafadz, 'ALHAMDULILLAHI RABBINAA GHAIRA MAKFIYIN WA LAA MUWADDA'IN WA LAA MUSTAGHNAN RABBANAA (Segala puji hanya milik Allah Rabb kami, bukan pujian yang tidak dianggap dan tidak dibutuhkan oleh tuhan) '.\""},"4734":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدٍ هُوَ ابْنُ زِيَادٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَتَى أَحَدَكُمْ خَادِمُهُ بِطَعَامِهِ فَإِنْ لَمْ يُجْلِسْهُ مَعَهُ فَلْيُنَاوِلْهُ أُكْلَةً أَوْ أُكْلَتَيْنِ أَوْ لُقْمَةً أَوْ لُقْمَتَيْنِ فَإِنَّهُ وَلِيَ حَرَّهُ وَعِلَاجَهُ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Muhammad] -yaitu Ibnu Ziyad- berkata; Aku mendengar [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika budak salah seorang dari kalian datang kepadanya dengan membawa makanan, jika ia tidak mengajaknya duduk bersama, hendaklah ia mengambilkan untuknya satu atau dua asupan, atau satu atau dua suapan. Sebab ia telah merasakan rasa lelah dan capeknya.\""},"4735":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي الْأَسْوَدِ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا شَقِيقٌ حَدَّثَنَا أَبُو مَسْعُودٍ الْأَنْصَارِيُّ قَالَكَانَ رَجُلٌ مِنْ الْأَنْصَارِ يُكْنَى أَبَا شُعَيْبٍ وَكَانَ لَهُ غُلَامٌ لَحَّامٌ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي أَصْحَابِهِ فَعَرَفَ الْجُوعَ فِي وَجْهِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَهَبَ إِلَى غُلَامِهِ اللَّحَّامِ فَقَالَ اصْنَعْ لِي طَعَامًا يَكْفِي خَمْسَةً لَعَلِّي أَدْعُو النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَامِسَ خَمْسَةٍ فَصَنَعَ لَهُ طُعَيِّمًا ثُمَّ أَتَاهُ فَدَعَاهُ فَتَبِعَهُمْ رَجُلٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا شُعَيْبٍ إِنَّ رَجُلًا تَبِعَنَا فَإِنْ شِئْتَ أَذِنْتَ لَهُ وَإِنْ شِئْتَ تَرَكْتَهُ قَالَ لَا بَلْ أَذِنْتُ لَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Abul Aswad] berkata, telah menceritakan kepada kami [Abu Usamah] berkata, telah menceritakan kepada kami [Al A'masy] berkata, telah menceritakan kepada kami [Syaqiq] berkata, telah menceritakan kepada kami [Abu Mas'ud Al Anshari] ia berkata, \"Seorang laki-laki Anshar bernama Abu Syu'aib memiliki seorang budak laki-laki yang pandai memasak daging, suatu ketika ia datang menemui Nabi shallallahu 'alaihi wasallam yang saat itu sedang bersama para sahabatnya. Ia melihat pada wajah Nabi shallallahu 'alaihi wasallam tanda kelaparan, maka ia segera menemui budak laki-lakinya seraya berkata, \"Buatlah makanan untukku yang cukup untuk lima orang, sebab aku ingin mengundang Nabi shallallahu 'alaihi wasallam dengan makanan yang cukup untuk lima orang.\" Budak tersebut kemudian membuat sedikit makanan, maka laki-laki Anshar itu mengundang Rasulullah. Beliau lalu datang dengan diikuti oleh seorang laki-laki (selain dari lima orang yang telah disiapkan makanan untuknya), Nabi shallallahu 'alaihi wasallam lantas bersabda: \"Wahai Abu Syu'aib, ada seorang laki-laki yang ikut kami, jika kamu mau kamu boleh memberinya izin, jika tidak maka kamu boleh meninggalkannya?\" Abu Syu'aib menjawab, \"Tidak, bahkan aku telah memberinya izin.\""},"4736":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ وَقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي جَعْفَرُ بْنُ عَمْرِو بْنِ أُمَيَّةَ أَنَّ أَبَاهُعَمْرَو بْنَ أُمَيَّةَ أَخْبَرَهُ أَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْتَزُّ مِنْ كَتِفِ شَاةٍ فِي يَدِهِ فَدُعِيَ إِلَى الصَّلَاةِ فَأَلْقَاهَا وَالسِّكِّينَ الَّتِي كَانَ يَحْتَزُّ بِهَا ثُمَّ قَامَ فَصَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Abul Yaman] berkata, telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri], dan [Laits] berkata, telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] ia berkata; telah mengabarkan kepadaku [Ja'far bin Amru bin Umayyah] bahwa bapaknya [Amru bin Umayyah] mengabarkan kepadanya, Bahwasanya ia melihat Rasulullah shallallahu 'alaihi wasallam memotong-motong daging lengan kambing yang ada di tangannya, ketika panggilan shalat diserukan, beliau meletakkan lengan kambing dan pisau yang beliau gunakan untuk memotong-motong. Beliau kemudian berdiri melaksanakan shalat dan tidak berwudlu lagi.\""},"4737":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وُضِعَ الْعَشَاءُ وَأُقِيمَتْ الصَّلَاةُ فَابْدَءُوا بِالْعَشَاءِوَعَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَعَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّهُ تَعَشَّى مَرَّةً وَهُوَ يَسْمَعُ قِرَاءَةَ الْإِمَامِ","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] berkata, telah menceritakan kepada kami [Wuhaib] dari [Ayyub] dari [Abu Qilabah] dari [Anas bin Malik] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika makan malam telah tersedia dan iqamat dikumandangkan, maka dahulukanlah makan malam.\" Dan dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam seperti ini.\" Dan dari Ayyub dari Nafi' dari Ibnu Umar bahwa suatu kali ia pernah makan malam sementara ia mendengar suara bacaan Imam.\""},"4738":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أُقِيمَتْ الصَّلَاةُ وَحَضَرَ الْعَشَاءُ فَابْدَءُوا بِالْعَشَاءِقَالَ وُهَيْبٌ وَيَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ إِذَا وُضِعَ الْعَشَاءُ","id":"Telah menceritakan kepada kami [Muhammad bin Yusus] berkata, telah menceritakan kepada kami [Sufyan] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika iqamah telah dikumandangkan, sementara makan malam telah tersaji, maka hendaklah kalian mulai dengan makan malam.\" [Wuhaib] dan [Yahya bin Sa'id] dari [Hisyam] menyebutkan, \"Jika makan malam telah terhidang.\""},"4739":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنِي أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ أَنَسًا قَالَأَنَا أَعْلَمُ النَّاسِ بِالْحِجَابِ كَانَ أُبَيُّ بْنُ كَعْبٍ يَسْأَلُنِي عَنْهُ أَصْبَحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَرُوسًا بِزَيْنَبَ بِنْتِ جَحْشٍ وَكَانَ تَزَوَّجَهَا بِالْمَدِينَةِ فَدَعَا النَّاسَ لِلطَّعَامِ بَعْدَ ارْتِفَاعِ النَّهَارِ فَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَلَسَ مَعَهُ رِجَالٌ بَعْدَ مَا قَامَ الْقَوْمُ حَتَّى قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَشَى وَمَشَيْتُ مَعَهُ حَتَّى بَلَغَ بَابَ حُجْرَةِ عَائِشَةَ ثُمَّ ظَنَّ أَنَّهُمْ خَرَجُوا فَرَجَعْتُ مَعَهُ فَإِذَا هُمْ جُلُوسٌ مَكَانَهُمْ فَرَجَعَ وَرَجَعْتُ مَعَهُ الثَّانِيَةَ حَتَّى بَلَغَ بَابَ حُجْرَةِ عَائِشَةَ فَرَجَعَ وَرَجَعْتُ مَعَهُ فَإِذَا هُمْ قَدْ قَامُوا فَضَرَبَ بَيْنِي وَبَيْنَهُ سِتْرًا وَأُنْزِلَ الْحِجَابُ","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] berkata, telah menceritakan kepada kami [Ya'qub bin Ibrahim] ia berkata; telah menceritakan kepadaku [Bapakku] dari [Shalih] dari [Ibnu Syihab] bahwa [Anas] berkata, \"Aku adalah orang yang paling paham dengan hijab, Ubai bin Ka'b pernah menanyakannya kepadaku. Rasulullah shallallahu 'alaihi wasallam menjadi pengantin dengan Zainab binti Jahsy, beliau menikahinya di Madinah. Beliau lalu mengundang para sahabat untuk menghadiri jamuan makan setelah siang hari. Rasulullah shallallahu 'alaihi wasallam kemudian duduk bersama beberapa orang setelah orang-orang pergi. Rasulullah shallallahu 'alaihi wasallam lalu berjalan pergi dan aku mengikutinya, hingga beliau sampai di depan pintu kamar Aisyah. Beliau mengira bahwa para sahabat tersebut sudah pulang, maka aku pun mengikuti beliau keluar dan ternyata mereka masih duduk-duduk di tempat mereka. Beliau lantas kembali masuk ke dalam, dan aku tetap mengikuti untuk yang kedua kalinya, hingga ketika sampai di depan pintu kamar Aisyah, beliau kembali keluar, dan aku tetap mengikutinya. Dan ternyata mereka semua telah pergi, kemudian beliau memasang hijab antara aku dengannya, lalu turunlah ayat hijab.\""},"4740":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ حَدَّثَنِي بُرَيْدٌ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَوُلِدَ لِي غُلَامٌ فَأَتَيْتُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمَّاهُ إِبْرَاهِيمَ فَحَنَّكَهُ بِتَمْرَةٍ وَدَعَا لَهُ بِالْبَرَكَةِ وَدَفَعَهُ إِلَيَّ وَكَانَ أَكْبَرَ وَلَدِ أَبِي مُوسَى","id":"Telah menceritakan kepadaku [Ishaq bin Nashr] berkata, telah menceritakan kepada kami [Abu Usamah] ia berkata; telah menceritakan kepadaku [Buraid] dari [Abu Burdah] dari [Abu Musa] radliallahu 'anhu, ia berkata, \"Anak laki-lakiku lahir, kemudian aku membawanya kepada Nabi shallallahu 'alaihi wasallam. Beliau lalu memberinya nama Ibrahim, beliau menyuapinya dengan kunyahan kurma dan mendoakannya dengan keberkahan, setelah itu menyerahkannya kepadaku.\" Ibrahim adalah anak tertua Abu Musa."},"4741":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِصَبِيٍّ يُحَنِّكُهُ فَبَالَ عَلَيْهِ فَأَتْبَعَهُ الْمَاءَ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Hisyam] dari [Bapaknya] dari [Aisyah] radliallahu 'anhuma, ia berkata, \"Seorang bayi dibawa ke hadapan Nabi shallallahu 'alaihi wasallam yang kemudian beliau suapi dengan kunyahan buah kurma, ketika bayi itu kencing, beliau memercikinya dengan air.\""},"4742":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهَا حَمَلَتْ بِعَبْدِ اللَّهِ بْنِ الزُّبَيْرِ بِمَكَّةَ قَالَتْ فَخَرَجْتُ وَأَنَا مُتِمٌّ فَأَتَيْتُ الْمَدِينَةَ فَنَزَلْتُ قُبَاءً فَوَلَدْتُ بِقُبَاءٍ ثُمَّ أَتَيْتُ بِهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَضَعْتُهُ فِي حَجْرِهِ ثُمَّ دَعَا بِتَمْرَةٍ فَمَضَغَهَا ثُمَّ تَفَلَ فِي فِيهِ فَكَانَ أَوَّلَ شَيْءٍ دَخَلَ جَوْفَهُ رِيقُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ حَنَّكَهُ بِالتَّمْرَةِ ثُمَّ دَعَا لَهُ فَبَرَّكَ عَلَيْهِ وَكَانَ أَوَّلَ مَوْلُودٍ وُلِدَ فِي الْإِسْلَامِ فَفَرِحُوا بِهِ فَرَحًا شَدِيدًا لِأَنَّهُمْ قِيلَ لَهُمْ إِنَّ الْيَهُودَ قَدْ سَحَرَتْكُمْ فَلَا يُولَدُ لَكُمْ","id":"Telah menceritakan kepada kami [Ishaq bin Nashr] berkata, telah menceritakan kepada kami [Abu Usamah] berkata, telah menceritakan kepada kami [Hisyam bin Urwah] dari [Bapaknya] dari [Asma binti Abu Bakar] radliallahu 'anhuma, Bahwasanya di Makkah ia hamil karena hubungannya dengan Abdullah bin Zubair (suaminya). Ia berkata, \"Aku lalu keluar menuju Madinah, ketika sampai di Quba, aku singgah dan melahirkan di sana. Aku lalu membawa bayiku menemui Rasulullah shallallahu 'alaihi wasallam dan aku letakkan di pangkuannya. Kemudian Beliau minta diambilkan buah kurma, lalu mengunyahnya untuk kemudian meludahkannya ke dalam bayiku. Maka pertama kali yang masuk ke dalam perutnya adalah ludah Rasulullah shallallahu 'alaihi wasallam. Beliau memberi kunyahan kurma dan mendoakan keberkahan kepadanya. Dia adalah bayi pertama yang lahir dalam Islam. Orang-orang pun bangga, sebab telah dikatakan kepada mereka 'sesungguhnya orang-orang Yahudi telah menyihir kalian, sehingga kalian tidak akan memiliki anak'.\""},"4743":{"ar":"حَدَّثَنَا مَطَرُ بْنُ الْفَضْلِ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عَوْنٍ عَنْ أَنَسِ بْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ ابْنٌ لِأَبِي طَلْحَةَ يَشْتَكِي فَخَرَجَ أَبُو طَلْحَةَ فَقُبِضَ الصَّبِيُّ فَلَمَّا رَجَعَ أَبُو طَلْحَةَ قَالَ مَا فَعَلَ ابْنِي قَالَتْ أُمُّ سُلَيْمٍ هُوَ أَسْكَنُ مَا كَانَ فَقَرَّبَتْ إِلَيْهِ الْعَشَاءَ فَتَعَشَّى ثُمَّ أَصَابَ مِنْهَا فَلَمَّا فَرَغَ قَالَتْ وَارُوا الصَّبِيَّ فَلَمَّا أَصْبَحَ أَبُو طَلْحَةَ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ فَقَالَ أَعْرَسْتُمْ اللَّيْلَةَ قَالَ نَعَمْ قَالَ اللَّهُمَّ بَارِكْ لَهُمَا فَوَلَدَتْ غُلَامًا قَالَ لِي أَبُو طَلْحَةَ احْفَظْهُ حَتَّى تَأْتِيَ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَى بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَرْسَلَتْ مَعَهُ بِتَمَرَاتٍ فَأَخَذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَمَعَهُ شَيْءٌ قَالُوا نَعَمْ تَمَرَاتٌ فَأَخَذَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَضَغَهَا ثُمَّ أَخَذَ مِنْ فِيهِ فَجَعَلَهَا فِي فِي الصَّبِيِّ وَحَنَّكَهُ بِهِ وَسَمَّاهُ عَبْدَ اللَّهِحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ عَوْنٍ عَنْ مُحَمَّدٍ عَنْ أَنَسٍ وَسَاقَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Mathar Ibnul Fadll] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Abdullah bin Aun] dari [Anas bin Sirin] dari [Anas bin Malik] radliallahu 'anhu, ia berkata, \"Anak Abu Thalhah sedang sakit, ketika Abu Thalhah keluar anaknya meninggal. Dan ketika Abu Thalhah kembali ia bertanya, \"Bagaimana keadaan anakku?\" Ummu Sulaim menjawab, \"Dia lebih tenang dari sebelumnya.\" Ummu Sulaim kemudian menyuguhkan makan malam, maka Abu Thalhah pun makan malam kemudian bersetubuh dengannya. Setelah selesai (dari jima') Ummu Sulaim berkata, \"Anakmu telah dikuburkan.\" Maka diwaktu pagi, Abu Thalhah mendatangi Rasulullah shallallahu 'alaihi wasallam dan mengabarkan kejadian tersebut. Beliau bertanya: \"Kalian tadi malam menjadi pengantin?\" Abu Thalhah menjawab, \"Ya.\" Beliau pun berdoa: \"Ya Allah, berkahilah keduanya.\" Ummu Sulaim kemudian melahirkan seorang anak, lalu Abu Thalhah berkata kepadaku, \"Jagalah ia hingga engkau bawa ke hadapan Nabi shallallahu 'alaihi wasallam.\" Anas kemudian membawa bayi tersebut kepada Nabi shallallahu 'alaihi wasallam, dan Ummu Sulaim membekalinya dengan beberapa kurma. Nabi shallallahu 'alaihi wasallam kemudian meraih bayi Abu Thalhah, beliau lalu bertanya: \"Apakah ia (Anas) membawa sesuatu?\" para sahabat menjawab, \"Ya. Beberapa butir kurma.\" Nabi shallallahu 'alaihi wasallam kemudian mengambil kurma dan menguyahnya, kemudian beliau ambil kunyahan dari mulutnya dan memasukkannya ke dalam mulut sang bayi, baru setelah itu memberinya nama Abdullah.\" Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Ibnu Abu Ady] dari [Ibnu Aun] dari [Muhammad] dari [Anas] lalu ia menyebutkan hadits tersebut.\""},"4744":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ سَلْمَانَ بْنِ عَامِرٍ قَالَ مَعَ الْغُلَامِ عَقِيقَةٌ وَقَالَ حَجَّاجٌ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا أَيُّوبُ وَقَتَادَةُ وَهِشَامٌ وَحَبِيبٌ عَنْ ابْنِ سِيرِينَ عَنْ سَلْمَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ غَيْرُ وَاحِدٍ عَنْ عَاصِمٍ وَهِشَامٍ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ الرَّبَابِ عَنْ سَلْمَانَ بْنِ عَامِرٍ الضَّبِّيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَاهُ يَزِيدُ بْنُ إِبْرَاهِيمَ عَنْ ابْنِ سِيرِينَ عَنْ سَلْمَانَ قَوْلَهُ وَقَالَ أَصْبَغُ أَخْبَرَنِي ابْنُ وَهْبٍ عَنْ جَرِيرِ بْنِ حَازِمٍ عَنْ أَيُّوبَ السَّخْتِيَانِيِّ عَنْ مُحَمَّدِ بْنِ سِيرِينَ حَدَّثَنَا سَلْمَانُ بْنُ عَامِرٍ الضَّبِّيُّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَعَ الْغُلَامِ عَقِيقَةٌ فَأَهْرِيقُوا عَنْهُ دَمًا وَأَمِيطُوا عَنْهُ الْأَذَى","id":"Telah menceritakan kepada kami [Abu Nu'man] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Muhammad] dari [Sulaiman bin Amir], ia berkata, \"Pada anak lelaki ada kewajiban akikah.\" Dan [Hajjaj] berkata, telah menceritakan kepada kami [Hammad] berkata, telah mengabarkan kepada kami [Ayyub] dan [Qatadah] dan [Hisyam] dan [Habib] dari [Ibnu Sirin] dari [Salman] dari Nabi shallallahu 'alaihi wasallam. Dan berkata [tidak satu orang] dari [Ashim] dan [Hisyam] dari [Hafshah binti Sirin] dari [Ar Rabab] dari [Salman bin Amir Adl Dlabiyyi] dari Nabi shallallahu 'alaihi wasallam. Dan [Yazid bin Ibrahim] juga menceritakan dari [Ibnu Sirin] dari [Salman] perkataannya, dan [Ashbagh] berkata, telah mengabarkan kepadaku [Ibnu Wahb] dari [Jarir bin Hazim] dari [Ayyub As Sakhtiyani] dari [Muhammad bin Sirin] berkata, telah menceritakan kepada kami [Salman bin Amir Adl Dlabbi] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada anak lelaki ada kewajiban 'akikah, maka potongkanlah hewan sebagai akikah dan buanglah keburukan darinya.\""},"4745":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي الْأَسْوَدِ حَدَّثَنَا قُرَيْشُ بْنُ أَنَسٍ عَنْ حَبِيبِ بْنِ الشَّهِيدِ قَالَ أَمَرَنِي ابْنُ سِيرِينَ أَنْ أَسْأَلَ الْحَسَنَمِمَّنْ سَمِعَ حَدِيثَ الْعَقِيقَةِ فَسَأَلْتُهُ فَقَالَ مِنْ سَمُرَةَ بْنِ جُنْدَبٍ","id":"Telah menceritakan kepadaku [Abdullah bin Abul Aswad] berkata, telah menceritakan kepada kami [Quraiys bin Anas] dari [Habib bin Asy Syahid] ia berkata, \"Ibnu Sirin menyuruhku agar aku bertanya kepada [Al Hasan] dari siapa ia mendengar hadits tentang akikah, aku pun menanyakannya, dia lalu menjawab, \"Dari [Samurah bin Jundub].\""},"4746":{"ar":"حَدَّثَنَا عَبْدَانُ حَدَّثَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ أَخْبَرَنَا الزُّهْرِيُّ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا فَرَعَ وَلَا عَتِيرَةَوَالْفَرَعُ أَوَّلُ النِّتَاجِ كَانُوا يَذْبَحُونَهُ لِطَوَاغِيتِهِمْ وَالْعَتِيرَةُ فِي رَجَبٍ","id":"Telah menceritakan kepada kami [Abdan] berkata, telah menceritakan kepada kami [Abdullah] berkata, telah mengabarkan kepada kami [Ma'mar] berkata, telah mengabarkan kepada kami [Az Zuhri] dari [Ibnul Musayyab] dari [Abu Hurairah] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada Fara' dan Atirah. Fara' adalah anak pertama seekor unta yang mereka sembelih untuk sesembahan mereka, dan Atirah adalah hewan (kambing) yang mereka potong di bulan rajab.\""},"4747":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ الزُّهْرِيُّ حَدَّثَنَا عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا فَرَعَ وَلَا عَتِيرَةَقَالَ وَالْفَرَعُ أَوَّلُ نِتَاجٍ كَانَ يُنْتَجُ لَهُمْ كَانُوا يَذْبَحُونَهُ لِطَوَاغِيَتِهِمْ وَالْعَتِيرَةُ فِي رَجَبٍ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] berkata, telah menceritakan kepada kami [Sufyan] berkata; [Az Zuhri] telah menceritakan kepada kami dari [Sa'id Ibnul Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada Fara' dan Atirah.\" Beliau lalu jelaskan: \"Fara' adalah anak pertama seekor unta yang mereka sembelih untuk sesembahan mereka, dan Atirah adalah hewan (kambing) yang mereka potong di bulan rajab.\""},"4748":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَكَرِيَّاءُ عَنْ عَامِرٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ رَضِيَ اللَّهُ عَنْهُ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَيْدِ الْمِعْرَاضِ قَالَ مَا أَصَابَ بِحَدِّهِ فَكُلْهُ وَمَا أَصَابَ بِعَرْضِهِ فَهُوَ وَقِيذٌ وَسَأَلْتُهُ عَنْ صَيْدِ الْكَلْبِ فَقَالَ مَا أَمْسَكَ عَلَيْكَ فَكُلْ فَإِنَّ أَخْذَ الْكَلْبِ ذَكَاةٌ وَإِنْ وَجَدْتَ مَعَ كَلْبِكَ أَوْ كِلَابِكَ كَلْبًا غَيْرَهُ فَخَشِيتَ أَنْ يَكُونَ أَخَذَهُ مَعَهُ وَقَدْ قَتَلَهُ فَلَا تَأْكُلْ فَإِنَّمَا ذَكَرْتَ اسْمَ اللَّهِ عَلَى كَلْبِكَ وَلَمْ تَذْكُرْهُ عَلَى غَيْرِهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] berkata, telah menceritakan kepada kami [Zakaria] dari [Amir] dari [Adi bin Hatim] radliallahu 'anhu, ia berkata, \"Aku bertanya kepada Nabi shallallahu 'alaihi wasallam tentang hasil buruan Al Mi'radl, beliau menjawab: \"Jika yang mengenai adalah bagian tajamnya maka makanlah, namun jika yang mengenai adalah pada bagian (sisi) tumpulnya maka itu adalah Waqidz (hewan yang dibunuh bukan dengan senjata tajam).\" Aku lalu bertanya tentang hasil buruan anjing, beliau lantas menjawab: \"Apa yang ditangkap untukmu maka makanlah, sebab gigitan anjing adalah sebagai sembelihannya. Jika engkau dapati anjing lain bersama dengan anjingmu, dan engkau kawatir ia ikut andil hingga buruannya mati, maka janganlah kamu makan. Sebab engkau hanya menyebutkan nama Allah pada anjingmu (saat melepasnya) dan bukan pada anjing yang selainnya.\""},"4749":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ قَالَ سَمِعْتُ عَدِيَّ بْنَ حَاتِمٍ رَضِيَ اللَّهُ عَنْهُ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمِعْرَاضِ فَقَالَ إِذَا أَصَبْتَ بِحَدِّهِ فَكُلْ فَإِذَا أَصَابَ بِعَرْضِهِ فَقَتَلَ فَإِنَّهُ وَقِيذٌ فَلَا تَأْكُلْ فَقُلْتُ أُرْسِلُ كَلْبِي قَالَ إِذَا أَرْسَلْتَ كَلْبَكَ وَسَمَّيْتَ فَكُلْ قُلْتُ فَإِنْ أَكَلَ قَالَ فَلَا تَأْكُلْ فَإِنَّهُ لَمْ يُمْسِكْ عَلَيْكَ إِنَّمَا أَمْسَكَ عَلَى نَفْسِهِ قُلْتُ أُرْسِلُ كَلْبِي فَأَجِدُ مَعَهُ كَلْبًا آخَرَ قَالَ لَا تَأْكُلْ فَإِنَّكَ إِنَّمَا سَمَّيْتَ عَلَى كَلْبِكَ وَلَمْ تُسَمِّ عَلَى آخَرَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Abu As Safar] dari [Asy Sya'bi] ia berkata, \"Aku mendengar [Adi bin Hatim] radliallahu 'anhu berkata, \"Aku bertanya Rasulullah shallallahu 'alaihi wasallam tentang hasil buruan Mi'radl, maka beliau pun menjawab: \"Jika yang mengenai adalah bagian tajamnya maka makanlah, namun jika yang mengenai adalah pada bagian (sisi) tumpulnya maka itu adalah Waqidz (hewan yang dibunuh bukan dengan senjata tajam), maka janganlah kamu makan.\" Aku bertanya lagi, \"Aku telah melepas anjingku!\" Beliau menjawab: \"Jika kamu melepasnya dengan menyebut nama Allah, maka makanlah.\" Aku bertanya lagi, \"Bagaimana jika ia memakannya?\" Beliau menjawab: \"Jangan kamu makan, sebab ia menangkap bukan untuk kamu, ia menangkap hanya untuk dirinya.\" Aku bertanya lagi, \"Saat aku melepas anjingku, aku lihat ada anjing lain?\" Beliau menjawab: \"Jangan kamu makan, sebab kamu menyebut nama Allah hanya untuk anjingmu, bukan untuk anjing yang lain.\""},"4750":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامِ بْنِ الْحَارِثِ عَنْ عَدِيِّ بْنِ حَاتِمٍ رَضِيَ اللَّهُ عَنْهُ قَالَ قُلْتُيَا رَسُولَ اللَّهِ إِنَّا نُرْسِلُ الْكِلَابَ الْمُعَلَّمَةَ قَالَ كُلْ مَا أَمْسَكْنَ عَلَيْكَ قُلْتُ وَإِنْ قَتَلْنَ قَالَ وَإِنْ قَتَلْنَ قُلْتُ وَإِنَّا نَرْمِي بِالْمِعْرَاضِ قَالَ كُلْ مَا خَزَقَ وَمَا أَصَابَ بِعَرْضِهِ فَلَا تَأْكُلْ","id":"Telah menceritakan kepada kami [Qabishah] berkata, telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari [Hammam Ibnul harits] dari [Adi bin Hatim] radliallahu 'anhu, ia berkata, \"Aku bertanya, \"Wahai Rasulullah, kami melepas anjing yang telah dilatih?\" Beliau menjawab: \"Makanlah apa yang dia tangkap untuk kamu.\" Aku bertanya, \"Bagaimana jika ia membunuhnya.\" Beliau menjawab: \"Meskipun ia membunuhnya.\" Aku bertanya lagi, \"Kami juga melempar (memanah/menombak) dengan mi'radl?\" Beliau menjawab: \"Makanlah apa yang terkoyak, adapun yang terkena pada bagian tumpulnya maka janganlah kamu makan.\""},"4751":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا حَيْوَةُ قَالَ أَخْبَرَنِي رَبِيعَةُ بْنُ يَزِيدَ الدِّمَشْقِيُّ عَنْ أَبِي إِدْرِيسَ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّ قَالَقُلْتُ يَا نَبِيَّ اللَّهِ إِنَّا بِأَرْضِ قَوْمٍ مِنْ أَهْلِ الْكِتَابِ أَفَنَأْكُلُ فِي آنِيَتِهِمْ وَبِأَرْضِ صَيْدٍ أَصِيدُ بِقَوْسِي وَبِكَلْبِي الَّذِي لَيْسَ بِمُعَلَّمٍ وَبِكَلْبِي الْمُعَلَّمِ فَمَا يَصْلُحُ لِي قَالَ أَمَّا مَا ذَكَرْتَ مِنْ أَهْلِ الْكِتَابِ فَإِنْ وَجَدْتُمْ غَيْرَهَا فَلَا تَأْكُلُوا فِيهَا وَإِنْ لَمْ تَجِدُوا فَاغْسِلُوهَا وَكُلُوا فِيهَا وَمَا صِدْتَ بِقَوْسِكَ فَذَكَرْتَ اسْمَ اللَّهِ فَكُلْ وَمَا صِدْتَ بِكَلْبِكَ الْمُعَلَّمِ فَذَكَرْتَ اسْمَ اللَّهِ فَكُلْ وَمَا صِدْتَ بِكَلْبِكَ غَيْرِ مُعَلَّمٍ فَأَدْرَكْتَ ذَكَاتَهُ فَكُلْ","id":"Telah menceritakan kepada kami [Abdullah bin Yazid] berkata, telah menceritakan kepada kami [Haiwah] ia berkata; telah mengabarkan kepadaku [Rabi'ah bin Yazid Ad Dimasyqi] dari [Abu Idris] dari [Tsa'labah Al Khusyani] ia berkata, \"Aku bertanya, \"Wahai Rasulullah, kami tinggal di daerah ahli kitab, apakah kami boleh makan dengan bejana mereka? kami juga tinggal di daerah yang suka berburu; kami berburu dengan tombak dan dengan anjing yang terlatih atau anjing yang belum terlatih. Maka apa yang harus kami lakukan?\" Beliau menjawab: \"Berkenaan dengan ahli kitab sebagaimana yang kamu sebutkan, jika kamu bisa mendapatkan bejana yang lain maka jangan kamu gunakan bejana mereka. Namun jika kamu tidak mendapatkan yang lainnya, maka cuci dan makanlah dengannya. Buruan yang kamu dapat dengan tombakmu, setelah menyebut nama Allah, maka makanlah, buruan yang didapat oleh anjingmu yang terlatih, setelah menyebut nama Allah saat melepasnya maka makanlah, dan buruan yang didapat oleh anjingmu yang tidak terlatih, jika kamu sempat menyembelihnya maka makanlah.\""},"4752":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ رَاشِدٍ حَدَّثَنَا وَكِيعٌ وَيَزِيدُ بْنُ هَارُونَ وَاللَّفْظُ لِيَزِيدَ عَنْ كَهْمَسِ بْنِ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍأَنَّهُ رَأَى رَجُلًا يَخْذِفُ فَقَالَ لَهُ لَا تَخْذِفْ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْخَذْفِ أَوْ كَانَ يَكْرَهُ الْخَذْفَ وَقَالَ إِنَّهُ لَا يُصَادُ بِهِ صَيْدٌ وَلَا يُنْكَى بِهِ عَدُوٌّ وَلَكِنَّهَا قَدْ تَكْسِرُ السِّنَّ وَتَفْقَأُ الْعَيْنَ ثُمَّ رَآهُ بَعْدَ ذَلِكَ يَخْذِفُ فَقَالَ لَهُ أُحَدِّثُكَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ الْخَذْفِ أَوْ كَرِهَ الْخَذْفَ وَأَنْتَ تَخْذِفُ لَا أُكَلِّمُكَ كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Yusuf bin Rasyid] berkata, telah menceritakan kepada kami [Waki'] dan [Yazid bin Harun] -dan lafadz hadits tersebut adalah lafadz Yazid- dari [Kahmas Ibnul Hasan] dari [Abdullah bin Buraidah] dari [Abdullah bin Mughaffal], Bahwasanya ia melihat seorang laki-laki melempar batu dengan ketapel, maka Abdullah bin Mughaffal pun berkata, \"Janganlah kamu melempar batu dengan ketapel, sebab Rasulullah shallallahu 'alaihi wasallam telah melarangnya, atau dia mengatakan, \"Rasulullah membencinya. Beliau bersabda: \"Sesungguhnya ia tidak bisa digunakan untuk memburu buruan dan tidak bisa untuk melukai (membunuh) musuh, ia hanya meremukkan tulang dan memecahkan mata.\" Setelah itu ia kembali melihat lelaki tersebut melempar batu dengan menggunakan ketapel, maka ia pun berkata, \"Aku sampaikan kepadamu hadits Rasulullah shallallahu 'alaihi wasallam, bahwa beliau melarang, atau membeci ketapel namun kamu tetap melakukannya, sungguh aku tidak akan berbicara denganmu begini dan begini.\""},"4753":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اقْتَنَى كَلْبًا لَيْسَ بِكَلْبِ مَاشِيَةٍ أَوْ ضَارِيَةٍ نَقَصَ كُلَّ يَوْمٍ مِنْ عَمَلِهِ قِيرَاطَانِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muslim] berkata, telah menceritakan kepada kami [Abdullah bin Dinar] ia berkata, \"Aku mendengar [Ibnu Umar] radliallahu 'anhuma, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa memelihara anjing yang bukan untuk berburu atau menjaga binatang ternak, maka pahalanya akan berkurang dua qirath setiap hari.\""},"4754":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا حَنْظَلَةُ بْنُ أَبِي سُفْيَانَ قَالَ سَمِعْتُ سَالِمًا يَقُولُ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ اقْتَنَى كَلْبًا إِلَّا كَلْبًا ضَارِيًا لِصَيْدٍ أَوْ كَلْبَ مَاشِيَةٍ فَإِنَّهُ يَنْقُصُ مِنْ أَجْرِهِ كُلَّ يَوْمٍ قِيرَاطَانِ","id":"Telah menceritakan kepada kami [Makki bin Ibrahim] berkata, telah mengabarkan kepada kami [Hanzhalah bin Abu Sufyan] ia berkata, \"Aku mendengar [Salim] berkata, \"Aku mendengar [Abdullah bin Umar] berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memelihara anjing selain anjing untuk berburu atau anjing untuk menjaga binatang ternak, maka pahalanya akan berkurang dua qirath setiap hari.\""},"4755":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اقْتَنَى كَلْبًا إِلَّا كَلْبَ مَاشِيَةٍ أَوْ ضَارِيًا نَقَصَ مِنْ عَمَلِهِ كُلَّ يَوْمٍ قِيرَاطَانِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Nafi'] dari [Abdullah bin Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memelihara anjing selain anjing untuk menjaga binatang ternak atau anjing untuk berburu, maka pahalanya akan berkurang dua qirath setiap hari.\""},"4756":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ بَيَانٍ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ إِنَّا قَوْمٌ نَصِيدُ بِهَذِهِ الْكِلَابِ فَقَالَ إِذَا أَرْسَلْتَ كِلَابَكَ الْمُعَلَّمَةَ وَذَكَرْتَ اسْمَ اللَّهِ فَكُلْ مِمَّا أَمْسَكْنَ عَلَيْكُمْ وَإِنْ قَتَلْنَ إِلَّا أَنْ يَأْكُلَ الْكَلْبُ فَإِنِّي أَخَافُ أَنْ يَكُونَ إِنَّمَا أَمْسَكَهُ عَلَى نَفْسِهِ وَإِنْ خَالَطَهَا كِلَابٌ مِنْ غَيْرِهَا فَلَا تَأْكُلْ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Bayan] dari [Asy Sya'bi] dari [Adi bin Hatim] ia berkata, \"Aku bertanya Rasulullah shallallahu 'alaihi wasallam, aku katakan, \"Kami adalah suatu kaum yang biasa berburu dengan anjing-anjing ini?\" Beliau menjawab: \"Jika kamu lepas anjingmu yang terlatih dengan menyebut nama Allah, maka makanlah apa yang ia tangkap untuk kamu, meskipun mereka membunuhnya. Kecuali jika anjing tersebut memakannya, sebab aku kawatir anjing itu menangkap untuk dirinya sendiri. Dan jika ada anjing lain bersama anjing tersebut, maka janganlah kamu makan (hasil buruannya).\""},"4757":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا ثَابِتُ بْنُ يَزِيدَ حَدَّثَنَا عَاصِمٌ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَرْسَلْتَ كَلْبَكَ وَسَمَّيْتَ فَأَمْسَكَ وَقَتَلَ فَكُلْ وَإِنْ أَكَلَ فَلَا تَأْكُلْ فَإِنَّمَا أَمْسَكَ عَلَى نَفْسِهِ وَإِذَا خَالَطَ كِلَابًا لَمْ يُذْكَرْ اسْمُ اللَّهِ عَلَيْهَا فَأَمْسَكْنَ وَقَتَلْنَ فَلَا تَأْكُلْ فَإِنَّكَ لَا تَدْرِي أَيُّهَا قَتَلَ وَإِنْ رَمَيْتَ الصَّيْدَ فَوَجَدْتَهُ بَعْدَ يَوْمٍ أَوْ يَوْمَيْنِ لَيْسَ بِهِ إِلَّا أَثَرُ سَهْمِكَ فَكُلْ وَإِنْ وَقَعَ فِي الْمَاءِ فَلَا تَأْكُلْوَقَالَ عَبْدُ الْأَعْلَى عَنْ دَاوُدَ عَنْ عَامِرٍ عَنْ عَدِيٍّ أَنَّهُ قَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْمِي الصَّيْدَ فَيَقْتَفِرُ أَثَرَهُ الْيَوْمَيْنِ وَالثَّلَاثَةَ ثُمَّ يَجِدُهُ مَيِّتًا وَفِيهِ سَهْمُهُ قَالَ يَأْكُلُ إِنْ شَاءَ","id":"Telah menceritakan kepada kami [Musa bin Ismail] berkata, telah menceritakan kepada kami [Tsabit bin Yazid] berkata, telah menceritakan kepada kami [Ashim] dari [Asy Sya'bi] dari [Adi bin Hatim] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika kamu lepas anjingmu dengan menyebut nama Allah, lalu ia menangkap (buruan) dan membunuhnya, maka makanlah. Jika anjing itu memakannya maka janganlah kamu makan, sebab ia menangkap untuk dirinya sendiri. Jika anjing tersebut bercampur dengan anjing lain yang belum disebut nama Allah saat melepasnya, maka janganlah kamu makan (hasil buruannya), sebab kamu tidak tahu anjing mana yang telah membunuhnya. Jika kamu memanah hewan buruan dan kamu baru menemukannya setelah lewat satu atau dua hari, sedang pada tubuh hewan buruan tersebut tidak ada bekas-bekas lain kecuali bekas panahmu, maka makanlah. Namun jika hewan buruan itu masuk ke dalam air maka janganlah kamu makan.\" Dan [Abdul A'la] menyebutkan dari [Dawud] dari [Amir] dari [Adi] Bahwasanya ia bertanya kepada Nabi shallallahu 'alaihi wasallam, \"Seseorang memanah hewan buruan, lalu ia mengikuti jejaknya dalam dua atau tiga hari dan mendapatkannya telah mati, sementara pada tubuhnya hanya ada bekas panahnya?\" Beliau menjawab: \"Ia boleh makan jika mau.\""},"4758":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أُرْسِلُ كَلْبِي وَأُسَمِّي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرْسَلْتَ كَلْبَكَ وَسَمَّيْتَ فَأَخَذَ فَقَتَلَ فَأَكَلَ فَلَا تَأْكُلْ فَإِنَّمَا أَمْسَكَ عَلَى نَفْسِهِ قُلْتُ إِنِّي أُرْسِلُ كَلْبِي أَجِدُ مَعَهُ كَلْبًا آخَرَ لَا أَدْرِي أَيُّهُمَا أَخَذَهُ فَقَالَ لَا تَأْكُلْ فَإِنَّمَا سَمَّيْتَ عَلَى كَلْبِكَ وَلَمْ تُسَمِّ عَلَى غَيْرِهِ وَسَأَلْتُهُ عَنْ صَيْدِ الْمِعْرَاضِ فَقَالَ إِذَا أَصَبْتَ بِحَدِّهِ فَكُلْ وَإِذَا أَصَبْتَ بِعَرْضِهِ فَقَتَلَ فَإِنَّهُ وَقِيذٌ فَلَا تَأْكُلْ","id":"Telah menceritakan kepada kami [Adam] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Abu As Safar] dari [Asy Sya'bi] dari [Adi bin Hatim] ia berkata, \"Aku bertanya, \"Wahai Rasulullah, aku telah melepas anjingku dengan menyebut nama Allah?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Jika kamu melepas anjingmu dengan menyebut nama Allah, lalu ia menangkap, membunuh dan memakannya, maka janganlah kamu makan. Sebab ia menangkap untuk dirinya sendiri.\" Aku bertanya lagi, \"Saat melepas anjingku aku mendapatkan ada anjing lain bersamanya, dan aku tidak tahu anjing mana yang telah menangkapnya?\" Beliau lalu menjawab: \"Jangan kamu makan, sebab engkau menyebut nama Allah hanya untuk anjingmu dan bukan untuk anjing lainnya.\" Aku lalu bertanya kepada beliau tentang hasil buruan dengan Mi'radl, maka beliau pun menjawab: \"Jika yang mengenai adalah pada bagian yang tajam maka makanlah, namun jika yang mengenai adalah pada bagian yang tumpul hingga terbunuh, sesungguhnya itu adalah Waqidz (hewan yang dibunuh bukan dengan senjata tajam), maka jangan kamu makan.\" "},"4759":{"ar":"حَدَّثَنِي مُحَمَّدٌ أَخْبَرَنِي ابْنُ فُضَيْلٍ عَنْ بَيَانٍ عَنْ عَامِرٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ رَضِيَ اللَّهُ عَنْهُ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنَّا قَوْمٌ نَتَصَيَّدُ بِهَذِهِ الْكِلَابِ فَقَالَ إِذَا أَرْسَلْتَ كِلَابَكَ الْمُعَلَّمَةَ وَذَكَرْتَ اسْمَ اللَّهِ فَكُلْ مِمَّا أَمْسَكْنَ عَلَيْكَ إِلَّا أَنْ يَأْكُلَ الْكَلْبُ فَلَا تَأْكُلْ فَإِنِّي أَخَافُ أَنْ يَكُونَ إِنَّمَا أَمْسَكَ عَلَى نَفْسِهِ وَإِنْ خَالَطَهَا كَلْبٌ مِنْ غَيْرِهَا فَلَا تَأْكُلْ","id":"Telah menceritakan kepadaku [Muhammad] berkata, telah mengabarkan kepadaku [Ibnu Fudlail] dari [Bayan] dari [Amir] dari [Adi bin Hatim] radliallahu 'anhu, ia berkata, \"Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam, kukatakan, \"Kami adalah suatu kaum yang biasa berburu dengan anjing-anjing ini?\" Beliau lalu menjawab: \"Jika kamu lepas anjingmu yang telah terlatih dengan menyebut nama Allah, maka makanlah apa yang telah ia tangkap untukmu. Kecuali jika anjing tersebut memakannya, maka jangan kamu makan. Sebab aku kawatir jika anjing itu menangkap untuk dirinya sendiri, dan jika ada anjing lain bersamanya, maka jangan kamu makan juga.\""},"4760":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ ح و حَدَّثَنِي أَحْمَدُ ابْنُ أَبِي رَجَاءٍ حَدَّثَنَا سَلَمَةُ بْنُ سُلَيْمَانَ عَنْ ابْنِ الْمُبَارَكِ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ قَالَ سَمِعْتُ رَبِيعَةَ بْنَ يَزِيدَ الدِّمَشْقِيَّ قَالَ أَخْبَرَنِي أَبُو إِدْرِيسَ عَائِذُ اللَّهِ قَالَ سَمِعْتُ أَبَا ثَعْلَبَةَ الْخُشَنِيَّ رَضِيَ اللَّهُ عَنْهُ يَقُولُأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا بِأَرْضِ قَوْمٍ أَهْلِ الْكِتَابِ نَأْكُلُ فِي آنِيَتِهِمْ وَأَرْضِ صَيْدٍ أَصِيدُ بِقَوْسِي وَأَصِيدُ بِكَلْبِي الْمُعَلَّمِ وَالَّذِي لَيْسَ مُعَلَّمًا فَأَخْبِرْنِي مَا الَّذِي يَحِلُّ لَنَا مِنْ ذَلِكَ فَقَالَ أَمَّا مَا ذَكَرْتَ أَنَّكَ بِأَرْضِ قَوْمٍ أَهْلِ الْكِتَابِ تَأْكُلُ فِي آنِيَتِهِمْ فَإِنْ وَجَدْتُمْ غَيْرَ آنِيَتِهِمْ فَلَا تَأْكُلُوا فِيهَا وَإِنْ لَمْ تَجِدُوا فَاغْسِلُوهَا ثُمَّ كُلُوا فِيهَا وَأَمَّا مَا ذَكَرْتَ أَنَّكَ بِأَرْضِ صَيْدٍ فَمَا صِدْتَ بِقَوْسِكَ فَاذْكُرْ اسْمَ اللَّهِ ثُمَّ كُلْ وَمَا صِدْتَ بِكَلْبِكَ الْمُعَلَّمِ فَاذْكُرْ اسْمَ اللَّهِ ثُمَّ كُلْ وَمَا صِدْتَ بِكَلْبِكَ الَّذِي لَيْسَ مُعَلَّمًا فَأَدْرَكْتَ ذَكَاتَهُ فَكُلْ","id":"Telah menceritakan kepada kami [Abu Ashim] dari [Haiwah bin Syuraih]. (dalam jalur lain disebutkan) Telah menceritakan kepadaku [Ahmad bin Abu Raja`] berkata, telah menceritakan kepada kami [Salamah bin Sulaiman] dari [Ibnul Mubarak] dari [Haiwah bin Syuraih] ia berkata; Aku mendengar [Rabi'ah Yazid bin Ad Dimasyqi] berkata; telah mengabarkan kepadaku [Abu Idris Aidzullah] ia berkata, \"Aku mendengar [Abu Tsa'labah] radliallahu 'anhu berkata, \"Aku mendatangi Rasulullah shallallahu 'alaihi wasallam, lalu kukatakan kepada beliau, \"Wahai Rasulullah, kami berada di wilayah orang-orang ahli kitab dan makan dengan bejana-bejana mereka, kami juga tinggal di daerah yang suka berburu, lalu kami berburu dengan tombak dan anjing, baik yang terlatih maupun yang tidak terlatih. Maka kabarkanlah kepada kami, apa yang halal untuk kami dari itu semua?\" Beliau lalu menjawab, \"Sebagaimana yang kamu sebutkan bahwa kamu tinggal di wilayah ahli kitab dan makan dengan bejana mereka, maka jika kalian mendapatkan bejana yang lain janganlah kalian makan dengan bejana-bejana mereka, jika tidak mendapatkan maka cucilah bejana tersebut lalu makanlah dengannya. Sedangkan masalahmu bahwa kamu tinggal di wilayah yang suka berburu, maka apa yang kamu hasilkan dengan anak panahmu, maka sebutlah nama Allah lalu makanlah. Kemudian hewan buruan yang ditangkap oleh anjingmu yang terlatih, maka sebutlah nama Allah lalu makanlah. Dan buruan yang dihasilkan oleh anjingmu yang tidak terlatih, dan kamu sempat menyembelihnya maka makanlah.\""},"4761":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ قَالَ حَدَّثَنِي هِشَامُ بْنُ زَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَنْفَجْنَا أَرْنَبًا بِمَرِّ الظَّهْرَانِ فَسَعَوْا عَلَيْهَا حَتَّى لَغِبُوا فَسَعَيْتُ عَلَيْهَا حَتَّى أَخَذْتُهَا فَجِئْتُ بِهَا إِلَى أَبِي طَلْحَةَ فَبَعَثَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِوَرِكَيْهَا أَوْ فَخِذَيْهَا فَقَبِلَهُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Syu'bah] ia berkata; telah menceritakan kepadaku [Hisyam bin Zaid] dari [Anas bin Malik] radliallahu 'anhu, ia berkata, \"Kami mengejar kelinci di Marru Zhahran (nama tempat), orang-orang berusaha untuk menangkapnya hingga mereka pun kelelahan. Maka aku pun ikut mengejarnya hingga aku dapat menangkapnya, kemudian kelinci itu aku bawa kepada Abu Thalhah. Setelah itu ia mengirimkan kedua kaki atau paha kelinci tersebut kepada Nabi shallallahu 'alaihi wasallam, dan beliau pun menerimanya.\""},"4762":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ مَوْلَى أَبِي قَتَادَةَ عَنْ أَبِي قَتَادَةَأَنَّهُ كَانَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا كَانَ بِبَعْضِ طَرِيقِ مَكَّةَ تَخَلَّفَ مَعَ أَصْحَابٍ لَهُ مُحْرِمِينَ وَهُوَ غَيْرُ مُحْرِمٍ فَرَأَى حِمَارًا وَحْشِيًّا فَاسْتَوَى عَلَى فَرَسِهِ ثُمَّ سَأَلَ أَصْحَابَهُ أَنْ يُنَاوِلُوهُ سَوْطًا فَأَبَوْا فَسَأَلَهُمْ رُمْحَهُ فَأَبَوْا فَأَخَذَهُ ثُمَّ شَدَّ عَلَى الْحِمَارِ فَقَتَلَهُ فَأَكَلَ مِنْهُ بَعْضُ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَى بَعْضُهُمْ فَلَمَّا أَدْرَكُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَلُوهُ عَنْ ذَلِكَ فَقَالَ إِنَّمَا هِيَ طُعْمَةٌ أَطْعَمَكُمُوهَا اللَّهُحَدّ��ثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي قَتَادَةَ مِثْلَهُ إِلَّا أَنَّهُ قَالَ هَلْ مَعَكُمْ مِنْ لَحْمِهِ شَيْءٌ","id":"Telah menceritakan kepada kami [Ismail] ia berkata; telah menceritakan kepadaku [Malik] dari [Abu An Nadlr] mantan budak Umar bin Ubaidullah, dari [Nafi'] mantan budak Abu Qatadah dari [Abu Qatadah], Bahwasanya ia pernah bersama Rasulullah shallallahu 'alaihi wasallam, hingga ketika mereka sampai di jalanan Makkah, ia dan para sahabatnya yang sedang mengenakan pakaian ihram tertinggal, saat itu dia sendiri yang tidak ihram. Lalu ia melihat seekor keledai liar, maka ia segera menaiki kudanya (untuk menangkap keledai tersebut). Ia minta kepada para sahabatnya untuk mengambilkan cambuknya yang jatuh namun mereka menolak, lalu ia minta diambilkan tombaknya dan mereka juga menolak. Maka ia pun mengambil sendiri kemudian menangkap keledai tersebut dan membunuhnya. Sebagian sahabatnya ada yang ikut memakan dagingnya, dan ada juga yang menolak. Ketika mereka dapat menyusul Nabi shallallahu 'alaihi wasallam, mereka pun menanyakan hal itu kepada beliau. Maka jawab beliau: \"Itu adalah makanan yang Allah berikan kepada kalian.\" Telah menceritakan kepada kami [Ismail], ia berkata; telah menceritakan kepadaku [Malik] dari [Zaid bin Aslam] dari [Atha' bin Yasar] dari [Abu Qatadah] seperti itu, beliau bersabda; apakah kalian memiliki sesuatu dari dagingnya?."},"4763":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ الْجُعْفِيُّ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ أَخْبَرَنَا عَمْرٌو أَنَّ أَبَا النَّضْرِ حَدَّثَهُ عَنْ نَافِعٍ مَوْلَى أَبِي قَتَادَةَ وَأَبِي صَالِحٍ مَوْلَى التَّوْأَمَةِ سَمِعْتُ أَبَا قَتَادَةَ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا بَيْنَ مَكَّةَ وَالْمَدِينَةِ وَهُمْ مُحْرِمُونَ وَأَنَا رَجُلٌ حِلٌّ عَلَى فَرَسٍ وَكُنْتُ رَقَّاءً عَلَى الْجِبَالِ فَبَيْنَا أَنَا عَلَى ذَلِكَ إِذْ رَأَيْتُ النَّاسَ مُتَشَوِّفِينَ لِشَيْءٍ فَذَهَبْتُ أَنْظُرُ فَإِذَا هُوَ حِمَارُ وَحْشٍ فَقُلْتُ لَهُمْ مَا هَذَا قَالُوا لَا نَدْرِي قُلْتُ هُوَ حِمَارٌ وَحْشِيٌّ فَقَالُوا هُوَ مَا رَأَيْتَ وَكُنْتُ نَسِيتُ سَوْطِي فَقُلْتُ لَهُمْ نَاوِلُونِي سَوْطِي فَقَالُوا لَا نُعِينُكَ عَلَيْهِ فَنَزَلْتُ فَأَخَذْتُهُ ثُمَّ ضَرَبْتُ فِي أَثَرِهِ فَلَمْ يَكُنْ إِلَّا ذَاكَ حَتَّى عَقَرْتُهُ فَأَتَيْتُ إِلَيْهِمْ فَقُلْتُ لَهُمْ قُومُوا فَاحْتَمِلُوا قَالُوا لَا نَمَسُّهُ فَحَمَلْتُهُ حَتَّى جِئْتُهُمْ بِهِ فَأَبَى بَعْضُهُمْ وَأَكَلَ بَعْضُهُمْ فَقُلْتُ لَهُمْ أَنَا أَسْتَوْقِفُ لَكُمْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَدْرَكْتُهُ فَحَدَّثْتُهُ الْحَدِيثَ فَقَالَ لِي أَبَقِيَ مَعَكُمْ شَيْءٌ مِنْهُ قُلْتُ نَعَمْ فَقَالَ كُلُوا فَهُوَ طُعْمٌ أَطْعَمَكُمُوهُ اللَّهُ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman Al Ju'fi] berkata; telah menceritakan kepadaku [Ibnu Wahb] berkata, telah mengabarkan kepada kami [Amru] bahwa [Abu An Nadlr] menceritakan kepadanya dari [Nafi] mantan budak Abu Qatadah, dan [Abu Shalih] mantan budak At Tau`amah ia berkata, Aku mendengar [Abu Qatadah] berkata, \"Aku bersama Nabi shallallahu 'alaihi wasallam berada di suatu daerah antara Makkah dan Madinah, saat itu para sahabat sedang ihram. Sementara aku tidak melakukan ihram, dan sedang di atas kuda. Ketika aku sedang berada di atas gunung, aku melihat orang-orang berkerumun melihat sesuatu, kemudian aku pergi ke arah mereka dan ternyata yang mereka lihat itu adalah keledai liar. Aku lalu bertanya kepada mereka, \"Apa ini?\" Mereka menjawab, \"Kami tidak tahu.\" Aku pun berkata, \"Itu adalah keledai liar.\" Mereka lantas berkata, \"Ya itu adalah sebagaimana yang kamu lihat.\" Saat itu aku lupa dengan cambukku, maka aku pun berkata kepada mereka, \"Tolong ambilkan cambukku.\" Mereka menjawab, \"Kami tidak akan menolong kamu dalam masalah itu.\" Aku lalu turun dan mengambilnya sendiri, kemudian aku mengikuti jejak keledai liar tersebut hingga dapat menangkap dan menyembelihnya. Kemudian aku datang menemui mereka dan kukatakan, \"Bangun dan angkatlah.\" Mereka menjawab, \"Kami tidak akan menyentuhnya.\" Maka aku pun membawa ke hadapan mereka, lalu sebagian mereka ada yang makan dan sebagian lain tidak mau memakannya. Aku lalu berkata kepada mereka, \"Aku akan sampaikan kepada Nabi shallallahu 'alaihi wasallam akan keberatan kalian.\" Kemudian aku menyusul beliau dan menceritakan kejadian tersebut, beliau pun bersabda kepadaku: \"Apakah kalian masih mempunyai sisa dagingnya?\" Aku jawab, \"Ya.\" Beliau bersabda lagi: \"Itu adalah makanan yang Allah berikan kepada kalian.\""},"4764":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَمْرٌو أَنَّهُ سَمِعَ جَابِرًا رَضِيَ اللَّهُ عَنْهُ يَقُولُغَزَوْنَا جَيْشَ الْخَبَطِ وَأُمِّرَ أَبُو عُبَيْدَةَ فَجُعْنَا جُوعًا شَدِيدًا فَأَلْقَى الْبَحْرُ حُوتًا مَيِّتًا لَمْ يُرَ مِثْلُهُ يُقَالُ لَهُ الْعَنْبَرُ فَأَكَلْنَا مِنْهُ نِصْفَ شَهْرٍ فَأَخَذَ أَبُو عُبَيْدَةَ عَظْمًا مِنْ عِظَامِهِ فَمَرَّ الرَّاكِبُ تَحْتَهُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] ia berkata; telah mengabarkan kepadaku [Amru] Bahwasanya ia mendengar [Jabir] radliallahu 'anhu berkata, \"Kami berperang dalam pertempuran Khabath, dan saat itu yang diangkat sebagai pemimpin adalah Abu Ubaidah. Kemudian kami merasakan kelaparan yang melilit, lalu laut mendamparkan seekor hiu besar yang disebut dengan nama al Anbar, dan belum pernah ada ikan sebesar itu. Maka selama setengah bulan kami hanya makan darinya, Abu Ubaidah lalu mengambil satu tulang dari ikan tersebut, dan (karena besarnya) seorang penunggang kuda dapat lewat di bawahnya.\""},"4765":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ أَخْبَرَنَا سُفْيَانُ عَنْ عَمْرٍو قَالَ سَمِعْتُ جَابِرًا يَقُولُبَعَثَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَ مِائَةِ رَاكِبٍ وَأَمِيرُنَا أَبُو عُبَيْدَةَ نَرْصُدُ عِيرًا لِقُرَيْشٍ فَأَصَابَنَا جُوعٌ شَدِيدٌ حَتَّى أَكَلْنَا الْخَبَطَ فَسُمِّيَ جَيْشَ الْخَبَطِ وَأَلْقَى الْبَحْرُ حُوتًا يُقَالُ لَهُ الْعَنْبَرُ فَأَكَلْنَا نِصْفَ شَهْرٍ وَادَّهَنَّا بِوَدَكِهِ حَتَّى صَلَحَتْ أَجْسَامُنَا قَالَ فَأَخَذَ أَبُو عُبَيْدَةَ ضِلَعًا مِنْ أَضْلَاعِهِ فَنَصَبَهُ فَمَرَّ الرَّاكِبُ تَحْتَهُ وَكَانَ فِينَا رَجُلٌ فَلَمَّا اشْتَدَّ الْجُوعُ نَحَرَ ثَلَاثَ جَزَائِرَ ثُمَّ ثَلَاثَ جَزَائِرَ ثُمَّ نَهَاهُ أَبُو عُبَيْدَةَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] berkata, telah mengabarkan kepada kami [Sufyan] dari [Amru] ia berkata, \"Aku mendengar [Jabir] berkata, \"Nabi shallallahu 'alaihi wasallam mengirim kami sejumlah tiga ratus orang penunggang kuda untuk mengintai rombongan dagang Quraiys, dan sebagai pemimpinnya adalah Abu Ubaidah. Kami kemudian kelaparan dengan kelaparan yang sangat luar biasa hingga kami memakan dedaunan pohon yang jatuh. Maka ekspedisi itu pun disebut dengan Jaisy Al Khabath (pasukan daun rontok). Kemudian ada seekor ikan hiu yang disebut dengan nama al Anbar terdampar dari laut, kami memakannya selama setengah bulan dan menggunakan lemaknya sebagai minyak hingga badan kami pun kembali segar.\" Jabir berkata, \"Abu Ubaidah kemudian mengambil satu tulang ikan tersebut dan menancapkannya, lalu seorang pengendara kuda lewat di bawahnya. Dan di antara kami ada seorang laki-laki yang ketika kelaparan semakin parah, ia menyembelih tiga ekor unta, lalu menyembelih lagi tiga ekor unta, kemudian Abu Ubaidah pun melarangnya.\""},"4766":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي يَعْفُورٍ قَالَ سَمِعْتُ ابْنَ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُمَا قَالَغَزَوْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَ غَزَوَاتٍ أَوْ سِتًّا كُنَّا نَأْكُلُ مَعَهُ الْجَرَادَقَالَ سُفْيَانُ وَأَبُو عَوَانَةَ وَإِسْرَائِيلُ عَنْ أَبِي يَعْفُورٍ عَنْ ابْنِ أَبِي أَوْفَى سَبْعَ غَزَوَاتٍ","id":"Telah menceritakan kepada kami [Abul Walid] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Ya'fur] ia berkata; aku mendengar [Ibnu Abu Aufa] radliallahu 'anhuma, ia berkata, \"Kami pernah bersama Nabi shallallahu 'alaihi wasallam melakukan peperangan sebanyak tujuh atau enam kali, dan setiap itu kami bersama beliau makan belalang.\" [Sufyan] dan [Abu Awanah] dan [Israil] menyebutkan dari [Abu Ya'fur] dari [Ibnu Abu Aufa] dengan lafadz, \"Tujuh peperangan.\""},"4767":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ قَالَ حَدَّثَنِي رَبِيعَةُ بْنُ يَزِيدَ الدِّمَشْقِيُّ قَالَ حَدَّثَنِي أَبُو إِدْرِيسَ الْخَوْلَانِيُّ قَالَ حَدَّثَنِي أَبُو ثَعْلَبَةَ الْخُشَنِيُّ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا بِأَرْضِ أَهْلِ الْكِتَابِ فَنَأْكُلُ فِي آنِيَتِهِمْ وَبِأَرْضِ صَيْدٍ أَصِيدُ بِقَوْسِي وَأَصِيدُ بِكَلْبِي الْمُعَلَّمِ وَبِكَلْبِي الَّذِي لَيْسَ بِمُعَلَّمٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا مَا ذَكَرْتَ أَنَّكَ بِأَرْضِ أَهْلِ كِتَابٍ فَلَا تَأْكُلُوا فِي آنِيَتِهِمْ إِلَّا أَنْ لَا تَجِدُوا بُدًّا فَإِنْ لَمْ تَجِدُوا بُدًّا فَاغْسِلُوهَا وَكُلُوا وَأَمَّا مَا ذَكَرْتَ أَنَّكُمْ بِأَرْضِ صَيْدٍ فَمَا صِدْتَ بِقَوْسِكَ فَاذْكُرْ اسْمَ اللَّهِ وَكُلْ وَمَا صِدْتَ بِكَلْبِكَ الْمُعَلَّمِ فَاذْكُرْ اسْمَ اللَّهِ وَكُلْ وَمَا صِدْتَ بِكَلْبِكَ الَّذِي لَيْسَ بِمُعَلَّمٍ فَأَدْرَكْتَ ذَكَاتَهُ فَكُلْهُ","id":"Telah menceritakan kepada kami [Abu Ashim] dari [Haiwah bin Syuraih] ia berkata; telah menceritakan kepadaku [Rabi'ah bin Ad Dimasyqi] ia berkata; telah menceritakan kepadaku [Abu Idris Al Khaulani] ia berkata; telah menceritakan kepada kami [Abu Tsa'labah Al Khusya'i] ia berkata, \"Aku mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, kami berada negeri ahli kitab dan makan dengan bejana mereka. Dan kami juga berada di wilayah yang suka melakukan perburuan, aku lalu berburu dengan tombak dan anjing, baik yang terlatih maupun yang tidak terlatih?\" Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Sebagaimana yang kamu sebutkan bahwa kamu berada di negeri ahli kitab, maka janganlah kalian makan dengan bejana mereka kecuali ada keharusan. Jika ada keharusan (karena tidak ada yang lain), maka cucilah lalu makan dengannya. Adapun bahwa kamu berada di wilayah yang suka melakukan perburuan, maka apa yang terkena oleh tombakmu, bacakanlah nama Allah lalu makanlah. Dan yang dihasilkan oleh anjingmu yang terlatih, maka sebutlah nama Allah lalu makanlah. Dan hasil buruan yang dihasilkan oleh anjingmu yang tidak terlatih, dan kamu masih sempat menyembelihnya, maka makanlah.\""},"4768":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ قَالَلَمَّا أَمْسَوْا يَوْمَ فَتَحُوا خَيْبَرَ أَوْقَدُوا النِّيرَانَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَامَ أَوْقَدْتُمْ هَذِهِ النِّيرَانَ قَالُوا لُحُومِ الْحُمُرِ الْإِنْسِيَّةِ قَالَ أَهْرِيقُوا مَا فِيهَا وَاكْسِرُوا قُدُورَهَا فَقَامَ رَجُلٌ مِنْ الْقَوْمِ فَقَالَ نُهَرِيقُ مَا فِيهَا وَنَغْسِلُهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ ذَاكَ","id":"Telah menceritakan kepada kami [Al Makki bin Ibrahim] ia berkata; telah menceritakan kepadaku [Yazid bin Abu Ubaid] dari [Salamah Ibnul Akwa'] ia berkata, \"Di sore hari setelah para sahabat menaklukkan Khaibar, mereka menyalakan api (tungku), maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Kalian menyalakan tungku api itu untuk apa?\" mereka menjawab, \"Memasak daging keledai kampung.\" Beliau pun bersabda: \"Buanglah apa yang ada di dalam tungku dan pecahkanlah periuknya!\" seorang laki-laki dari mereka lalu berdiri dan berkata, \"Wahai Rasulullah, apakah kami harus membuang dan mencucinya?\" Beliau menjawab: \"Seperti itulah.\""},"4769":{"ar":"حَدَّثَنِي مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ بْنِ رَافِعٍ عَنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذِي الْحُلَيْفَةِ فَأَصَابَ النَّاسَ جُوعٌ فَأَصَبْنَا إِبِلًا وَغَنَمًا وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أُخْرَيَاتِ النَّاسِ فَعَجِلُوا فَنَصَبُوا الْقُدُورَ فَدُفِعَ إِلَيْهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِالْقُدُورِ فَأُكْفِئَتْ ثُمَّ قَسَمَ فَعَدَلَ عَشَرَةً مِنْ الْغَنَمِ بِبَعِيرٍ فَنَدَّ مِنْهَا بَعِيرٌ وَكَانَ فِي الْقَوْمِ خَيْلٌ يَسِيرَةٌ فَطَلَبُوهُ فَأَعْيَاهُمْ فَأَهْوَى إِلَيْهِ رَجُلٌ بِسَهْمٍ فَحَبَسَهُ اللَّهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِهَذِهِ الْبَهَائِمِ أَوَابِدَ كَأَوَابِدِ الْوَحْشِ فَمَا نَدَّ عَلَيْكُمْ مِنْهَا فَاصْنَعُوا بِهِ هَكَذَا قَالَ وَقَالَ جَدِّي إِنَّا لَنَرْجُو أَوْ نَخَافُ أَنْ نَلْقَى الْعَدُوَّ غَدًا وَلَيْسَ مَعَنَا مُدًى أَفَنَذْبَحُ بِالْقَصَبِ فَقَالَ مَا أَنْهَرَ الدَّمَ وَذُكِرَ اسْمُ اللَّهِ عَلَيْهِ فَكُلْ لَيْسَ السِّنَّ وَالظُّفُرَ وَسَأُخْبِرُكُمْ عَنْهُ أَمَّا السِّنُّ فَعَظْمٌ وَأَمَّا الظُّفُرُ فَمُدَى الْحَبَشَةِ","id":"Telah menceritakan kepada kami [Musa bin Ismail] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Said bin Masruq] dari [Abayah bin Rifa'ah bin Rafi'] dari kakeknya [Rafi' bin Khadij] ia berkata, \"Saat kami berada di Dzul Hulaifah bersama Nabi shallallahu 'alaihi wasallam, orang-orang merasakan lapar. Kemudian kami mendapatkan unta dan kambing, sementara saat itu Nabi shallallahu 'alaihi wasallam masih bersama rombongan yang ada di belakang (terakhir). Orang-orang pun segera membuat tungku dan memasang periuk, ketika Nabi shallallahu 'alaihi wasallam sampai di tempat mereka, maka beliau pun memerintahkan agar periuk tersebut ditumpahkan isinya, lalu ditumpahkanlah periuk tersebut. Beliau kemudian membagi-bagikan harta ghanimah dan menyamakan sepuluh kambing dengan seekor unta. Lalu lepaslah seekor unta dari mereka, padahal mereka hanya memiliki kuda yang lemah. Mereka kemudian mengejar unta tersebut hingga merasa kelelahan, lalu salah seorang dari mereka memanahnya dengan panah hingga Allah pun menjadikan unta tersebut tertahan (tertangkap). Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Sesungguhnya di antara binatang ini (unta) ada yang beringas, maka jika kalian mengalami yang seperti ini, hendaklah kalian lakukan seperti tadi.\" Abayah berkata, \"Kakekku berkata, \"Kami sangat khawatir ketika esok hari bertemu dengan musuh, kami tidak lagi memiliki pisau tajam, maka apakah boleh jika kami menyembelihnya dengan kayu yang tajam?\" Beliau menjawab: \"Apa saja yang dapat mengalirkan darah dan disebut nama Allah atasnya, maka makanlah. Kecuali As-Sin dan kuku. Aku jelaskan kepada kalian; As-Sin adalah tulang, sedangkan kuku karena itu adalah alat penyembelihan orang-orang Habasyah.\""},"4770":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ الْمُخْتَارِ أَخْبَرَنَا مُوسَى بْنُ عُقْبَةَ قَالَ أَخْبَرَنِي سَالِمٌ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ لَقِيَ زَيْدَ بْنَ عَمْرِو بْنِ نُفَيْلٍ بِأَسْفَلِ بَلْدَحٍ وَذَاكَ قَبْلَ أَنْ يُنْزَلَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَحْيُ فَقَدَّمَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُفْرَةً فِيهَا لَحْمٌ فَأَبَى أَنْ يَأْكُلَ مِنْهَا ثُمَّ قَالَ إِنِّي لَا آكُلُ مِمَّا تَذْبَحُونَ عَلَى أَنْصَابِكُمْ وَلَا آكُلُ إِلَّا مِمَّا ذُكِرَ اسْمُ اللَّهِ عَلَيْهِ","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] berkata, telah menceritakan kepada kami [Abdul Aziz] -yaitu Ibnul Mukhtar- berkata, telah mengabarkan kepada kami [Musa bin Uqbah] ia berkata; telah mengabarkan kepadaku [Salim] Bahwasanya ia mendengar [Abdullah] menceritakan dari Rasulullah shallallahu 'alaihi wasallam, Bahwasanya beliau berjumpa dengan Zaid bin Amru bin Nufail di bawah Baldah -dan itu adalah ketika belum turun wahyu kepada Rasulullah shallallahu 'alaihi wasallam-, Rasulullah shallallahu 'alaihi wasallam kemudian menyodorkan kepadanya nampan berisi daging, namun ia enggan untuk memakannya. Beliau pun bersabda: \"Sesungguhnya aku tidak makan apa yang kalian sembah untuk sesembahan kalian, dan aku juga tidak makan sesuatu yang tidak disebut nama Allah atasnya.\""},"4771":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ جُنْدَبِ بْنِ سُفْيَانَ الْبَجَلِيِّ قَالَضَحَّيْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُضْحِيَةً ذَاتَ يَوْمٍ فَإِذَا أُنَاسٌ قَدْ ذَبَحُوا ضَحَايَاهُمْ قَبْلَ الصَّلَاةِ فَلَمَّا انْصَرَفَ رَآهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمْ قَدْ ذَبَحُوا قَبْلَ الصَّلَاةِ فَقَالَ مَنْ ذَبَحَ قَبْلَ الصَّلَاةِ فَلْيَذْبَحْ مَكَانَهَا أُخْرَى وَمَنْ كَانَ لَمْ يَذْبَحْ حَتَّى صَلَّيْنَا فَلْيَذْبَحْ عَلَى اسْمِ اللَّهِ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Al Aswad bin Qais] dari [Jundub bin Sufyan Al Bajali] ia berkata, \"Suatu hari kami pernah menyembelih hewan kurban bersama Rasulullah shallallahu 'alaihi wasallam, ternyata orang-orang telah menyembelih hewan kurban mereka, namun hal itu mereka lakukan sebelum pelaksanaan shalat. Setelah Nabi shallallahu 'alaihi wasallam selesai melaksanakan shalat beliau melihat mereka telah menyembelih sembelihan mereka sebelum shalat, maka beliau pun bersabda: \"Barangsiapa menyembelih sebelum shalat, hendaklah ia menyembelih lagi sebagai gantinya. Dan barangsiapa belum menyembelih hingga kami selesai shalat, maka hendaklah ia menyembelih atas nama Allah.\""},"4772":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا مُعْتَمِرٌ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ سَمِعَ ابْنَ كَعْبِ بْنِ مَالِكٍ يُخْبِرُ ابْنَ عُمَرَ أَنَّ أَبَاهُ أَخْبَرَهُأَنَّ جَارِيَةً لَهُمْ كَانَتْ تَرْعَى غَنَمًا بِسَلْعٍ فَأَبْصَرَتْ بِشَاةٍ مِنْ غَنَمِهَا مَوْتًا فَكَسَرَتْ حَجَرًا فَذَبَحَتْهَا فَقَالَ لِأَهْلِهِ لَا تَأْكُلُوا حَتَّى آتِيَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْأَلَهُ أَوْ حَتَّى أُرْسِلَ إِلَيْهِ مَنْ يَسْأَلُهُ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ بَعَثَ إِلَيْهِ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَكْلِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakar Al Muqaddami] berkata, telah menceritakan kepada kami [Mu'tamir] dari [Ubaidullah] dari [Nafi'] ia mendengar [Ibnu Ka'b bin Malik] mengabarkan kepada Ibnu Umar, bahwa [Bapaknya] mengabarkan kepadanya, bahwa budak perempuan mereka mengembala kambing di Sal' (nama tempat), budak wanita itu kemudian melihat bahwa di antara kambingnya ada yang akan mati, maka iapun memecah batu dan menyembelihnya dengan pecahan batu tersebut. Ka'b lalu berkata kepada keluarganya, \"Kalian jangan memakannya hingga aku menemui Nabi shallallahu 'alaihi wasallam dan bertanya kepadanya, atau ia mengatakan, \"hingga aku mengutus seseorang yang bisa menanyakannya kepada beliau. Ka'b kemudian mengutus seseorang menemui Nabi shallallahu 'alaihi wasallam, maka Nabi shallallahu 'alaihi wasallam pun memerintahkan untuk memakannya.\""},"4773":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ رَجُلٍ مِنْ بَنِي سَلِمَةَأَخْبَرَ عَبْدَ اللَّهِ أَنَّ جَارِيَةً لِكَعْبِ بْنِ مَالِكٍ تَرْعَى غَنَمًا لَهُ بِالْجُبَيْلِ الَّذِي بِالسُّوقِ وَهُوَ بِسَلْعٍ فَأُصِيبَتْ شَاةٌ فَكَسَرَتْ حَجَرًا فَذَبَحَتْهَا بِهِ فَذَكَرُوا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُمْ بِأَكْلِهَا","id":"Telah menceritakan kepada kami [Musa] berkata, telah menceritakan kepada kami [Juwairiyah] dari [Nafi'] dari [seorang laki-laki] dari bani Salamah, ia mengabarkan kepada Abdullah bin Umar bahwa budak perempuan Ka'b bin Malik mengembalakan kambing miliknya di gunung kecil, di daerah pasar, yaitu tempat yang berada di Sal'. Salah satu kambingnya sakit, lalu budak wanita itu memecah batu dan menyembelih kambing yang sakit itu dengan pecahan batu tersebut. Orang-orang pun menceritakan hal itu kepada Nabi shallallahu 'alaihi wasallam, dan beliau memerintahkan untuk tetap memakannya.\""},"4774":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنِي أَبِي عَنْ شُعْبَةَ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ جَدِّهِ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ لَيْسَ لَنَا مُدًى فَقَالَ مَا أَنْهَرَ الدَّمَ وَذُكِرَ اسْمُ اللَّهِ فَكُلْ لَيْسَ الظُّفُرَ وَالسِّنَّ أَمَّا الظُّفُرُ فَمُدَى الْحَبَشَةِ وَأَمَّا السِّنُّ فَعَظْمٌ وَنَدَّ بَعِيرٌ فَحَبَسَهُ فَقَالَ إِنَّ لِهَذِهِ الْإِبِلِ أَوَابِدَ كَأَوَابِدِ الْوَحْشِ فَمَا غَلَبَكُمْ مِنْهَا فَاصْنَعُوا بِهِ هَكَذَا","id":"Telah menceritakan kepada kami [Abdan] ia berkata; telah mengabarkan kepadaku [Bapakku] dari [Syu'bah] dari [Sa'id bin Masruq] dari [Abayah bin Rifa'ah] dari [Kakeknya] bahwa ia berkata, \"Wahai Rasulullah, kami tidak memiliki pisau tajam?\" beliau pun bersabda: \"Apa saja yang dapat mengalirkan darah dan disebutkan nama Allah atasnya, maka makanlah. Kecuali kuku dan As-Sin. Sebab kuku adalah alat penyembelihan orang-orang Habasyah, sementara As-Sin adalah tulang.\" Lalu ada seekor unta yang kabur kemudian (mereka) menangkapnya, beliau lalu bersabda: \"Sesungguhnya di antara unta-unta ini ada unta yang beringas, jika kalian mampu, maka hendaklah kalian melakukannya seperti ini.\""},"4775":{"ar":"حَدَّثَنَا صَدَقَةُ أَخْبَرَنَا عَبْدَةُ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِأَنَّ امْرَأَةً ذَبَحَتْ شَاةً بِحَجَرٍ فَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَمَرَ بِأَكْلِهَاوَقَالَ اللَّيْثُ حَدَّثَنَا نَافِعٌ أَنَّهُ سَمِعَ رَجُلًا مِنْ الْأَنْصَارِ يُخْبِرُ عَبْدَ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ جَارِيَةً لِكَعْبٍ بِهَذَا","id":"Telah menceritakan kepada kami [Shadaqah] berkata, telah mengabarkan kepada kami [Abdah] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Ka'b bin Malik] dari [Bapaknya], bahwa ada seorang wanita menyembelih seekor kambing dengan batu, Nabi shallallahu 'alaihi wasallam lalu ditanya tentang itu, maka beliau memerintahkan untuk tetap memakannya.\" [Al laits] berkata; telah menceritakan kepada kami [Nafi'] Bahwasanya ia mendengar [seorang laki-laki Anshar] mengabarkan kepada Abdullah, dari Nabi shallallahu 'alaihi wasallam, bahwa budak wanita Ka'b -menyebutkan Hadits seperti ini-.\""},"4776":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ رَجُلٍ مِنَ الْأَنْصَارِ عَنْ مُعَاذِ بْنِ سَعْدٍ أَوْ سَعْدِ بْنِ مُعَاذٍ أَخْبَرَهُأَنَّ جَارِيَةً لِكَعْبِ بْنِ مَالِكٍ كَانَتْ تَرْعَى غَنَمًا بِسَلْعٍ فَأُصِيبَتْ شَاةٌ مِنْهَا فَأَدْرَكَتْهَا فَذَبَحَتْهَا بِحَجَرٍ فَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كُلُوهَا","id":"Telah menceritakan kepada kami [Ismail] berkata; telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Laki-laki Anshar] dari [Mu'adz bin Sa'd atau Sa'd bin Mu'adz] ia mengabarkan kepadanya, bahwa budak wanita Ka'b bin Malik mengembalakan kambing di daerah Sal', lalu salah satu kambingnya terkena sakit hingga ia pun menyembelihnya dengan batu. Ketika Nabi shallallahu 'alaihi wasallam ditanya tentang hukum (daging sembelihannya), beliau menjawab: \"Makanlah.\""},"4777":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ أَبِيهِ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلْ يَعْنِي مَا أَنْهَرَ الدَّمَ إِلَّا السِّنَّ وَالظُّفُرَ","id":"Telah menceritakan kepada kami [Qabishah] berkata, telah menceritakan kepada kami [Sufyan] dari [Bapaknya] dari [Abayah bin Rifa'ah] dari [Rafi' bin Khadij] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Makanlah -yakni apa-apa yang mengalirkan darah- kecuali tulang dan kuku.\""},"4778":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ حَدَّثَنَا أُسَامَةُ بْنُ حَفْصٍ الْمَدَنِيُّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ قَوْمًا قَالُوا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ قَوْمًا يَأْتُونَا بِاللَّحْمِ لَا نَدْرِي أَذُكِرَ اسْمُ اللَّهِ عَلَيْهِ أَمْ لَا فَقَالَ سَمُّوا عَلَيْهِ أَنْتُمْ وَكُلُوهُقَالَتْ وَكَانُوا حَدِيثِي عَهْدٍ بِالْكُفْرِ تَابَعَهُ عَلِيٌّ عَنْ الدَّرَاوَرْدِيِّ وَتَابَعَهُ أَبُو خَالِدٍ وَالطُّفَاوِيُّ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaidullah] berkata, telah menceritakan kepada kami [Usamah bin Hafsh Al Madani] dari [Hisyam bin Urwah] dari [Bapaknya] dari [Aisyah] radliallahu 'anhuma, bahwa suatu kaum pernah bertanya kepada Nabi shallallahu 'alaihi wasallam, \"Suatu kaum datang dengan membawa daging, namun kami tidak tahu apakah saat menyembelihnya menyebut nama Allah atau tidak?\" Beliau menjawab: \"Kalau begitu sebutlah nama Allah, lalu makanlah oleh kalian.\" Aisyah berkata, \"Mereka adalah orang-orang yang baru masuk Islam.\" Hadits ini dikuatkan oleh [Ali] dari [Ad Darawardi], dan dikuatkan juga oleh [Abu Khalid] dan [Ath Thufawi].\""},"4779":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا مُحَاصِرِينَ قَصْرَ خَيْبَرَ فَرَمَى إِنْسَانٌ بِجِرَابٍ فِيهِ شَحْمٌ فَنَزَوْتُ لِآخُذَهُ فَالْتَفَتُّ فَإِذَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَحْيَيْتُ مِنْهُ","id":"Telah menceritakan kepada kami [Abul Walid] berkata, telah menceritakan kepada kami [Syu'bah] dari [Humaid bin Hilal] dari [Abdullah bin Mughaffal] radliallahu 'anhu, ia berkata, \"Kami pernah mengepung istana Khaibar, tiba-tiba ada seseorang yang melempar geriba yang didalamnya terdapat lemak. Maka aku pun segera melompat untuk mengambilnya, ketika aku menoleh ternyata ada Nabi shallallahu 'alaihi wasallam sehingga aku pun malu dibuatnya.\""},"4780":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَبِي عَنْ عَبَايَةَ بْنِ رِفَاعَةَ بْنِ رَافِعِ بْنِ خَدِيجٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا لَاقُو الْعَدُوِّ غَدًا وَلَيْسَتْ مَعَنَا مُدًى فَقَالَ اعْجَلْ أَوْ أَرِنْ مَا أَنْهَرَ الدَّمَ وَذُكِرَ اسْمُ اللَّهِ فَكُلْ لَيْسَ السِّنَّ وَالظُّفُرَ وَسَأُحَدِّثُكَ أَمَّا السِّنُّ فَعَظْمٌ وَأَمَّا الظُّفُرُ فَمُدَى الْحَبَشَةِ وَأَصَبْنَا نَهْبَ إِبِلٍ وَغَنَمٍ فَنَدَّ مِنْهَا بَعِيرٌ فَرَمَاهُ رَجُلٌ بِسَهْمٍ فَحَبَسَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِهَذِهِ الْإِبِلِ أَوَابِدَ كَأَوَابِدِ الْوَحْشِ فَإِذَا غَلَبَكُمْ مِنْهَا شَيْءٌ فَافْعَلُوا بِهِ هَكَذَا","id":"Telah menceritakan kepada kami [Amru bin Ali] berkata, telah menceritakan kepada kami [Yahya] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepada kami [Bapakku] dari [Abayah bin Rifa'ah bin Rafi' bin Khadij] dari [Rafi' bin Khadij] ia berkata, \"Aku bertanya kepada Rasulullah, besok kita akan bertemu dengan musuh dan kita tidak lagi mempunyai pisau tajam?\" Beliau menjawab: \"Sembelihlah dengan sesuatu yang dapat mengalirkan darah, sebutlah nama Allah lalu makanlah, kecuali dengan gigi dan kuku. Aku jelaskan kepada kalian; gigi itu sejenis tulang, sedangkan kuku adalah alat yang biasa digunakan oleh bangsa Habsyah (untuk menyembelih).\" Kami lalu mendapatkan rampasan unta dan kambing, saat ada salah satu unta tersebut yang kabur, seorang laki-laki melemparnya dengan anak panah. Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya di antara unta-unta ini ada yang beringas sebagaimana binatang buas, jika kalian merasa susah dibuatnya maka lakukanlah seperti itu.\""},"4781":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا سُفْيَانُ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ قَالَ أَخْبَرَتْنِي فَاطِمَةُ بِنْتُ الْمُنْذِرِ امْرَأَتِي عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَتْنَحَرْنَا عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَسًا فَأَكَلْنَاهُ","id":"Telah menceritakan kepada kami [Khallad bin Yahya] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepada kami [Hisyam bin Urwah] ia berkata; telah mengabarkan kepadaku [Fatimah binti Al Mundzir] isteriku, dari [Asma binti Abu Bakar] radliallahu 'anhuma, ia berkata, \"Pada masa Nabi shallallahu 'alaihi wasallam kami pernah menyembelih kurban berupa kuda, lalu kami pun memakannya.\""},"4782":{"ar":"حَدَّثَنَا إِسْحَاقُ سَمِعَ عَبْدَةَ عَنْ هِشَامٍ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَ قَالَتْذَبَحْنَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَسًا وَنَحْنُ بِالْمَدِينَةِ فَأَكَلْنَاهُ","id":"Telah menceritakan kepada kami [Ishaq] ia mendengar [Abdah] dari [Hisyam] dari [Fatimah] dari [Asma] ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam, kami pernah menyembelih kuda di Madinah dan kami pun memakannya.\""},"4783":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ هِشَامٍ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ أَنَّ أَسْمَاءَ بِنْتَ أَبِي بَكْرٍ قَالَتْنَحَرْنَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَسًا فَأَكَلْنَاهُتَابَعَهُ وَكِيعٌ وَابْنُ عُيَيْنَةَ عَنْ هِشَامٍ فِي النَّحْرِ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Hisyam] dari [Fatimah bin Al Mundzir] bahwa [Asma binti Abu Bakar] radliallahu 'anhuma berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam kami pernah berkurban dengan menyembelih kuda, lalu kami memakannya.\" Hadits ini dikuatkan oleh [Waki'] dan [Ibnu Uyainah] dari [Hisyam] tentang penyembelihan kurban.\""},"4784":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ هِشَامِ بْنِ زَيْدٍ قَالَدَخَلْتُ مَعَ أَنَسٍ عَلَى الْحَكَمِ بْنِ أَيُّوبَ فَرَأَى غِلْمَانًا أَوْ فِتْيَانًا نَصَبُوا دَجَاجَةً يَرْمُونَهَا فَقَالَ أَنَسٌ نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُصْبَرَ الْبَهَائِمُ","id":"Telah menceritakan kepada kami [Abul Walid] berkata, telah menceritakan kepada kami [Syu'bah] dari [Hisyam bin Zaid] ia berkata, \"Pernah aku dan Anas menemui Al Hakam bin Ayyub, lalu Anas melihat seorang pemuda memasang seekor ayam untuk sasaran panahnya, maka [Anas] pun berkata, \"Nabi shallallahu 'alaihi wasallam telah melarang menjadikan bintang untuk dijadikan sasaran (latihan) tembak.\""},"4785":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يَعْقُوبَ أَخْبَرَنَا إِسْحَاقُ بْنُ سَعِيدِ بْنِ عَمْرٍو عَنْ أَبِيهِ أَنَّهُ سَمِعَهُ يُحَدِّثُ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ دَخَلَ عَلَى يَحْيَى بْنِ سَعِيدٍ وَغُلَامٌ مِنْ بَنِي يَحْيَى رَابِطٌ دَجَاجَةً يَرْمِيهَا فَمَشَى إِلَيْهَا ابْنُ عُمَرَ حَتَّى حَلَّهَا ثُمَّ أَقْبَلَ بِهَا وَبِالْغُلَامِ مَعَهُ فَقَالَ ازْجُرُوا غُلَامَكُمْ عَنْ أَنْ يَصْبِرَ هَذَا الطَّيْرَ لِلْقَتْلِ فَإِنِّي سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ تُصْبَرَ بَهِيمَةٌ أَوْ غَيْرُهَا لِلْقَتْلِ","id":"Telah menceritakan kepada kami [Ahmad bin Ya'qub] berkata, telah mengabarkan kepada kami [Ishaq bin Sa'id bin Amru] dari [Bapaknya] Bahwasanya ia mendengar dia menceritakan dari [Ibnu Umar] radliallahu 'anhuma, bahwa ia pernah menemui Yahya bin Sa'id, sementara ada seorang anak laki-laki keturunan Yahya mengikat seekor ayam untuk dijadikan sebagai sasaran tembaknya, maka Ibnu Umar pun berjalan ke arahnya dan melepaskan ayam tersebut. kemudian ia kembali lagi bersama ayam dan anak laki-laki tersebut, setelah itu ia berkata, \"Hardiklah anak laki-laki kalian dari menjadikan burung ini sebagai sasaran tembaknya, sesungguhnya aku mendengar Nabi shallallahu 'alaihi wasallam melarang untuk menjadikan binatang atau selainnya sebagai sasaran tembak.\""},"4786":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ كُنْتُ عِنْدَ ابْنِ عُمَرَفَمَرُّوا بِفِتْيَةٍ أَوْ بِنَفَرٍ نَصَبُوا دَجَاجَةً يَرْمُونَهَا فَلَمَّا رَأَوْا ابْنَ عُمَرَ تَفَرَّقُوا عَنْهَا وَقَالَ ابْنُ عُمَرَ مَنْ فَعَلَ هَذَا إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ مَنْ فَعَلَ هَذَاتَابَعَهُ سُلَيْمَانُ عَنْ شُعْبَةَ حَدَّثَنَا الْمِنْهَالُ عَنْ سَعِيدٍ عَنْ ابْنِ عُمَرَ لَعَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ مَثَّلَ بِالْحَيَوَانِ وَقَالَ عَدِيٌّ عَنْ سَعِيدٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu An Nu'man] berkata, telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Sa'id bin Jubair] ia berkata, \"Aku pernah bersama [Ibnu Umar] melewati sekelompok orang yang sedang menjadikan ayam sebagai sasaran tembak mereka, ketika mereka melihat Ibnu Umar mereka pun kabur. Ibnu Umar lalu berkata, \"Siapa yang melakukan ini! Sesungguhnya Nabi shallallahu 'alaihi wasallam melaknat orang yang melakukan perbuatan seperti ini.\" Hadits ini dikuatkan oleh [Sulaiman] dari [Syu'bah] berkata, telah menceritakan kepada kami [Al Minhal] dari [Sa'id] dari [Ibnu Umar] ia berkata, \"Nabi shallallahu 'alaihi wasallam melaknat orang yang memutilasi hewan.\" [Adi] menyebutkan dari [Sa'id] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam.\""},"4787":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَدِيُّ بْنُ ثَابِتٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ النُّهْبَةِ وَالْمُثْلَةِ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Syu'bah] ia berkata; telah mengabarkan kepadaku [Adi bin Tsabit] ia berkata; Aku mendengar [Abdullah bin Yazid] dari Nabi shallallahu 'alaihi wasallam, Bahwasanya beliau melarang dari perbuatan mutilasi.\""},"4788":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ زَهْدَمٍ الْجَرْمِيِّ عَنْ أَبِي مُوسَى يَعْنِي الْأَشْعَرِيَّ رَضِيَ اللَّهُ عَنْهُ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ دَجَاجًا","id":"Telah menceritakan kepada kami [Yahya] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ayyub] dari [Abu Qilabah] dari [Zahdam Al Jarmi] dari [Abu Musa] -yaitu Al Asy'ari- radliallahu 'anhu, ia berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam makan daging ayam.\""},"4789":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ بْنُ أَبِي تَمِيمَةَ عَنْ الْقَاسِمِ عَنْ زَهْدَمٍ قَالَكُنَّا عِنْدَ أَبِي مُوسَى الْأَشْعَرِيِّ وَكَانَ بَيْنَنَا وَبَيْنَ هَذَا الْحَيِّ مِنْ جَرْمٍ إِخَاءٌ فَأُتِيَ بِطَعَامٍ فِيهِ لَحْمُ دَجَاجٍ وَفِي الْقَوْمِ رَجُلٌ جَالِسٌ أَحْمَرُ فَلَمْ يَدْنُ مِنْ طَعَامِهِ قَالَ ادْنُ فَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ مِنْهُ قَالَ إِنِّي رَأَيْتُهُ أَكَلَ شَيْئًا فَقَذِرْتُهُ فَحَلَفْتُ أَنْ لَا آكُلَهُ فَقَالَ ادْنُ أُخْبِرْكَ أَوْ أُحَدِّثْكَ إِنِّي أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَفَرٍ مِنْ الْأَشْعَرِيِّينَ فَوَافَقْتُهُ وَهُوَ غَضْبَانُ وَهُوَ يَقْسِمُ نَعَمًا مِنْ نَعَمِ الصَّدَقَةِ فَاسْتَحْمَلْنَاهُ فَحَلَفَ أَنْ لَا يَحْمِلَنَا قَالَ مَا عِنْدِي مَا أَحْمِلُكُمْ عَلَيْهِ ثُمَّ أُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَهْبٍ مِنْ إِبِلٍ فَقَالَ أَيْنَ الْأَشْعَرِيُّونَ أَيْنَ الْأَشْعَرِيُّونَ قَالَ فَأَعْطَانَا خَمْسَ ذَوْدٍ غُرَّ الذُّرَى فَلَبِثْنَا غَيْرَ بَعِيدٍ فَقُلْتُ لِأَصْحَابِي نَسِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمِينَهُ فَوَاللَّهِ لَئِنْ تَغَفَّلْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمِينَهُ لَا نُفْلِحُ أَبَدًا فَرَجَعْنَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْنَا يَا رَسُولَ اللَّهِ إِنَّا اسْتَحْمَلْنَاكَ فَحَلَفْتَ أَنْ لَا تَحْمِلَنَا فَظَنَنَّا أَنَّكَ نَسِيتَ يَمِينَكَ فَقَالَ إِنَّ اللَّهَ هُوَ حَمَلَكُمْ إِنِّي وَاللَّهِ إِنْ شَاءَ اللَّهُ لَا أَحْلِفُ عَلَى يَمِينٍ فَأَرَى غَيْرَهَا خَيْرًا مِنْهَا إِلَّا أَتَيْتُ الَّذِي هُوَ خَيْرٌ وَتَحَلَّلْتُهَا","id":"Telah menceritakan kepada kami [Abu Ma'mar] berkata, telah menceritakan kepada kami [Abdul Warits] berkata, telah menceritakan kepada kami [Ayyub bin Abu Tamimah] dari [Al Qasim] dari [Zahdam] ia berkata, \"Aku pernah bersama [Abu Musa Al Asy'ari], sementara kami dengan kaum tersebut sedang menjalin hubungan persaudaraan, kemudian kami di jamu dengan jamuan yang terdapat daging ayam. Di kaum tersebut terdapat seorang laki-laki berkulit merah sedang duduk menyendiri dan tidak mau mendekat, lalu Abu Musa berkata, \"Mendekatlah karena aku pernah melihat Rasulullah shallallahu 'alaihi wasallam memakannya.\" Laki-laki itu menjawab, \"Sesungguhnya aku pernah melihat beliau memakan sesuatu yang aku merasa jijik dengannya, lalu aku bersumpah untuk tidak memakannya.\" Abu Musa berkata, \"Kemarilah aku akan memberitahukanmu, atau menceritakan kepadamu, Saya pernah mendatangi Nabi shallallahu 'alaihi wasallam bersama sekelompok orang-orang Asy'ari, ketika itu kami mendapati beliau sedang marah sambil membagi unta sedekah, lalu kami memohon perbelanjaan perang kepada beliau, namun beliau bersumpah untuk tidak memberikan perbelanjaan perang, beliau bersabda: \"Sungguh saya tidak dapat memberikan perbelanjaan perang kepada kalian, karena saya tidak memiliki sesuatu untuk membelanjai kalian semua.\" Selang beberapa saat, Rasulullah shallallahu 'alaihi wasallam diberi beberapa unta (hasil ghanimah), kemudian beliau bersabda: \"Kemanakah orang-orang Asy'ariyyin tadi? Kemanakah orang-orang Asy'ariyyin tadi?\" Abu Musa melanjutkan, \"Lalu beliau menyuruh untuk memberikannya kepada kami, yaitu lima ekor unta berpunuk putih. Belum jauh kami pergi, aku berkata kepada teman-temanku, \"Sepertinya Rasulullah shallallahu 'alaihi wasallam lupa dengan sumpahnya tadi, demi Allah sekiranya Rasulullah shallallahu 'alaihi wasallam benar-benar lupa dengan sumpah yang pernah di ucapkan tadi, niscaya kita tidak akan beruntung selama-lamanya.\" Lalu kami kembali menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya kami meminta perbelanjaan perang kepada anda, namun anda bersumpah untuk tidak memberikan perbelanjaan perang kepada kami, kami menyangka anda lupa dengan sumpah yang telah anda ucapkan.\" Beliau menjawab: \"Memang, sesungguhnya bukan sayalah yang menanggung perbelanjaan kalian, tetapi Allahlah yang menanggungnya. Demi Allah, sesungguhnya saya -Insya Allah- tidak akan mengucapkan suatu sumpah, bila kemudian saya melihat sesuatu yang lebih baik daripada sumpahku itu, melainkan saya melaksanakan yang lebih baik dari sumpahku, dengan membayar denda sumpahku itu.\""},"4790":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا هِشَامٌ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَ قَالَتْنَحَرْنَا فَرَسًا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكَلْنَاهُ","id":"Telah menceritakan kepada kami [Al Humaidi] berkata, telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepada kami [Hisyam] dari [Fatimah] dari [Asma] ia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam kami pernah berkurban dengan menyembelih kuda, lalu kami pun memakannya.\""},"4791":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمْ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ خَيْبَرَ عَنْ لُحُومِ الْحُمُرِ وَرَخَّصَ فِي لُحُومِ الْخَيْلِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Amru bin Dinar] dari [Muhammad bin Ali] dari [Jabir bin Abdullah] radliallahu 'anhuma, ia berkata, \"Pada hari penaklukan Khaibar Nabi shallallahu 'alaihi wasallam melarang untuk memakan daging keledai dan memberi keringanan untuk makan daging kuda.\""},"4792":{"ar":"حَدَّثَنَا صَدَقَةُ أَخْبَرَنَا عَبْدَةُ عَنْ عُبَيْدِ اللَّهِ عَنْ سَالِمٍ وَنَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَانَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِ يَوْمَ خَيْبَرَحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ قَالَ نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِ تَابَعَهُ ابْنُ الْمُبَارَكِ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ وَقَالَ أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ سَالِمٍ","id":"Telah menceritakan kepada kami [Shadaqah] berkata, telah mengabarkan kepada kami [Abdah] dari [Ubaidullah] dari [Salim] dan [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma, bahwa pada saat penaklukan Khaibar Nabi shallallahu 'alaihi wasallam melarang makan daging keledai jinak.\" Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Ubaidullah] berkata, telah menceritakan kepadaku [Nafi'] dari [Abdullah] ia berkata, \"Nabi shallallahu 'alaihi wasallam melarang makan daging keledai jinak.\" Hadits ini dikuatkan oleh [Ibnul Mubarak] dari [Ubaidullah] dari [Nafi'], dan [Abu Usamah] menyebutkan dari [Ubaidullah] dari [Salim].\""},"4793":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ اللَّهِ وَالْحَسَنِ ابْنَيْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ أَبِيهِمَا عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُمْ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُتْعَةِ عَامَ خَيْبَرَ وَعَنْ لُحُومِ حُمُرِ الْإِنْسِيَّةِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] berkata, telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Abdullah] dan [Al Hasan] keduanya anak Muhammad bin Ali, dari [Bapak keduanya] dari [Ali] radliallahu 'anhum, ia berkata, \"Saat penaklukan Khaibar Rasulullah shallallahu 'alaihi wasallam melarang dari nikah mut'ah dan makan daging keledai.\""},"4794":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ عَمْرٍو عَنْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ خَيْبَرَ عَنْ لُحُومِ الْحُمُرِ وَرَخَّصَ فِي لُحُومِ الْخَيْلِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Hammad] dari [Amru] dari [Muhammad bin Ali] dari [Jabir bin Abdullah] ia berkata, \"Saat penaklukan Khaibar Nabi shallallahu 'alaihi wasallam melarang makan daging keledai dan memberi keringanan makan daging kuda.\""},"4795":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ قَالَ حَدَّثَنِي عَدِيٌّ عَنْ الْبَرَاءِ وَابْنِ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُمْ قَالَانَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لُحُومِ الْحُمُرِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Syu'bah] ia berkata; telah menceritakan kepadaku [Adi] dari [Al Bara] dan [Ibnu Abu Aufa] radliallahu 'anhum, keduanya berkata, \"Nabi shallallahu 'alaihi wasallam melarang makan daging keledai.\""},"4796":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ أَبَا إِدْرِيسَ أَخْبَرَهُ أَنَّ أَبَا ثَعْلَبَةَ قَالَحَرَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لُحُومَ الْحُمُرِ الْأَهْلِيَّةِتَابَعَهُ الزُّبَيْدِيُّ وَعُقَيْلٌ عَنْ ابْنِ شِهَابٍ وَقَالَ مَالِكٌ وَمَعْمَرٌ وَالْمَاجِشُونُ وَيُونُسُ وَابْنُ إِسْحَاقَ عَنْ الزُّهْرِيِّ نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كُلِّ ذِي نَابٍ مِنْ السِّبَاعِ","id":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab] bahwa [Abu Idris] telah mengabarkan kepadanya bahwa [Abu Tsa'labah] berkata; \"Rasulullah shallallahu 'alaihi wasallam telah mengharamkan daging keledai jinak.\" Hadits ini di perkuat juga oleh [Az Zubaidi] dan ['Uqail] dari [Ibnu Syihab]. Berkata juga [Malik], [Ma'mar], [Al Majisun], [Yunus] serta [Ibnu Ishaq] dari [Az Zuhri] bahwa Nabi shallallahu 'alaihi wasallam melarang makan daging binatang buas yang bertaring.\""},"4797":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَهُ جَاءٍ فَقَالَ أُكِلَتْ الْحُمُرُ ثُمَّ جَاءَهُ جَاءٍ فَقَالَ أُكِلَتْ الْحُمُرُ ثُمَّ جَاءَهُ جَاءٍ فَقَالَ أُفْنِيَتْ الْحُمُرُ فَأَمَرَ مُنَادِيًا فَنَادَى فِي النَّاسِ إِنَّ اللَّهَ وَرَسُولَهُ يَنْهَيَانِكُمْ عَنْ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِ فَإِنَّهَا رِجْسٌ فَأُكْفِئَتْ الْقُدُورُ وَإِنَّهَا لَتَفُورُ بِاللَّحْمِ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] telah mengabarkan kepada kami [Abdul Wahab Ats Tsaqafi] dari [Ayyub] dari [Muhammad] dari [Anas bin Malik] -radliallahu 'anhu- bahwa seseorang datang kepada Rasulullah shallallahu 'alaihi wasallam sambil berkata; \"Daging keledai telah banyak di konsumsi, \" selang beberapa saat orang tersebut datang lagi sambil berkata; \"Daging keledai telah banyak di konsumsi, \" setelah beberapa saat orang tersebut datang lagi seraya berkata; \"Keledai telah binasa.\" Maka beliau memerintahkan seseorang untuk menyeru di tengah-tengah manusia, sesungguhnya Allah dan Rasul-Nya melarang kalian mengkonsumsi daging keledai jinak, karena daging itu najis.\" Oleh karena itu mereka menumpahkan periuk yang di gunakan untuk memasak daging tersebut.\""},"4798":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ عَمْرٌو قُلْتُ لِجَابِرِ بْنِ زَيْدٍيَزْعُمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ حُمُرِ الْأَهْلِيَّةِ فَقَالَ قَدْ كَانَ يَقُولُ ذَاكَ الْحَكَمُ بْنُ عَمْرٍو الْغِفَارِيُّ عِنْدَنَا بِالْبَصْرَةِوَلَكِنْ أَبَى ذَاكَ الْبَحْرُ ابْنُ عَبَّاسٍ وَقَرَأَ{ قُلْ لَا أَجِدُ فِيمَا أُوحِيَ إِلَيَّ مُحَرَّمًا }","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan], ['Amru] berkata; aku berkata kepada [Jabir bin Zaid] bahwa orang-orang menganggap Rasulullah shallallahu 'alaihi wasallam telah melarang makan daging keledai jinak, lantas Jabir menjawab; [Hakam bin 'Amru Al Ghifari] juga pernah mengatakan seperti itu di sisi kami ketika berada di Bashrah, akan tetapi sang lautan (ilmu) yaitu [Ibnu Abbas] tidak membenarkan pernyataan itu sambil mengutip ayat \"Katakanlah: \"Tiadalah Aku peroleh dalam wahyu yang diwahyukan kepadaku, sesuatu yang diharamkan bagi orang yang hendak memakannya QS Al An'am; 145"},"4799":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي ثَعْلَبَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ أَكْلِ كُلِّ ذِي نَابٍ مِنْ السِّبَاعِتَابَعَهُ يُونُسُ وَمَعْمَرٌ وَابْنُ عُيَيْنَةَ وَالْمَاجِشُونُ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Abu Idris Al Khaulani] dari [Abu Tsa'labah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam melarang makan daging binatang buas yang bertaring.\" Hadits ini juga dikuatkan oleh riwayat [Yunus], [Ma'mar], [Ibnu 'Uyainah] dan [Al Majisyun] dari [Az Zuhri]."},"4800":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ أَنَّ عُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِشَاةٍ مَيِّتَةٍ فَقَالَ هَلَّا اسْتَمْتَعْتُمْ بِإِهَابِهَا قَالُوا إِنَّهَا مَيِّتَةٌ قَالَ إِنَّمَا حَرُمَ أَكْلُهَا","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ya'kub bin Ibrahim] telah menceritakan kepada kami [Ayahku] dari [Shalih] dia berkata; telah menceritakan kepadaku [Ibnu Syihab] bahwa ['Ubaidullah bin Abdullah] telah mengabarkan kepadanya bahwa [Abdullah bin Abbas] radliallahu 'anhuma telah mengabarkan kepadanya, sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah melewati bangkai seekor kambing, lalu beliau bersabda: \"Kenapa kalian tidak memanfa'atkan kulitnya?\" Mereka (para sahabat) menjawab; \"Ia telah menjadi bangkai\" beliau bersabda: \"Hanyasanya yang diharamkan adalah memakannya.\""},"4801":{"ar":"حَدَّثَنَا خَطَّابُ بْنُ عُثْمَانَ حَدَّثَنَا مُحَمَّدُ بْنُ حِمْيَرَ عَنْ ثَابِتِ بْنِ عَجْلَانَ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَنْزٍ مَيِّتَةٍ فَقَالَ مَا عَلَى أَهْلِهَا لَوْ انْتَفَعُوا بِإِهَابِهَا","id":"Telah menceritakan kepada kami [Khattab bin Utsman] telah menceritakan kepada kami [Muhammad bin Himyar] dari [Tsabit bin 'Ajlan] dia berkata; aku mendengar [Sa'id bin Jubair] berkata; aku mendengar [Ibnu Abbas] radliallahu 'anhuma berkata; \"Nabi shallallahu 'alaihi wasallam pernah melewati bangkai seekor kambing, lalu beliau bersabda: \"Kenapa pemiliknya tidak memanfa'atkan kulitnya?\""},"4802":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا عُمَارَةُ بْنُ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مَكْلُومٍ يُكْلَمُ فِي سَبِيلِ اللَّهِ إِلَّا جَاءَ يَوْمَ الْقِيَامَةِ وَكَلْمُهُ يَدْمَى اللَّوْنُ لَوْنُ دَمٍ وَالرِّيحُ رِيحُ مِسْكٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami ['Umarah bin Al Qa'qa'] dari [Abu Zur'ah bin 'Amru bin Jarir] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah setiap luka yang terluka (karena berjuang) di jalan Allah, kecuali akan datang pada hari kiamat dengan keadaan lukanya seperti hari ia terluka, warnanya warna darah dan baunya bau kesturi.\""},"4803":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الْجَلِيسِ الصَّالِحِ وَالسَّوْءِ كَحَامِلِ الْمِسْكِ وَنَافِخِ الْكِيرِ فَحَامِلُ الْمِسْكِ إِمَّا أَنْ يُحْذِيَكَ وَإِمَّا أَنْ تَبْتَاعَ مِنْهُ وَإِمَّا أَنْ تَجِدَ مِنْهُ رِيحًا طَيِّبَةً وَنَافِخُ الْكِيرِ إِمَّا أَنْ يُحْرِقَ ثِيَابَكَ وَإِمَّا أَنْ تَجِدَ رِيحًا خَبِيثَةً","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Perumpamaan teman yang shalih dengan teman yang buruk bagaikan penjual minyak wangi dengan pandai besi, bisa jadi penjual minyak wangi itu akan menghadiahkan kepadamu atau kamu membeli darinya atau kamu akan mendapatkan bau wanginya sedangkan pandai besi hanya akan membakar bajumu atau kamu akan mendapatkan bau tidak sedapnya.\""},"4804":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ هِشَامِ بْنِ زَيْدٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَنْفَجْنَا أَرْنَبًا وَنَحْنُ بِمَرِّ الظَّهْرَانِ فَسَعَى الْقَوْمُ فَلَغِبُوا فَأَخَذْتُهَا فَجِئْتُ بِهَا إِلَى أَبِي طَلْحَةَ فَذَبَحَهَا فَبَعَثَ بِوَرِكَيْهَا أَوْ قَالَ بِفَخِذَيْهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبِلَهَا","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Hisyam bin Zaid] dari [Anas] radliallahu 'anhu dia berkata; \"Ketika kami lewat di Marr Azh Zhahran, tiba-tiba kami di kagetkan oleh seekor kelinci, lalu kami kejar kelinci tersebut hingga orang-orang kelelahan mengejarnya, namun saya berhasil menangkapnya dan membawanya kepada Abu Thalhah, kemudian dia menyembelihnya dan mengirimkan kedua paha belakangnya kepada Nabi shallallahu 'alaihi wasallam, -atau perawi berkata \"kedua paha depannya\"- lalu beliau menerimanya.\""},"4805":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الضَّبُّ لَسْتُ آكُلُهُ وَلَا أُحَرِّمُهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abdul Aziz bin Muslim] telah menceritakan kepada kami [Abdullah bin Dinar] dia berkata; saya mendengar [Ibnu Umar] radliallahu 'anhuma berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Mengenai daging biawak, maka saya tidak memakannya dan tidak pula mengharamkannya.\""},"4806":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا عَنْ خَالِدِ بْنِ الْوَلِيدِأَنَّهُ دَخَلَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْتَ مَيْمُونَةَ فَأُتِيَ بِضَبٍّ مَحْنُوذٍ فَأَهْوَى إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ فَقَالَ بَعْضُ النِّسْوَةِ أَخْبِرُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا يُرِيدُ أَنْ يَأْكُلَ فَقَالُوا هُوَ ضَبٌّ يَا رَسُولَ اللَّهِ فَرَفَعَ يَدَهُ فَقُلْتُ أَحَرَامٌ هُوَ يَا رَسُولَ اللَّهِ فَقَالَ لَا وَلَكِنْ لَمْ يَكُنْ بِأَرْضِ قَوْمِي فَأَجِدُنِي أَعَافُهُ قَالَ خَالِدٌ فَاجْتَرَرْتُهُ فَأَكَلْتُهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْظُرُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Abu Umamah bin Sahl] dari [Abdullah bin Abbas] radliallahu 'anhuma dari [Khalid bin Al Walid] bahwa dia bersama Rasulullah shallallahu 'alaihi wasallam pernah masuk ke rumah Maimunah, lalu dihidangkan daging biawak, ketika Rasulullah shallallahu 'alaihi wasallam hendak mengambil daging tersebut sebagian wanita berkata; \"Beritahukanlah kepada Rasulullah shallallahu 'alaihi wasallam tentang makanan yang hendak beliau makan.\" Orang-orang pun berkata; \"Wahai Rasulullah, itu adalah daging biawak, \" Lalu beliau mengangkat tangannya, aku pun berkata; \"Apakah daging itu haram wahai Rasulullah?\" beliau bersabda: \"Tidak, karena daging tersebut tidak ada pada kaumku, maka aku tidak menyukainya.\" Khalid berkata; \"Lalu aku meraih daging tersebut dan memakannya, sementara Rasulullah shallallahu 'alaihi wasallam melihatku.\""},"4807":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّهُ سَمِعَ ابْنَ عَبَّاسٍ يُحَدِّثُهُ عَنْ مَيْمُونَةَأَنَّ فَأْرَةً وَقَعَتْ فِي سَمْنٍ فَمَاتَتْ فَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْهَا فَقَالَ أَلْقُوهَا وَمَا حَوْلَهَا وَكُلُوهُقِيلَ لِسُفْيَانَ فَإِنَّ مَعْمَرًا يُحَدِّثُهُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَ مَا سَمِعْتُ الزُّهْرِيَّ يَقُولُ إِلَّا عَنْ عُبَيْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَقَدْ سَمِعْتُهُ مِنْهُ مِرَارًا","id":"Telah menceritakan kepada kami [Al Humaidi] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Ubaidullah bin Abdullah bin 'Utbah] bahwa dia mendengar [Ibnu Abbas] pernah menceritakan kepadanya dari [Maimunah] bahwa seekor tikus terjatuh di minyak samin dan mati, lantas Nabi shallallahu 'alaihi wasallam ditanya mengenai hal itu, beliau bersabda: \"Buanglah tikus itu dan sesuatu yang ada di sekitarnya, lalu makanlah minyak samin tersebut.\" Dikatakan kepada Sufyan; \"Sesungguhnya Ma'mar menceritakan hadits tersebut dari Az Zuhri dari Sa'id bin Musayyab dari Abu Hurairah, Sufyan menjawab; \"Aku tidak pernah mendengar Az Zuhri meriwayatkan kecuali dari Ubaidullah dari Ibnu Abbas dari Maimunah dari Nabi shallallahu 'alaihi wasallam, sungguh aku telah berulang kali mendengar darinya seperti itu.\""},"4808":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّعَنْ الدَّابَّةِ تَمُوتُ فِي الزَّيْتِ وَالسَّمْنِ وَهُوَ جَامِدٌ أَوْ غَيْرُ جَامِدٍ الْفَأْرَةِ أَوْ غَيْرِهَا قَالَ بَلَغَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِفَأْرَةٍ مَاتَتْ فِي سَمْنٍ فَأَمَرَ بِمَا قَرُبَ مِنْهَا فَطُرِحَ ثُمَّ أُكِلَعَنْ حَدِيثِ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Abdullah] dari [Yunus] dari [Az Zuhri] mengenai seekor binatang melata yang mati di minyak samin baik yang telah memadat ataupun masih mencair, baik itu seekor tikus ataupun binatang melata lainnya, Az Zuhri berkata; \"Telah sampai (riwayat) kepada kami bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan supaya membuang tikus tersebut dan sesuatu yang ada di sekelilingnya, baru minyak tersebut dapat di konsumsi, \" yaitu dari hadits riwayat ['Ubaidullah bin Abdullah]."},"4809":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ رَضِيَ اللَّهُ عَنْهُمْ قَالَتْسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ فَأْرَةٍ سَقَطَتْ فِي سَمْنٍ فَقَالَ أَلْقُوهَا وَمَا حَوْلَهَا وَكُلُوهُ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Maimunah] -radliallahu 'anhhum- dia berkata; Nabi shallallahu 'alaihi wasallam pernah di tanya mengenai seekor tikus yang terjatuh di minyak samin, beliau bersabda: \"Buanglah tikus itu dan sesuatu yang ada disekitarnya, lalu makanlah minyak samin tersebut.\""},"4810":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ حَنْظَلَةَ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّهُ كَرِهَ أَنْ تُعْلَمَ الصُّورَةُ وَقَالَ ابْنُ عُمَرَ نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُضْرَبَتَابَعَهُ قُتَيْبَةُ حَدَّثَنَا الْعَنْقَزِيُّ عَنْ حَنْظَلَةَ وَقَالَ تُضْرَبُ الصُّورَةُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Handlalah] dari [Salim] dari [Ibnu Umar] bahwa dia tidak menyukai gambar (tato) pada wajah, Ibnu Umar juga berkata; Nabi shallallahu 'alaihi wasallam melarang memukul pada wajah.\" Hadits ini juga di perkuat oleh [Qutaibah]. Telah menceritakan kepada kami [Al Anqazi] dari [Handlalah], dia berkata; \"Yaitu (melarang) memukul kepala.\""},"4811":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ هِشَامِ بْنِ زَيْدٍ عَنْ أَنَسٍ قَالَدَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَخٍ لِي يُحَنِّكُهُ وَهُوَ فِي مِرْبَدٍ لَهُ فَرَأَيْتُهُ يَسِمُ شَاةً حَسِبْتُهُ قَالَ فِي آذَانِهَا","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Hisyam bin Zaid] dari [Anas] dia berkata; Aku menemui Nabi shallallahu 'alaihi wasallam bersama saudaraku yang sedang beliau tahnik (mengunyahkan kurma atau sesuatu yang manis lalu di masukkan kedalam mulut bayi) ketika berada di kandang unta, maka aku melihat beliau menandai seekor kambing -aku kira Anas mengatakan; \"Di telinganya.\""},"4812":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا سَعِيدُ بْنُ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍ قَالَقُلْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّنَا نَلْقَى الْعَدُوَّ غَدًا وَلَيْسَ مَعَنَا مُدًى فَقَالَ مَا أَنْهَرَ الدَّمَ وَذُكِرَ اسْمُ اللَّهِ فَكُلُوهُ مَا لَمْ يَكُنْ سِنٌّ وَلَا ظُفُرٌ وَسَأُحَدِّثُكُمْ عَنْ ذَلِكَ أَمَّا السِّنُّ فَعَظْمٌ وَأَمَّا الظُّفْرُ فَمُدَى الْحَبَشَةِ وَتَقَدَّمَ سَرَعَانُ النَّاسِ فَأَصَابُوا مِنْ الْغَنَائِمِ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي آخِرِ النَّاسِ فَنَصَبُوا قُدُورًا فَأَمَرَ بِهَا فَأُكْفِئَتْ وَقَسَمَ بَيْنَهُمْ وَعَدَلَ بَعِيرًا بِعَشْرِ شِيَاهٍ ث��مَّ نَدَّ بَعِيرٌ مِنْ أَوَائِلِ الْقَوْمِ وَلَمْ يَكُنْ مَعَهُمْ خَيْلٌ فَرَمَاهُ رَجُلٌ بِسَهْمٍ فَحَبَسَهُ اللَّهُ فَقَالَ إِنَّ لِهَذِهِ الْبَهَائِمِ أَوَابِدَ كَأَوَابِدِ الْوَحْشِ فَمَا فَعَلَ مِنْهَا هَذَا فَافْعَلُوا مِثْلَ هَذَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu Al Ahwash] telah menceritakan kepada kami [Sa'id bin Masruq] dari ['Abayah bin Rifa'ah] dari [Ayahnya] dari kakeknya [Rafi' bin Khadij] dia berkata; aku bertanya kepada Nabi shallallahu 'alaihi wasallam; \"Kami akan bertemu musuh esok hari, sementara kami tidak membawa pisau.\" Beliau bersabda: \"Gunakanlah sesuatu yang dapat mengalirkan darah dan sebutlah nama Allah kemudian makanlah selama -yang digunakan untuk menyembelih- tidak dari gigi atau kuku, dan aku akan menceritakan hal itu kepada kalian, adapun gigi adalah tulang sedangkan kuku adalah pisaunya orang-orang Habsyah.\" Kemudian para sahabat berjalan cepat hingga mendapatkan ghanimah, sementara Nabi shallallahu 'alaihi wasallam berada di rombongan terakhir, lalu orang-orang membuat tungku untuk memasak, ketika beliau mengetahui hal itu, beliau memerintahkan untuk menumpahkan periuk tersebut. Setelah itu beliau membagi-bagi ghanimah dan menyetarakan satu ekor unta dengan sepuluh ekor kambing. Tiba-tiba seekor unta milik suatu kaum kabur, sementara mereka tidak ada yang mengendarai kuda (untuk mengejarnya), lantas salah seorang dari mereka membidik unta tersebut dengan tombak hingga dengan izin Allah unta tersebut berhasil ditangkap, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di antara binatang-binatang ternak ada yang memiliki sifat-sifat seperti yang di miliki oleh binatang liar, maka tindakan yang biasa kamu lakukan pada binatang liar tersebut hendaknya kamu lakukan pula kepadanya seperti itu.\""},"4813":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا عُمَرُ بْنُ عُبَيْدٍ الطَّنَافِسِيُّ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَنَدَّ بَعِيرٌ مِنْ الْإِبِلِ قَالَ فَرَمَاهُ رَجُلٌ بِسَهْمٍ فَحَبَسَهُ قَالَ ثُمَّ قَالَ إِنَّ لَهَا أَوَابِدَ كَأَوَابِدِ الْوَحْشِ فَمَا غَلَبَكُمْ مِنْهَا فَاصْنَعُوا بِهِ هَكَذَا قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّا نَكُونُ فِي الْمَغَازِي وَالْأَسْفَارِ فَنُرِيدُ أَنْ نَذْبَحَ فَلَا تَكُونُ مُدًى قَالَ أَرِنْ مَا نَهَرَ أَوْ أَنْهَرَ الدَّمَ وَذُكِرَ اسْمُ اللَّهِ فَكُلْ غَيْرَ السِّنِّ وَالظُّفُرِ فَإِنَّ السِّنَّ عَظْمٌ وَالظُّفُرَ مُدَى الْحَبَشَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] telah mengabarkan kepada kami [Umar bin 'Ubaid Ath Thanafisi] dari [Sa'id bin Masruq] dari ['Abayah bin Rifa'ah] dari kakeknya [Rafi' bin Khadij] radliallahu 'anhu dia berkata; \"Kami bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, tiba-tiba seekor unta kabur, Rafi' melanjutkan; lalu seseorang membidiknya dengan tombak hingga berhasil menangkapnya, Rafi' melanjutkan; kemudian beliau bersabda: \"Sesungguhnya ia memiliki sifat-sifat seperti yang di miliki oleh binatang liar, oleh karenanya jika kalian kewalahan, hendaknya kalian lakukan seperti itu.\" Rafi' berkata; lalu aku bertanya; \"Wahai Rasulullah, bagaimana jika kami berada dalam suatu ekspedisi atau perjalanan sedangkan kami hendak menyembelih sembelihan, sementara kami tidak memiliki pisau?\" Beliau menjawab: \"Gunakanlah sesuatu yang dapat mengalirkan darah dan sebutlah nama Allah kemudian makanlah, selama -yang digunakan menyembelih- selain gigi dan kuku, karena gigi adalah tulang sedangkan kuku adalah pisaunya orang-orang Habsyah.\""},"4814":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ زُبَيْدٍ الْإِيَامِيِّ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَوَّلَ مَا نَبْدَأُ بِهِ فِي يَوْمِنَا هَذَا أَنْ نُصَلِّيَ ثُمَّ نَرْجِعَ فَنَنْحَرَ مَنْ فَعَلَهُ فَقَدْ أَصَابَ سُنَّتَنَا وَمَنْ ذَبَحَ قَبْلُ فَإِنَّمَا هُوَ لَحْمٌ قَدَّمَهُ لِأَهْلِهِ لَيْسَ مِنْ النُّسُكِ فِي شَيْءٍ فَقَامَ أَبُو بُرْدَةَ بْنُ نِيَارٍ وَقَدْ ذَبَحَ فَقَالَ إِنَّ عِنْدِي جَذَعَةً فَقَالَ اذْبَحْهَا وَلَنْ تَجْزِيَ عَنْ أَحَدٍ بَعْدَكَقَالَ مُطَرِّفٌ عَنْ عَامِرٍ عَنْ الْبَرَاءِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ذَبَحَ بَعْدَ الصَّلَاةِ تَمَّ نُسُكُهُ وَأَصَابَ سُنَّةَ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Zubaid Al Iyyami] dari [As Sya'bi] dari [Al Barra`] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang pertama kali kita lakukan pada hari ini ('iedul adha) adalah mengerjakan shalat kemudian pulang dan menyembelih binatang kurban, barangsiapa melakukan hal itu, maka dia telah bertindak sesuai dengan sunnah kita, dan barangsiapa menyembelih biantang kurban sebelum (shalat ied), maka sesembelihannya itu hanya berupa daging yang ia berikan kepada keluarganya, tidak ada hubungannya dengan ibadah kurban sedikitpun.\" Lalu Abu Burdah bin Niyar berdiri seraya berkata; \"Sesungguhnya aku masih memiliki jad'ah (anak kambing yang berusia dua tahun), maka beliau bersabda: \"Sembelihlah, namun hal itu tidak untuk orang lain setelahmu.\" [Muttharif] berkata; dari ['Amir] dari [Al Barra`], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menyembelih (hewan kurban) setelah shalat (ied) maka ibadah kurbannya telah sempurna dan dia telah melaksanakan sunnah kaum Muslimin dengan tepat.\""},"4815":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَاعِيلُ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ذَبَحَ قَبْلَ الصَّلَاةِ فَإِنَّمَا ذَبَحَ لِنَفْسِهِ وَمَنْ ذَبَحَ بَعْدَ الصَّلَاةِ فَقَدْ تَمَّ نُسُكُهُ وَأَصَابَ سُ��َّةَ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Muhammad] dari [Anas bin Malik] radliallahu 'anhu, dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menyembelih (binatang kurban) sebelum shalat (ied), maka ia menyembelih untuk dirinya sendiri, dan barangsiapa menyembelih setelah shalat (ied), maka ibadah kurbannya telah sempurna dan bertindak sesuai dengan sunnah kaum Muslimin.\""},"4816":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ بَعْجَةَ الْجُهَنِيِّ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ قَالَقَسَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَصْحَابِهِ ضَحَايَا فَصَارَتْ لِعُقْبَةَ جَذَعَةٌ فَقُلْتُ يَا رَسُولَ اللَّهِ صَارَتْ لِي جَذَعَةٌ قَالَ ضَحِّ بِهَا","id":"Telah menceritakan kepada kami [Mu'adz bin Fadlalah] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Ba'jah Al Juhani] dari ['Uqbah bin 'Amir Al Juhani] dia berkata; Nabi shallallahu 'alaihi wasallam pernah membagi-bagikan binatang kurban kepada para sahabatnya, sementara 'Uqbah sendiri hanya mendapatkan Jad'ah (anak kambing yang berusia dua tahun), maka kataku selanjutnya; \"Wahai Rasulullah, aku hanya mendapatkan jad'ah (anak kambing yang berusia dua tahun)?\" beliau bersabda: \"Berkurbanlah dengannya.\""},"4817":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا وَحَاضَتْ بِسَرِفَ قَبْلَ أَنْ تَدْخُلَ مَكَّةَ وَهِيَ تَبْكِي فَقَالَ مَا لَكِ أَنَفِسْتِ قَالَتْ نَعَمْ قَالَ إِنَّ هَذَا أَمْرٌ كَتَبَهُ اللَّهُ عَلَى بَنَاتِ آدَمَ فَاقْضِي مَا يَقْضِي الْحَاجُّ غَيْرَ أَنْ لَا تَطُوفِي بِالْبَيْتِ فَلَمَّا كُنَّا بِمِنًى أُتِيتُ بِلَحْمِ بَقَرٍ فَقُلْتُ مَا هَذَا قَالُوا ضَحَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَزْوَاجِهِ بِالْبَقَرِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Sufyan] dari [Abdurrahman bin Qasim] dari [Ayahnya] dari [Aisyah] radliallahu 'anha bahwa Nabi shallallahu 'alaihi wasallam pernah menemuinya ketika berada di Sarif sebelum masuk ke Makkah, beliau mendapatinya sedang menangis karena datang bulan, lalu beliau bertanya: \"Kenapa, apakah kamu sedang haidh?\" Aisyah menjawab; \"Ya.\" Beliau bersabda: \"Sesungguhnya hal ini telah di tetapkan Allah atas wanita-wanita anak Adam, lakukanlah apa yang biasa di kerjakan dalam berhaji, namun kamu jangan thawaf di Ka'bah.\" Ketika kami sampai di Mina, aku di beri daging sapi, lantas tanyaku; \"Daging apakah ini?\" para sahabat menjawab; \"Rasulullah shallallahu 'alaihi wasallam menyembelih binatang kurban berupa sapi untuk para isterinya.\""},"4818":{"ar":"حَدَّثَنَا صَدَقَةُ أَخْبَرَنَا ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ ابْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ مَنْ كَانَ ذَبَحَ قَبْلَ الصَّلَاةِ فَلْيُعِدْ فَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ هَذَا يَوْمٌ يُشْتَهَى فِيهِ اللَّحْمُ وَذَكَرَ جِيرَانَهُ وَعِنْدِي جَذَعَةٌ خَيْرٌ مِنْ شَاتَيْ لَحْمٍ فَرَخَّصَ لَهُ فِي ذَلِكَ فَلَا أَدْرِي بَلَغَتْ الرُّخْصَةُ مَنْ سِوَاهُ أَمْ لَا ثُمَّ انْكَفَأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى كَبْشَيْنِ فَذَبَحَهُمَا وَقَامَ النَّاسُ إِلَى غُنَيْمَةٍ فَتَوَزَّعُوهَا أَوْ قَالَ فَتَجَزَّعُوهَا","id":"Telah menceritakan kepada kami [Shadaqah] telah mengabarkan kepada kami [Ibnu 'Ulayyah] dari [Ayyub] dari [Ibnu Sirin] dari [Anas bin Malik] dia berkata; pada hari raya kurban, Nabi shallallahu 'alaihi wasallam pernah bersabda: \"Barangsiapa menyembelih binatang kurban sebelum shalat (ied), hendaknya ia mengulangi lagi.\" Lalu ada seorang laki-laki yang berdiri sambil bertanya; \"Wahai Rasulullah, Sesungguhnya hari ini adalah hari di bagi-bagikannya daging kurban, -lalu ia menyebutkan sebagian para tetangganya- sementara aku hanya memiliki jad'ah (anak kambing yang berusia dua tahun) yang lebih banyak dagingnya daripada dua ekor kambing biasa.\" Maka beliau memberi keringanan kepadanya untuk berkurban dengan kambing tersebut, aku tidak tahu apakah keringanan tersebut juga untuk yang lain atau tidak. Setelah itu Nabi shallallahu 'alaihi wasallam pergi menuju dua ekor kambing dan menyembelihnya, lalu orang-orang pun pergi menuju sekumpulan kambing dan membagi-bagikannya.\""},"4819":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدٍ عَنْ ابْنِ أَبِي بَكْرَةَ عَنْ أَبِي بَكْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الزَّمَانَ قَدْ اسْتَدَارَ كَهَيْئَتِهِ يَوْمَ خَلَقَ اللَّهُ السَّمَوَاتِ وَالْأَرْضَ السَّنَةُ اثْنَا عَشَرَ شَهْرًا مِنْهَا أَرْبَعَةٌ حُرُمٌ ثَلَاثٌ مُتَوَالِيَاتٌ ذُو الْقَعْدَةِ وَذُو الْحِجَّةِ وَالْمُحَرَّمُ وَرَجَبُ مُضَرَ الَّذِي بَيْنَ جُمَادَى وَشَعْبَانَ أَيُّ شَهْرٍ هَذَا قُلْنَا اللَّهُ وَرَسُولُهُ أَعْلَمُ فَسَكَتَ حَتَّى ظَنَنَّا أَنَّهُ سَيُسَمِّيهِ بِغَيْرِ اسْمِهِ قَالَ أَلَيْسَ ذَا الْحِجَّةِ قُلْنَا بَلَى قَالَ أَيُّ بَلَدٍ هَذَا قُلْنَا اللَّهُ وَرَسُولُهُ أَعْلَمُ فَسَكَتَ حَتَّى ظَنَنَّا أَنَّهُ سَيُسَمِّيهِ بِغَيْرِ اسْمِهِ قَالَ أَلَيْسَ الْبَلْدَةَ قُلْنَا بَلَى قَالَ فَأَيُّ يَوْمٍ هَذَا قُلْنَا اللَّهُ وَرَسُولُهُ أَعْلَمُ فَسَكَتَ حَتَّى ظَنَنَّا أَنَّهُ سَيُسَمِّيهِ بِغَيْرِ اسْمِهِ قَالَ أَلَيْسَ يَوْمَ النَّحْرِ قُلْنَا بَلَى قَالَ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ قَالَ مُحَمَّدٌ وَأَحْسِبُهُ قَالَ وَأَعْرَاضَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا وَسَتَلْقَوْنَ رَبَّكُمْ فَيَسْأَلُكُمْ عَنْ أَعْمَالِكُمْ أَلَا فَلَا تَرْجِعُوا بَعْدِي ضُلَّالًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ أَلَا لِيُبَلِّغْ الشَّاهِدُ الْغَائِبَ فَلَعَلَّ بَعْضَ مَنْ يَبْلُغُهُ أَنْ يَكُونَ أَوْعَى لَهُ مِنْ بَعْضِ مَنْ سَمِعَهُ وَكَانَ مُحَمَّدٌ إِذَا ذَكَرَهُ قَالَ صَدَقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ أَلَا هَلْ بَلَّغْتُ أَلَا هَلْ بَلَّغْتُ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] telah menceritakan kepada kami [Abdul Wahab] telah menceritakan kepada kami [Ayyub] dari [Muhammad] dari [Ibnu Abu Bakrah] dari [Abu Bakrah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya zaman itu terus berputar sama seperti saat Allah menciptakan langit dan bumi, setahun ada dua belas bulan, dan empat di antaranya adalah bulan-bulan haram, dan tiga di antaranya adalah bulan-bulan yang berurutan yaitu; Dzul Qa'dah, Dzul Hijjah, Muharram dan Rajab. Sedangkan bulan Rajab adalah bulan Mudzar yaitu bulan yang terletak antara Jumadil Akhir dan Sya'ban.\" (beliau bertanya): \"Bulan apakah sekarang ini?\" kami menjawab; \"Allah dan Rasul-Nya yang lebih mengetahui.\" Beliau terdiam beberapa saat, hingga kami menduga bahwa beliau akan menyebutnya dengan nama yang lain, lalu beliau bersabda: \"Bukankah sekarang bulan Dzul Hijjah?\" kami menjawab; \"Benar.\" Beliau bertanya lagi: \"Negeri apakah ini?\" kami menjawab; \"Allah dan Rasul-Nya yang lebih mengetahui.\" Beliau terdiam beberapa saat, hingga kami menduga beliau akan menyebutnya dengan nama yang lain, lalu beliau bersabda: \"Bukankah sekarang kita berada di negeri Baldah?\" kami menjawab; \"Benar.\" Beliau kembali bertanya: \"Hari apakah ini?\" kami menjawab; \"Allah dan Rasul-Nya yang lebih mengetahui.\" Beliau terdiam beberapa saat, hingga kami mengira beliau akan menyebutnya dengan nama yang lain. Kemudian beliau bersabda: \"Bukankah sekarang adalah hari Nahr (kurban)?\" kami menjawab; \"Benar.\" Beliau kemudian bersabda: \"Sesungguhnya darah kalian, harta bendamu -Muhammad berkata; saya kira beliau juga bersabda: dan kehormatan kalian- adalah haram atas diri kalian, seperti haramnya harimu sekarang ini, di negerimu ini, dan di bulan kalian ini. Sesungguhnya kalian pasti akan bertemu dengan Rabb kalian (di hari kiamat kelak), dan Dia akan menanyakan tentang semua amal perbuatan kalian. Oleh karena itu, sepeninggalku nanti, janganlah kalian kembali kepada kesesatan -dimana sebagian dari kalian membunuh sebagian yang lain-, hendaknya orang yang hadir pada saat ini menyampaikan kepada orang yang tidak hadir! bisa jadi orang yang mendengar dari mulut kedua justru lebih menjaga apa-apa yang di dengarnya daripada orang yang mendengarnya secara langsung.\" Sedangkan apabila Muhammad menyebutkan hadits tersebut, dia berkata; \"Nabi shallallahu 'alaihi wasallam benar.\" Setelah itu beliau bersabda: \"Bukankah aku telah menyampaikannya, bukankah aku telah menyampaikannya?! Hingga dua kali."},"4820":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ قَالَ كَانَ عَبْدُ اللَّهِيَنْحَرُ فِي الْمَنْحَرِ قَالَ عُبَيْدُ اللَّهِ يَعْنِي مَنْحَرَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakr Al Muqaddami] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dia berkata; bahwa [Abdullah] pernah menyembelih binatang kurban di tempat penyembelihan, Ubaidullah mengatakan; \"Yaitu di tempat yang biasa digunakan Nabi shallallahu 'alaihi wasallam untuk menyembelih binatang kurban.\""},"4821":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ كَثِيرِ بْنِ فَرْقَدٍ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْبَحُ وَيَنْحَرُ بِالْمُصَلَّى","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Katsir bin Farqad] dari [Nafi'] bahwa [Ibnu Umar] radliallahu 'anhuma telah mengabarkan kepadanya, dia berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa menyembelih binatang kurban di tempat yang di gunakan untuk shalat (ied).\""},"4822":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُضَحِّي بِكَبْشَيْنِ وَأَنَا أُضَحِّي بِكَبْشَيْنِ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyyas] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abdul Aziz bin Shuhaib] dia berkata; saya mendengar [Anas bin Malik] radliallahu 'anhu berkata; Nabi shallallahu 'alaihi wasallam berkurban dengan dua ekor domba, sementara aku juga berkurban dengan dua ekor domba.\""},"4823":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْكَفَأَ إِلَى كَبْشَيْنِ أَقْرَنَيْنِ أَمْلَحَيْنِ فَذَبَحَهُمَا بِيَدِهِتَابَعَهُ وُهَيْبٌ عَنْ أَيُّوبَ وَقَالَ إِسْمَاعِيلُ وَحَاتِمُ بْنُ وَرْدَانَ عَنْ أَيُّوبَ عَنْ ابْنِ سِيرِينَ عَنْ أَنَسٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdul Wahab] telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam pergi menuju dua ekor domba yang warna putihnya lebih banyak di banding warna hitamnya dan bertanduk, lalu beliau menyembelih domba tersebut dengan tangannya sendiri.\" Hadits ini juga di kuatkan oleh riwayat [Wuhaib] dari [Ayyub]. [Isma'il] dan [Hatim bin Wardan] juga berkata dari [Ayyub] dari [Ibnu Sirin] dari [Anas]."},"4824":{"ar":"حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَاهُ غَنَمًا يَقْسِمُهَا عَلَى صَحَابَتِهِ ضَحَايَا فَبَقِيَ عَتُودٌ فَذَكَرَهُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ضَحِّ أَنْتَ بِهِ","id":"Telah menceritakan kepada kami [Amru bin Khalid] telah menceritakan kepada kami [Al Laits] dari [Yazid] dari [Abu Al Khair] dari ['Uqbah bin 'Amir] radliallahu 'anhu bahwa Nabi shallallahu 'alaihi wasallam pernah menyerahkan sejumlah kambing kepadanya untuk dibagi-bagikan kepada para sahabat beliau sebagai binatang kurban, setelah dibagi-bagikan ternyata masih tinggal seekor anak kambing yang masih sangat muda, lalu hal itu diberitahukan kepada Nabi shallallahu 'alaihi wasallam, maka beliau bersabda: \"Berkurbanlah kamu dengan kambing tersebut.\""},"4825":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُطَرِّفٌ عَنْ عَامِرٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَضَحَّى خَالٌ لِي يُقَالُ لَهُ أَبُو بُرْدَةَ قَبْلَ الصَّلَاةِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَاتُكَ شَاةُ لَحْمٍ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ عِنْدِي دَاجِنًا جَذَعَةً مِنْ الْمَعَزِ قَالَ اذْبَحْهَا وَلَنْ تَصْلُحَ لِغَيْرِكَ ثُمَّ قَالَ مَنْ ذَبَحَ قَبْلَ الصَّلَاةِ فَإِنَّمَا يَذْبَحُ لِنَفْسِهِ وَمَنْ ذَبَحَ بَعْدَ الصَّلَاةِ فَقَدْ تَمَّ نُسُكُهُ وَأَصَابَ سُنَّةَ الْمُسْلِمِينَتَابَعَهُ عُبَيْدَةُ عَنْ الشَّعْبِيِّ وَإِبْرَاهِيمَ وَتَابَعَهُ وَكِيعٌ عَنْ حُرَيْثٍ عَنْ الشَّعْبِيِّ وَقَالَ عَاصِمٌ وَدَاوُدُ عَنْ الشَّعْبِيِّ عِنْدِي عَنَاقُ لَبَنٍ وَقَالَ زُبَيْدٌ وَفِرَاسٌ عَنْ الشَّعْبِيِّ عِنْدِي جَذَعَةٌ وَقَالَ أَبُو الْأَحْوَصِ حَدَّثَنَا مَنْصُورٌ عَنَاقٌ جَذَعَةٌ وَقَالَ ابْنُ عَوْنٍ عَنَاقٌ جَذَعٌ عَنَاقُ لَبَنٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Khalid bin Abdullah] telah menceritakan kepada kami [Muttharif] dari ['Amir] dari [Al Barra` bin 'Azib] radliallahu 'anhu dia berkata; Pamanku yaitu Abu Burdah pernah menyembelih binatang kurban sebelum shalat (ied), maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Kambingmu hanya berupa daging biasa (bukan daging kurban) Lantas pamanku berkata; \"Ya Rasulullah, sesungguhnya aku hanya memiliki seekor jad'ah (anak kambing yang berusia dua tahun).\" Beliau bersabda: \"Berkurbanlah dengan kambing tersebut, namun hal itu tidak sah untuk selain kamu.\" Kemudian beliau melanjutkan sabdanya: \"Barang siapa berkurban sebelum shalat (Iedul Adlha), dia hanya menyembelih untuk dirinya sendiri, dan barang siapa menyembelih setelah shalat (Iedul Adlha), maka sempurnalah ibadahnya dan dia telah melaksanakan sunnah kaum Muslimin dengan tepat.\" Hadits ini diperkuat oleh [Ubaidah] dari [Asy Sya'bi] dan [Ibrahim] dan diperkuat pula oleh [Waki'] dari [Huraits] dari [Asy Sya'bi], dan berkata [Ashim] dan [Daud] dari [Asy Sya'bi], sesungguhnya aku mempunyai kambing perahan. Dan berkata [Zubaid] dan [Firas] dari [Asy Sya'bi], saya mempunyai anak kambing berumur dua tahun, dan berkata [Abu Al Ahwash] telah menceritakan kepada kami [Manshur], kambing perah yang berumur dua tahun. Dan berkata [Ibnu Aun], kambing perah yang berumur dua taun yang diperah susunya"},"4826":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ عَنْ أَبِي جُحَيْفَةَ عَنْ الْبَرَاءِ قَالَذَبَحَ أَبُو بُرْدَةَ قَبْلَ الصَّلَاةِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْدِلْهَا قَالَ لَيْسَ عِنْدِي إِلَّا جَذَعَةٌ قَالَ شُعْبَةُ وَأَحْسِبُهُ قَالَ هِيَ خَيْرٌ مِنْ مُسِنَّةٍ قَالَ اجْعَلْهَا مَكَانَهَا وَلَنْ تَجْزِيَ عَنْ أَحَدٍ بَعْدَكَوَقَالَ حَاتِمُ بْنُ وَرْدَانَ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ عَنَاقٌ جَذَعَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Salamah] dari [Abu Juhaifah] dari [Al Barra`] dia berkata; Abu Burdah pernah menyembelih binatang kurban sebelum shalat (Iedul Adlha), maka Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Gantilah kurbanmu.\" Dia berkata; \"Aku tidak memilikinya lagi kecuali hanya jad'ah (anak kambing berusia dua tahun). [Syu'bah] mengatakan; aku mengira Abu Burdah mengatakan; \"dan dia lebih baik daripada kambing muda.\" Beliau bersabda: \"Kurbanlah dengan kambing itu, dan tidak sah untuk orang lain setelahmu.\" [Hatim bin Wardan] mengatakan dari [Ayyub] dari [Muhammad] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, perawi berkata; \"Betina jad'ah (anak kambing yang berusia dua tahun).\""},"4827":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ قَالَضَحَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَبْشَيْنِ أَمْلَحَيْنِ فَرَأَيْتُهُ وَاضِعًا قَدَمَهُ عَلَى صِفَاحِهِمَا يُسَمِّي وَيُكَبِّرُ فَذَبَحَهُمَا بِيَدِهِ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Qatadah] dari [Anas] dia berkata; Nabi shallallahu 'alaihi wasallam berkurban dengan dua ekor domba yang warna putihnya lebih banyak daripada warna hitam, aku melihat beliau meletakkan kaki beliau di atas rusuk domba tersebut sambil menyebut nama Allah dan bertakbir, lalu beliau menyembelih domba itu dengan tangan beliau sendiri.\""},"4828":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَرِفَ وَأَنَا أَبْكِي فَقَالَ مَا لَكِ أَنَفِسْتِ قُلْتُ نَعَمْ قَالَ هَذَا أَمْرٌ كَتَبَهُ اللَّهُ عَلَى بَنَاتِ آدَمَ اقْضِي مَا يَقْضِي الْحَاجُّ غَيْرَ أَنْ لَا تَطُوفِي بِالْبَيْتِ وَضَحَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نِسَائِهِ بِالْبَقَرِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Sufyan] dari [Abdurrahman bin Al Qasim] dari [Ayahnya] dari [Aisyah] radliallahu 'anha dia berkata; Rasulullah shallallahu 'alaihi wasallam menemuiku ketika berada di Sarif, sementara aku sedang menangis, lalu beliau bertanya: \"Kenapa denganmu? Apakah kamu haidl?\" Jawabku; \"Ya\" beliau bersabda: \"Ini adalah suatu perkara yang telah ditetapkan Allah atas para wanita anak Adam, lakukanlah sebagaimana yang di lakukan oleh orang-orang yang berhaji, namun kamu jangan melakukan thawaf di Ka'bah.\" Setelah itu Rasulullah shallallahu 'alaihi wasallam berkurban untuk para isterinya dengan seekor sapi.\""},"4829":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ الْمِنْهَالِ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي زُبَيْدٌ قَالَ سَمِعْتُ الشَّعْبِيَّ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ إِنَّ أَوَّلَ مَا نَبْدَأُ بِهِ مِنْ يَوْمِنَا هَذَا أَنْ نُصَلِّيَ ثُمَّ نَرْجِعَ فَنَنْحَرَ فَمَنْ فَعَلَ هَذَا فَقَدْ أَصَابَ سُنَّتَنَا وَمَنْ نَحَرَ فَإِنَّمَا هُوَ لَحْمٌ يُقَدِّمُهُ لِأَهْلِهِ لَيْسَ مِنْ النُّسُكِ فِي شَيْءٍ فَقَالَ أَبُو بُرْدَةَ يَا رَسُولَ اللَّهِ ذَبَحْتُ قَبْلَ أَنْ أُصَلِّيَ وَعِنْدِي جَذَعَةٌ خَيْرٌ مِنْ مُسِنَّةٍ فَقَالَ اجْعَلْهَا مَكَانَهَا وَلَنْ تَجْزِيَ أَوْ تُوفِيَ عَنْ أَحَدٍ بَعْدَكَ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Syu'bah] dia berkata; telah mengabarkan kepadaku [Zubaid] dia berkata; saya mendengar [As Sya'bi] dari [Al Barra`] radliallahu 'anhu dia berkata; saya mendengar Nabi shallallahu 'alaihi wasallam berkhutbah, sabdanya: \"Sesungguhnya yang pertama kali kita lakukan pada hari ini adalah melaksanakan shalat ('iedul adlha) kemudian kembali pulang dan menyembelih binatang kurban, barangsiapa melakukan hal ini, berarti dia telah bertindak sesuai dengan sunnah kita, barangsiapa menyembelih binatang kurban sebelum (shalat ied), maka sesembelihannya itu hanya berupa daging yang ia berikan kepada keluarganya, tidak ada hubungannya dengan ibadah kurban sedikitpun.\" Lalu Abu Burdah berkata; \"Aku menyembelih sebelum shalat, sementara aku masih memiliki jad'ah (anak kambing yang berusia dua tahun) yang lebih baik daripada kambing muda, maka beliau bersabda: \"Sembelihlah binatang kurban itu, namun hal itu tidak sah untuk orang lain setelahmu.\""},"4830":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ذَبَحَ قَبْلَ الصَّلَاةِ فَلْيُعِدْ فَقَالَ رَجُلٌ هَذَا يَوْمٌ يُشْتَهَى فِيهِ اللَّحْمُ وَذَكَرَ هَنَةً مِنْ جِيرَانِهِ فَكَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَذَرَهُ وَعِنْدِي جَذَعَةٌ خَيْرٌ مِنْ شَاتَيْنِ فَرَخَّصَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَدْرِي بَلَغَتْ الرُّخْصَةُ أَمْ لَا ثُمَّ انْكَفَأَ إِلَى كَبْشَيْنِ يَعْنِي فَذَبَحَهُمَا ثُمَّ انْكَفَأَ النَّاسُ إِلَى غُنَيْمَةٍ فَذَبَحُوهَا","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Ayyub] dari [Muhammad] dari [Anas] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa menyembelih binatang kurban sebelum shalat (iedul adlha) hendaknya ia mengulangi kurbannya.\" Seseorang berdiri dan berkata; \"Wahai Rasulullah, sesungguhnya hari ini adalah hari pembagian daging kurban -lalu laki-laki itu menceritakan kesusahan yang di alami tetangganya, seakan-akan dia berharap Nabi shallallahu 'alaihi wasallam membenarkan perbuatannya- sementara aku hanya masih memiliki jad'ah (anak kambing yang berusia dua tahun) yang lebih aku cintai daripada dua ekor kambing muda.\" Maka nabi shallallahu 'alaihi wasallam memberi keringanan kepadanya, aku tidak mengetahui apakah keringanan itu berlaku juga kepada orang lain ataukah tidak. Selanjutnya beliau berpaling dan pergi menuju dua ekor domba lalu beliau menyembelihnya, setelah itu orang-orang berpaling dan pergi menuju segerombolan kambing, lalu mereka menyembelihnya.\""},"4831":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا الْأَسْوَدُ بْنُ قَيْسٍ سَمِعْتُ جُنْدَبَ بْنَ سُفْيَانَ الْبَجَلِيَّ قَالَشَهِدْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ فَقَالَ مَنْ ذَبَحَ قَبْلَ أَنْ يُصَلِّيَ فَلْيُعِدْ مَكَانَهَا أُخْرَى وَمَنْ لَمْ يَذْبَحْ فَلْيَذْبَحْ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Al Aswad bin Qais] saya mendengar [Jundab bin Sufyan Al Bajali] berkata; aku ikut menyaksikan Nabi shallallahu 'alaihi wasallam pada hari raya kurban, lalu beliau bersabda: \"Barangsiapa menyembelih binatang kurban sebelum shalat (iedul adlha), hendaknya ia mengulangi kurbannya, dan barangsiapa belum berkurban hendaknya ia berkurban.\""},"4832":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ فِرَاسٍ عَنْ عَامِرٍ عَنْ الْبَرَاءِ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ فَقَالَ مَنْ صَلَّى صَلَاتَنَا وَاسْتَقْبَلَ قِبْلَتَنَا فَلَا يَذْبَحْ حَتَّى يَنْصَرِفَ فَقَامَ أَبُو بُرْدَةَ بْنُ نِيَارٍ فَقَالَ يَا رَسُولَ اللَّهِ فَعَلْتُ فَقَالَ هُوَ شَيْءٌ عَجَّلْتَهُ قَالَ فَإِنَّ عِنْدِي جَذَعَةً هِيَ خَيْرٌ مِنْ مُسِنَّتَيْنِ آذْبَحُهَا قَالَ نَعَمْ ثُمَّ لَا تَجْزِي عَنْ أَحَدٍ بَعْدَكَ قَالَ عَامِرٌ هِيَ خَيْرُ نَسِيكَتَيْهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] dari [Firas] dari ['Amir] dari [Al Barra`] dia berkata; \"Pada suatu hari Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat, setelah itu beliau bersabda: \"Barangsiapa mengerjakan shalat seperti shalat kami, dan menghadap kiblat kami, hendaknya tidak menyembelih binatang kurban sehingga selesai mengerjakan shalat.\" Lalu Abu Burdah bin Niyar berdiri dan berkata; \"Wahai Rasulullah, padahal aku telah melakukannya.\" Beliau bersabda: \"Itu adalah ibadah yang kamu kerjakan dengan tergesa-gesa.\" Abu Burdah berkata; \"Sesungguhnya aku masih memiki jad'ah (anak kambing yang berusia dua tahun) dan dia lebih baik daripada dua ekor kambing muda, apakah aku juga harus menyembelihnya untuk berkurban? Beliau bersabda: \"Ya, namun hal itu tidak sah untuk orang lain setelahmu.\" Amir berkata; \"Itu lebih baik daripada ibadah kurban yang kamu lakukan\""},"4833":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ حَدَّثَنَا أَنَسٌ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُضَحِّي بِكَبْشَيْنِ أَمْلَحَيْنِ أَقْرَنَيْنِ وَيَضَعُ رِجْلَهُ عَلَى صَفْحَتِهِمَا وَيَذْبَحُهُمَا بِيَدِهِ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammam] dari [Qatadah] telah menceritakan kepada kami [Anas] radliallahu 'anhu bahwa Nabi shallallahu 'alaihi wasallam pernah berkurban dengan dua ekor domba yang warna putihnya lebih banyak daripada warna hitamnya dan bertanduk, beliau meletakkan kaki beliau di atas rusuk domba tersebut lalu menyembelihnya dengan tangan beliau sendiri.\""},"4834":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَضَحَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَبْشَيْنِ أَمْلَحَيْنِ أَقْرَنَيْنِ ذَبَحَهُمَا بِيَدِهِ وَسَمَّى وَكَبَّرَ وَوَضَعَ رِجْلَهُ عَلَى صِفَاحِهِمَا","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas] dia berkata; Nabi shallallahu 'alaihi wasallam berkurban dengan dua ekor domba yang warna putihnya lebih dominan di banding warna hitamnya, dan bertanduk, beliau menyembelih domba tersebut dengan tangan beliau sendiri sambil menyebut nama Allah dan bertakbir dan meletakkan kaki beliau di atas rusuk domba tersebut.\""},"4835":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا إِسْمَاعِيلُ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ أَنَّهُ أَتَى عَائِشَةَ فَقَالَ لَهَايَا أُمَّ الْمُؤْمِنِينَ إِنَّ رَجُلًا يَبْعَثُ بِالْهَدْيِ إِلَى الْكَعْبَةِ وَيَجْلِسُ فِي الْمِصْرِ فَيُوصِي أَنْ تُقَلَّدَ بَدَنَتُهُ فَلَا يَزَالُ مِنْ ذَلِكِ الْيَوْمِ مُحْرِمًا حَتَّى يَحِلَّ النَّاسُ قَالَ فَسَمِعْتُ تَصْفِيقَهَا مِنْ وَرَاءِ الْحِجَابِ فَقَالَتْ لَقَدْ كُنْتُ أَفْتِلُ قَلَائِدَ هَدْيِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَبْعَثُ هَدْيَهُ إِلَى الْكَعْبَةِ فَمَا يَحْرُمُ عَلَيْهِ مِمَّا حَلَّ لِلرِّجَالِ مِنْ أَهْلِهِ حَتَّى يَرْجِعَ النَّاسُ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Isma'il] dari [Asy Sya'bi] dari [Masruq] bahwa dia pernah menemui [Aisyah] sambil bertanya; \"Wahai ummul mukminin, ada seorang laki-laki mengirimkan hewan kurbannya ke Ka'bah, sementara laki-laki yang mengirim binatang kurban itu berada di daerahnya, dia berwasiat (kepada orang yang di serahi binatang kurban) untuk mengalungi binatang kurbannya. Waktu itu laki-laki (yang di serahi binatang kurban) masih dalam keadaan ihram, hingga akhirnya orang-orang melakukan tahallul.\" Masruq berkata; \"Kemudian aku mendengar tepuk tangan Aisyah dari balik tabir sambil berkata; \"Sesungguhnya aku juga pernah membuatkan kalung binatang kurban Rasulullah shallallahu 'alaihi wasallam, kemudian beliau mengirim binatang kurban itu ke Ka'bah, dan segala sesuatu yang halal di lakukan oleh suami kepada isterinya di haramkan atasnya hingga orang-orang kembali pulang (dari menunaikan ibadah haji).\""},"4836":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ عَمْرٌو أَخْبَرَنِي عَطَاءٌ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَكُنَّا نَتَزَوَّدُ لُحُومَ الْأَضَاحِيِّ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمَدِينَةِ وَقَالَ غَيْرَ مَرَّةٍ لُحُومَ الْهَدْيِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan], ['Amru] berkata; telah mengabarkan kepadaku ['Atha`] bahwa dia mendengar [Jabir bin Abdullah] radliallahu 'anhuma berkata; Pada masa Nabi shallallahu 'alaihi wasallam kami biasa menyimpan daging kurban sebagai perbekalan kami menuju Madinah, Jabir juga mengatakan berkali-kali tentang daging binatang kurban.\""},"4837":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي سُلَيْمَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ الْقَاسِمِ أَنَّ ابْنَ خَبَّابٍ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ يُحَدِّثُأَنَّهُ كَانَ غَائِبًا فَقَدِمَ فَقُدِّمَ إِلَيْهِ لَحْمٌ قَالُوا هَذَا مِنْ لَحْمِ ضَحَايَانَا فَقَالَ أَخِّرُوهُ لَا أَذُوقُهُ قَالَ ثُمَّ قُمْتُ فَخَرَجْتُ حَتَّى آتِيَ أَخِي أَبَا قَتَادَةَ وَكَانَ أَخَاهُ لِأُمِّهِ وَكَانَ بَدْرِيًّا فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ إِنَّهُ قَدْ حَدَثَ بَعْدَكَ أَمْرٌ","id":"Telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Sulaiman] dari [Yahya bin Sa'id] dari [Al Qasim] bahwa [Ibnu Khabbab] mengabarkan kepadanya, dia pernah mendengar [Abu Sa'id] bercerita bahwa suatu ketika dia pernah datang dari suatu perjalanan, lalu beberapa potong daging di hidangkan di hadapannya, keluarganya berkata; \"Ini adalah sisa dari daging kurban kita.\" Maka Abu Sa'id berkata; \"Singkirkanlah, sebab aku tidak mau memakannya.\" Abu Sa'id melanjutkan, setelah itu aku berdiri dan pergi menemui saudaraku yaitu Abu Qatadah -dia adalah saudara seibu dan salah seorang ahli Badr- lalu aku menceritakan hal itu kepadanya, Abu Qatadah menjawab; \"Sesungguhnya telah terjadi pula peristiwa seperti yang kamu alami.\""},"4838":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ضَحَّى مِنْكُمْ فَلَا يُصْبِحَنَّ بَعْدَ ثَالِثَةٍ وَبَقِيَ فِي بَيْتِهِ مِنْهُ شَيْءٌ فَلَمَّا كَانَ الْعَامُ الْمُقْبِلُ قَالُوا يَا رَسُولَ اللَّهِ نَفْعَلُ كَمَا فَعَلْنَا عَامَ الْمَاضِي قَالَ كُلُوا وَأَطْعِمُوا وَادَّخِرُوا فَإِنَّ ذَلِكَ الْعَامَ كَانَ بِالنَّاسِ جَهْدٌ فَأَرَدْتُ أَنْ تُعِينُوا فِيهَا","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Yazid bin Abu 'Ubaid] dari [Salamah bin Al Akwa'] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa saja di antara kalian yang berkurban, janganlah menyisakan daging kurban di rumahnya melebihi tiga hari.\" Pada tahun berikutnya orang-orang bertanya; \"Wahai Rasulullah, apakah kami harus melakukan sebagaimana yang kami lakukan pada tahun lalu?\" beliau bersabda: \"Makanlah daging kurban tersebut dan bagilah sebagiannya kepada orang lain serta simpanlah sebagian yang lain, sebab tahun lalu orang-orang dalam keadaan kesusahan, oleh karena itu saya bermaksud supaya kalian dapat membantu mereka.\""},"4839":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْالضَّحِيَّةُ كُنَّا نُمَلِّحُ مِنْهُ فَنَقْدَمُ بِهِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ فَقَالَ لَا تَأْكُلُوا إِلَّا ثَلَاثَةَ أَيَّامٍ وَلَيْسَتْ بِعَزِيمَةٍ وَلَكِنْ أَرَادَ أَنْ يُطْعِمَ مِنْهُ وَاللَّهُ أَعْلَمُ","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah] dia berkata; telah menceritakan kepadaku [saudaraku] dari [Sulaiman] dari [Yahya bin Sa'id] dari ['Amrah binti Abdurrahman] dari [Aisyah] radliallahu 'anha dia berkata; Kami pernah menggarami daging kurban, lalu kami menyerahkannya kepada Nabi shallallahu 'alaihi wasallam di Madinah, maka beliau bersabda: \"Janganlah kalian memakannya jika melebihi tiga hari, hal ini bukan karena keharusan, akan tetapi aku hanya hendak membagikannya kepada yang lain.\" Wallahu a'lam"},"4840":{"ar":"حَدَّثَنَا حِبَّانُ بْنُ مُوسَى أَخْبَرَنَا عَبْدُ اللَّهِ قَالَ أَخْبَرَنِي يُونُسُ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي أَبُو عُبَيْدٍ مَوْلَى ابْنِ أَزْهَرَأَنَّهُ شَهِدَ الْعِيدَ يَوْمَ الْأَضْحَى مَعَ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ فَصَلَّى قَبْلَ الْخُطْبَةِ ثُمَّ خَطَبَ النَّاسَ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ نَهَاكُمْ عَنْ صِيَامِ هَذَيْنِ الْعِيدَيْنِ أَمَّا أَحَدُهُمَا فَيَوْمُ فِطْرِكُمْ مِنْ صِيَامِكُمْ وَأَمَّا الْآخَرُ فَيَوْمٌ تَأْكُلُونَ مِنْ نُسُكِكُمْقَالَ أَبُو عُبَيْدٍثُمَّ شَهِدْتُ الْعِيدَ مَعَ عُثْمَانَ بْنِ عَفَّانَ فَكَانَ ذَلِكَ يَوْمَ الْجُمُعَةِ فَصَلَّى قَبْلَ الْخُطْبَةِ ثُمَّ خَطَبَ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّ هَذَا يَوْمٌ قَدْ اجْتَمَعَ لَكُمْ فِيهِ عِيدَانِ فَمَنْ أَحَبَّ أَنْ يَنْتَظِرَ الْجُمُعَةَ مِنْ أَهْلِ الْعَوَالِي فَلْيَنْتَظِرْ وَمَنْ أَحَبَّ أَنْ يَرْجِعَ فَقَدْ أَذِنْتُ لَهُ قَالَ أَبُو عُبَيْدٍ ثُمَّ شَهِدْتُهُ مَعَ عَلِيِّ بْنِ أَبِي طَالِبٍ فَصَلَّى قَبْلَ الْخُطْبَةِ ثُمَّ خَطَبَ النَّاسَ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَاكُمْ أَنْ تَأْكُلُوا لُحُومَ نُسُكِكُمْ فَوْقَ ثَلَاثٍ وَعَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي عُبَيْدٍ نَحْوَهُ","id":"Telah menceritakan kepada kami [Hibban bin Musa] telah mengabarkan kepada kami [Abdullah] dia berkata; telah mengabarkan kepadaku [Yunus] dari [Az Zuhri] dia berkata; telah menceritakan kepadaku [Abu 'Ubaid] bekas budak Ibnu Azhar, bahwa dia pernah ikut shalat Iedul Adlha bersama [Umar bin Khatthab] radliallahu 'anhu, maka dia mengerjakan shalat sebelum khutbah, lalu berkhutbah di hadapan manusia, katanya; \"Wahai sekalian manusia, sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarang kalian untuk berpuasa di dua hari raya ini, salah satu dari hari itu adalah hari raya di mana kalian berbuka setelah kalian berpuasa, sedangkan yang kedua adalah pada hari kalian memakan daging binatang kurban kalian.\" Abu 'Ubaid berkata; Setelah itu aku juga pernah shalat ied bersama [Utsman bin 'Affan], waktu itu bertepatan dengan hari Jum'at, kemudian dia mengerjakan shalat ied sebelum berkhutbah lalu berkhutbah, katanya; \"Wahai sekalian manusia, sesungguhnya pada hari ini telah berkumpul dua hari raya kalian, maka siapa di antara kalian dari penduduk luar kota yang hendak menunggu di sini (hingga tiba waktu Jum'at), silahkan menunggu, namun jika menginginkan pulang sekarang, maka aku telah mengizinkannya pulang.\" Abu 'Ubaid mengatakan; \"Setelah itu, aku juga pernah ikut shalat ied bersama [Ali bin Abu Thalib], dia mengerjakan shalat ied sebelum berkhutbah, kemudian dia berkhutbah di hadapan manusia, katanya; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarang kalian memakan daging kurban kalian lebih dari tiga hari.\" Dari dari [Ma'mar] dari [Az Zuhri] dari [Abu 'Ubaid] seperti itu juga."},"4841":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ عَنْ ابْنِ أَخِي ابْنِ شِهَابٍ عَنْ عَمِّهِ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوا مِنْ الْأَضَاحِيِّ ثَلَاثًا وَكَانَ عَبْدُ اللَّهِ يَأْكُلُ بِالزَّيْتِ حِينَ يَنْفِرُ مِنْ مِنًى مِنْ أَجْلِ لُحُومِ الْهَدْيِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim] telah mengabarkan kepada kami [Ya'qub bin Ibrahim bin Sa'd] dari [Ibnu Akhi Ibnu Syihab] dari pamannya [Ibnu Syihab] dari [Salim] dari [Abdullah bin Umar] radliallahu 'anhuma dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makanlah daging kurban selama tiga hari.\" Sementara Abdullah makan daging kurban tersebut dengan minyak, ketika dia kembali dari Mina.\""},"4842":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَرِبَ الْخَمْرَ فِي الدُّنْيَا ثُمَّ لَمْ يَتُبْ مِنْهَا حُرِمَهَا فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari [Abdullah bin Umar] radliallahu 'anhuma bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meminum khamr di dunia dan tidak bertaubat, maka akan di haramkan baginya di akhirat kelak.\""},"4843":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ لَيْلَةَ أُسْرِيَ بِهِ بِإِيلِيَاءَ بِقَدَحَيْنِ مِنْ خَمْرٍ وَلَبَنٍ فَنَظَرَ إِلَيْهِمَا ثُمَّ أَخَذَ اللَّبَنَ فَقَالَ جِبْرِيلُ الْحَمْدُ لِلَّهِ الَّذِي هَدَاكَ لِلْفِطْرَةِ وَلَوْ أَخَذْتَ الْخَمْرَ غَوَتْ أُمَّتُكَتَابَعَهُ مَعْمَرٌ وَابْنُ الْهَادِ وَعُثْمَانُ بْنُ عُمَرَ وَالزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku [Sa'id bin Musayyib] bahwa dia mendengar [Abu Hurairah] radliallahu 'anhu, bahwa pada malam Rasulullah shallallahu 'alaihi wasallam diisra`kan yaitu ketika sampai di Iliya`, dihidangkan ke hadapan beliau dua gelas yang berisikan susu dan berisikan khamer, lalu aku melihat keduanya dan mengambil gelas yang berisi susu, maka Jibril berkata; 'Segala puji bagi Allah yang telah memberimu petunjuk kepada fitrah, seandainya engkau memilih khamer maka umatmu akan tersesat.' Riwayat ini juga di perkuat oleh riwayat [Ma'mar], [Ibnu Al Had], dan [Utsman bin Umar] serta [Az Zubaidi] dari [Az Zuhri]."},"4844":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُقَالَ سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا لَا يُحَدِّثُكُمْ بِهِ غَيْرِي قَالَ مِنْ أَشْرَاطِ السَّاعَةِ أَنْ يَظْهَرَ الْجَهْلُ وَيَقِلَّ الْعِلْمُ وَيَظْهَرَ الزِّنَا وَتُشْرَبَ الْخَمْرُ وَيَقِلَّ الرِّجَالُ وَيَكْثُرَ النِّسَاءُ حَتَّى يَكُونَ لِخَمْسِينَ امْرَأَةً قَيِّمُهُنَّ رَجُلٌ وَاحِدٌ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Anas] radliallahu 'anhu, dia berkata; saya mendengar suatu hadits dari Rasulullah shallallahu 'alaihi wasallam yang beliau tidak menyampaikan hadits tersebut kepada kalian selain kepadaku, beliau bersabda: \"Di antara tanda-tanda hari Kiamat adalah kebodohan merajalela, sedikitnya ilmu, perzinahan merajalela, di minumnya minuman keras, sedikitnya jumlah laki-laki sementara jumlah wanita semakin banyak, bahkan lima puluh wanita yang ditanggung satu orang laki-laki.\""},"4845":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ سَمِعْتُ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ وَابْنَ الْمُسَيَّبِ يَقُولَانِ قَالَ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزْنِي الزَّانِي حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلَا يَشْرَبُ الْخَمْرَ حِينَ يَشْرَبُهَا وَهُوَ مُؤْمِنٌ وَلَا يَسْرِقُ السَّارِقُ حِينَ يَسْرِقُ وَهُوَ مُؤْمِنٌقَالَ ابْنُ شِهَابٍ وَأَخْبَرَنِي عَبْدُ الْمَلِكِ بْنُ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ أَنَّ أَبَا بَكْرٍ كَانَ يُحَدِّثُهُ عَنْ أَبِي هُرَيْرَةَ ثُمَّ يَقُولُ كَانَ أَبُو بَكْرٍ يُلْحِقُ مَعَهُنَّ وَلَا يَنْتَهِبُ نُهْبَةً ذَاتَ شَرَفٍ يَرْفَعُ النَّاسُ إِلَيْهِ أَبْصَارَهُمْ فِيهَا حِينَ يَنْتَهِبُهَا وَهُوَ مُؤْمِنٌ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dia berkata; saya mendengar [Abu Salamah bin Abdurrahman] dan [Ibnu Musayyab] keduanya berkata, [Abu Hurairah] radliallahu 'anhu berkata; sesungguhnya Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang itu berzina, ketika sedang berzina dia dalam keadaan mukmin. Tidak pula seseorang itu minum khamer ketika sedang minum khamer ia dalam keadaan mukmin. Dan tidak pula seseorang itu mencuri ketika sedang mencuri ia dalam keadaan mukmin.\" [Ibnu Syihab] berkata; telah mengabarkan kepadaku pula [Abdul Malik bin Abu Bakr bin Abdurrahman bin Al Harits bin Hisyam] bahwa [Abu Bakr] pernah menceritakan kepadanya dari [Abu Hurairah], lalu dia berkata; \"Abu Bakar menambahkan dalam hadits tersebut dengan redaksi; \"Dan tidaklah seseorang merampas harta orang lain yang karenanya orang-orang memandangnya sebagai orang yang terpandang, ketika dia merampas harta tersebut dalam keadaan mukmin.\""},"4846":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ صَبَّاحٍ حَدَّثَنَا مُحَمَّدُ بْنُ سَابِقٍ حَدَّثَنَا مَالِكٌ هُوَ ابْنُ مِغْوَلٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَقَدْ حُرِّمَتْ الْخَمْرُ وَمَا بِالْمَدِينَةِ مِنْهَا شَيْءٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Shabbah] telah menceritakan kepada kami [Muhammad bin Sabiq] telah menceritakan kepada kami [Malik] yaitu Ibnu Mighwal dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma dia berkata; \"Katika khamer diharamkan, maka tidak didapati sedikitpun jenis minuman keras di Madinah.\""},"4847":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو شِهَابٍ عَبْدُ رَبِّهِ بْنُ نَافِعٍ عَنْ يُونُسَ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسٍ قَالَحُرِّمَتْ عَلَيْنَا الْخَمْرُ حِينَ حُرِّمَتْ وَمَا نَجِدُ يَعْنِي بِالْمَدِينَةِ خَمْرَ الْأَعْنَابِ إِلَّا قَلِيلًا وَعَامَّةُ خَمْرِنَا الْبُسْرُ وَالتَّمْرُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Abu Syihab Abdu Rabbihi bin Nafi'] dari [Yunus] dari [Tsabit Al Bunani] dari [Anas] dia berkata; \"Khamr telah diharamkan atas kami, katika hal itu diharamkan maka kami tidak mendapati jenis khamr dari (perasan) anggur di Madinah kecuali hanya sedikit, ketika itu kebanyakan khamr kami terbuat dari perasan busr (kurma yang masih muda) dan tamr (kurma kering).\""},"4848":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ أَبِي حَيَّانَ حَدَّثَنَا عَامِرٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَامَ عُمَرُ عَلَى الْمِنْبَرِ فَقَالَأَمَّا بَعْدُ نَزَلَ تَحْرِيمُ الْخَمْرِ وَهِيَ مِنْ خَمْسَةٍ الْعِنَبِ وَالتَّمْرِ وَالْعَسَلِ وَالْحِنْطَةِ وَالشَّعِيرِ وَالْخَمْرُ مَا خَامَرَ الْعَقْلَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Abu Hayyan] telah menceritakan kepada kami ['Amir] dari [Ibnu Umar] radliallahu 'anhuma, [Umar] pernah berdiri di atas mimbar seraya berkata; \"Amma ba'du, keharaman khamr telah turun yaitu yang terbuat dari lima jenis; anggur, kurma kering, madu, biji gandum dan tepung, sedangkan khamr adalah sesuatu yang dapat menghalangi akal (sehat).\""},"4849":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكُ بْنُ أَنَسٍ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ أَسْقِي أَبَا عُبَيْدَةَ وَأَبَا طَلْحَةَ وَأُبَيَّ بْنَ كَعْبٍ مِنْ فَضِيخِ زَهْوٍ وَتَمْرٍ فَجَاءَهُمْ آتٍ فَقَالَ إِنَّ الْخَمْرَ قَدْ حُرِّمَتْ فَقَالَ أَبُو طَلْحَةَ قُمْ يَا أَنَسُ فَأَهْرِقْهَا فَأَهْرَقْتُهَا","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah] dia berkata; telah menceritakan kepadaku [Malik bin Anas] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] radliallahu 'anhu dia berkata; \"Aku pernah menuangkan minuman dari fadlih (minuman keras dari perasan kurma muda) dan tamr (minuman keras dari perasan kurma kering) kepada Abu 'Ubaidah, Abu Thalhah, Ubay bin Ka'b, tiba-tiba seseorang datang sambil berkata; \"Sesungguhnya khamr telah diharamkan.\" Lantas Abu Thalhah berkata; \"Wahai Anas, bangunlah dan tumpahkanlah!.\" Maka aku pun menumpahkan khamr tersebut.\""},"4850":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ قَالَ سَمِعْتُ أَنَسًا قَالَكُنْتُ قَائِمًا عَلَى الْحَيِّ أَسْقِيهِمْ عُمُومَتِي وَأَنَا أَصْغَرُهُمْ الْفَضِيخَ فَقِيلَ حُرِّمَتْ الْخَمْرُ فَقَالُوا أَكْفِئْهَا فَكَفَأْتُهَا قُلْتُ لِأَنَسٍ مَا شَرَابُهُمْ قَالَ رُطَبٌ وَبُسْرٌ فَقَالَ أَبُو بَكْرِ بْنُ أَنَسٍ وَكَانَتْ خَمْرَهُمْ فَلَمْ يُنْكِرْ أَنَسٌ وَحَدَّثَنِي بَعْضُ أَصْحَابِي أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُ كَانَتْ خَمْرَهُمْ يَوْمَئِذٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Mu'tamir] dari [Ayahnya] dia berkata; saya mendengar [Anas] berkata; \"Aku pernah menjadi pelayan yang bertugas menuangkan minuman kepada paman-pamanku di suatu tempat, sementara diriku adalah yang paling muda di antara mereka, ketika itu aku menuangkan Fadlih (minuman keras dari perasan kurma muda) tiba-tiba ada yang berkata; \"Sesungguhnya khamar telah di haramkan.\" Lantas mereka berkata; \"Tumpahkanlah\" maka aku pun menumpahkannya. Aku bertanya kepada Anas; \"Apakah yang mereka minum waktu itu?\" dia menjawab; \"yaitu ruthab (minuman keras dari perasan kurma basah) dan busr (minuman keras dari perasan kurma muda atau masih pentil).\" Abu Bakar bin Anas berkata; \"Seperti itulah khamr mereka, sementara Anas tidak mengingkarinya.\" Dan sebagian sahabatku juga pernah menceritakan kepadaku bahwa dia pernah mendengar Anas bin Malik berkata; \"Seperti itulah khmar mereka waktu itu.\""},"4851":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا يُوسُفُ أَبُو مَعْشَرٍ الْبَرَّاءُ قَالَ سَمِعْتُ سَعِيدَ بْنَ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي بَكْرُ بْنُ عَبْدِ اللَّهِ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُمْأَنَّ الْخَمْرَ حُرِّمَتْ وَالْخَمْرُ يَوْمَئِذٍ الْبُسْرُ وَالتَّمْرُ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakr Al Muqaddami] telah menceritakan kepada kami [Yusuf Abu Ma'syar Al Barra`] dia berkata; saya mendengar [Sa'id bin 'Ubaidullah] berkata; telah menceritakan kepadaku [Bakr bin Abdullah] bahwa [Anas bin Malik] telah menceritakan kepada mereka bahwa Khamr telah di haramkan, ketika itu khmer terbuat dari busr (minuman keras dari perasan kurma muda atau masih pentil) dan tamr (minuman keras dari perasan kurma kering)."},"4852":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْبِتْعِ فَقَالَ كُلُّ شَرَابٍ أَسْكَرَ فَهُوَ حَرَامٌ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman] bahwa [Aisyah] berkata; Rasulullah shallallahu 'alaihi wasallam pernah di tanya mengenai bit'i (minuman keras yang terbuat dari madu), lalu beliau bersabda: \"Setiap minuman yang dapat memabukkan hukumnya haram.\""},"4853":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْبِتْعِ وَهُوَ نَبِيذُ الْعَسَلِ وَكَانَ أَهْلُ الْيَمَنِ يَشْرَبُونَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ شَرَابٍ أَسْكَرَ فَهُوَ حَرَامٌ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] bahwa [Aisyah] radliallahu 'anha berkata; Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang bit'i yaitu (minuman keras) yang terbuat dari perasan madu dan sebagai minuman yang banyak di konsumsi oleh penduduk Yaman, maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Setiap minuman yang memabukkan hukumnya haram.\" "},"4854":{"ar":"وَعَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَنْتَبِذُوا فِي الدُّبَّاءِ وَلَا فِي الْمُزَفَّتِوَكَانَ أَبُو هُرَيْرَةَ يُلْحِقُ مَعَهَا الْحَنْتَمَ وَالنَّقِيرَ","id":"Telah menceritakan kepada kami [Az Zuhri] dia berkata; telah menceritakan kepadaku [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian membuat perasan dalam duba' (tempat minum dari labu yang di buang isinya dan di gunakan untuk merendam perasan kurma atau anggur) dan muzaffat (tempat minum yang di polesi dengan ter).\" Sementara riwayat Abu Hurairah melengkapinya dengan \"hantam (tempat minum yang terbuat dari tanah liat, rambut dan darah) dan naqiir (tempat minum yang terbuat dari pohon atau kayu yang di lubangi).\""},"4855":{"ar":"حَدَّثَنَا أَحْمَدُ ابْنُ أَبِي رَجَاءٍ حَدَّثَنَا يَحْيَى عَنْ أَبِي حَيَّانَ التَّيْمِيِّ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَ خَطَبَ عُمَرُ عَلَى مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَإِنَّهُ قَدْ نَزَلَ تَحْرِيمُ الْخَمْرِ وَهِيَ مِنْ خَمْسَةِ أَشْيَاءَ الْعِنَبِ وَالتَّمْرِ وَالْحِنْطَةِ وَالشَّعِيرِ وَالْعَسَلِ وَالْخَمْرُ مَا خَامَرَ الْعَقْلَ وَثَلَاثٌ وَدِدْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يُفَارِقْنَا حَتَّى يَعْهَدَ إِلَيْنَا عَهْدًا الْجَدُّ وَالْكَلَالَةُ وَأَبْوَابٌ مِنْ أَبْوَابِ الرِّبَا قَالَ قُلْتُ يَا أَبَا عَمْرٍو فَشَيْءٌ يُصْنَعُ بِالسِّنْدِ مِنْ الْأُرْزِ قَالَ ذَاكَ لَمْ يَكُنْ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ عَلَى عَهْدِ عُمَرَوَقَالَ حَجَّاجٌ عَنْ حَمَّادٍ عَنْ أَبِي حَيَّانَ مَكَانَ الْعِنَبِ الزَّبِيبَ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Raja`] telah menceritakan kepada kami [Yahya] dari [Abu Hayyan At Taimi] dari [As Sya'bi] dari [Ibnu Umar] radliallahu 'anhuma dia berkata; [Umar] pernah berkhutbah di atas mimbar Rasulullah shallallahu 'alaihi wasallam, katanya; \"Sesungguhnya telah ditetapkan keharaman khamr yaitu dari lima jenis; (perasan) anggur, tamr (minuman dari perasan kurma kering), biji gandum, tepung dan madu, sedangkan khamr adalah sesuatu yang dapat menghalangi akal (sehat), dan tiga perkara yang aku berharap Rasulullah shallallahu 'alaihi wasallam memberikan penjelasan kepada kami sebelum beliau meninggal; (hak waris) seorang kakek, al Kalalah, dan pintu-pintu riba.\" Asy Sya'bi berkata, \"Aku berkata, \"Wahai Abu Amru, bagaimana dengan perasan nabidz yang terbuat dari biji padi?\" Ibnu Umar menjawab, \"Itu belum pernah ada di masa Rasulullah shallallahu 'alaihi wasallam, atau ia mengatakan, \"di masa Umar.\" [Hajjaj] menyebutkan dari [Hammad] dari [Abu Hayyan], \"Anggur sama dengan kismis.\" "},"4856":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ قَالَالْخَمْرُ يُصْنَعُ مِنْ خَمْسَةٍ مِنْ الزَّبِيبِ وَالتَّمْرِ وَالْحِنْطَةِ وَالشَّعِيرِ وَالْعَسَلِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Abu As Safar] dari [As Sya'bi] dari [Ibnu Umar] dari [Umar] dia berkata; \"Khamr itu terbuat dari lima jenis, yaitu dari kismis, tamr (kurma kering), hinthah (biji gandum), tepung, dan (perasan) madu.\""},"4857":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي حَازِمٍ قَالَ سَمِعْتُ سَهْلًا يَقُولُأَتَى أَبُو أُسَيْدٍ السَّاعِدِيُّ فَدَعَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي عُرْسِهِ فَكَانَتْ امْرَأَتُهُ خَادِمَهُمْ وَهِيَ الْعَرُوسُ قَالَ أَتَدْرُونَ مَا سَقَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْقَعْتُ لَهُ تَمَرَاتٍ مِنْ اللَّيْلِ فِي تَوْرٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub bin Abdurrahman] dari [Abu Hazim] dia berkata; saya mendengar [Sahl] berkata; \"Abu Usaid as Sa'idi datang dan mengundang Rasulullah shallallahu 'alaihi wasallam di tempat pelaminannya, sementara istri Abu Usaid membantu mereka pada hari ketika dia menjadi pengantin. (Sahal) berkata; 'Apakah kalian mengetahui apa yang aku tuangkan kepada Rasulullah Shallallahu'alaihiwasallam? Aku tuangkan kepada beliau (munuman) dari rendaman kurma semalam dalam kuali.\""},"4858":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ سَالِمٍ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الظُّرُوفِ فَقَالَتْ الْأَنْصَارُ إِنَّهُ لَا بُدَّ لَنَا مِنْهَا قَالَ فَلَا إِذًاوَقَالَ خَلِيفَةُ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ جَابِرٍ بِهَذَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ بِهَذَا وَقَالَ فِيهِ لَمَّا نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْأَوْعِيَةِ","id":"Telah menceritakan kepada kami [Yusuf bin Musa] telah menceritakan kepada kami [Muhammad bin Abdullah Abu Ahmad Az Zubairi] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Salim] dari [Jabir] radliallahu 'anhu dia berkata; Rasulullah shallallahu 'alaihi wasallam melarang membuat tempat minum dari kulit, maka orang-orang Anshar berkata; \"Padahal kami harus memakainya\" beliau bersabda: \"Oh, kalau begitu tidak mengapa.\" [Khalifah] mengatakan; telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Salim bin Abu Al Ja'd] dari [Jabir] seperti ini, telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Sufyan] juga seperti ini, dia mengatakan; \"Yaitu ketika Nabi shallallahu 'alaihi wasallam melarang dari membuat beberapa jenis tempat minum.\""},"4859":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ سُلَيْمَانَ بْنِ أَبِي مُسْلِمٍ الْأَحْوَلِ عَنْ مُجَاهِدٍ عَنْ أَبِي عِيَاضٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْأَسْقِيَةِ قِيلَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ كُلُّ النَّاسِ يَجِدُ سِقَاءً فَرَخَّصَ لَهُمْ فِي الْجَرِّ غَيْرِ الْمُزَفَّتِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepadaku [Sulaiman bin Abu Muslim Al Ahwal] dari [Mujahid] dari [Abu 'Iyadl] dari [Abdullah bin 'Amru] radliallahu 'anhuma dia berkata; \"Ketika Nabi shallallahu 'alaihi wasallam melarang beberapa jenis tempat air minum, lantas ditanyakan kepada Nabi shallallahu 'alaihi wasallam; \"Kalau begitu orang-orang akan kesulitan mendapatkan tempat air minum!.\" Maka beliau memberi keringanan pada al jar (tempat air minum yang terbuat dari tembikar) selain Muzaffat (tempat air minum yang di polesi dengan ter)."},"4860":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنِي سُلَيْمَانُ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدُّبَّاءِ وَالْمُزَفَّتِحَدَّثَنَا عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ بِهَذَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] telah menceritakan kepadaku [Sulaiman] dari [Ibrahim At Taimi] dari [Al Harits bin Suwaid] dari [Ali] radliallahu 'anhu bahwa Nabi shallallahu 'alaihi wasallam melarang duba' (tempat minum dari labu yang di buang isinya dan di gunakan untuk merendam perasan kurma atau anggur) dan Muzaffat (tempat minum yang dipolesi dengan ter).\" Telah menceritakan kepada kami [Utsman] telah menceritakan kepada kami [Jarir] dari [Al A'masy] seperti ini."},"4861":{"ar":"حَدَّثَنِي عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ قُلْتُ لِلْأَسْوَدِهَلْ سَأَلْتَ عَائِشَةَ أُمَّ الْمُؤْمِنِينَ عَمَّا يُكْرَهُ أَنْ يُنْتَبَذَ فِيهِ فَقَالَ نَعَمْ قُلْتُ يَا أُمَّ الْمُؤْمِنِينَ عَمَّ نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُنْتَبَذَ فِيهِ قَالَتْ نَهَانَا فِي ذَلِكَ أَهْلَ الْبَيْتِ أَنْ نَنْتَبِذَ فِي الدُّبَّاءِ وَالْمُزَفَّتِ قُلْتُ أَمَا ذَكَرَتْ الْجَرَّ وَالْحَنْتَمَ قَالَ إِنَّمَا أُحَدِّثُكَ مَا سَمِعْتُ أَفَأُحَدِّثُ مَا لَمْ أَسْمَعْ","id":"Telah menceritakan kepada kami [Utsman] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] kataku kepada [Al Aswad] apakah kamu pernah bertanya kepada [Ummul Mukminin Aisyah] tentang jenis tempat minum yang tidak di perbolehkan untuk merendam perasan (anggur atau kurma), Al Aswad menjawab; Ya pernah, tanyaku (kepada Aisyah); \"Wahai Ummul Mukminin, jenis tempat minum seperti apakah yang dilarang oleh Nabi shallallahu 'alaihi wasallam untuk merendam (perasan angur atau kurma)?\" Aisyah menjawab; \"Beliau melarang kami begitu juga kepada ahli bait beliau dari merendam (perasan anggur atau kurma) dalam duba' (tempat minum dari labu yang di buang isinya dan di gunakan untuk merendam perasan kurma atau anggur) dan muzaffat (tempat minum yang di polesi dengan ter). Aku (Ibrahim) bertanya; \"Apakah Aisyah tidak menyebutkan tentang al jar (tempat air minum yang terbuat dari tembikar) dan hantam (tempat minum yang terbuat dari tanah liat, rambut dan darah)? Al Aswad menjawab; \"Aku hanya menceritakan kepadamu dari hadits yang aku dengar, dan aku tidak mau menceritakan kepadamu sesuatu yang belum aku dengar.\""},"4862":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الشَّيْبَانِيُّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُمَا قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْجَرِّ الْأَخْضَرِ قُلْتُ أَنَشْرَبُ فِي الْأَبْيَضِ قَالَ لَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami [As Syaibani] dia berkata; saya mendengar [Abdullah bin Abu Aufa] radliallahu 'anhuma berkata; Nabi shallallahu 'alaihi wasallam melarang al jar al ahdlar (tempat air minum yang terbuat dari tembikar yang dicat hijau), tanyaku; \"apakah kami (diperbolehkan) dari yang berwarna putih? Dia menjawab; \"Tidak.\""},"4863":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ الْقَارِيُّ عَنْ أَبِي حَازِمٍ قَالَ سَمِعْتُ سَهْلَ بْنَ سَعْدٍ السَّاعِدِيَّأَنَّ أَبَا أُسَيْدٍ السَّاعِدِيَّ دَعَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعُرْسِهِ فَكَانَتْ امْرَأَتُهُ خَادِمَهُمْ يَوْمَئِذٍ وَهِيَ الْعَرُوسُ فَقَالَتْ مَا تَدْرُونَ مَا أَنْقَعْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْقَعْتُ لَهُ تَمَرَاتٍ مِنْ اللَّيْلِ فِي تَوْرٍ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Ya'qub bin Abdurrahman Al Qari] dari [Abu Hazim] dia berkata; saya mendengar [Sahl bin Sa'd As Sa'idi] bahwa Abu Usaid As Sa'idi pernah mengundang Nabi shallallahu 'alaihi wasallam di hari pernikahannya, sementara istri Abu Usaid jugalah yang melayani mereka (para undangan) padahal ia sebagai pengantin (mempelai puteri). Isteri Abu Usaid berkata, Apakah kalian mengetahui apa yang aku tuangkan kepada Rasulullah shallallahu 'alaihi wasallam? Aku tuangkan kepada beliau (munuman) dari rendaman kurma semalam di dalam kuali.\""},"4864":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي الْجُوَيْرِيَةِ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍعَنْ الْبَاذَقِ فَقَالَ سَبَقَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَاذَقَ فَمَا أَسْكَرَ فَهُوَ حَرَامٌ قَالَ الشَّرَابُ الْحَلَالُ الطَّيِّبُ قَالَ لَيْسَ بَعْدَ الْحَلَالِ الطَّيِّبِ إِلَّا الْحَرَامُ الْخَبِيثُ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Abu Al Juwairiyah] dia berkata; saya bertanya kepada [Ibnu Abbas] tentang al badzaq (perasan yang terbuat dari anggur yang dimasak), Ibnu Abbas menjawab; \"Muhammad shallallahu 'alaihi wasallam telah menjelaskan (keharaman) al badzaq, sesuatu yang dapat memabukkan hukumnya haram, katanya lagi; minuman yang halal lagi baik, katanya melanjutkan; \"Tidaklah setelah sesuatu yang halal lagi baik melainkan haram lagi jelek.\""},"4865":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ الْحَلْوَاءَ وَالْعَسَلَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Hisyam bin Urwah] dari [ayahnya] dari [Aisyah] radliallahu 'anha dia berkata; bahwa Nabi shallallahu 'alaihi wasallam sangat menyukai manisan dan madu.\""},"4866":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَإِنِّي لَأَسْقِي أَبَا طَلْحَةَ وَأَبَا دُجَانَةَ وَسُهَيْلَ بْنَ الْبَيْضَاءِ خَلِيطَ بُسْرٍ وَتَمْرٍ إِذْ حُرِّمَتْ الْخَمْرُ فَقَذَفْتُهَا وَأَنَا سَاقِيهِمْ وَأَصْغَرُهُمْ وَإِنَّا نَعُدُّهَا يَوْمَئِذٍ الْخَمْرَوَقَالَ عَمْرُو بْنُ الْحَارِثِ حَدَّثَنَا قَتَادَةُ سَمِعَ أَنَسًا","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Anas] radliallahu 'anhu, dia berkata; \"Sesungguhnya aku pernah menuangkan minuman campuran busr (kurma muda) dan tamr (kurma kering) kepada Abu Thalhah, Abu Dujanah dan Suhail bin Baidla`, tiba-tiba khamr di haramkan, lalu aku tumpahkan semuanya padahal aku adalah pelayan yang bertugas menuangkan minuman dan aku termasuk orang yang paling muda di anatara mereka, kami menganggap perasan tersebut sebagai khamr.\" ['Amru bin Al Harits] telah menceritakan kepada kami [Qatadah] bahwa dia mendengar dari [Anas]."},"4867":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي عَطَاءٌ أَنَّهُ سَمِعَ جَابِرًا رَضِيَ اللَّهُ عَنْهُ يَقُولُنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الزَّبِيبِ وَالتَّمْرِ وَالْبُسْرِ وَالرُّطَبِ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] telah mengabarkan kepadaku ['Atha`] bahwa dia mendengar [Jabir] radliallahu 'anhu berkata; Nabi shallallahu 'alaihi wasallam melarang (minuman keras yang terbuat) dari kismis, tamr (kurma kering), busr (kurma muda) dan ruthab (kurma basah).\""},"4868":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُجْمَعَ بَيْنَ التَّمْرِ وَالزَّهْوِ وَالتَّمْرِ وَالزَّبِيبِ وَلْيُنْبَذْ كُلُّ وَاحِدٍ مِنْهُمَا عَلَى حِدَةٍ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Hisyam] telah mengabarkan kepada kami [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dari [ayahnya] dia berkata; Nabi shallallahu 'alaihi wasallam melarang mencampur antara perasan kurma kering dengan zahw (kurma muda), antara tamr (kurma kering) dengan kismis, lalu setiap dari keduanya di rendam dalam satu wadah.\""},"4869":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ أُسْرِيَ بِهِ بِقَدَحِ لَبَنٍ وَقَدَحِ خَمْرٍ","id":"Telah menceritakan kepada kami [Abdan] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] dari [Sa'id bin Musayyib] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Di malam isra', Rasulullah shallallahu 'alaihi wasallam pernah di beri segelas susu dan segelas khamr."},"4870":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ سَمِعَ سُفْيَانَ أَخْبَرَنَا سَالِمٌ أَبُو النَّضْرِ أَنَّهُ سَمِعَ عُمَيْرًا مَوْلَى أُمِّ الْفَضْلِ يُحَدِّثُ عَنْ أُمِّ الْفَضْلِ قَالَتْشَكَّ النَّاسُ فِي صِيَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ عَرَفَةَ فَأَرْسَلْتُ إِلَيْهِ بِإِنَاءٍ فِيهِ لَبَنٌ فَشَرِبَ فَكَانَ سُفْيَانُ رُبَّمَا قَالَ شَكَّ النَّاسُ فِي صِيَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ عَرَفَةَ فَأَرْسَلَتْ إِلَيْهِ أُمُّ الْفَضْلِفَإِذَا وُقِّفَ عَلَيْهِ قَالَ هُوَ عَنْ أُمِّ الْفَضْلِ","id":"Telah menceritakan kepada kami [Al Humaidi] dia mendengar [Sufyan] telah mengabarkan kepada kami [Salim Abu Nadlr] bahwa dia mendengar ['Umair] bekas budak Ummu Fadl menceritakan dari [Ummu Fadl] dia berkata; Orang-orang ragu mengenai puasa 'Arafah Rasulullah shallallahu 'alaihi wasallam, oleh karena itu aku mengirim semangkuk susu kepada beliau, lalu beliau meminumnya.\" Sedangkan Sufyan sepertinya mengatakan; \"Orang-orang ragu akan puasanya Rasulullah shallallahu 'alaihi wasallam pada hari 'Arafah, maka Ummu Fadl akan mengirim orang kepadanya. Namun Sufyan meriwayatkan Hadits itu secara mursal, apabila ditanya dari siapakah riwayat itu? Ia akan mengatakan; \"(riwayat) Itu dari Ummu Fadl.\""},"4871":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ وَأَبِي سُفْيَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَجَاءَ أَبُو حُمَيْدٍ بِقَدَحٍ مِنْ لَبَنٍ مِنْ النَّقِيعِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَّا خَمَّرْتَهُ وَلَوْ أَنْ تَعْرُضَ عَلَيْهِ عُودًاحَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ سَمِعْتُ أَبَا صَالِحٍ يَذْكُرُ أُرَاهُ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَ جَاءَ أَبُو حُمَيْدٍ رَجُلٌ مِنْ الْأَنْصَارِ مِنْ النَّقِيعِ بِإِنَاءٍ مِنْ لَبَنٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَّا خَمَّرْتَهُ وَلَوْ أَنْ تَعْرُضَ عَلَيْهِ عُودًا وَحَدَّثَنِي أَبُو سُفْيَانَ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dan [Abu Sufyan] dari [Jabir bin Abdullah] dia berkata; Abu Humaid datang membawa tempat bersisi susu, lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Tidakkah kau tutupi, bisa jadi itu akan bermanfaat\". Telah menceritakan kepada kami [Umar bin Hafsh] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Al A'masy] dia berkata; saya mendengar [Abu Shalih] menyebutkan (redaksi hadits), yang saya mengiranya dari [Jabir], yaitu \"Bisa jadi hal itu bermanfa'at buatmu.\" Dan telah menceritakan kepadaku Abu Sufyan dari Jabir dari Nabi shallallahu 'alaihi wasallam seperti ini juga."},"4872":{"ar":"حَدَّثَنِي مَحْمُودٌ أَخْبَرَنَا النَّضْرُ أَخْبَرَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ الْبَرَاءَ رَضِيَ اللَّهُ عَنْهُ قَالَقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَكَّةَ وَأَبُو بَكْرٍ مَعَهُ قَالَ أَبُو بَكْرٍ مَرَرْنَا بِرَاعٍ وَقَدْ عَطِشَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَحَلَبْتُ كُثْبَةً مِنْ لَبَنٍ فِي قَدَحٍ فَشَرِبَ حَتَّى رَضِيتُ وَأَتَانَا سُرَاقَةُ بْنُ جُعْشُمٍ عَلَى فَرَسٍ فَدَعَا عَلَيْهِ فَطَلَبَ إِلَيْهِ سُرَاقَةُ أَنْ لَا يَدْعُوَ عَلَيْهِ وَأَنْ يَرْجِعَ فَفَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku [Mahmud] telah mengabarkan kepada kami [An Nadlr] telah mengabarkan kepada kami [Syu'bah] dari [Abu Ishaq] dia berkata; saya mendengar [Al Barra`] radliallahu 'anhu berkata; Nabi shallallahu 'alaihi wasallam bersama Abu Bakar tiba dari Makkah, lalu Abu Bakar berkata; \"Kami pernah melewati seorang penggembala, sementara Rasulullah shallallahu 'alaihi wasallam kehausan, Abu Bakar melanjutkan; \"Lalu aku memeraskan semangkuk susu untuk beliau, setelah itu beliau meminumnya hingga aku merasa puas, selanjutnya Suraqah bin Ju'syum mendatangi kami dengan mengendarai kuda, maka beliau mendo'akan kecelakan atasnya hingga Suraqah meminta beliau supaya berhenti mendo'akan kecelakan atasnya dan kembali pulang, lalu Nabi shallallahu 'alaihi wasallam melaksanakan keinginannya."},"4873":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نِعْمَ الصَّدَقَةُ اللِّقْحَةُ الصَّفِيُّ مِنْحَةً وَالشَّاةُ الصَّفِيُّ مِنْحَةً تَغْدُو بِإِنَاءٍ وَتَرُوحُ بِآخَرَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az Zinad] dari [Abdurrahman] dari [Abu Hurairah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik sedekah adalah unta bunting yang banyak susunya dan kambing bunting yang banyak susunya (yang dipinjamkan), yaitu ketika pergi dengan kantong susu (penuh) dan ketika pulang membawa kantong susu yang lain.\""},"4874":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ الْأَوْزَاعِيِّ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَرِبَ لَبَنًا فَمَضْمَضَ وَقَالَ إِنَّ لَهُ دَسَمًا وَقَالَ إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُفِعْتُ إِلَى السِّدْرَةِ فَإِذَا أَرْبَعَةُ أَنْهَارٍ نَهَرَانِ ظَاهِرَانِ وَنَهَرَانِ بَاطِنَانِ فَأَمَّا الظَّاهِرَانِ النِّيلُ وَالْفُرَاتُ وَأَمَّا الْبَاطِنَانِ فَنَهَرَانِ فِي الْجَنَّةِ فَأُتِيتُ بِثَلَاثَةِ أَقْدَاحٍ قَدَحٌ فِيهِ لَبَنٌ وَقَدَحٌ فِيهِ عَسَلٌ وَقَدَحٌ فِيهِ خَمْرٌ فَأَخَذْتُ الَّذِي فِيهِ اللَّبَنُ فَشَرِبْتُ فَقِيلَ لِي أَصَبْتَ الْفِطْرَةَ أَنْتَ وَأُمَّتُكَقَالَ هِشَامٌ وَسَعِيدٌ وَهَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ مَالِكِ بْنِ صَعْصَعَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْأَنْهَارِ نَحْوَهُ وَلَمْ يَذْكُرُوا ثَلَاثَةَ أَقْدَاحٍ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Al Auza'i] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] radliallahu 'anhuma bahwa Rasulullah shallallahu 'alaihi wasallam pernah meminum susu lalu berkumur-kumur, beliau bersabda: \"Sesungguhnya ia mengandung lemak.\" [Ibrahim bin Thahman] mengatakan dari [Syu'bah] dari [Qatadah] dari [Anas bin Malik] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda; \"Ketika aku diangkat menuju Sidratul Muntaha, aku melewati empat sungai, dua sungai telah nampak olehku sementara dua lainnya belum nampak, dua sungai yang nampak olehku adalah sungai nil dan sungai efrat, sedangkan dua sungai yang tidak nampak olehku adalah sungai yang berada di surga, lalu aku diberi tiga mangkuk, satu mangkuk bersisi susu, satu mangkuk lagi berisi madu dan satu mangkuk lainnya berisi khamr, maka aku mengambil mangkuk yang berisi susu dan meminumnya, lalu diberitahukan kepadaku; \"Kamu dan ummatmu telah memilih fithrah.\" [Hisyam] dan [Sa'id] serta [Hammam] berkata dari [Qatadah] dari [Anas bin Malik] dari [Malik bin Sha'sha'ah] dari Nabi shallallahu 'alaihi wasallam mengenai beberapa sungai seperti hadits di atas, namun mereka tidak menyebutkan tiga mangkuk.\""},"4875":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَ أَبُو طَلْحَةَ أَكْثَرَ أَنْصَارِيٍّ بِالْمَدِينَةِ مَالًا مِنْ نَخْلٍ وَكَانَ أَحَبُّ مَالِهِ إِلَيْهِ بَيْرُحَاءَ وَكَانَتْ مُسْتَقْبِلَ الْمَسْجِدِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْخُلُهَا وَيَشْرَبُ مِنْ مَاءٍ فِيهَا طَيِّبٍ قَالَ أَنَسٌ فَلَمَّا نَزَلَتْ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }قَامَ أَبُو طَلْحَةَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ يَقُولُ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }وَإِنَّ أَحَبَّ مَالِي إِلَيَّ بَيْرُحَاءَ وَإِنَّهَا صَدَقَةٌ لِلَّهِ أَرْجُو بِرَّهَا وَذُخْرَهَا عِنْدَ اللَّهِ فَضَعْهَا يَا رَسُولَ اللَّهِ حَيْثُ أَرَاكَ اللَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَخٍ ذَلِكَ مَالٌ رَابِحٌ أَوْ رَايِحٌ شَكَّ عَبْدُ اللَّهِ وَقَدْ سَمِعْتُ مَا قُلْتَ وَإِنِّي أَرَى أَنْ تَجْعَلَهَا فِي الْأَقْرَبِينَ فَقَالَ أَبُو طَلْحَةَ أَفْعَلُ يَا رَسُولَ اللَّهِ فَقَسَمَهَا أَبُو طَلْحَةَ فِي أَقَارِبِهِ وَفِي بَنِي عَمِّهِوَقَالَ إِسْمَاعِيلُ وَيَحْيَى بْنُ يَحْيَى رَايِحٌ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Ishaq bin Abdullah] bahwa dia mendengar [Anas bin Malik] berkata; Abu Thalhah adalah sahabat Anshar yang paling banyak hartanya di Madinah yaitu berupa kebun kurma, sementara harta yang paling dia cintai ialah (kebun kurma) yang berada di Bairuha' dan yang menghadap ke Masjid, Rasulullah Shallallahu'alaihi wasallam juga sering memasukinya dan minum airnya yang jernih, Anas berkata; ketika ayat ini turun Tidaklah engkau mendapatkan kebaikan hingga engkau menginfakkan apa yang paling engkau sukai QS Ali Imran; 92, Maka Abu Thalhah berdiri dan berkata; \"Ya Rasulullah, sesungguhnya Allah telah berfirman \"Tidaklah engkau mendapatkan kebaikan hingga engkau menginfakkan apa yang paling engkau sukai\" dan sungguh harta yang paling aku sukai adalah Bairuha' dan telah aku infakkan dijalan Allah, aku hanya berharap kebaikannya dan aku harapkan simpanannya disisi Allah, maka taruhlah ia dimanapun engkau kehendaki ya Rasulullah, selanjutnya Rasulullah Shallallahu'alaihi wasallam bersabda: \"Wah…! Itu adalah harta yang sangat berharga, harta yang sangat berharga, sungguh aku telah mendengar apa yang kamu katakan agar kamu menjadikannya sebagian untuk karib kerabatmu, \" lalu Abu Thalhah berkata; \"Akan aku lakukan ya Rasulullah, \" maka ia membaginya untuk keluarganya dan anak pamannya.\" Sementara [Isma'il] dan [Yahya bin Yahya] menyebutkan dengan redaksi \"raayihun (berharga).\""},"4876":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَرِبَ لَبَنًا وَأَتَى دَارَهُ فَحَلَبْتُ شَاةً فَشُبْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْبِئْرِ فَتَنَاوَلَ الْقَدَحَ فَشَرِبَ وَعَنْ يَسَارِهِ أَبُو بَكْرٍ وَعَنْ يَمِينِهِ أَعْرَابِيٌّ فَأَعْطَى الْأَعْرَابِيَّ فَضْلَهُ ثُمَّ قَالَ الْأَيْمَنَ فَالْأَيْمَنَ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Anas bin Malik] radliallahu 'anhu bahwa dia melihat Rasulullah shallallahu 'alaihi wasallam meminum susu, lalu beliau memasuki rumahnya, kemudian aku memeras susu kambing untuk Rasulullah shallallahu 'alaihi wasallam yang aku campur dengan air dari sumur, setelah itu beliau mengambil mangkuk tersebut dan meminumnya sementara di samping kiri beliau terdapat Abu Bakar dan di samping kanannya seorang arab badui, namun beliau memberikan sisanya kepada arab badui sambil bersabda: \"Yang kanan dan kanan.\""},"4877":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ سَعِيدِ بْنِ الْحَارِثِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى رَجُلٍ مِنْ الْأَنْصَارِ وَمَعَهُ صَاحِبٌ لَهُ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَ عِنْدَكَ مَاءٌ بَاتَ هَذِهِ اللَّيْلَةَ فِي شَنَّةٍ وَإِلَّا كَرَعْنَا قَالَ وَالرَّجُلُ يُحَوِّلُ الْمَاءَ فِي حَائِطِهِ قَالَ فَقَالَ الرَّجُلُ يَا رَسُولَ اللَّهِ عِنْدِي مَاءٌ بَائِتٌ فَانْطَلِقْ إِلَى الْعَرِيشِ قَالَ فَانْطَلَقَ بِهِمَا فَسَكَبَ فِي قَدَحٍ ثُمَّ حَلَبَ عَلَيْهِ مِنْ دَاجِنٍ لَهُ قَالَ فَشَرِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ شَرِبَ الرَّجُلُ الَّذِي جَاءَ مَعَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Abu 'Amir] telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Sa'id bin Al harits] dari [Jabir bin Abdullah] radliallahu 'anhuma bahwa Nabi shallallahu 'alaihi wasallam bersama sahabat beliau pernah mendatangi seorang laki-laki dari Anshar. Lalu Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Apakah kamu memiliki air yang tersisa malam ini dalam griba, jika tidak kami akan menghirupnya secara langsung.\" Jabir bin Abdullah berkata; laki-laki itu sedang membenahi saluran airnya ke kebunnya, Jabir melanjutkan; lalu laki-laki Anshar tersebut berkata; \"Wahai Rasulullah, saya masih memiliki air yang tersisa malam ini, mari kita menuju tenda.\" Abdullah berkata; \"Lalu beliau pergi bersamanya dan menuangkan air kedalam mangkuk, kemudian dia juga memerahkan susu dari kambing piaraannya, Jabir melanjutkan; \"Lantas Rasulullah shallallahu 'alaihi wasallam meminumnya begitu juga dengan sahabat yang datang bersama beliau.\" "},"4878":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ أَخْبَرَنِي هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْجِبُهُ الْحَلْوَاءُ وَالْعَسَلُ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Abu Usamah] dia berkata; telah mengabarkan kepadaku [Hisyam] dari [ayahnya] dari [Aisyah] radliallahu 'anha dia berkata; bahwa Nabi shallallahu 'alaihi wasallam sangat menyukai manisan dan madu.\""},"4879":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مِسْعَرٌ عَنْ عَبْدِ الْمَلِكِ بْنِ مَيْسَرَةَ عَنْ النَّزَّالِ قَالَ أَتَى عَلِيٌّ رَضِيَ اللَّهُ عَنْهُعَلَى بَابِ الرَّحَبَةِ فَشَرِبَ قَائِمًا فَقَالَ إِنَّ نَاسًا يَكْرَهُ أَحَدُهُمْ أَنْ يَشْرَبَ وَهُوَ قَائِمٌ وَإِنِّي رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَ كَمَا رَأَيْتُمُونِي فَعَلْتُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Mis'ar] dari [Abdul Malik bin Maisarah] dari [An Nazal] dia berkata; [Ali] radliallahu 'anhu pernah datang dan berdiri di depan pintu rahbah, lalu dia minum sambil berdiri setelah itu dia berkata; \"Sesungguhnya orang-orang merasa benci bila salah seorang dari kalian minum sambil berdiri, padahal aku pernah melihat Nabi shallallahu 'alaihi wasallam melakukannya sebagaimana kalian melihatku saat ini.\""},"4880":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ مَيْسَرَةَ سَمِعْتُ النَّزَّالَ بْنَ سَبْرَةَ يُحَدِّثُ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُأَنَّهُ صَلَّى الظُّهْرَ ثُمَّ قَعَدَ فِي حَوَائِجِ النَّاسِ فِي رَحَبَةِ الْكُوفَةِ حَتَّى حَضَرَتْ صَلَاةُ الْعَصْرِ ثُمَّ أُتِيَ بِمَاءٍ فَشَرِبَ وَغَسَلَ وَجْهَهُ وَيَدَيْهِ وَذَكَرَ رَأْسَهُ وَرِجْلَيْهِ ثُمَّ قَامَ فَشَرِبَ فَضْلَهُ وَهُوَ قَائِمٌ ثُمَّ قَالَ إِنَّ نَاسًا يَكْرَهُونَ الشُّرْبَ قِيَامًا وَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَنَعَ مِثْلَ مَا صَنَعْتُ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abdul Malik bin Maisarah] saya mendengar [An Nazzal bin Sabrah] bercerita dari [Ali] radliallahu 'anhu bahwa setelah melaksanakan shalat zhuhur dia duduk untuk memenuhi kebutuhan orang-orang di Rahbah sampai tiba shalat ashar, kemudian ia diberi air dan meminumnya, selebihnya ia gunakan untuk membasuh mukanya, wajahnya, kedua tangannya -perawi juga menyebutkan kepala dan kedua kakinya- lalu dia berdiri dan meminum sisa (air wudlu'nya) sambil berdiri, kemudian dia berkata; Sesungguhnya orang-orang merasa tidak suka minum sambil berdiri, padahal Nabi shallallahu 'alaihi wasallam pernah melakukan sebagaimana yang aku perbuat saat ini.\""},"4881":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ الْأَح��وَلِ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَشَرِبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمًا مِنْ زَمْزَمَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari ['Ashim Al Ahwal] dari [As Sya'bi] dari [Ibnu Abbas] dia berkata; Nabi shallallahu 'alaihi wasallam pernah minum air dari zamzam sambil berdiri.\""},"4882":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ أَخْبَرَنَا أَبُو النَّضْرِ عَنْ عُمَيْرٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ أُمِّ الْفَضْلِ بِنْتِ الْحَارِثِأَنَّهَا أَرْسَلَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَدَحِ لَبَنٍ وَهُوَ وَاقِفٌ عَشِيَّةَ عَرَفَةَ فَأَخَذَ بِيَدِهِ فَشَرِبَهُزَادَ مَالِكٌ عَنْ أَبِي النَّضْرِ عَلَى بَعِيرِهِ","id":"Telah menceritakan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Abdul Aziz bin Salamah] telah mengabarkan kepada kami [Abu An Nadlr] dari ['Umair] bekas budak Ibnu Abbas, dari [Ummu Fadl binti Al Harits] bahwa dia pernah mengirim semangkuk susu kepada Nabi shallallahu 'alaihi wasallam ketika beliau sedang berhenti di 'Arafah, lalu beliau mengambilnya dan meminumnya.\" [Malik] menambahkan dari [Abu An Nadlar] \" di atas untanya\"."},"4883":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِلَبَنٍ قَدْ شِيبَ بِمَاءٍ وَعَنْ يَمِينِهِ أَعْرَابِيٌّ وَعَنْ شِمَالِهِ أَبُو بَكْرٍ فَشَرِبَ ثُمَّ أَعْطَى الْأَعْرَابِيَّ وَقَالَ الْأَيْمَنَ فَالْأَيْمَنَ","id":"Telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Anas bin Malik] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam pernah diberi susu yang dicampur dengan air, sementara di sebelah kanan beliau terdapat arab badui dan di sebelah kiri beliau adalah Abu Bakar, kemudian beliau meminum susu tersebut dan memberikan sisanya kepada arab badui sambil bersabda: \"Yang kanan dan kanan.\""},"4884":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي حَازِمِ بْنِ دِينَارٍ عَنْ سَهْلِ بْنِ سَعْدٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِشَرَابٍ فَشَرِبَ مِنْهُ وَعَنْ يَمِينِهِ غُلَامٌ وَعَنْ يَسَارِهِ الْأَشْيَاخُ فَقَالَ لِلْغُلَامِ أَتَأْذَنُ لِي أَنْ أُعْطِيَ هَؤُلَاءِ فَقَالَ الْغُلَامُ وَاللَّهِ يَا رَسُولَ اللَّهِ لَا أُوثِرُ بِنَصِيبِي مِنْكَ أَحَدًا قَالَ فَتَلَّهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَدِهِ","id":"Telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Malik] dari [Abu Hazim bin Dinar] dari [Sahl bin Sa'd] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam pernah diberi minuman lalu beliau meminumnya, sementara di sebelah kanan beliau terdapat anak muda dan sebelah kiri beliau orang-orang tua, lalu beliau bersabda kepada anak muda: \"Apakah kamu mengizinkan aku untuk memberi sisanya kepada mereka?\" maka anak muda itu menjawab; \"Demi Allah wahai Rasulullah, aku tidak akan memberikan bagianku dari sisamu kepada seorangpun.\" Sahl berkata; \"lantas Rasulullah shallallahu 'alaihi wasallam memberikan pada tangannya.\""},"4885":{"ar":"حَدَّثَنَا يَحْيَى بْنُ صَالِحٍ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ سَعِيدِ بْنِ الْحَارِثِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى رَجُلٍ مِنْ الْأَنْصَارِ وَمَعَهُ صَاحِبٌ لَهُ فَسَلَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَاحِبُهُ فَرَدَّ الرَّجُلُ فَقَالَ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي وَهِيَ سَاعَةٌ حَارَّةٌ وَهُوَ يُحَوِّلُ فِي حَائِطٍ لَهُ يَعْنِي الْمَاءَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَ عِنْدَكَ مَاءٌ بَاتَ فِي شَنَّةٍ وَإِلَّا كَرَعْنَا وَالرَّجُلُ يُحَوِّلُ الْمَاءَ فِي حَائِطٍ فَقَالَ الرَّجُلُ يَا رَسُولَ اللَّهِ عِنْدِي مَاءٌ بَاتَ فِي شَنَّةٍ فَانْطَلَقَ إِلَى الْعَرِيشِ فَسَكَبَ فِي قَدَحٍ مَاءً ثُمَّ حَلَبَ عَلَيْهِ مِنْ دَاجِنٍ لَهُ فَشَرِبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَعَادَ فَشَرِبَ الرَّجُلُ الَّذِي جَاءَ مَعَهُ","id":"Telah menceritakan kepada kami [Yahya bin Shalih] telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Sa'id bin Al Harits] dari [Jabir bin Abdullah] radliallahu 'anhuma bahwa Nabi shallallahu 'alaihi wasallam menemui seorang laki-laki Anshar, waktu itu beliau bersama salah seorang sahabatnya, lalu Nabi shallallahu 'alaihi wasallam dan sahabat yang menyertainya memberi salam kepada laki-laki Anshar tersebut, laki-laki itu pun menjawab salam beliau dan berkata; \"Wahai Rasulullah, demi ayah dan ibumu, ini adalah hari yang sangat panas -sementara laki-laki Anshar itu sedang membenahi saluran air di kebunnya, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah kamu memiliki air yang tersisa malam ini dalam griba, jika tidak kami akan menghirupnya langsung (dari saluran air tersebut) \" -sementara laki-laki itu masih membenahi saluran air di kebunnya-, maka laki-laki Anshar itu berkata; \"Wahai Rasulullah, saya masih memiliki air yang tersisa malam ini dalam griba, kemudian ia menuju tendanya dan menuangkan air ke dalam mangkuk, kemudian dia juga memerahkan susu dari kambing piaraannya, lalu Rasulullah shallallahu 'alaihi wasallam meminumnya beliau pun mengulanginya lagi, begitu juga dengan sahabat yang datang bersama beliau turut meminumnya.\""},"4886":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ قَالَ سَمِعْتُ أَنَسًا رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ قَائِمًا عَلَى الْحَيِّ أَسْقِيهِمْ عُمُومَتِي وَأَنَا أَصْغَرُهُمْ الْفَضِيخَ فَقِيلَ حُرِّمَتْ الْخَمْرُ فَقَالَ اكْفِئْهَا فَكَفَأْنَا قُلْتُ لِأَنَسٍ مَا شَرَابُهُمْ قَالَ رُطَبٌ وَبُسْرٌ فَقَالَ أَبُو بَكْرِ بْنُ أَنَسٍ وَكَانَتْ خَمْرَهُمْ فَلَمْ يُنْكِرْ أَنَسٌ وَحَدَّثَنِي بَعْضُ أَصْحَابِي أَنَّهُ سَمِعَ أَنَسًا يَقُولُ كَانَتْ خَمْرَهُمْ يَوْمَئِذٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Mu'tamir] dari [ayahnya] dia berkata; saya mendengar [Anas] radliallahu 'anhu berkata; aku pernah menjadi pelayan di suatu daerah yang bertugas menuangkan minuman al fadlih (minuman keras yang terbuat dari kurma) kepada para pamanku, sedangkan aku adalah orang yang paling muda di antara mereka, tiba-tiba di beritahukan bahwa khamr telah di haramkan, maka dia (salah seorang pamanku) berkata; \"Tumpahkanlah ia.\" Aku pun langsung menumpahkannya, \" aku bertanya kepada Anas; \"Apakah minuman mereka saat itu?\" dia menjawab; \"yaitu minuman (keras) yang terbuat dari ruthab (kurma basah) dan busr (kurma muda).\" Abu Bakar bin Anas berkata; \"Itulah khamr mereka saat itu, dan Anas tidak mengingkarinya.\" Dan sebagian dari sahabatku juga pernah menceritakan kepadaku bahwa dia pernah mendengar Anas berkata; \"Dan saat itu khamr mereka terbuat dari jenis itu.\""},"4887":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ أَخْبَرَنَا رَوْحُ بْنُ عُبَادَةَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ جُنْحُ اللَّيْلِ أَوْ أَمْسَيْتُمْ فَكُفُّوا صِبْيَانَكُمْ فَإِنَّ الشَّيَاطِينَ تَنْتَشِرُ حِينَئِذٍ فَإِذَا ذَهَبَ سَاعَةٌ مِنْ اللَّيْلِ فَحُلُّوهُمْ فَأَغْلِقُوا الْأَبْوَابَ وَاذْكُرُوا اسْمَ اللَّهِ فَإِنَّ الشَّيْطَانَ لَا يَفْتَحُ بَابًا مُغْلَقًا وَأَوْكُوا قِرَبَكُمْ وَاذْكُرُوا اسْمَ اللَّهِ وَخَمِّرُوا آنِيَتَكُمْ وَاذْكُرُوا اسْمَ اللَّهِ وَلَوْ أَنْ تَعْرُضُوا عَلَيْهَا شَيْئًا وَأَطْفِئُوا مَصَابِيحَكُمْ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Rauh bin 'Ubadah] telah mengabarkan kepada kami [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku ['Atha'] bahwa dia mendengar [Jabir bin Abdullah] radliallahu 'anhuma berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila hari mulai malam atau malam telah tiba, maka tahanlah anak-anak kalian, karena saat itu syetan berkeliaran, apabila malam sudah mulai larut maka lepaskanlah mereka dan tutuplah pintu-pintu rumah kalian dan sebutlah nama Allah, karena syetan tidak mampu membuka pintu yang tertutup, dan tutuplah tempat air minum kalian sambil menyebut nama Allah dan tutup pula wadah-wadah kalian sambil menyebut nama Allah walaupun hanya dengan sesuatu yang dapat menutupinya dan matikanlah lampu-lampu kalian.\""},"4888":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا هَمَّامٌ عَنْ عَطَاءٍ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَطْفِئُوا الْمَصَابِيحَ إِذَا رَقَدْتُمْ وَغَلِّقُوا الْأَبْوَابَ وَأَوْكُوا الْأَسْقِيَةَ وَخَمِّرُوا الطَّعَامَ وَالشَّرَابَ وَأَحْسِبُهُ قَالَ وَلَوْ بِعُودٍ تَعْرُضُهُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammam] dari ['Atha`] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Matikanlah lampu-lampu kalian apabila kalian hendak tidur, dan tutuplah pintu rumah kalian, tutuplah wadah-wadah kalian serta tutup pula tempat makan dan tempat minum kalian -aku mengira beliau juga bersabda- walaupun hanya dengan sepotong kayu yang dapat menutupinya.\""},"4889":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ اخْتِنَاثِ الْأَسْقِيَةِ يَعْنِي أَنْ تُكْسَرَ أَفْوَاهُهَا فَيُشْرَبَ مِنْهَا","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Abu Sa'id Al Khudri] radliallahu 'anhu dia berkata; Rasulullah shallallahu 'alaihi wasallam melarang meminum langsung dari mulut geribah (ngokop -jawa) yaitu dengan memecahkan sedikit mulut geribah lalu meminum langsung darinya.\""},"4890":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ اخْتِنَاثِ الْأَسْقِيَةِقَالَ عَبْدُ اللَّهِ قَالَ مَعْمَرٌ أَوْ غَيْرُهُ هُوَ الشُّرْبُ مِنْ أَفْوَاهِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Muqattil] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] dia berkata; telah menceritakan kepadaku ['Ubaidullah bin Abdullah] bahwa dia mendengar [Abu Sa'id Al Khudri] berkata; saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam melarang minum langsung dari geribah (tempat air minum).\" Abdullah mengatakan; Ma'mar dan yang lain mengatakan yaitu minum air langsung dari mulut geribah.\""},"4891":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَيُّوبُ قَالَ لَنَا عِكْرِمَةُأَلَا أُخْبِرُكُمْ بِأَشْيَاءَ قِصَارٍ حَدَّثَنَا بِهَا أَبُو هُرَيْرَةَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الشُّرْبِ مِنْ فَمِ الْقِرْبَةِ أَوْ السِّقَاءِ وَأَنْ يَمْنَعَ جَارَهُ أَنْ يَغْرِزَ خَشَبَهُ فِي دَارِهِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Ayyub], [Ikrimah] pernah berkata kepada kami; \"Maukah aku beritahukan kepada kalian sesuatu yang singkat yang pernah diceritakan oleh [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam melarang minum langsung dari mulut geribah atau tempat air minum dan hendaklah seseorang melarang tetangganya menyandarkan kayu di rumahnya.\""},"4892":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُشْرَبَ مِنْ فِي السِّقَاءِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Isma'il] telah mengabarkan kepada kami [Ayyub] dari [Ikrimah] dari [Abu Hurairah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam melarang seseorang minum langsung dari mulut geribah.\""},"4893":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الشُّرْبِ مِنْ فِي السِّقَاءِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Khalid] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; Nabi shallallahu 'alaihi wasallam melarang seseorang minum langsung dari mulut geribah.\""},"4894":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا شَرِبَ أَحَدُكُمْ فَلَا يَتَنَفَّسْ فِي الْإِنَاءِ وَإِذَا بَالَ أَحَدُكُمْ فَلَا يَمْسَحْ ذَكَرَهُ بِيَمِينِهِ وَإِذَا تَمَسَّحَ أَحَدُكُمْ فَلَا يَتَمَسَّحْ بِيَمِينِهِ","id":"Telah menceritakan kepada kami [Nu'aim] telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abdullah bin Abu Qatadah] dari [Ayahnya] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian minum, maka janganlah bernafas di tempat air minum tersebut, dan apabila salah seorang dari kalian kencing maka janganlah menyentuh kemaluannya dengan tangan kanan, namun apabila salah seorang dari kalian harus menyentuhnya, hendaknya tidak menyentuh dengan tangan kanannya.\""},"4895":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ وَأَبُو نُعَيْمٍ قَالَا حَدَّثَنَا عَزْرَةُ بْنُ ثَابِتٍ قَالَ أَخْبَرَنِي ثُمَامَةُ بْنُ عَبْدِ اللَّهِ قَالَ كَانَ أَنَسٌيَتَنَفَّسُ فِي الْإِنَاءِ مَرَّتَيْنِ أَوْ ثَلَاثًا وَزَعَمَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَنَفَّسُ ثَلَاثًا","id":"Telah menceritakan kepada kami [Abu 'Ashim] dan [Abu Nu'aim] keduanya berkata; telah menceritakan kepada kami [Azrah bin Tsabit] dia berkata; telah mengabarkan kepadaku [Tsumamah bin Abdullah] dia berkata; bahwa [Anas] biasa bernafas dalam tempat air minum sebanyak dua kali atau tiga kali, dan dia mengira bahwa Nabi shallallahu 'alaihi wasallam juga bernafas tiga kali (ketika minum).\""},"4896":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ابْنِ أَبِي لَيْلَى قَالَ كَانَ حُذَيْفَةُ بِالْمَدَايِنِفَاسْتَسْقَى فَأَتَاهُ دِهْقَانٌ بِقَدَحِ فِضَّةٍ فَرَمَاهُ بِهِ فَقَالَ إِنِّي لَمْ أَرْمِهِ إِلَّا أَنِّي نَهَيْتُهُ فَلَمْ يَنْتَهِ وَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا عَنْ الْحَرِيرِ وَالدِّيبَاجِ وَالشُّرْبِ فِي آنِيَةِ الذَّهَبِ وَالْفِضَّةِ وَقَالَ هُنَّ لَهُمْ فِي الدُّنْيَا وَهِيَ لَكُمْ فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibnu Abu Laila] dia berkata; Ketika [Hudzaifah] di Madayin (Mada`in), dia pernah meminta air untuk minum, lalu Dihqan memberinya air minum di dalam bejana yang terbuat dari perak, maka ia membuangnya sambil berkata; \"Sesungguhnya aku tidak bermaksud membuangnya melainkan aku telah melarangnya (menggunakan tempat yang terbuat dari perak) namun tetap saja ia menggunakannya, sesungguhnya Nabi shallallahu 'alaihi wasallam melarang kami memakai kain sutera, dibaj (sejenis sutera) dan tempat minum yang terbuat dari emas dan perak, beliau bersabda: \"Itu semua untuk mereka (orang kafir) di dunia, dan untuk kalian di akhirat kelak.\""},"4897":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ عَوْنٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ أَبِي لَيْلَى قَالَ خَرَجْنَا مَعَ حُذَيْفَةَوَذَكَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَشْرَبُوا فِي آنِيَةِ الذَّهَبِ وَالْفِضَّةِ وَلَا تَلْبَسُوا الْحَرِيرَ وَالدِّيبَاجَ فَإِنَّهَا لَهُمْ فِي الدُّنْيَا وَلَكُمْ فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Mutsanna] telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Ibnu 'Aun] dari [Mujahid] dari [Ibnu Abu Laila] dia berkata; kami pernah bepergian bersama [Hudzaifah], lalu dia menyebutkan perihal Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kalian minum dari tempat yang terbuat emas dan perak dan janganlah kalian menggunakan kain sutera dan dibaj (sejenis sutera), karena itu semua untuk mereka (orang-orang kafir) di dunia dan untuk kalian di akhirat kelak.\""},"4898":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكُ بْنُ أَنَسٍ عَنْ نَافِعٍ عَنْ زَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ الصِّدِّيقِ عَنْ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الَّذِي يَشْرَبُ فِي إِنَاءِ الْفِضَّةِ إِنَّمَا يُجَرْجِرُ فِي بَطْنِهِ نَارَ جَهَنَّمَ","id":"Telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Malik bin Anas] dari [Nafi'] dari [Zaid bin Abdullah bin Umar] dari [Abdullah bin Abdurrahman bin Abu Bakr As Siddik] dari [Ummu Salamah isteri Nabi shallallahu 'alaihi wasallam] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang minum dari bejana yang terbuat dari perak, hanyasanya ia menuangkan neraka Jahannam ke dalam perutnya.\""},"4899":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَشْعَثِ بْنِ سُلَيْمٍ عَنْ مُعَاوِيَةَ بْنِ سُوَيْدِ بْنِ مُقَرِّنٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَبْعٍ وَنَهَانَا عَنْ سَبْعٍ أَمَرَنَا بِعِيَادَةِ الْمَرِيضِ وَاتِّبَاعِ الْجِنَازَةِ وَتَشْمِيتِ الْعَاطِسِ وَإِجَابَةِ الدَّاعِي وَإِفْشَاءِ السَّلَامِ وَنَصْرِ الْمَظْلُومِ وَإِبْرَارِ الْمُقْسِمِ وَنَهَانَا عَنْ خَوَاتِيمِ الذَّهَبِ وَعَنْ الشُّرْبِ فِي الْفِضَّةِ أَوْ قَالَ آنِيَةِ الْفِضَّةِ وَعَنْ الْمَيَاثِرِ وَالْقَسِّيِّ وَعَنْ لُبْسِ الْحَرِيرِ وَالدِّيبَاجِ وَالْإِسْتَبْرَقِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] dari [Al Asy'ats bin Sulaim] dari [Mu'awiyah bin Suwaid bin Muqarrin] dari [Al Barra` bin Azib] dia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kami tujuh perkara dan melarang tujuh perkara, beliau memerintahkan untuk menjenguk orang sakit, mengiringi jenazah, mendo'akan orang yang bersin, memenuhi undangan, menyebarkan salam, menolong orang yang terzhalimi dan melaksanakan sumpah, dan melarang kami memakai cincin dari emas, minum dari bejana yang terbuat dari perak, mayasir, qasiy, harir, dibaj dan istabraq (semua jenis pakaian yang terbuat dari sutera atau campuran sutera).\""},"4900":{"ar":"حَدَّثَنِي عَمْرُو بْنُ عَبَّاسٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ سَالِمٍ أَبِي النَّضْرِ عَنْ عُمَيْرٍ مَوْلَى أُمِّ الْفَضْلِ عَنْ أُمِّ الْفَضْلِأَنَّهُمْ شَكُّوا فِي صَوْمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ عَرَفَةَ فَبَعَثَتْ إِلَيْهِ بِقَدَحٍ مِنْ لَبَنٍ فَشَرِبَهُ","id":"Telah menceritakan kepada kami ['Amru bin Abbas] telah menceritakan kepada kami [Abdurrahman] telah menceritakan kepada kami [Sufyan] dari [Salim Abu An Nadlr] dari ['Umair] bekas budak Ummu Fadl, dari [Ummu Fadl] bahwa orang-orang ragu-ragu mengenai puasa Nabi shallallahu 'alaihi wasallam di hari 'Arafah, lantas Ummu Fadl mengirimkan semangkuk susu untuk beliau, lalu beliau meminumnya.\""},"4901":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَذُكِرَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْرَأَةٌ مِنْ الْعَرَبِ فَأَمَرَ أَبَا أُسَيْدٍ السَّاعِدِيَّ أَنْ يُرْسِلَ إِلَيْهَا فَأَرْسَلَ إِلَيْهَا فَقَدِمَتْ فَنَزَلَتْ فِي أُجُمِ بَنِي سَاعِدَةَ فَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى جَاءَهَا فَدَخَلَ عَلَيْهَا فَإِذَا امْرَأَةٌ مُنَكِّسَةٌ رَأْسَهَا فَلَمَّا كَلَّمَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ أَعُوذُ بِاللَّهِ مِنْكَ فَقَالَ قَدْ أَعَذْتُكِ مِنِّي فَقَالُوا لَهَا أَتَدْرِينَ مَنْ هَذَا قَالَتْ لَا قَالُوا هَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ لِيَخْطُبَكِ قَالَتْ كُنْتُ أَنَا أَشْقَى مِنْ ذَلِكَ فَأَقْبَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ حَتَّى جَلَسَ فِي سَقِيفَةِ بَنِي سَاعِدَةَ هُوَ وَأَصْحَابُهُ ثُمَّ قَالَ اسْقِنَا يَا سَهْلُ فَخَرَجْتُ لَهُمْ بِهَذَا الْقَدَحِ فَأَسْقَيْتُهُمْ فِيهِ فَأَخْرَجَ لَنَا سَهْلٌ ذَلِكَ الْقَدَحَ فَشَرِبْنَا مِنْهُ قَالَ ثُمَّ اسْتَوْهَبَهُ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ بَعْدَ ذَلِكَ فَوَهَبَهُ لَهُ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] telah menceritakan kepada kami [Abu Ghassan] dia berkata; telah menceritakan kepadaku [Abu Hazim] dari [Sahl bin Sa'd] radliallahu 'anhu dia berkata; \"Ketika dituturkan kepada Rasulullah shallallahu 'alaihi wasallam tentang cerita seorang wanita Arab, maka beliau pun memerintahkan Abu Usaid untuk memanggilnya. Tidak lama kemudian wanita itu datang dan tinggal di tempat yang bagus milik Bani Sa'idah. Lalu Rasulullah shallallahu 'alaihi wasallam keluar hingga menemui wanita tersebut, beliau masuk ke rumah tersebut, dan ternyata wanita itu selalu menundukkan kepalanya. Pada saat Rasulullah shallallahu 'alaihi wasallam mengajaknya bicara, wanita itu justru berkata; \"Saya berlindung kepada Allah darimu.\" Beliau menjawab: \"Baiklah, saya juga melindungimu dariku.\" Setelah itu para sahabat berkata kepadanya; \"Tahukah kamu siapakah orang ini?\" wanita itu menjawab; \"Tidak.\" Para sahabat berkata; \"Orang itu adalah Rasulullah shallallahu 'alaihi wasallam, beliau datang untuk melamarmu.\" Wanita itu berkata; \"Kalau begitu, saya termasuk orang yang tidak beruntung.\" Lalu Nabi shallallahu 'alaihi wasallam kembali dan duduk di bangsa Bani Sa'idah bersama dengan para sahabatnya. Kemudian beliau bersabda: \"Tuangkanlah kepada kami minuman wahai Sahal.\" Lalu saya mengeluarkan mangkuk ini untuk mereka dan memberikan minuman kepada mereka dengan menggunakan mangkuk tersebut.\" -Setelah itu Sahl mengeluarkan mangkuk tersebut untuk kami dan kami pun meminum air darinya.\" Abu Hazim berkata; \"Selang beberapa tahun kemudian, Umar bin Abdul Aziz meminta mangkuk itu, maka mangkuk tersebut di berikan kepadanya.\""},"4902":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُدْرِكٍ قَالَ حَدَّثَنِي يَحْيَى بْنُ حَمَّادٍ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ عَاصِمٍ الْأَحْوَلِ قَالَرَأَيْتُ قَدَحَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ أَنَسِ بْنِ مَالِكٍ وَكَانَ قَدْ انْصَدَعَ فَسَلْسَلَهُ بِفِضَّةٍ قَالَ وَهُوَ قَدَحٌ جَيِّدٌ عَرِيضٌ مِنْ نُضَارٍ قَالَ قَالَ أَنَسٌ لَقَدْ سَقَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْقَدَحِ أَكْثَرَ مِنْ كَذَا وَكَذَا قَالَ وَقَالَ ابْنُ سِيرِينَ إِنَّهُ كَانَ فِيهِ حَلْقَةٌ مِنْ حَدِيدٍ فَأَرَادَ أَنَسٌ أَنْ يَجْعَلَ مَكَانَهَا حَلْقَةً مِنْ ذَهَبٍ أَوْ فِضَّةٍ فَقَالَ لَهُ أَبُو طَلْحَةَ لَا تُغَيِّرَنَّ شَيْئًا صَنَعَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَرَكَهُ","id":"Telah menceritakan kepada kami [Al Hasan bin Al Mudrik] dia berkata; telah menceritakan kepadaku [Yahya bin Hammad] telah mengabarkan kepada kami [Abu 'Awanah] dari ['Ashim bin Al Ahwal] dia berkata; aku pernah melihat mangkuk nabi shallallahu 'alaihi wasallam ada pada [Anas bin Malik], sedangkan mangkuk tersebut telah retak, lalu dia menyambungnya dengan perak, Anas berkata; \"Mangkuk itu adalah mangkuk yang sangat bagus yang terbuat dari kayu pilihan, 'Ashim melanjutkan; Anas berkata; Sungguh aku telah menuangkan (minuman) kepada Rasulullah shallallahu 'alaihi wasallam dengan mangkuk tersebut hingga sekian kali. Perawi berkata; Ibnu Sirin mengatakan; bahwa mangkuk tersebut terdapat rantai yang terbuat dari besi, lalu Anas hendak menggantinya dengan rantai yang terbuat dari emas atau perak, maka Abu Thalhah berkata kepadanya; \"Janganlah kamu merubah sesuatu yang telah di buat oleh Rasulullah shallallahu 'alaihi wasallam.\" Anas pun membiarkan seperti itu.\""},"4903":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ قَالَ حَدَّثَنِي سَالِمُ بْنُ أَبِي الْجَعْدِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا هَذَا الْحَدِيثَ قَالَقَدْ رَأَيْتُنِي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ حَضَرَتْ الْعَصْرُ وَلَيْسَ مَعَنَا مَاءٌ غَيْرَ فَضْلَةٍ فَجُعِلَ فِي إِنَاءٍ فَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهِ فَأَدْخَلَ يَدَهُ فِيهِ وَفَرَّجَ أَصَابِعَهُ ثُمَّ قَالَ حَيَّ عَلَى أَهْلِ الْوُضُوءِ الْبَرَكَةُ مِنْ اللَّهِ فَلَقَدْ رَأَيْتُ الْمَاءَ يَتَفَجَّرُ مِنْ بَيْنِ أَصَابِعِهِ فَتَوَضَّأَ النَّاسُ وَشَرِبُوا فَجَعَلْتُ لَا آلُوا مَا جَعَلْتُ فِي بَطْنِي مِنْهُ فَعَلِمْتُ أَنَّهُ بَرَكَةٌ قُلْتُ لِجَابِرٍ كَمْ كُنْتُمْ يَوْمَئِذٍ قَالَ أَلْفًا وَأَرْبَعَ مِائَةٍتَابَعَهُ عَمْرُو بْنُ دِينَارٍ عَنْ جَابِرٍ وَقَالَ حُصَيْنٌ وَعَمْرُو بْنُ مُرَّةَ عَنْ سَالِمٍ عَنْ جَابِرٍ خَمْسَ عَشْرَةَ مِائَةً وَتَابَعَهُ سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ جَابِرٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dia berkata; telah menceritakan kepadaku [Salim bin Abu Al Ja'd] dari [Jabir bin Abdullah] radliallahu 'anhuma tentang hadits ini, dia berkata; \"Sungguh aku pernah bersama Nabi shallallahu 'alaihi wasallam, ketika itu waktu shalat Ashar telah tiba sedangkan kami tidak memiliki persediaan air kecuali hanya sedikit, lalu air tersebut ditaruh ke dalam wadah dan diberikan kepada Nabi shallallahu 'alaihi wasallam, setelah itu beliau memasukkan tangan beliau ke dalam wadah tersebut sambil meregangkan jari jemarinya kemudian beliau bersabda: \"Mari berwudlu' untuk mendapatkan keberkahan dari Allah.\" Sungguh aku melihat air memancar dari jari-jemari beliau, orang-orang pun bergegas melakukan wudlu sambil minum, dan aku pun bergegas untuk mengenyangkan perutku dengan air tersebut karena aku tahu kalau air itu sarat dengan keberkahan.\" Kataku kepada Jabir; \"Berapakah jumlah kalian waktu itu?\" dia menjawab; \"seribu empat ratus personil\" hadits ini juga di perkuat oleh riwayat ['Amru bin Dinar] dari [Jabir], sementara [Hushain] dan ['Amru bin Murrah] mengatakan dari [Salim] dari [Jabir] sebanyak seribu lima ratus personil, hadits ini juga di perkuat pula oleh riwayat [Sa'id bin Musayyib] dari [Jabir].\""},"4904":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مُصِيبَةٍ تُصِيبُ الْمُسْلِمَ إِلَّا كَفَّرَ اللَّهُ بِهَا عَنْهُ حَتَّى الشَّوْكَةِ يُشَاكُهَا","id":"Telah menceritakan kepada kami [Abu Al Yaman Al Hakam bin Nafi'] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Urwah bin Az Zubair] bahwa [Aisyah] radliallahu 'anha isteri Nabi shallallahu 'alaihi wasallam berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah suatu musibah yang menimpa seorang muslim bahkan duri yang melukainya sekalipun melainkan Allah akan menghapus (kesalahannya).\""},"4905":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا زُهَيْرُ بْنُ مُحَمَّدٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَلْحَلَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ وَعَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا يُصِيبُ الْمُسْلِمَ مِنْ نَصَبٍ وَلَا وَصَبٍ وَلَا هَمٍّ وَلَا حُزْنٍ وَلَا أَذًى وَلَا غَمٍّ حَتَّى الشَّوْكَةِ يُشَاكُهَا إِلَّا كَفَّرَ اللَّهُ بِهَا مِنْ خَطَايَاهُ","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] telah menceritakan kepada kami [Abdul Malik bin 'Amru] telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Muhammad bin 'Amru bin Halhalah] dari ['Atha` bin Yasar] dari [Abu Sa'id Al Khudri] dan dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidaklah seorang muslim tertimpa suatu penyakit dan keletihan, kehawatiran dan kesedihan, dan tidak juga gangguan dan kesusahan bahkan duri yang melukainya melainkan Allah akan menghapus kesalahan-kesalahannya.\""},"4906":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ سَعْدٍ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الْمُؤْمِنِ كَالْخَامَةِ مِنْ الزَّرْعِ تُفَيِّئُهَا الرِّيحُ مَرَّةً وَتَعْدِلُهَا مَرَّةً وَمَثَلُ الْمُنَافِقِ كَالْأَرْزَةِ لَا تَزَالُ حَتَّى يَكُونَ انْجِعَافُهَا مَرَّةً وَاحِدَةًوَقَالَ زَكَرِيَّاءُ حَدَّثَنِي سَعْدٌ حَدَّثَنَا ابْنُ كَعْبٍ عَنْ أَبِيهِ كَعْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] dari [Sa'd] dari [Abdullah bin Ka'b] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Permisalan seorang mukmin seperti dahan di suatu pohon, terkadang angin menjadikannya bengkok dan terkadang berdiri, lurus. Sebaliknya permisalan orang munafik seperti tanaman padi yang senantiasa berdiri, hingga sekali ia jatuh, ia akan langsung roboh.\" [Zakariya] mengatakan; telah menceritakan kepadaku [Sa'd] telah menceritakan kepada kami [Ibnu Ka'b] dari ayahnya [Ka'b] dari Nabi shallallahu 'alaihi wasallam."},"4907":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ فُلَيْحٍ قَالَ حَدَّثَنِي أَبِي عَنْ هِلَالِ بْنِ عَلِيٍّ مِنْ بَنِي عَامِرِ بْنِ لُؤَيٍّ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْمُؤْمِنِ كَمَثَلِ الْخَامَةِ مِنْ الزَّرْعِ مِنْ حَيْثُ أَتَتْهَا الرِّيحُ كَفَأَتْهَا فَإِذَا اعْتَدَلَتْ تَكَفَّأُ بِالْبَلَاءِ وَالْفَاجِرُ كَالْأَرْزَةِ صَمَّاءَ مُعْتَدِلَةً حَتَّى يَقْصِمَهَا اللَّهُ إِذَا شَاءَ","id":"Telah menceritakan kepada kami [Ibrahim bin Mundzir] dia berkata; telah menceritakan kepadaku [Muhammad bin Fulaih] dia berkata; telah menceritakan kepadaku [Ayahku] dari [Hilal bin Ali] penduduk dari Bani 'Amir bin Lu`ai, dari ['Atha` bin Yasar] dari [Abu Hurairah] radliallahu 'anhu dia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Permisalan seorang mukmin seperti dahan di suatu pohon yang dapat bengkok ketika tertiaup angin dan apabila tertimpa musibah dia akan tetap tegak lurus, sedangkan permisalan orang fajir ibarat tanaman padi yang senantiasa tegak sehingga Allah akan merobohkannya kapan saja Dia kehendaki.\""},"4908":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ أَنَّهُ قَالَ سَمِعْتُ سَعِيدَ بْنَ يَسَارٍ أَبَا الْحُبَابِ يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يُرِدْ اللَّهُ بِهِ خَيْرًا يُصِبْ مِنْهُ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Muhammad bin Abdullah bin Abdurrahman bin Abu Sha'sha'ah] bahwa dia berkata, saya mendengar [Sa'id bin Yasar Abu Al Hubbab] berkata; saya mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di kehendaki Allah kebaikan, maka Dia akan mengujinya.\""},"4909":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ ح حَدَّثَنِي بِشْرُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَا رَأَيْتُ أَحَدًا أَشَدَّ عَلَيْهِ الْوَجَعُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dan diriwayatkan dari jalur lain, telah menceritakan kepadaku [Bisyr bin Muhammad] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Syu'bah] dari [Al A'masy] dari [Abu Wa`il] dari [Masruq] dari [Aisyah] radliallahu 'anha dia berkata; \"Aku tidak pernah melihat seseorang yang lebih merasakan penderitaan ketika sakit dari Rasulullah shallallahu 'alaihi wasallam.\""},"4910":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرَضِهِ وَهُوَ يُوعَكُ وَعْكًا شَدِيدًا وَقُلْتُ إِنَّكَ لَتُوعَكُ وَعْكًا شَدِيدًا قُلْتُ إِنَّ ذَاكَ بِأَنَّ لَكَ أَجْرَيْنِ قَالَ أَجَلْ مَا مِنْ مُسْلِمٍ يُصِيبُهُ أَذًى إِلَّا حَاتَّ اللَّهُ عَنْهُ خَطَايَاهُ كَمَا تَحَاتُّ وَرَقُ الشَّجَرِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim At Taimi] dari [Al Harits bin Suwaid] dari [Abdullah] radliallahu 'anhu; saya pernah menjenguk Nabi shallallahu 'alaihi wasallam ketika sakit, sepertinya beliau sedang merasakan rasa sakit, kataku selanjutnya; \"Sepertinya anda sedang merasakan rasa sakit yang amat berat, oleh karena itulah anda mendapatkan pahala dua kali lipat.\" Beliau menjawab: \"Benar, tidaklah seorang muslim yang tertimpa musibah melainkan Allah akan menggugurkan kesalahan-kesalahannya sebagaimana pohon menggugurkan dedaunannya.\""},"4911":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ عَنْ عَبْدِ اللَّهِ قَالَدَخَلْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُوعَكُ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّكَ لَتُوعَكُ وَعْكًا شَدِيدًا قَالَ أَجَلْ إِنِّي أُوعَكُ كَمَا يُوعَكُ رَجُلَانِ مِنْكُمْ قُلْتُ ذَلِكَ أَنَّ لَكَ أَجْرَيْنِ قَالَ أَجَلْ ذَلِكَ كَذَلِكَ مَا مِنْ مُسْلِمٍ يُصِيبُهُ أَذًى شَوْكَةٌ فَمَا فَوْقَهَا إِلَّا كَفَّرَ اللَّهُ بِهَا سَيِّئَاتِهِ كَمَا تَحُطُّ الشَّجَرَةُ وَرَقَهَا","id":"Telah menceritakan kepada kami ['Abdan] dari [Abu Hamzah] dari [Al A'masy] dari [Ibrahim At Taimi] dari [Al Harits bin Suwaid] dari [Abdullah] dia berkata; saya pernah menjenguk Rasulullah shallallahu 'alaihi wasallam ketika beliau sedang menderita sakit, lalu aku berkata; \"Wahai Rasulullah, sepertinya anda sedang merasakan sakit yang amat berat\" beliau bersabda: \"Benar, rasa sakit yang menimpaku ini sama seperti rasa sakit yang menimpa dua orang dari kalian.\" Kataku selanjutnya; \"Sebab itu anda mendapatkan pahala dua kali lipat.\" Beliau menjawab: \"Benar, seperti itulah, dan tidaklah seorang muslim yang tertimpa suatu musibah (penyakit) atau yang lain, melainkan Allah akan menghapuskan kesalahan-kesalahannya sebagaimana pohon menggugurkan dedaunannya.\""},"4912":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَطْعِمُوا الْجَائِعَ وَعُودُوا الْمَرِيضَ وَفُكُّوا الْعَانِيَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abu 'Awanah] dari [Manshur] dari [Abu Wa`il] dari [Abu Musa Al Asy'ari] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berilah makan terhadap orang yang kelaparan, jenguklah orang sakit dan bebaskanlah tawanan.\""},"4913":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي أَشْعَثُ بْنُ سُلَيْمٍ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ سُوَيْدِ بْنِ مُقَرِّنٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَبْعٍ وَنَهَانَا عَنْ سَبْعٍ نَهَانَا عَنْ خَاتَمِ الذَّهَبِ وَلُبْسِ الْحَرِيرِ وَالدِّيبَاجِ وَالْإِسْتَبْرَقِ وَعَنْ الْقَسِّيِّ وَالْمِيثَرَةِ وَأَمَرَنَا أَنْ نَتْبَعَ الْجَنَائِزَ وَنَعُودَ الْمَرِيضَ وَنُفْشِيَ السَّلَامَ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dia berkata; telah mengabarkan kepadaku [Asy'ats bin Sulaim] dia berkata; saya mendengar [Mu'awiyah bin Suwaid bin Muqarrin] dari [Al Barra` bin 'Azib] radliallahu 'anhuma dia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kami tujuh perkara dan melarang kami dari tujuh perkara, beliau melarang kami dari memakai cincin emas, mengenakan sutera, dibaj, istabraq (kain sejenis sutera), qasiy dan misarah (yaitu kain yang terbuat dari campuran sutera), dan memerintahkan kami untuk mengiringi jenazah, menjenguk orang sakit dan menebarkan salam.\""},"4914":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ الْمُنْكَدِرِ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُمَرِضْتُ مَرَضًا فَأَتَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي وَأَبُو بَكْرٍ وَهُمَا مَاشِيَانِ فَوَجَدَانِي أُغْمِيَ عَلَيَّ فَتَوَضَّأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ صَبَّ وَضُوءَهُ عَلَيَّ فَأَفَقْتُ فَإِذَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ أَصْنَعُ فِي مَالِي كَيْفَ أَقْضِي فِي مَالِي فَلَمْ يُجِبْنِي بِشَيْءٍ حَتَّى نَزَلَتْ آيَةُ الْمِيرَاثِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Sufyan] dari [Ibnu Al Munkadir] dia mendengar [Jabir bin Abdullah] radliallahu 'anhuma berkata; Aku pernah menderita sakit, lalu Nabi shallallahu 'alaihi wasallam dan Abu Bakar datang menjengukku dengan berjalan kaki, ketika beliau menemuiku ternyata aku sedang pingsan, maka beliau berwudlu' dan memercikkan sisa air wudlu'nya kepadaku, aku pun tersadar, ternyata Nabi shallallahu 'alaihi wasallam sudah berada di depanku, lalu aku berkata; \"Wahai Rasulullah, bagaimana caranya aku mengurus harta bendaku, bagaimana caranya aku memutuskan terhadap harta bendaku?\" beliau tetap tidak menjawab sampai turun ayat tentang harta warisan.\""},"4915":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عِمْرَانَ أَبِي بَكْرٍ قَالَ حَدَّثَنِي عَطَاءُ بْنُ أَبِي رَبَاحٍ قَالَ قَالَ لِي ابْنُ عَبَّاسٍأَلَا أُرِيكَ امْرَأَةً مِنْ أَهْلِ الْجَنَّةِ قُلْتُ بَلَى قَالَ هَذِهِ الْمَرْأَةُ السَّوْدَاءُ أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنِّي أُصْرَعُ وَإِنِّي أَتَكَشَّفُ فَادْعُ اللَّهَ لِي قَالَ إِنْ شِئْتِ صَبَرْتِ وَلَكِ الْجَنَّةُ وَإِنْ شِئْتِ دَعَوْتُ اللَّهَ أَنْ يُعَافِيَكِ فَقَالَتْ أَصْبِرُ فَقَالَتْ إِنِّي أَتَكَشَّفُ فَادْعُ اللَّهَ لِي أَنْ لَا أَتَكَشَّفَ فَدَعَا لَهَاحَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا مَخْلَدٌ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي عَطَاءٌ أَنَّهُ رَأَى أُمَّ زُفَرَ تِلْكَ امْرَأَةً طَوِيلَةً سَوْدَاءَ عَلَى سِتْرِ الْكَعْبَةِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Imran bin Abu Bakar] dia berkata; telah menceritakan kepadaku ['Atha` bin Abu Rabah] dia berkata; [Ibnu Abbas] pernah berkata kepadaku; \"Maukah aku tunjukkan kepadamu seorang wanita dari penduduk surga?\" jawabku; \"Tentu.\" Dia berkata; \"Wanita berkulit hitam ini, dia pernah menemui Nabi shallallahu 'alaihi wasallam sambil berkata; \"Sesungguhnya aku menderita epilepsi dan auratku sering tersingkap (ketika sedang kambuh), maka berdoalah kepada Allah untukku.\" Beliau bersabda: \"Jika kamu berkenan, bersabarlah maka bagimu surga, dan jika kamu berkenan, maka aku akan berdoa kepada Allah agar Allah menyembuhkanmu.\" Ia berkata; \"Baiklah aku akan bersabar.\" Wanita itu berkata lagi; \"Namun berdoalah kepada Allah agar (auratku) tidak tersingkap.\" Maka beliau mendoakan untuknya.\" Telah menceritakan kepada kami Muhammad telah mengabarkan kepada kami Makhlad dari Ibnu Juraij telah mengabarkan kepadaku 'Atha' bahwa dia pernah melihat Ummu Zufar adalah wanita tersebut, ia adalah wanita berpawakan tinggi, berkulit hitam sedang berada di tirai Ka'bah.\""},"4916":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي ابْنُ الْهَادِ عَنْ عَمْرٍو مَوْلَى الْمُطَّلِبِ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ قَالَ إِذَا ��بْتَلَيْتُ عَبْدِي بِحَبِيبَتَيْهِ فَصَبَرَ عَوَّضْتُهُ مِنْهُمَا الْجَنَّةَ يُرِيدُ عَيْنَيْهِتَابَعَهُ أَشْعَثُ بْنُ جَابِرٍ وَأَبُو ظِلَالِ بْنُ هِلَالٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] dia berkata; telah menceritakan kepadaku [Ibnu Al Hadi] dari ['Amru] bekas budak Al Mutthalib, dari [Anas bin Malik] radliallahu 'anhu dia berkata; saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Allah berfirman; \"Apabila Aku menguji hamba-Ku dengan penyakit pada kedua matanya, kemudian ia mampu bersabar, maka Aku akan menggantinya dengan surga.\" maksud (habibataihi) adalah kedua matanya. Hadits ini juga diperkuat oleh riwayat [Asy'ats bin Jabir] dan [Abu Dzilal bin Hilal] dari [Anas] dari Nabi shallallahu 'alaihi wasallam."},"4917":{"ar":"حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وُعِكَ أَبُو بَكْرٍ وَبِلَالٌ رَضِيَ اللَّهُ عَنْهُمَا قَالَتْ فَدَخَلْتُ عَلَيْهِمَا قُلْتُ يَا أَبَتِ كَيْفَ تَجِدُكَ وَيَا بِلَالُ كَيْفَ تَجِدُكَ قَالَتْ وَكَانَ أَبُو بَكْرٍ إِذَا أَخَذَتْهُ الْحُمَّى يَقُولُ كُلُّ امْرِئٍ مُصَبَّحٌ فِي أَهْلِهِوَالْمَوْتُ أَدْنَى مِنْ شِرَاكِ نَعْلِهِوَكَانَ بِلَالٌ إِذَا أَقْلَعَتْ عَنْهُ يَقُولُ أَلَا لَيْتَ شِعْرِي هَلْ أَبِيتَنَّ لَيْلَةًبِوَادٍ وَحَوْلِي إِذْخِرٌ وَجَلِيلُوَهَلْ أَرِدَنْ يَوْمًا مِيَاهَ مِجَنَّةٍوَهَلْ تَبْدُوَنْ لِي شَامَةٌ وَطَفِيلُقَالَتْ عَائِشَةُ فَجِئْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَقَالَ اللَّهُمَّ حَبِّبْ إِلَيْنَا الْمَدِينَةَ كَحُبِّنَا مَكَّةَ أَوْ أَشَدَّ اللَّهُمَّ وَصَحِّحْهَا وَبَارِكْ لَنَا فِي مُدِّهَا وَصَاعِهَا وَانْقُلْ حُمَّاهَا فَاجْعَلْهَا بِالْجُحْفَةِ","id":"Telah menceritakan kepada kami [Qutaibah] dari [Malik] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] dia berkata; \"Ketika Rasulullah shallaallahu'alaihi wa sallam sampai di Madinah, Abu Bakar dan Bilal menderita sakit. Lalu Aisyah menjenguk mereka berdua. Aku bertanya; \"Wahai ayahku, bagaimana keadaanmu? Dan engkau Bilal, bagaimana keadaanmu?\" Aisyah melanjutkan; Dan setiap kali Abu Bakar menderita sakit panas, maka dia akan berkata; \"Setiap orang bertanggung jawab terhadap keluarganya dan kematian itu lebih dekat dari pada tali sandalnya.\" Sedangkan jika Bilal menderita sakit demam, dia akan berkata; \"Alangkah baiknya syairku, apakah aku harus bermalam di suatu lembah sementara di sampingku terdapat orang-orang yang membanggakan lagi mulia. Apakah suatu hari mereka akan menginginkan airnya yang melimpah. Apakah sudah tampak olehku gunung Syamah dan Thafil?\" Aisyah berkata; Kemudian aku mendatangi Rasulullah shallaallahu'alaihi wa sallam dan mengabarkan keadaan mereka kepada beliau. Lalu beliau berdo'a: ALLAHUMMA HABBIB ILAINAA ALMADINAH KAHUBBINA MAKKATA AW ASYADDA ALLAHUMMA WA SHAHHIHHA WA BAARIK LANAA FI MUDDIHA WA SHAA'IHAA WANQUL HUMMAHA FAJ'ALHA BIL JUHFAH (Ya Allah, jadikanlah kecintaan kami kepada Madinah seperti kecintaan kami kepada Mekkah atau lebih. Ya Allah, perbaikilah ia, Berkahilah kami pada takaran mudnya dan sha'nya dan pindahkanlah wabah penyakitnya ke Juhfah.\""},"4918":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَاصِمٌ قَالَ سَمِعْتُ أَبَا عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ ابْنَةً لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَتْ إِلَيْهِ وَهُوَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَعْدٌ وَأُبَيٌّ نَحْسِبُ أَنَّ ابْنَتِي قَدْ حُضِرَتْ فَاشْهَدْنَا فَأَرْسَلَ إِلَيْهَا السَّلَامَ وَيَقُولُ إِنَّ لِلَّهِ مَا أَخَذَ وَمَا أَعْطَى وَكُلُّ شَيْءٍ عِنْدَهُ مُسَمًّى فَلْتَحْتَسِبْ وَلْتَصْبِرْ فَأَرْسَلَتْ تُقْسِمُ عَلَيْهِ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقُمْنَا فَرُفِعَ الصَّبِيُّ فِي حَجْرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَفْسُهُ جُئِّثُ فَفَاضَتْ عَيْنَا النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ سَعْدٌ مَا هَذَا يَا رَسُولَ اللَّهِ قَالَ هَذِهِ رَحْمَةٌ وَضَعَهَا اللَّهُ فِي قُلُوبِ مَنْ شَاءَ مِنْ عِبَادِهِ وَلَا يَرْحَمُ اللَّهُ مِنْ عِبَادِهِ إِلَّا الرُّحَمَاءَ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Syu'bah] dia berkata; telah mengabarkan kepadaku ['Ashim] dia berkata; saya mendengar [Abu Utsman] dari [Usamah bin Zaid] radliallahu 'anhuma, seorang puteri Nabi shallallahu 'alaihi wasallam mengirim seorang utusan kepada Nabi yang ketika itu Usamah, Sa'd dan Ubbay, bersama Nabi shallallahu 'alaihi wasallam, (seingatku) utusan itu menyampaikan pesan yang isinya; \"Anakku telah menjelang wafat, maka tolong engkau (nabi) datang! Namun Nabi (tak sempat datang) dan hanya mengutusnya seraya menyampaikan pesan; \"Tolong sampaikan salam kepadanya dan katakanlah; \"Milik Allah lah segala yang diambil-Nya dan segala yang diberikan-Nya, dan segala sesuatu mempunyai batasan waktu tertentu disisi-Nya, maka hendaklah dia hanya mengharap ganjaran dan bersabar.\" (Merasa tidak puas), puteri nabi mengirim utusan untuk kedua kalinya sambil menyumpahinya (agar bisa membujuk nabi). Spontan nabi beranjak, dan kami pun berdiri. (ketika sampai), cucu nabi diletakkan di pangkuan Nabi shallallahu 'alaihi wasallam sedang nafasnya sudah tersengal-sengal karena tinggal sisa-sisa nyawanya. Kedua mata Nabi shallallahu 'alaihi wasallam pun berlinang, sehingga Sa'd bertanya; \"Kenapa anda menangis ya Rasulullah?\" Beliau menjawab: \"Ini adalah pertanda kasih sayang yang Allah letakkan di hati hamba sesuai yang di kehendaki-Nya, dan Allah tidak akan meletakkan rasa kasih sayang pada para hamba-Nya kecuali terhadap orang-orang yang mempunyai rasa kasih sayang.\""},"4919":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُخْتَارٍ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى أَعْرَابِيٍّ يَعُودُهُ قَالَ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ عَلَى مَرِيضٍ يَعُودُهُ فَقَالَ لَهُ لَا بَأْسَ طَهُورٌ إِنْ شَاءَ اللَّهُ قَالَ قُلْتَ طَهُورٌ كَلَّا بَلْ هِيَ حُمَّى تَفُورُ أَوْ تَثُورُ عَلَى شَيْخٍ كَبِيرٍ تُزِيرُهُ الْقُبُورَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَعَمْ إِذًا","id":"Telah menceritakan kepada kami [Mu'allaa bin Asad] telah menceritakan kepada kami [Abdul Aziz bin Muhtar] telah menceritakan kepada kami [Khalid] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma bahwa Nabi shallallahu 'alaihi wasallam pernah menjenguk seorang Arab badui, Ibnu Abbas melanjutkan; \"Setiap kali beliau menjenguk orang sakit, maka beliau akan mengatakan kepadanya: \"Tidak apa-apa, Insya Allah baik-baik saja.\" Ibnu Abbas berkata; lalu aku bertanya; \"Baik?!, tidak mungkin, sebab penyakit yang di deritanya adalah demam yang sangat kritis, yang apabila diderita oleh orang tua akan menyebabkannya meninggal dunia.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Kalau begitu, memang benar.\""},"4920":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ غُلَامًا لِيَهُودَ كَانَ يَخْدُمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَرِضَ فَأَتَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُهُ فَقَالَ أَسْلِمْ فَأَسْلَمَوَقَالَ سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ أَبِيهِ لَمَّا حُضِرَ أَبُو طَالِبٍ جَاءَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas] radliallahu 'anhu bahwa seorang budak milik orang Yahudi pernah menjadi pelayannya Nabi shallallahu 'alaihi wasallam, lalu dia jatuh sakit, maka Nabi shallallahu 'alaihi wasallam pergi menjenguknya sambil bersabda: \"Masuk Islamlah kamu.\" Lalu dia masuk Islam.\" Sa'id bin Musayyib berkata; dari Ayahnya \"Ketika Abu Thalib hendak meninggal, Nabi shallallahu 'alaihi wasallam datang menjenguknya.\""},"4921":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى حَدَّثَنَا هِشَامٌ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهِ نَاسٌ يَعُودُونَهُ فِي مَرَضِهِ فَصَلَّى بِهِمْ جَالِسًا فَجَعَلُوا يُصَلُّونَ قِيَامًا فَأَشَارَ إِلَيْهِمْ اجْلِسُوا فَلَمَّا فَرَغَ قَالَ إِنَّ الْإِمَامَ لَيُؤْتَمُّ بِهِ فَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا رَفَعَ فَارْفَعُوا وَإِنْ صَلَّى جَالِسًا فَصَلُّوا جُلُوسًاقَالَ أَبُو عَبْد اللَّهِ قَالَ الْحُمَيْدِيُّ هَذَا الْحَدِيثُ مَنْسُوخٌ لِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آخِرَ مَا صَلَّى صَلَّى قَاعِدًا وَالنَّاسُ خَلْفَهُ قِيَامٌ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Hisyam] dia berkata; telah mengabarkan kepadaku [Ayahku] dari [Aisyah] radliallahu 'anha bahwa Nabi shallallahu 'alaihi wasallam pernah dijenguk oleh beberapa orang ketika beliau sakit, kemudian beliau mengerjakan shalat sambil duduk, maka orang-orang pun ikut mengerjakan shalat sambil berdiri, lalu beliau memberi isyarat supaya mereka juga duduk, seusai shalat beliau bersabda: \"Sesungguhnya dijadikannya Imam itu untuk diikuti, apabila dia ruku' maka kalian juga harus ruku', apabila dia mengangkat kepala maka kalian juga harus mengangkat kepala, apabila dia shalat sambil duduk maka kalian harus shalat sambil duduk.\" Abu Abdullah berkata; Al Humaidi berkata; hadits ini hukumnya mansukh (terhapus), karena Nabi shallallahu 'alaihi wasallam di akhir hayatnya selalu mengerjakan shalat sambil duduk, sementara orang-orang yang di belakang beliau shalat sambil berdiri.\""},"4922":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا الْجُعَيْدُ عَنْ عَائِشَةَ بِنْتِ سَعْدٍ أَنَّ أَبَاهَاقَالَ تَشَكَّيْتُ بِمَكَّةَ شَكْوًا شَدِيدًا فَجَاءَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي فَقُلْتُ يَا نَبِيَّ اللَّهِ إِنِّي أَتْرُكُ مَالًا وَإِنِّي لَمْ أَتْرُكْ إِلَّا ابْنَةً وَاحِدَةً فَأُوصِي بِثُلُثَيْ مَالِي وَأَتْرُكُ الثُّلُثَ فَقَالَ لَا قُلْتُ فَأُوصِي بِالنِّصْفِ وَأَتْرُكُ النِّصْفَ قَالَ لَا قُلْتُ فَأُوصِي بِالثُّلُثِ وَأَتْرُكُ لَهَا الثُّلُثَيْنِ قَالَ الثُّلُثُ وَالثُّلُثُ كَثِيرٌ ثُمَّ وَضَعَ يَدَهُ عَلَى جَبْهَتِهِ ثُمَّ مَسَحَ يَدَهُ عَلَى وَجْهِي وَبَطْنِي ثُمَّ قَالَ اللَّهُمَّ اشْفِ سَعْدًا وَأَتْمِمْ لَهُ هِجْرَتَهُ فَمَا زِلْتُ أَجِدُ بَرْدَهُ عَلَى كَبِدِي فِيمَا يُخَالُ إِلَيَّ حَتَّى السَّاعَةِ","id":"Telah menceritakan kepada kami [Al Makki bin Ibrahim] telah mengabarkan kepada kami [Al Ju'aid] dari [Aisyah binti Sa'd] bahwa [Ayahnya] berkata; Aku pernah menderita rasa sakit yang amat berat ketika di Makkah, maka Nabi shallallahu 'alaihi wasallam datang menjengukku, lalu aku berkata kepada beliau; \"Wahai Nabi Allah, aku akan meninggalkan banyak harta benda, namun aku tidak memiliki seorang pun (ahli warits) selain seorang puteri, oleh karena itu aku wasiatkan dua pertiga dari harta bendaku dan aku tinggalkan sepertiganya\" beliau bersabda: \"Jangan.\" Kataku; \"Kalau begitu, aku wasiatkan setengahnya dan aku sisakan setengah.\" Beliau menjawab: \"Jangan.\" Kataku selanjutnya; \"Kalau begitu aku wasiatkan sepertiga dan aku sisakan yang dua pertiganya.\" Beliau bersabda: \"Sepertiga, sepertiga pun masih banyak, \" lalu beliau meletakkan tangan beliau di atas keningnya kemudian beliau mengusap wajah dan perutku sambil berdo'a: \"ALLAHUMMASYFII SA'D WA ATMIM LAHU HIJRATAHU (Ya Allah, sembuhkanlah penyakit Sa'd dan sempurnakanlah hijrahnya).\" Maka aku masih merasakan rasa sejuk di hatiku hingga saat ini.\""},"4923":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍدَخَلْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُوعَكُ وَعْكًا شَدِيدًا فَمَسِسْتُهُ بِيَدِي فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّكَ لَتُو��َكُ وَعْكًا شَدِيدًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجَلْ إِنِّي أُوعَكُ كَمَا يُوعَكُ رَجُلَانِ مِنْكُمْ فَقُلْتُ ذَلِكَ أَنَّ لَكَ أَجْرَيْنِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجَلْ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مُسْلِمٍ يُصِيبُهُ أَذًى مَرَضٌ فَمَا سِوَاهُ إِلَّا حَطَّ اللَّهُ لَهُ سَيِّئَاتِهِ كَمَا تَحُطُّ الشَّجَرَةُ وَرَقَهَا","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Ibrahim At Taimi] dari [Al Harits bin Suwaid] dia berkata; [Abdullah bin Mas'ud] berkata; Aku pernah menjenguk Rasulullah shallallahu 'alaihi wasallam, ketika itu beliau sedang menderita rasa sakit yang sangat berat, lalu aku memegang beliau sambil berkata; \"Wahai Rasulullah, sepertinya anda sedang menderita sakit yang sangat berat, \" beliau menjawab: \"Benar, rasa sakit yang menimpaku ini sama seperti rasa sakit yang menimpa dua orang dari kalian.\" Kataku selanjutnya; \"Sebab itu anda mendapatkan pahala dua kali lipat.\" Beliau menjawab: \"Benar, \" kemudian beliau bersabda lagi: \"Tidaklah seorang muslim yang menderita sakit atau yang lain, melainkan Allah akan menghapuskan kesalahan-kesalahannya sebagaimana pohon menggugurkan dedaunannya.\""},"4924":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرَضِهِ فَمَسِسْتُهُ وَهُوَ يُوعَكُ وَعْكًا شَدِيدًا فَقُلْتُ إِنَّكَ لَتُوعَكُ وَعْكًا شَدِيدًا وَذَلِكَ أَنَّ لَكَ أَجْرَيْنِ قَالَ أَجَلْ وَمَا مِنْ مُسْلِمٍ يُصِيبُهُ أَذًى إِلَّا حَاتَّتْ عَنْهُ خَطَايَاهُ كَمَا تَحَاتُّ وَرَقُ الشَّجَرِ","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim At Taimi] dari [Al Harits bin Suwaid] dari [Abdullah] radliallahu 'anhu dia berkata; aku menjenguk Nabi shallallahu 'alaihi wasallam ketika beliau sakit, lalu aku memegang beliau sementara beliau sedang menahan sakit yang amat berat, maka kataku; \"Sepertinya anda sedang merasakan sakit yang amat berat, karena itu anda mendapatkan pahala dua kali lipat.\" Beliau bersabda: \"Benar, dan tidaklah seorang muslim yang tertimpa musibah (sakit) melainkan Allah akan menghapuskan kesalahan-kesalahannya sebagaimana pohon menggugurkan dedaunannya.\""},"4925":{"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ خَالِدٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَى رَجُلٍ يَعُودُهُ فَقَالَ لَا بَأْسَ طَهُورٌ إِنْ شَاءَ اللَّهُ فَقَالَ كَلَّا بَلْ حُمَّى تَفُورُ عَلَى شَيْخٍ كَبِيرٍ كَيْمَا تُزِيرَهُ الْقُبُورَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَعَمْ إِذًا","id":"Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Khalid bin Abdullah] dari [Khalid] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma bahwa Rasulullah shallallahu 'alaihi wasallam pernah menjenguk seorang laki-laki yang sedang sakit, beliau lalu bersabda: \"Tidak apa-apa, Insya Allah baik-baik saja.\" Ibnu Abbas berkata; \"Baik?!, tidak mungkin, sebab penyakit yang di deritanya adalah demam yang sangat kritis, yang apabila diderita oleh orang tua akan menyebabkannya meninggal dunia.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Kalau begitu, memang benar.\""},"4926":{"ar":"حَدَّثَنِي يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ أَنَّ أُسَامَةَ بْنَ زَيْدٍ أَخْبَرَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكِبَ عَلَى حِمَارٍ عَلَى إِكَافٍ عَلَى قَطِيفَةٍ فَدَكِيَّةٍ وَأَرْدَفَ أُسَامَةَ وَرَاءَهُ يَعُودُ سَعْدَ بْنَ عُبَادَةَ قَبْلَ وَقْعَةِ بَدْرٍ فَسَارَ حَتَّى مَرَّ بِمَجْلِسٍ فِيهِ عَبْدُ اللَّهِ بْنُ أُبَيٍّ ابْنُ سَلُولَ وَذَلِكَ قَبْلَ أَنْ يُسْلِمَ عَبْدُ اللَّهِ وَفِي الْمَجْلِسِ أَخْلَاطٌ مِنْ الْمُسْلِمِينَ وَالْمُشْرِكِينَ عَبَدَةِ الْأَوْثَانِ وَالْيَهُودِ وَفِي الْمَجْلِسِ عَبْدُ اللَّهِ بْنُ رَوَاحَةَ فَلَمَّا غَشِيَتْ الْمَجْلِسَ عَجَاجَةُ الدَّابَّةِ خَمَّرَ عَبْدُ اللَّهِ بْنُ أُبَيٍّ أَنْفَهُ بِرِدَائِهِ قَالَ لَا تُغَبِّرُوا عَلَيْنَا فَسَلَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَوَقَفَ وَنَزَلَ فَدَعَاهُمْ إِلَى اللَّهِ فَقَرَأَ عَلَيْهِمْ الْقُرْآنَ فَقَالَ لَهُ عَبْدُ اللَّهِ بْنُ أُبَيٍّ يَا أَيُّهَا الْمَرْءُ إِنَّهُ لَا أَحْسَنَ مِمَّا تَقُولُ إِنْ كَانَ حَقًّا فَلَا تُؤْذِنَا بِهِ فِي مَجْلِسِنَا وَارْجِعْ إِلَى رَحْلِكَ فَمَنْ جَاءَكَ فَاقْصُصْ عَلَيْهِ قَالَ ابْنُ رَوَاحَةَ بَلَى يَا رَسُولَ اللَّهِ فَاغْشَنَا بِهِ فِي مَجَالِسِنَا فَإِنَّا نُحِبُّ ذَلِكَ فَاسْتَبَّ الْمُسْلِمُونَ وَالْمُشْرِكُونَ وَالْيَهُودُ حَتَّى كَادُوا يَتَثَاوَرُونَ فَلَمْ يَزَلْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى سَكَتُوا فَرَكِبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَابَّتَهُ حَتَّى دَخَلَ عَلَى سَعْدِ بْنِ عُبَادَةَ فَقَالَ لَهُ أَيْ سَعْدُ أَلَمْ تَسْمَعْ مَا قَالَ أَبُو حُبَابٍ يُرِيدُ عَبْدَ اللَّهِ بْنَ أُبَيٍّ قَالَ سَعْدٌ يَا رَسُولَ اللَّهِ اعْفُ عَنْهُ وَاصْفَحْ فَلَقَدْ أَعْطَاكَ اللَّهُ مَا أَعْطَاكَ وَلَقَدْ اجْتَمَعَ أَهْلُ هَذِهِ الْبَحْرَةِ عَلَى أَنْ يُتَوِّجُوهُ فَيُعَصِّبُوهُ فَلَمَّا رَدَّ ذَلِكَ بِالْحَقِّ الَّذِي أَعْطَاكَ شَرِقَ بِذَلِكَ فَذَلِكَ الَّذِي فَعَلَ بِهِ مَا رَأَيْتَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Urwah] bahwa [Usamah bin Zaid] mengabarkan kepadanya bahwa Nabi shallallahu 'alaihi wasallam pernah mengendarai keledai milik beliau, diatasnya ada pelana bersulam beludru Fadaki, sementara Usamah bin Zaid membonceng di belakang beliau ketika hendak menjenguk Sa'ad bin 'Ubadah sebelum peristiwa Badar, lalu beliau berjalan dan sempat melintasi suatu majlis yang di majlis tersebut terdapat Abdullah bin Ubay bin Salul, kejadian itu sebelum Abdullah masuk Islam, dan dalam majlis tersebut terdapat pula beberapa orang kaum Muslimin yang bercampur baur dengan orang-orang musyrik, para penyembah patung, dan orang-orang Yahudi, terdapat pula Abdullah bin Rawahah, saat majlis itu dipenuhi kepulan debu keledai, 'Abdullah bin Ubai menutupi hidungnya dengan selendang sambil berkata: \"Jangan mengepuli kami dengan debu, \" kemudian Nabi shallallahu 'alaihi wasallam mengucapkan salam pada mereka lalu berhenti dan turun, setelah itu Nabi shallallahu 'alaihi wasallam mengajak mereka menuju Allah lalu beliau membacakan al-Qur'an kepada mereka. 'Abdullah bin Ubay berkata kepada beliau: \"Wahai saudara! Sesungguhnya apa yang kamu katakan tidak ada kebaikannya sedikit pun, bila apa yang kau katakan itu benar, maka janganlah kamu mengganggu kami di majlis ini, silahkan kembali ke kendaraan anda, lalu siapa saja dari kami mendatangi anda, silahkan anda bercerita padanya.\" 'Abdullah bin Rawahah berkata; \"Wahai Rasulullah, bergabunglah dengan kami di majlis ini karena kami menyukai hal itu.\" Kaum muslimin, orang-orang musyrik dan orang-orang Yahudi pun saling mencaci hingga mereka hendak saling menyerang, Nabi shallallahu 'alaihi wasallam terus menenangkan mereka hingga mereka semuanya diam, kemudian beliau naik kendaraan hingga masuk ke kediaman Sa'd bin 'Ubadah lalu beliau bersabda: \"Hai Sa'd! Apa kau tidak mendengar ucapan Abu Hubab?\" maksud beliau tentang ucapan 'Abdullah bin Ubay. Sa'ad berkata; \"Maafkan dia wahai Rasulullah dan berlapang dadalah kepadanya, demi Allah, Allah telah memberi anda apa yang telah diberikan pada anda. Penduduk telaga ini (penduduk Madinah -red) bersepakat untuk memilihnya dan mengangkatnya, namun karena kebenaran yang diberikan kepada anda itu muncul, sehingga menghalangi ia menjabat sebagai pemimpin, maka seperti itulah perbuatannya sebagaimana yang anda lihat.\""},"4927":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبَّاسٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدٍ هُوَ ابْنُ المُنْكَدِرِ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي لَيْسَ بِرَاكِبِ بَغْلٍ وَلَا بِرْذَوْنٍ","id":"Telah menceritakan kepada kami ['Amru bin 'Abbas] telah menceritakan kepada kami [Abdurrahman] telah menceritakan kepada kami [Sufyan] dari [Muhammad yaitu Ibnu Al Munkadir] dari [Jabir] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam pernah datang menjengukku tanpa mengendarai bighal (peranakan kuda dengan keledai) dan tidak pula birdzaun (keledai yang asal-usul keturunannya bukan dari Arab).\""},"4928":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ وَأَيُّوبَ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ رَضِيَ اللَّهُ عَنْهُمَرَّ بِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أُوقِدُ تَحْتَ الْقِدْرِ فَقَالَ أَيُؤْذِيكَ هَوَامُّ رَأْسِكَ قُلْتُ نَعَمْ فَدَعَا الْحَلَّاقَ فَحَلَقَهُ ثُمَّ أَمَرَنِي بِالْفِدَاءِ","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dan [Ayyub] dari [Mujahid] dari [Abdurrahman bin Abu Laila] dari [Ka'b bin 'Ujrah] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam pernah melewatiku sementara aku sedang menyalakan api di bawah periuk, lalu beliau bertanya: \"Apakah kepalamu terganggu (dengan kutu)?\" Aku menjawab; \"Ya.\" Lalu beliau memanggil tukang cukur dan mencukurnya, kemudian beliau memerintahkanku membayar fidyah.\""},"4929":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَبُو زَكَرِيَّاءَ أَخْبَرَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ سَمِعْتُ الْقَاسِمَ بْنَ مُحَمَّدٍ قَالَ قَالَتْ عَائِشَةُوَا رَأْسَاهْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاكِ لَوْ كَانَ وَأَنَا حَيٌّ فَأَسْتَغْفِرَ لَكِ وَأَدْعُوَ لَكِ فَقَالَتْ عَائِشَةُ وَا ثُكْلِيَاهْ وَاللَّهِ إِنِّي لَأَظُنُّكَ تُحِبُّ مَوْتِي وَلَوْ كَانَ ذَاكَ لَظَلِلْتَ آخِرَ يَوْمِكَ مُعَرِّسًا بِبَعْضِ أَزْوَاجِكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَلْ أَنَا وَا رَأْسَاهْ لَقَدْ هَمَمْتُ أَوْ أَرَدْتُ أَنْ أُرْسِلَ إِلَى أَبِي بَكْرٍ وَابْنِهِ وَأَعْهَدَ أَنْ يَقُولَ الْقَائِلُونَ أَوْ يَتَمَنَّى الْمُتَمَنُّونَ ثُمَّ قُلْتُ يَأْبَى اللَّهُ وَيَدْفَعُ الْمُؤْمِنُونَ أَوْ يَدْفَعُ اللَّهُ وَيَأْبَى الْمُؤْمِنُونَ","id":"Telah menceritakan kepada kami [Yahya bin Yahya Abu Zakariya`] telah mengabarkan kepada kami [Sulaiman bin Bilal] dari [Yahya bin Sa'id] dia berkata; saya mendengar [Al Qasim bin Muhammad] berkata; [Aisyah] berkata; \"Aduh kepalaku pusing.\" maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalaulah kematianmu terjadi dan aku masih hidup, tentu aku memintakan ampun untukmu dan mendoakan kebaikan bagimu. Kata 'Aisyah \"Duhh,, sungguh aku beranggapan bahwa engkau mencintai kematianku! Dan kalaulah kematian itu terjadi pada dirimu, niscaya engkau harus menjadi pengantin di akhir-akhir harimu (maksudnya 'Aisyah sangat mengimpikan agar akhir-akhir hayat nabi, beliau berada di rumahnya, bukan di rumah isteri nabi yang lain). Lantas Nabi shallallahu 'alaihi wasallam mengatakan: \"Bahkan aku merasa sakit kepala, sungguh aku berkeinginan atau ingin mengutus seorang utusan kepada Abu Bakar dan anaknya, dan aku sampaikan washiyat; \"Biarlah orang berkomentar apa saja, atau biarlah orang bercita-cita apa saja, yang jelas kemudian aku katakan: 'Allah enggan dan orang-orang mukmin menolak atau dengan redaksi lain Allah menolak dan orang-orang mukmin enggan.\""},"4930":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ حَدَّثَنَا سُلَيْمَانُ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ عَنْ ابْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَدَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُوعَكُ فَمَسِسْتُهُ بِيَدِي فَقُلْتُ إِنَّكَ لَتُوعَكُ وَعْكًا شَدِيدًا قَالَ أَجَلْ كَمَا يُوعَكُ رَجُلَانِ مِنْكُمْ قَالَ لَكَ أَجْرَانِ قَالَ نَعَمْ مَا مِنْ مُسْلِمٍ يُصِيبُهُ أَذًى مَرَضٌ فَمَا سِوَاهُ إِلَّا حَطَّ اللَّهُ سَيِّئَاتِهِ كَمَا تَحُطُّ الشَّجَرَةُ وَرَقَهَا","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Abdul Aziz bin Muslim] telah menceritakan kepada kami [Sulaiman] dari [Ibrahim Attaimi] dari [Al Harits bin Suwaid] dari [Ibnu Mas'ud] radliallahu 'anhu mengatakan; \"Aku menemui Nabi shallallahu 'alaihi wasallam ketika beliau sedang menderita demam yang sangat berat, lantas kupegang dengan tanganku. Aku berujar; 'Sepertinya engkau terkena sakit dan demam yang sedemikian serius'. Beliau menjawab: \"Benar, rasa sakit yang menimpaku ini sama seperti rasa sakit yang menimpa dua orang dari kalian.\" Aku berujar; \"Oh, kalau begitu anda mendapatkan pahala dua kali lipat?! Jawab beliau: 'Engkau benar, tidaklah seorang muslim terkena gangguan, baik itu sakit atau lainnya, melainkan Allah akan menghapus kesalahan-kesalahannya karena sakitnya sebagaimana pohon mengugurkan daunnya.\""},"4931":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي سَلَمَةَ أَخْبَرَنَا الزُّهْرِيُّ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَجَاءَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي مِنْ وَجَعٍ اشْتَدَّ بِي زَمَنَ حَجَّةِ الْوَدَاعِ فَقُلْتُ بَلَغَ بِي مَا تَرَى وَأَنَا ذُو مَالٍ وَلَا يَرِثُنِي إِلَّا ابْنَةٌ لِي أَفَأَتَصَدَّقُ بِثُلُثَيْ مَالِي قَالَ لَا قُلْتُ بِالشَّطْرِ قَالَ لَا قُلْتُ الثُّلُثُ قَالَ الثُّلُثُ كَثِيرٌ أَنْ تَدَعَ وَرَثَتَكَ أَغْنِيَاءَ خَيْرٌ مِنْ أَنْ تَذَرَهُمْ عَالَةً يَتَكَفَّفُونَ النَّاسَ وَلَنْ تُنْفِقَ نَفَقَةً تَبْتَغِي بِهَا وَجْهَ اللَّهِ إِلَّا أُجِرْتَ عَلَيْهَا حَتَّى مَا تَجْعَلُ فِي فِي امْرَأَتِكَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abdul Aziz bin Abdullah bin Abu Salamah] telah mengabarkan kepada kami [Az Zuhri] dari ['Amir bin Sa'd] dari [Ayahnya] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah datang menjengukku ketika aku sedang menderita sakit keras yaitu ketika Haji Wada', maka aku berkata; \"Wahai Rasulullah, keadaan saya semakin parah, seperti yang telah anda lihat saat ini, sedangkan saya adalah orang yang memiliki banyak harta, sementara saya hanya memiliki seorang anak perempuan yang akan mewarisi harta peninggalan saya, maka bolehkah saya menyedekahkan dua pertiga dari harta saya?\" beliau bersabda: \"Jangan.\" Saya bertanya lagi; \"Kalau begitu, bagaimana jika separuhnya?\" beliau menjawab: \"Jangan, \" Tanyaku lagi; \"Kalau begitu bagaimana kalau sepertiganya? Beliau menjawab: Sepertiga pun sudah banyak, sebenarnya jika kamu meninggalkan ahli warismu dalam keadaan kaya, itu lebih baik daripada kamu meninggalkan mereka dalam keadaan yang serba kekurangan dan meminta-minta kepada orang lain. Tidakkah Kamu menafkahkan suatu nafkah dengan tujuan untuk mencari ridla Allah, melainkan kamu akan mendapatkan pahala lantaran dari nafkah pemberianmu itu, hingga sesuap makanan yang kamu suguhkan ke mulut istrimu.\""},"4932":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى حَدَّثَنَا هِشَامٌ عَنْ مَعْمَرٍ و حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا حُضِرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي الْبَيْتِ رِجَالٌ فِيهِمْ عُمَرُ بْنُ الْخَطَّابِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلُمَّ أَكْتُبْ لَكُمْ كِتَابًا لَا تَضِلُّوا بَعْدَهُ فَقَالَ عُمَرُ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ غَلَبَ عَلَيْهِ الْوَجَعُ وَعِنْدَكُمْ الْقُرْآنُ حَسْبُنَا كِتَابُ اللَّهِ فَاخْتَلَفَ أَهْلُ الْبَيْتِ فَاخْتَصَمُوا مِنْهُمْ مَنْ يَقُولُ قَرِّبُوا يَكْتُبْ لَكُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كِتَابًا لَنْ تَضِلُّوا بَعْدَهُ وَمِنْهُمْ مَنْ يَقُولُ مَا قَالَ عُمَرُ فَلَمَّا أَكْثَرُوا اللَّغْوَ وَالِاخْتِلَافَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُومُوا قَالَ عُبَيْدُ اللَّهِ فَكَانَ ابْنُ عَبَّاسٍ يَقُولُ إِنَّ الرَّزِيَّةَ كُلَّ الرَّزِيَّةِ مَا حَالَ بَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَيْنَ أَنْ يَكْتُبَ لَهُمْ ذَلِكَ الْكِتَابَ مِنْ اخْتِلَافِهِمْ وَلَغَطِهِمْ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah menceritakan kepada kami [Hisyam] dari [Ma'mar] dan dari jalur lain telah menceritakan kepadaku [Abdullah bin Muhammad] telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; \"Tatkala Rasulullah shallallahu 'alaihi wasallam mendekati ajalnya, sedangkan di rumah beliau telah hadir beberapa orang, diantaranya adalah Umar bin Khattab, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Kemarilah, saya akan menulis suatu catatan yang kalian tidak akan tersesat sepeninggalku.\" Lalu Umar berkata; \"Tampaknya sakit beliau bertambah parah, bukankah di sisi kalian terdapat Al Qur'an? Cukuplah bagi kita Kitabullah.\" Orang-orang yang berada di sekitar beliau ketika itu berbeda pendapat, lalu mereka saling berbantah-bantahan. Ada yang mengatakan; \"Mendekatlah kepada beliau, supaya Rasulullah shallallahu 'alaihi wasallam dapat menuliskan suatu wasiat buat kalian, agar kalian tidak tersesat sepeninggalnya.\" Dan yang lain berpendapat seperti perkataan Umar, sehingga mereka menjadi ribut di sekitar Rasulullah shallallahu 'alaihi wasallam. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berdirilah kalian semua (maksudnya pergi dari sisi beliau).\" Ubaidullah mengatakan; Ibnu Abbas berkata; \"Kerugian besar (bagi kaum Muslimin), mereka gagal menuliskan pesan terakhir Rasulullah shallallahu 'alaihi wasallam karena mereka saling berbantah-bantahan di sekitar Rasulullah shallallahu 'alaihi wasallam.\""},"4933":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ حَدَّثَنَا حَاتِمٌ هُوَ ابْنُ إِسْمَاعِيلَ عَنْ الْجُعَيْدِ قَالَ سَمِعْتُ السَّائِبَ يَقُولُذَهَبَتْ بِي خَالَتِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ ابْنَ أُخْتِي وَجِعٌ فَمَسَحَ رَأْسِي وَدَعَا لِي بِالْبَرَكَةِ ثُمَّ تَوَضَّأَ فَشَرِبْتُ مِنْ وَضُوئِهِ وَقُمْتُ خَلْفَ ظَهْرِهِ فَنَظَرْتُ إِلَى خَاتَمِ النُّبُوَّةِ بَيْنَ كَتِفَيْهِ مِثْلَ زِرِّ الْحَجَلَةِ","id":"Telah menceritakan kepada kami [Ibrahim bin Hamzah] telah menceritakan kepada kami [Hatim yaitu Ibnu Isma'il] dari [Al Ju'aid] dia berkata; aku mendengar [As Sa`ib] berkata; aku bersama bibiku pernah datang kepada Rasulullah shallallahu 'alaihi wasallam, lalu dia berkata; \"Wahai Rasulullah, sesungguhnya anak saudaraku ini sedang menderita sakit.\" Lalu beliau memegang kepalaku dan mendo'akan keberkahan kepadaku, kemudian beliau berwudlu dan aku pun minum dari sisa air wudlu' tersebut, setelah itu aku berdiri di belakang beliau hingga aku sempat melihat setempel kenabiannya berada di antara kedua pundak beliau seperti biji kancing.\""},"4934":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا ثَابِتٌ الْبُنَانِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَتَمَنَّيَنَّ أَحَدُكُمْ الْمَوْتَ مِنْ ضُرٍّ أَصَابَهُ فَإِنْ كَانَ لَا بُدَّ فَاعِلًا فَلْيَقُلْ اللَّهُمَّ أَحْيِنِي مَا كَانَتْ الْحَيَاةُ خَيْرًا لِي وَتَوَفَّنِي إِذَا كَانَتْ الْوَفَاةُ خَيْرًا لِي","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Tsabit Al Bunani] dari [Anas bin Malik] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian mengharapkan kematian karena musibah yang menimpanya, kalau memang hal itu harus, hendaknya ia mengatakan; Ya Allah, hidupkanlah aku jika kehidupan itu baik untukku, dan matikanlah aku jika kematian itu baik bagiku.\""},"4935":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ قَالَ دَخَلْنَا عَلَى خَبَّابٍنَعُودُهُ وَقَدْ اكْتَوَى سَبْعَ كَيَّاتٍ فَقَالَ إِنَّ أَصْحَابَنَا الَّذِينَ سَلَفُوا مَضَوْا وَلَمْ تَنْقُصْهُمْ الدُّنْيَا وَإِنَّا أَصَبْنَا مَا لَا نَجِدُ لَهُ مَوْضِعًا إِلَّا التُّرَابَ وَلَوْلَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا أَنْ نَدْعُوَ بِالْمَوْتِ لَدَعَوْتُ بِهِ ثُمَّ أَتَيْنَاهُ مَرَّةً أُخْرَى وَهُوَ يَبْنِي حَائِطًا لَهُ فَقَالَ إِنَّ الْمُسْلِمَ لَيُؤْجَرُ فِي كُلِّ شَيْءٍ يُنْفِقُهُ إِلَّا فِي شَيْءٍ يَجْعَلُهُ فِي هَذَا التُّرَابِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dia berkata; Aku pernah menjenguk [Khubbab], sementara dirinya berobat dengan kay (terapi dengan menempelkan besi panas pada bagian tubuh yang sakit) sebanyak tujuh kali, lalu dia berkata; \"Sesungguhnya para sahabat kami yang telah mendahului kami, mereka telah pergi sementara mereka tidak mendapatkan bagian sedikitpun dari kehidupan dunia melainkan hanya sepetak tanah, sekiranya Nabi shallallahu 'alaihi wasallam tidak melarang kami untuk mengharapkan kematian, niscaya kami akan mengharapkan kematian.\" Di kesempatan lain kami menemuinya lagi sementara dirinya sedang membangun rumahnya, lalu dia berkata; \"Seseorang akan diberi balasan dalam semua yang ia belanjakan selain yang ia belanjakan untuk sebidang tanah ini.\""},"4936":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو عُبَيْدٍ مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَنْ يُدْخِلَ أَحَدًا عَمَلُهُ الْجَنَّةَ قَالُوا وَلَا أَنْتَ يَا رَسُولَ اللَّهِ قَالَ لَا وَلَا أَنَا إِلَّا أَنْ يَتَغَمَّدَنِي اللَّهُ بِفَضْلٍ وَرَحْمَةٍ فَسَدِّدُوا وَقَارِبُوا وَلَا يَتَمَنَّيَنَّ أَحَدُكُمْ الْمَوْتَ إِمَّا مُحْسِنًا فَلَعَلَّهُ أَنْ يَزْدَادَ خَيْرًا وَإِمَّا مُسِيئًا فَلَعَلَّهُ أَنْ يَسْتَعْتِبَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Abu 'Ubaid] bekas budak Abdurrahman bin Auf bahwa [Abu Hurairah] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorang pun yang masuk surga karena amalannya.\" Para sahabat bertanya; \"Begitu juga dengan engkau wahai Rasulullah?\" beliau bersabda: \"tidak juga dengan diriku, kecuali bila Allah melimpahkan karunia dan rahmat-Nya padaku, oleh karena itu berlaku luruslah dan bertaqarublah dan janganlah salah seorang dari kalian mengharapkan kematian, jika dia orang baik semoga saja bisa menambah amal kebaikannya, dan jika dia orang yang buruk (akhlaknya) semoga bisa menjadikannya dia bertaubat.\""},"4937":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ قَالَ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُسْتَنِدٌ إِلَيَّ يَقُولُ اللَّهُمَّ اغْفِرْ لِي وَارْحَمْنِي وَأَلْحِقْنِي بِالرَّفِيقِ","id":"Telah menceritakan kepada kami [Abdullah bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari [Hsiyam] dari ['Abbad bin Abdullah bin Az Zubair] dia berkata; saya mendengar [Aisyah] radliallahu 'anha berkata; saya mendengar Nabi shallallahu 'alaihi wasallam ketika beliau sedang berada di pangkauanku, sabdanya: \"Ya Allah, ampunalah aku, rahmatilah aku serta pertemukanlah daku dengan Ar Rafiq.\""},"4938":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَتَى مَرِيضًا أَوْ أُتِيَ بِهِ قَالَ أَذْهِبْ الْبَاسَ رَبَّ النَّاسِ اشْفِ وَأَنْتَ الشَّافِي لَا شِفَاءَ إِلَّا شِفَاؤُكَ شِفَاءً لَا يُغَادِرُ سَقَمًاقَالَ عَمْرُو بْنُ أَبِي قَيْسٍ وَإِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ وَأَبِي الضُّحَى إِذَا أُتِيَ بِالْمَرِيضِ وَقَالَ جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى وَحْدَهُ وَقَالَ إِذَا أَتَى مَرِيضًا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] dari [Manshur] dari [Ibrahim] dari [Masruq] dari [Aisyah] radliallahu 'anha bahwa apabila Rasulullah shallallahu 'alaihi wasallam menjenguk orang sakit atau ada orang yang sakit datang kepada beliau, beliau berdo'a: \"ADZHIBIL BA`SA RABBAN NAASI ISYFII WA ANTA SYAAFI LAA SYIFAA`A ILLA SYIFAA`UKA SYIFAA`A LAA YUGHAADIRU SAQAMA (Hilangkanlah penyakit wahai Rab sekalian manusia, sembuhkanlah wahai dzat Yang Maha Menyembuhkan, tidak ada yang dapat menyembuhkan melainkan kesembuhan dari-Mu, yaitu kesembuhan yang tidak membawa rasa sakit).\" ['Amru bin Abu Qais], [Ibrahim bin Thahman] mengatakan dari [Manshur] dari [Ibrahim] dan [Abu Adl Dluha] dengan redaksi \"Apabila ada orang yang sakit datang kepada beliau.\" Sementara [Jarir] mengatakan dari [Manshur] dari [Abu Adl Dluha] saja, dia berkata; \"Apabila beliau menjenguk orang sakit.\""},"4939":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَدَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَرِيضٌ فَتَوَضَّأَ فَصَبَّ عَلَيَّ أَوْ قَالَ صُبُّوا عَلَيْهِ فَعَقَلْتُ فَقُلْتُ لَا يَرِثُنِي إِلَّا كَلَالَةٌ فَكَيْفَ الْمِيرَاثُ فَنَزَلَتْ آيَةُ الْفَرَائِضِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Al Munkadir] dia berkata; saya mendengar [Jabir bin Abdullah] radliallahu 'anhu berkata; \"Nabi shallallahu 'alaihi wasallam menjengukku ketika saya sakit, lalu beliau berwudlu' dan memercikkan air wudlu'nya kepadaku, atau bersabda: \"percikkanlah (air) padanya.\" lantas saya pun tersadar, lalu saya berkata; \"Wahai Rasulullah, saya tidak ada yang mewarisiku kecuali hanya kalalah (ahli warits sendirian), bagaimana aku harus membagi harta peninggalanku? Setelah itu turunlah ayat tentang fara`idl (harta peninggalan).\""},"4940":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وُعِكَ أَبُو بَكْرٍ وَبِلَالٌ قَالَتْ فَدَخَلْتُ عَلَيْهِمَا فَقُلْتُ يَا أَبَتِ كَيْفَ تَجِدُكَ وَيَا بِلَالُ كَيْفَ تَجِدُكَ قَالَتْ وَكَانَ أَبُو بَكْرٍ إِذَا أَخَذَتْهُ الْحُمَّى يَقُولُ كُلُّ امْرِئٍ مُصَبَّحٌ فِي أَهْلِهِوَالْمَوْتُ أَدْنَى مِنْ شِرَاكِ نَعْلِهِوَكَانَ بِلَالٌ إِذَا أُقْلِعَ عَنْهُ يَرْفَعُ عَقِيرَتَهُ فَيَقُولُ أَلَا لَيْتَ شِعْرِي هَلْ أَبِيتَنَّ لَيْلَةًبِوَادٍ وَحَوْلِي إِذْخِرٌ وَجَلِيلُوَهَلْ أَرِدَنْ يَوْمًا مِيَاهَ مِجَنَّةٍوَهَلْ تَبْدُوَنْ لِي شَامَةٌ وَطَفِيلُقَالَ قَالَتْ عَائِشَةُ فَجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَقَالَ اللَّهُمَّ حَبِّبْ إِلَيْنَا الْمَدِينَةَ كَحُبِّنَا مَكَّةَ أَوْ أَشَدَّ وَصَحِّحْهَا وَبَارِكْ لَنَا فِي صَاعِهَا وَمُدِّهَا وَانْقُلْ حُمَّاهَا فَاجْعَلْهَا بِالْجُحْفَةِ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha bahwa dia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam sampai (di Madinah), Abu Bakar dan Bilal menderita sakit, lalu aku menjenguk mereka berdua. Aku bertanya; \"Wahai ayahku, bagaimana keadaanmu? Dan engkau Bilal, bagaimana keadaanmu?\" Aisyah melanjutkan; Dan setiap kali Abu Bakar menderita sakit panas, maka dia akan berkata; \"Setiap orang bertanggung jawab terhadap keluarganya dan kematian itu lebih dekat dari pada tali sandalnya.\" Sedangkan jika Bilal sakit demamnya semakin tinggi, maka dia akan berkata; \"Alangkah baiknya syairku, apakah aku harus bermalam di suatu lembah sementara di sampingku terdapat orang-orang yang membanggakan diri lagi mulia. Apakah suatu hari mereka akan menginginkan air yang melimpah. Apakah sudah tampak olehku gunung Syamah dan Thafil?\" Abu Urwah berkata; Aisyah melanjutkan; Kemudian aku mendatangi Rasulullah shallaallahu 'alaihi wa sallam dan mengabarkan keadaan mereka kepada beliau. Lalu beliau berdo'a: ALLAHUMMA HABBIB ILAINAA ALMADINAH KAHUBBINA MAKKATA AW ASYADDA ALLAHUMMA WA SHAHHIHHA WA BAARIK LANAA FI SHAA'IHAA WA MUDDIHA WANQUL HUMMAHA FAJ'ALHA BIL JUHFAH (Ya Allah, jadikanlah kecintaan kami kepada Madinah seperti kecintaan kami kepada Mekkah atau lebih. Ya Allah, perbaikilah ia, Berkahilah kami pada takaran sha' dan mudnya dan pindahkanlah wabah penyakitnya ke Juhfah.\""},"4941":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا عُمَرُ بْنُ سَعِيدِ بْنِ أَبِي حُسَيْنٍ قَالَ حَدَّثَنِي عَطَاءُ بْنُ أَبِي رَبَاحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَنْزَلَ اللَّهُ دَاءً إِلَّا أَنْزَلَ لَهُ شِفَاءً","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abu Ahmad Az Zubairi] telah menceritakan kepada kami ['Umar bin Sa'id bin Abu Husain] dia berkata; telah menceritakan kepadaku ['Atha` bin Abu Rabah] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Allah tidak akan menurunkan penyakit melainkan menurunkan obatnya juga.\""},"4942":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ خَالِدِ بْنِ ذَكْوَانَ عَنْ رُبَيِّعَ بِنْتِ مُعَوِّذِ بْنِ عَفْرَاءَ قَالَتْكُنَّا نَغْزُو مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَسْقِي الْقَوْمَ وَنَخْدُمُهُمْ وَنَرُدُّ الْقَتْلَى وَالْجَرْحَى إِلَى الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Bisyr bin Al Mufadlal] dari [Khalid bin Dzakwan] dari [Rubayyi' binti Mu'awwidz bin 'Afra`] dia berkata; Kami pernah ikut perang bersama Nabi shallallahu 'alaihi wasallam, kami bertugas memberi minum kepada pasukan dan membantu menyiapkan keperluan mereka, serta ikut membawa orang-orang yang gugur dan yang terluka ke Madinah.\""},"4943":{"ar":"حَدَّثَنِي الْحُسَيْنُ حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا مَرْوَانُ بْنُ شُجَاعٍ حَدَّثَنَا سَالِمٌ الْأَفْطَسُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَالشِّفَاءُ فِي ثَلَاثَةٍ شَرْبَةِ عَسَلٍ وَشَرْطَةِ مِحْجَمٍ وَكَيَّةِ نَارٍ وَأَنْهَى أُمَّتِي عَنْ الْكَيِّرَفَعَ الْحَدِيثَ وَرَوَاهُ الْقُمِّيُّ عَنْ لَيْثٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْعَسَلِ وَالْحَجْمِ","id":"Telah menceritakan kepada kami [Al Husain] telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Marwan bin Syuja'] telah menceritakan kepada kami [Salim Al Afthas] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; \"Terapi pengobatan itu ada tiga cara, yaitu minum madu, bekam dan kay (menempelkan besi panas pada daerah yang terluka), sedangkan aku melarang ummatku berobat dengan kay.\" Hadits ini di rafa'kan (kepada Nabi shallallahu 'alaihi wasallam). Dan di riwayatkan pula oleh [Al Qumi] dari [Laits] dari [Mujahid] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam tentang minum madu dan berbekam.\""},"4944":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ أَخْبَرَنَا سُرَيْجُ بْنُ يُونُسَ أَبُو الْحَارِثِ حَدَّثَنَا مَرْوَانُ بْنُ شُجَاعٍ عَنْ سَالِمٍ الْأَفْطَسِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الشِّفَاءُ فِي ثَلَاثَةٍ فِي شَرْطَةِ مِحْجَمٍ أَوْ شَرْبَةِ عَسَلٍ أَوْ كَيَّةٍ بِنَارٍ وَأَنَا أَنْهَى أُمَّتِي عَنْ الْكَيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim] telah mengabarkan kepada kami [Suraij bin Yunus Abu Al Harits] telah menceritakan kepada kami [Marwan bin Suja'] dari [Salim Al Afthas] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Terapi pengobatan itu ada tiga cara, yaitu; berbekam, minum madu dan kay (menempelkan besi panas pada daerah yang terluka), sedangkan aku melarang ummatku berobat dengan kay.\""},"4945":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ أَخْبَرَنِي هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْجِبُهُ الْحَلْوَاءُ وَالْعَسَلُ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Abu Usamah] dia berkata; telah mengabarkan kepadaku [Hisyam] dari [Ayahnya] dari [Aisyah] radliallahu 'anha dia berkata; Nabi shallallahu 'alaihi wasallam sangat menyukai manisan dan madu.\""},"4946":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْغَسِيلِ عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنْ كَانَ فِي شَيْءٍ مِنْ أَدْوِيَتِكُمْ أَوْ يَكُونُ فِي شَيْءٍ مِنْ أَدْوِيَتِكُمْ خَيْرٌ فَفِي شَرْطَةِ مِحْجَمٍ أَوْ شَرْبَةِ عَسَلٍ أَوْ لَذْعَةٍ بِنَارٍ تُوَافِقُ الدَّاءَ وَمَا أُحِبُّ أَنْ أَكْتَوِيَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Abdurrahman bin Al Ghasil] dari ['Ashim bin Umar bin Qatadah] dia berkata; saya mendengar [Jabir bin Abdullah] radliallahu 'anhuma berkata; saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Sekiranya ada obat yang baik untuk kalian atau ada sesuatu yang baik untuk kalian jadikan obat, maka itu terdapat pada bekam atau minum madu atau sengatan api panas (terapi dengan menempelkan besi panas di daerah yang luka) dan saya tidak menyukai kay.\""},"4947":{"ar":"حَدَّثَنَا عَيَّاشُ بْنُ الْوَلِيدِ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَخِي يَشْتَكِي بَطْنَهُ فَقَالَ اسْقِهِ عَسَلًا ثُمَّ أَتَى الثَّانِيَةَ فَقَالَ اسْقِهِ عَسَلًا ثُمَّ أَتَاهُ الثَّالِثَةَ فَقَالَ اسْقِهِ عَسَلًا ثُمَّ أَتَاهُ فَقَالَ قَدْ فَعَلْتُ فَقَالَ صَدَقَ اللَّهُ وَكَذَبَ بَطْنُ أَخِيكَ اسْقِهِ عَسَلًا فَسَقَاهُ فَبَرَأَ","id":"Telah menceritakan kepada kami [Ayyas bin Al Walid] telah menceritakan kepada kami [Abdul A'la] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Abu Al Mutawakkil] dari [Abu Sa'id] bahwa seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam sambil berkata; \"Saudaraku sedang menderita sakit perut.\" Beliau bersabda: \"Minumilah madu.\" Kemudian laki-laki itu datang kedua kalinya, lalu beliau tetap bersabda: \"Minumilah madu.\" Kemudian laki-laki itu datang yang ketiga kalinya, beliau bersabda: \"Minumilah madu.\" Kemudian dia datang lagi sambil berkata; \"Aku telah melakukannya.\" Maka beliau bersabda: \"Maha benar Allah, dan perut saudaramulah yang berdusta, berilah minum madu.\" Lalu ia pun meminuminya madu dan akhirnya sembuh."},"4948":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا سَلَّامُ بْنُ مِسْكِينٍ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍأَنَّ نَاسًا كَانَ بِهِمْ سَقَمٌ قَالُوا يَا رَسُولَ اللَّهِ آوِنَا وَأَطْعِمْنَا فَلَمَّا صَحُّوا قَالُوا إِنَّ الْمَدِينَةَ وَخِمَةٌ فَأَنْزَلَهُمْ الْحَرَّةَ فِي ذَوْدٍ لَهُ فَقَالَ اشْرَبُوا أَلْبَانَهَا فَلَمَّا صَحُّوا قَتَلُوا رَاعِيَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتَاقُوا ذَوْدَهُ فَبَعَثَ فِي آثَارِهِمْ فَقَطَعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَرَ أَعْيُنَهُمْ فَرَأَيْتُ الرَّجُلَ مِنْهُمْ يَكْدِمُ الْأَرْضَ بِلِسَانِهِ حَتَّى يَمُوتَقَالَ سَلَّامٌ فَبَلَغَنِي أَنَّ الْحَجَّاجَ قَالَ لِأَنَسٍ حَدِّثْنِي بِأَشَدِّ عُقُوبَةٍ عَاقَبَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَدَّثَهُ بِهَذَا فَبَلَغَ الْحَسَنَ فَقَالَ وَدِدْتُ أَنَّهُ لَمْ يُحَدِّثْهُ بِهَذَا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Sallam bin Miskin] telah menceritakan kepada kami [Tsabit] dari [Anas] bahwa beberapa orang sedang menderita sakit, lalu mereka berkata; \"Wahai Rasulullah, berilah kami tempat untuk menginap dan jamulah kami, ketika keadaan mereka mulai membaik, mereka berkata; \"Sesungguhnya kota Madinah tidak cocok untuk kami, \" lantas beliau menyuruh mereka supaya pergi ke padang tempat gembalaan unta-unta milik beliau, lalu beliau bersabda: \"Setelah itu minumlah susunya.\" Ketika mereka semuanya sehat, ternyata mereka membunuh penggembala Nabi shallallahu 'alaihi wasallam dan merampok sejumlah unta beliau, maka beliau memerintahkan untuk mengejar mereka. Kemudian beliau memotong tangan-tangan mereka dan kaki-kaki mereka serta mencongkel mata mereka, dan aku melihat salah seorang dari mereka menjulurkan lidahnya ke tanah sampai akhirnya mati terkapar.\" Sallam berkata; telah sampai kepadaku bahwa Al Hajjaj pernah berkata kepada Anas; \"Ceritakanlah kepadaku tentang hukuman yang paling sadis yang pernah di lakukan oleh Nabi shallallahu 'alaihi wasallam, lalu Anas menceritakan hadits di atas, ternyata hal itu sampai kepada Al Hasan, maka dia berkata; \"Aku menyangka bahwa Anas belum pernah menyampaikan hadits ini.\""},"4949":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ نَاسًا اجْتَوَوْا فِي الْمَدِينَةِ فَأَمَرَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَلْحَقُوا بِرَاعِيهِ يَعْنِي الْإِبِلَ فَيَشْرَبُوا مِنْ أَلْبَانِهَا وَأَبْوَالِهَا فَلَحِقُوا بِرَاعِيهِ فَشَرِبُوا مِنْ أَلْبَانِهَا وَأَبْوَالِهَا حَتَّى صَلَحَتْ أَبْدَانُهُمْ فَقَتَلُوا الرَّاعِيَ وَسَاقُوا الْإِبِلَ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَ فِي طَلَبِهِمْ فَجِيءَ بِهِمْ فَقَطَعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَرَ أَعْيُنَهُمْقَالَ قَتَادَةُ فَحَدَّثَنِي مُحَمَّدُ بْنُ سِيرِينَأَنَّ ذَلِكَ كَانَ قَبْلَ أَنْ تَنْزِلَ الْحُدُودُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas] radliallahu 'anhu bahwa sekelompok orang sedang menderita sakit ketika berada di Madinah, maka Nabi shallallahu 'alaihi wasallam memerintahkan mereka supaya menemui penggembala beliau dan meminum susu dan kencing unta, mereka lalu pergi menemui sang penggembala dan meminum air susu dan kencing unta tersebut sehingga badan-badan mereka kembali sehat, setelah badan mereka sehat mereka justru membunuh penggembala dan merampok unta-untanya, setelah kabar itu sampai ke nabi shallallahu 'alaihi wasallam, beliau pun memerintahkan untuk mengejar mereka, kemudian mereka di bawa ke hadapan Nabi, lantas Nabi memotong tangan dan kaki mereka serta mencongkel mata mereka.\" Qatadah berkata; telah menceritakan kepadaku Muhammad bin Sirin bahwa peristiwa tersebut terjadi sebelum turunnya ayat tentang hudud (hukuman).\""},"4950":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ حَدَّثَنَا إِسْرَائِيلُ عَنْ مَنْصُورٍ عَنْ خَالِدِ بْنِ سَعْدٍ قَالَ خَرَجْنَا وَمَعَنَا غَالِبُ بْنُ أَبْجَرَ فَمَرِضَ فِي الطَّرِيقِ فَقَدِمْنَا الْمَدِينَةَ وَهُوَ مَرِيضٌ فَعَادَهُ ابْنُ أَبِي عَتِيقٍ فَقَالَلَنَا عَلَيْكُمْ بِهَذِهِ الْحُبَيْبَةِ السَّوْدَاءِ فَخُذُوا مِنْهَا خَمْسًا أَوْ سَبْعًا فَاسْحَقُوهَا ثُمَّ اقْطُرُوهَا فِي أَنْفِهِ بِقَطَرَاتِ زَيْتٍ فِي هَذَا الْجَانِبِ وَفِي هَذَا الْجَانِبِ فَإِنَّ عَائِشَةَ حَدَّثَتْنِيأَنَّهَا سَمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ هَذِهِ الْحَبَّةَ السَّوْدَاءَ شِفَاءٌ مِنْ كُلِّ دَاءٍ إِلَّا مِنْ السَّامِ قُلْتُ وَمَا السَّامُ قَالَ الْمَوْتُ","id":"Telah menceritakan kepada kami [Abdullah bin Abu Syaibah] telah menceritakan kepada kami ['Ubaidullah] telah menceritakan kepada kami [Isra`il] dari [Manshur] dari [Khalid bin Sa'd] dia berkata; Kami pernah bepergian yang di antaranya terdapat Ghalib bin Abjar, di tengah jalan ia jatuh sakit, ketika sampai di Madinah ia masih menderita sakit, lalu [Ibnu Abu 'Atiq] menjenguknya dan berkata kepada kami; \"Hendaknya kalian memberinya habbatus sauda' (jintan hitam), ambillah lima atau tujuh biji, lalu tumbuklah hingga halus, setelah itu teteskanlah di hidungnya di sertai dengan tetesan minyak sebelah sini dan sebelah sini, karena sesungguhnya [Aisyah] pernah menceritakan kepadaku bahwa dia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya habbatus sauda' ini adalah obat dari segala macam penyakit kecuali saam.\" Aku bertanya; \"Apakah saam itu?\" beliau menjawab: \"Kematian.\""},"4951":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ وَسَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرَهُمَا أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي الْحَبَّةِ السَّوْدَاءِ شِفَاءٌ مِنْ كُلِّ دَاءٍ إِلَّا السَّامَ قَالَ ابْنُ شِهَابٍ وَالسَّامُ الْمَوْتُ وَالْحَبَّةُ السَّوْدَاءُ الشُّونِيزُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Abu Salamah] dan [Sa'id bin Musayyib] bahwa [Abu Hurairah] telah mengabarkan kepada keduanya, bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dalam habbatus sauda' (jintan hitam) terdapat obat dari segala penyakit kecuali kematian.\" Ibnu Syihab berkata; \"Maksud dari kematian adalah maut sedangkan habbatus sauda' adalah pohon syuniz.\""},"4952":{"ar":"حَدَّثَنَا حِبَّانُ بْنُ مُوسَى أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ بْنُ يَزِيدَ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّهَا كَانَتْ تَأْمُرُ بِالتَّلْبِينِ لِلْمَرِيضِ وَلِلْمَحْزُونِ عَلَى الْهَالِكِ وَكَانَتْ تَقُولُ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ التَّلْبِينَةَ تُجِمُّ فُؤَادَ الْمَرِيضِ وَتَذْهَبُ بِبَعْضِ الْحُزْنِ","id":"Telah menceritakan kepada kami [Hibban bin Musa] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus bin Yazid] dari ['Uqail] dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah] radliallahu 'anha bahwa dia memerintahkan untuk menkonsumsi talbinah (adonan yang terbuat dari gandum dan buah kurma) untuk orang yang sakit dan orang yang sedih karena musibah yang menimpanya, dia juga berkata; \"Sesungguhnya saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya talbinah (adonan yang terbuat dari gandum dan buah kurma) itu dapat menyembuhkan hati yang sakit dan menghilangkan kesedihan.\""},"4953":{"ar":"حَدَّثَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّهَا كَانَتْ تَأْمُرُ بِالتَّلْبِينَةِ وَتَقُولُ هُوَ الْبَغِيضُ النَّافِعُ","id":"Telah menceritakan kepada kami [Farwah bin Abu Al Maghra`] telah menceritakan kepada kami [Ali bin Mushir] telah menceritakan kepada kami [Hisyam] dari [Ayahnya] dari ['Aisyah] bahwa dia juga memeritahkan supaya menkonsumsi talbinah (adonan yang terbuat dari gandum dan buah kurma), katanya; \"Talbinah adalah obat yang tidak di sukai namun sangat bermanfa'at.\""},"4954":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ وَأَعْطَى الْحَجَّامَ أَجْرَهُ وَاسْتَعَطَ","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] telah menceritakan kepada kami [Wuhaib] dari [Ibnu Thawus] dari [Ayahnya] dari [Ibnu Abbas] radliallahu 'anhuma dari Nabi shallallahu 'alaihi wasallam bahwa beliau pernah berbekam dan mengupah orang yang membekamnya sambil bergurah (memasukkan obat ke hidung untuk mengeluarkan kotoran yang ada dalam tenggorokan).\""},"4955":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا ابْنُ عُيَيْنَةَ قَالَ سَمِعْتُ الزُّهْرِيَّ عَنْ عُبَيْدِ اللَّهِ عَنْ أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍ قَالَتْ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَلَيْكُمْ بِهَذَا الْعُودِ الْهِنْدِيِّ فَإِنَّ فِيهِ سَبْعَةَ أَشْفِيَةٍ يُسْتَعَطُ بِهِ مِنْ الْعُذْرَةِ وَيُلَدُّ بِهِ مِنْ ذَاتِ الْجَنْبِوَدَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِابْنٍ لِي لَمْ يَأْكُلْ الطَّعَامَ فَبَالَ عَلَيْهِ فَدَعَا بِمَاءٍ فَرَشَّ عَلَيْهِ","id":"Telah menceritakan kepada kami [Shadaqah bin Al Fadl] telah mengabarkan kepada kami [Ibnu 'Uyainah] dia berkata; saya mendengar [Az Zuhri] dari ['Ubaidullah] dari [Ummu Qais binti Mihshan] berkata; saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Gunakanlah dahan kayu India, karena didalamnya terdapat tujuh macam penyembuh, dan dapat menghilangkan penyakit (racun) di antaranya adalah radang penyakit paru.' Ibnu Sam'an berkata dalam haditsnya; \"Karena sesungguhnya padanya terdapat obat dari tujuh macam jenis penyakit, di antaranya adalah radang penyakit paru (dada).\" Lalu aku menemui Nabi shallallahu 'alaihi wasallam sambil membawa bayiku yang belum makan makanan, lalu bayiku mengencingi beliau, maka beliau meminta air dan memercikinya.\""},"4956":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَاحْتَجَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ صَائِمٌ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] dia berkata; \"Nabi shallallahu 'alaihi wasallam pernah berbekam ketika sedang berpuasa.\""},"4957":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ طَاوُسٍ وَعَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَاحْتَجَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُحْرِمٌ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Thawus] dan ['Atha`] dari [Ibnu Abbas] dia berkata; \"Nabi shallallahu 'alaihi wasallam pernah berbekam ketika beliau sedang ihram.\""},"4958":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا حُمَيْدٌ الطَّوِيلُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّهُ سُئِلَ عَنْ أَجْرِ الْحَجَّامِ فَقَالَ احْتَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَجَمَهُ أَبُو طَيْبَةَ وَأَعْطَاهُ صَاعَيْنِ مِنْ طَعَامٍ وَكَلَّمَ مَوَالِيَهُ فَخَفَّفُوا عَنْهُ وَقَالَ إِنَّ أَمْثَلَ مَا تَدَاوَيْتُمْ بِهِ الْحِجَامَةُ وَالْقُسْطُ الْبَحْرِيُّ وَقَالَ لَا تُعَذِّبُوا صِبْيَانَكُمْ بِالْغَمْزِ مِنْ الْعُذْرَةِ وَعَلَيْكُمْ بِالْقُسْطِ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Humaid Ath Thawil] dari [Anas] radliallahu 'anhu bahwa dia di tanya mengenai upah tukang bekam, dia menjawab; \"Abu Thaibah pernah membekam Rasulullah shallallahu 'alaihi wasallam, lalu beliau memberinya dua sha' makanan dan meyarankan supaya meringankan beban hamba sahayanya, setelah itu beliau bersabda: \"Sebaik-baik sesuatu yang kalian gunakan untuk obat adalah bekam dan terapi kayu gaharu\", beliau juga bersabda: \"Dan janganlah kalian sakiti anak kalian dengan memasukkan jari ke dalam mulut.\""},"4959":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ تَلِيدٍ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرٌو وَغَيْرُهُ أَنَّ بُكَيْرًا حَدَّثَهُ أَنَّ عَاصِمَ بْنَ عُمَرَ بْنِ قَتَادَةَ حَدَّثَهُ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاعَادَ الْمُقَنَّعَ ثُمَّ قَالَ لَا أَبْرَحُ حَتَّى تَحْتَجِمَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ فِيهِ شِفَاءً","id":"Telah menceritakan kepada kami [Sa'id bin Talid] dia berkata; telah menceritakan kepadaku [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku ['Amru] dan yang lainnya, bahwa [Bukair] telah menceritakan kepadanya bahwa ['Ashim bin Umar bin Qatadah] menceritakan kepadanya bahwa [Jabir bin Abdullah] radliallahu 'anhuma pernah menjenguk Muqanna' kemudian dia berkata; \"Kamu tidak akan sembuh hingga berbekam, karena aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya padanya terdapat obat.\""},"4960":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي سُلَيْمَانُ عَنْ عَلْقَمَةَ أَنَّهُ سَمِعَ عَبْدَ الرَّحْمَنِ الْأَعْرَجَ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ ابْنَ بُحَيْنَةَ يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ بِلَحْيِ جَمَلٍ مِنْ طَرِيقِ مَكَّةَ وَهُوَ مُحْرِمٌ فِي وَسَطِ رَأْسِهِوَقَالَ الْأَنْصَارِيُّ أَخْبَرَنَا هِشَامُ بْنُ حَسَّانَ حَدَّثَنَا عِكْرِمَةُ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ فِي رَأْسِهِ","id":"Telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Sulaiman] dari ['Alqamah] bahwa dia mendengar [Abdurrahman Al A'raj] bahwa dia mendengar [Abdullah bin Buhainah] menceritakan bahwa Rasulullah shallallahu 'alaihi wasallam pernah berbekam di tengah-tengah kepalanya ketika di lahyil jamal yaitu ketika hendak menuju Makkah, sementara beliau sedang berihram.\" [Al Anshari] berkata; telah mengabarkan kepada kami [Hisyam bin Hasan] telah menceritakan kepada kami [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma bahwa Rasulullah shallallahu 'alaihi wasallam pernah berbekam di kepalanya.\""},"4961":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ هِشَامٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍاحْتَجَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَأْسِهِ وَهُوَ مُحْرِمٌ مِنْ وَجَعٍ كَانَ بِهِ بِمَاءٍ يُقَالُ لَهُ لُحْيُ جَمَلٍوَقَالَ مُحَمَّدُ بْنُ سَوَاءٍ أَخْبَرَنَا هِشَامٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ وَهُوَ مُحْرِمٌ فِي رَأْسِهِ مِنْ شَقِيقَةٍ كَانَتْ بِهِ","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Hisyam] dari [Ikrimah] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam pernah berbekam di kepalanya karena rasa sakit yang di deritanya sementara beliau sedang berihram, ketika itu beliau singgah di dekat mata air yang bernama Lahyil Jamal.\" [Muhammad bin Sawa'] juga berkata; telah mengabarkan kepada kami [Hisyam] dari [Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam pernah berbekam di kepalanya karena rasa sakit yang di deritanya ketika sedang berihram.\""},"4962":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبَانَ حَدَّثَنَا ابْنُ الْغَسِيلِ قَالَ حَدَّثَنِي عَاصِمُ بْنُ عُمَرَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنْ كَانَ فِي شَيْءٍ مِنْ أَدْوِيَتِكُمْ خَيْرٌ فَفِي شَرْبَةِ عَسَلٍ أَوْ شَرْطَةِ مِحْجَمٍ أَوْ لَذْعَةٍ مِنْ نَارٍ وَمَا أُحِبُّ أَنْ أَكْتَوِيَ","id":"Telah menceritakan kepada kami [Isma'il bin Aban] telah menceritakan kepada kami [Ibnu Al Ghasil] dia berkata; telah menceritakan kepadaku ['Ashim bin Umar] dari [Jabir bin Abdullah] dia berkata; saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Sekiranya ada sesuatu yang lebih baik untuk kalian pergunakan sebagai obat, maka itu ada terdapat pada minum madu, berbekam dan sengatan api panas (terapi dengan menempelkan besi panas di daerah yang luka) dan saya tidak menyukai kay (terapi dengan menempelkan besi panas pada daerah yang luka).\""},"4963":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ قَالَ سَمِعْتُ مُجَاهِدًا عَنْ ابْنِ أَبِي لَيْلَى عَنْ كَعْبٍ هُوَ ابْنُ عُجْرَةَ قَالَأَتَى عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَمَنَ الْحُدَيْبِيَةِ وَأَنَا أُوقِدُ تَحْتَ بُرْمَةٍ وَالْقَمْلُ يَتَنَاثَرُ عَنْ رَأْسِي فَقَالَ أَيُؤْذِيكَ هَوَامُّكَ قُلْتُ نَعَمْ قَالَ فَاحْلِقْ وَصُمْ ثَلَاثَةَ أَيَّامٍ أَوْ أَطْعِمْ سِتَّةً أَوْ انْسُكْ نَسِيكَةً قَالَ أَيُّوبُ لَا أَدْرِي بِأَيَّتِهِنَّ بَدَأَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad] dari [Ayyub] dia berkata; saya mendengar [Mujahid] dari [Ibnu Abu Laila] dari [Ka'b bin 'Ujrah] dia berkata; Nabi shallallahu 'alaihi wasallam menemuiku pada peristiwa Hudaibiyah, sementara aku sedang menyalakan api di bawah tungku, karena banyaknya kutu yang ada di rambutku, maka beliau bertanya: \"Apakah hal itu sangat mengganggumu?\" jawabku; \"Ya\" beliau bersabda: \"Cukurlah lalu berpuasalah tiga hari atau berilah makan kepada enam orang miskin atau berkurbanlah.\" Ayyub berkata; \"Aku tidak tahu manakah di antara ketiga fidyah tersebut yang lebih dulu di kerjakan.\""},"4964":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ هِشَامُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سُلَيْمَانَ بْنِ الْغَسِيلِ حَدَّثَنَا عَاصِمُ بْنُ عُمَرَ بْنِ قَتَادَةَ قَالَ سَمِعْتُ جَابِرًاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنْ كَانَ فِي شَيْءٍ مِنْ أَدْوِيَتِكُمْ شِفَاءٌ فَفِي شَرْطَةِ مِحْجَمٍ أَوْ لَذْعَةٍ بِنَارٍ وَمَا أُحِبُّ أَنْ أَكْتَوِيَ","id":"Telah menceritakan kepada kami [Abu Al Walid Hisyam bin Abdul Malik] telah menceritakan kepada kami [Abdurrahman bin Sulaiman bin Al Ghasil] telah menceritakan kepada kami ['Ashim bin Umar bin Qatadah] dia berkata; saya mendegar [Jabir] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sekiranya ada pengobatan yang baik untuk kalian jadikan sebagai obat, maka itu ada terdapat pada bekam dan sengatan api panas (terapi dengan menempelkan besi panas di daerah yang luka) namun aku tidak menyukai kay (terapi dengan menempelkan besi panas pada daerah yang luka).\""},"4965":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مَيْسَرَةَ حَدَّثَنَا ابْنُ فُضَيْلٍ حَدَّثَنَا حُصَيْنٌ عَنْ عَامِرٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ لَا رُقْيَةَ إِلَّا مِنْ عَيْنٍ أَوْ حُمَةٍ فَذَكَرْتُهُ لِسَعِيدِ بْنِ جُبَيْرٍ فَقَالَ حَدَّثَنَا ابْنُ عَبَّاسٍقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُرِضَتْ عَلَيَّ الْأُمَمُ فَجَعَلَ النَّبِيُّ وَالنَّبِيَّانِ يَمُرُّونَ مَعَهُمْ الرَّهْطُ وَالنَّبِيُّ لَيْسَ مَعَهُ أَحَدٌ حَتَّى رُفِعَ لِي سَوَادٌ عَظِيمٌ قُلْتُ مَا هَذَا أُمَّتِي هَذِهِ قِيلَ بَلْ هَذَا مُوسَى وَقَوْمُهُ قِيلَ انْظُرْ إِلَى الْأُفُقِ فَإِذَا سَوَادٌ يَمْلَأُ الْأُفُقَ ثُمَّ قِيلَ لِي انْظُرْ هَا هُنَا وَهَا هُنَا فِي آفَاقِ السَّمَاءِ فَإِذَا سَوَادٌ قَدْ مَلَأَ الْأُفُقَ قِيلَ هَذِهِ أُمَّتُكَ وَيَدْخُلُ الْجَنَّةَ مِنْ هَؤُلَاءِ سَبْعُونَ أَلْفًا بِغَيْرِ حِسَابٍ ثُمَّ دَخَلَ وَلَمْ يُبَيِّنْ لَهُمْ فَأَفَاضَ الْقَوْمُ وَقَالُوا نَحْنُ الَّذِينَ آمَنَّا بِاللَّهِ وَاتَّبَعْنَا رَسُولَهُ فَنَحْنُ هُمْ أَوْ أَوْلَادُنَا الَّذِينَ وُلِدُوا فِي الْإِسْلَامِ فَإِنَّا وُلِدْنَا فِي الْجَاهِلِيَّةِ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ فَقَالَ هُمْ الَّذِينَ لَا يَسْتَرْقُونَ وَلَا يَتَطَيَّرُونَ وَلَا يَكْتَوُونَ وَعَلَى رَبِّهِمْ يَتَوَكَّلُونَ فَقَالَ عُكَاشَةُ بْنُ مِحْصَنٍ أَمِنْهُمْ أَنَا يَا رَسُولَ اللَّهِ قَالَ نَعَمْ فَقَامَ آخَرُ فَقَالَ أَمِنْهُمْ أَنَا قَالَ سَبَقَكَ بِهَا عُكَّاشَةُ","id":"Telah menceritakan kepada kami [Imran bin Maisarah] telah menceritakan kepada kami [Ibnu Al Fudlail] telah menceritakan kepada kami [Hushain] dari ['Amir] dari [Imran bin Hushain] radliallahu 'anhuma dia berkata; \"Tidak ada ruqyah (jampi-jampi dari Qur'an dan Sunnah) kecuali dari penyakit 'Ain atau demam, lalu hal itu kusampaikan kepada [Sa'id bin Jubair], dia berkata; telah menceritakan kepada kami [Ibnu Abbas] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Beberapa ummat pernah ditampakkan kepadaku, maka nampaklah seorang nabi dan dua orang nabi lain lewat bersama dengan beberapa orang saja, dan seorang nabi lagi yang tidak bersama seorang pun, hingga tampak olehku segerombolan manusia yang sangat banyak, aku pun bertanya; \"Apakah segerombolan manusia itu adalah ummatku?\" di beritahukan; \"Ini adalah Musa dan kaumnya.\" Lalu diberitahukan pula kepadaku; \"Lihatlah ke ufuk.\" Ternyata di sana terdapat segerombolan manusia yang memenuhi ufuk, kemduian di beritahukan kepadaku; \"Lihatlah di sebelah sini dan di sebelah sana, yaitu di ufuk langit.\" Ternyata di sana telah di padati dengan segerombolan manusia yang sangat banyak, \" di beritahukan kepadaku; \"Ini adalah ummatmu, dan di antara mereka terdapat tujuh puluh ribu yang masuk surga tanpa hisab.\" Setelah itu beliau masuk ke rumah dan belum sempat memberi penjelasan kepada mereka (para sahabat), maka orang-orang menjadi ribut, mereka berkata; \"Kita adalah orang-orang yang telah beriman kepada Allah dan mengikuti jejak Rasul-Nya, mungkinkah kelompok tersebut adalah kita ataukah anak-anak kita yang dilahirkan dalam keadaan Islam sementara kita dilahirkan di zaman Jahiliyah.\" Maka hal itu sampai kepada Nabi shallallahu 'alaihi wasallam, lantas beliau keluar dan bersabda: \"Mereka adalah orang-orang yang tidak pernah minta untuk di ruqyah, tidak pernah bertathayur (menganggap sial pada binatang) dan tidak pula melakukan terapi dengan kay (terapi dengan menempelkan besi panas pada daerah yang sakit), sedangkan kepada Rabb mereka bertawakkal.\" Lalu Ukasah bin Mihshan berkata; \"Apakah aku termasuk di antara mereka ya Rasulullah?\" beliau menjawab; \"Ya.\" Selanjutnya sahabat yang lain berdiri dan berkata; \"Apakah aku termasuk dari mereka?\" beliau bersabda: \"Ukasah telah mendahuluimu.\""},"4966":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ قَالَ حَدَّثَنِي حُمَيْدُ بْنُ نَافِعٍ عَنْ زَيْنَبَ عَنْ أُمِّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ امْرَأَةً تُوُفِّيَ زَوْجُهَا فَاشْتَكَتْ عَيْنَهَا فَذَكَرُوهَا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَكَرُوا لَهُ الْكُحْلَ وَأَنَّهُ يُخَافُ عَلَى عَيْنِهَا فَقَالَ لَقَدْ كَانَتْ إِحْدَاكُنَّ تَمْكُثُ فِي بَيْتِهَا فِي شَرِّ أَحْلَاسِهَا أَوْ فِي أَحْلَاسِهَا فِي شَرِّ بَيْتِهَا فَإِذَا مَرَّ كَلْبٌ رَمَتْ بَعْرَةً فَهَلَّا أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Syu'bah] dia berkata; telah menceritakan kepadaku [Humaid bin Nafi'] dari [Zainab] dari [Ummu Salamah] radliallahu 'anha bahwa seorang wanita ditinggal mati oleh suaminya, hingga matanya menjadi bengkak (karena sering menangis), lantas orang-orang mengadukan hal itu kepada Nabi shallallahu 'alaihi wasallam dan mereka juga menyebutkan supaya wanita itu menggunakan celak karena khawatir matanya akan semakin parah, maka beliau bersabda: \"Sungguh dahulu salah seorang dari kalian pernah tinggal di rumah yang paling jelek -atau di sejelek-jelek rumah- (perawi ragu mengenai redaksi haditsnya), jika ada seekor anjing yang lewat, maka dia akan melemparnya dengan kotoran, kenapa tidak cukup waktu hanya empat bulan sepuluh hari untuk tinggal di rumahnya?\""},"4967":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ سَمِعْتُ عَمْرُو بْنَ حُرَيْثٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ زَيْدٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْكَمْأَةُ مِنْ الْمَنِّ وَمَاؤُهَا شِفَاءٌ لِلْعَيْنِقَالَ شُعْبَةُ وَأَخْبَرَنِي الْحَكَمُ بْنُ عُتَيْبَةَ عَنْ الْحَسَنِ الْعُرَنِيِّ عَنْ عَمْرِو بْنِ حُرَيْثٍ عَنْ سَعِيدِ بْنِ زَيْدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ شُعْبَةُ لَمَّا حَدَّثَنِي بِهِ الْحَكَمُ لَمْ أُنْكِرْهُ مِنْ حَدِيثِ عَبْدِ الْمَلِكِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik] saya mendengar ['Amru bin Huraits] berkata; saya mendengar [Sa'id bin Zaid] berkata; saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Cendawan berasal dari al Manna, dan airnya merupakan obat untuk penyakit mata.\" [Syu'bah] berkata, dan telah mengabarkan kepadaku [Al Hakam bin 'Utbah] dari [Al Hasan Al 'Urani] dari ['Amru bin Huraits] dari [Sa'id bin Zaid] dari Nabi shallallahu 'alaihi wasallam. Syu'bah berkata, tatkala Al Hakam menceritakan hadits kepadaku aku tidak mengingkarinya dari hadits Abdul Malik."},"4968":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي مُوسَى بْنُ أَبِي عَائِشَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ وَعَائِشَةَأَنَّ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُ قَبَّلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مَيِّتٌقَالَ وَقَالَتْ عَائِشَةُ لَدَدْنَاهُ فِي مَرَضِهِ فَجَعَلَ يُشِيرُ إِلَيْنَا أَنْ لَا تَلُدُّونِي فَقُلْنَا كَرَاهِيَةُ الْمَرِيضِ لِلدَّوَاءِ فَلَمَّا أَفَاقَ قَالَ أَلَمْ أَنْهَكُمْ أَنْ تَلُدُّونِي قُلْنَا كَرَاهِيَةَ الْمَرِيضِ لِلدَّوَاءِ فَقَالَ لَا يَبْقَى فِي الْبَيْتِ أَحَدٌ إِلَّا لُدَّ وَأَنَا أَنْظُرُ إِلَّا الْعَبَّاسَ فَإِنَّهُ لَمْ يَشْهَدْكُمْ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepadaku [Musa bin Abu 'Aisyah] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dan ['Aisyah] bahwa [Abu Bakar] radliallahu 'anhu pernah mencium nabi shallallahu 'alaihi wasallam ketika beliau wafat, selanjutnya Aisyah berkata; \"Kami memasukkan obat melalui mulut beliau ketika beliau sakit, lalu beliau memberi isyarat kepada kami dengan mengatakan: \"Janganlah kalian memasukkan obat lewat mulutku (dengan paksa).\" Maka kami berkata; \"Ah, itu biasa, memang orang sakit tidak suka obat.\" Ketika beliau tersadar, beliau bersabda: \"Tidakkah aku telah melarang kalian memasukkan obat kedalam mulutku!, janganlah kalian memasukkan obat ke dalam mulutku.\" Kami pun berkata; \"Ah biasa, memang orang sakit tidak suka obat.\" Lalu beliau bersabda: \"Tidak ada seorangpun dalam rumah kecuali dirinya harus di obati (dengan paksa) melalui mulutnya kecuali Abbas, karena ia tidak bersama kalian.\""},"4969":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ عَنْ أُمِّ قَيْسٍ قَالَتْدَخَلْتُ بِابْنٍ لِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ أَعْلَقْتُ عَلَيْهِ مِنْ الْعُذْرَةِ فَقَالَ عَلَى مَا تَدْغَرْنَ أَوْلَادَكُنَّ بِهَذَا الْعِلَاقِ عَلَيْكُنَّ بِهَذَا الْعُودِ الْهِنْدِيِّ فَإِنَّ فِيهِ سَبْعَةَ أَشْفِيَةٍ مِنْهَا ذَاتُ الْجَنْبِ يُسْعَطُ مِنْ الْعُذْرَةِ وَيُلَدُّ مِنْ ذَاتِ الْجَنْبِ فَسَمِعْتُ الزُّهْرِيَّ يَقُولُ بَيَّنَ لَنَا اثْنَيْنِ وَلَمْ يُبَيِّنْ لَنَا خَمْسَةً قُلْتُ لِسُفْيَانَ فَإِنَّ مَعْمَرًا يَقُولُ أَعْلَقْتُ عَلَيْهِ قَالَ لَمْ يَحْفَظْ إِنَّمَا قَالَ أَعْلَقْتُ عَنْهُ حَفِظْتُهُ مِنْ فِي الزُّهْرِيِّ وَوَصَفَ سُفْيَانُ الْغُلَامَ يُحَنَّكُ بِالْإِصْبَعِ وَأَدْخَلَ سُفْيَانُ فِي حَنَكِهِ إِنَّمَا يَعْنِي رَفْعَ حَنَكِهِ بِإِصْبَعِهِ وَلَمْ يَقُلْ أَعْلِقُوا عَنْهُ شَيْئًا","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] telah mengabarkan kepadaku ['Ubaidullah bin Abdullah] dari [Ummu Qais] dia berkata; Aku mengunjungi Nabi shallallahu 'alaihi wasallam bersama anakku yang baru saja saya obati kerongkongannya dengan tanganku, maka beliau bersabda: \"Dengan maksud apa kamu mengobati penyakit tenggorokan anakmu dengan memasukkan jemari tangan? Gunakanlah kayu India, karena padanya terdapat tujuh ragam penyembuhan, dan dapat di masukkan sebagai obat tetes hidung untuk menyembuhkan penyakit kerongkongan dan dapat pula menjadi penyembuh dari penyakit radang selaput dada.\" Aku mendengar Az Zuhri berkata; \"Dua hal telah dijelaskan kepadaku, namun aku belum mendapatkan penjelasan mengenai yang lima hal lagi, lalu aku berkata kepada Sufyan, sesungguhnya Ma'mar pernah berkata dengan lafazh; 'A'laqtu 'alaihi', perawi berkata; \"Bahwa Ma'mar belum pernah mendengarnya, karena Sufyan hanya mengatakan dengan redaksi; \"A'laqtu 'anhu, aku pernah mendengarnya langsung dari mulut Az Zuhri bahwa Sufyan mensifati seorang anak kecil yang ditahnik (mengunyahkan kurma kemudian dimasukkan ke dalam mulut bayi) dengan jari, kemudian Sufyan memasukkan jarinya ke kerongkongan, maka maksud dari hadits di atas adalah mengangkat kerongkongan dengan jari-jari (yaitu dengan memasukkan jari-jari melalui mulut), dan dia tidak mengatakan; \"Menggantungkan sesuatu padanya.\""},"4970":{"ar":"بَاب حَدَّثَنَا بِشْرُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ وَيُونُسُ قَالَ الزُّهْرِيُّ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ لَمَّا ثَقُلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاشْتَدَّ وَجَعُهُ اسْتَأْذَنَ أَزْوَاجَهُ فِي أَنْ يُمَرَّضَ فِي بَيْتِي فَأَذِنَّ لَهُ فَخَرَجَ بَيْنَ رَجُلَيْنِ تَخُطُّ رِجْلَاهُ فِي الْأَرْضِ بَيْنَ عَبَّاسٍ وَآخَرَ فَأَخْبَرْتُ ابْنَ عَبَّاسٍ قَالَ هَلْ تَدْرِي مَنْ الرَّجُلُ الْآخَرُ الَّذِي لَمْ تُسَمِّ عَائِشَةُ قُلْتُ لَا قَالَ هُوَ عَلِيٌّ قَالَتْ عَائِشَةُفَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ مَا دَخَلَ بَيْتَهَا وَاشْتَدَّ بِهِ وَجَعُهُ هَرِيقُوا عَلَيَّ مِنْ سَبْعِ قِرَبٍ لَمْ تُحْلَلْ أَوْكِيَتُهُنَّ لَعَلِّي أَعْهَدُ إِلَى النَّاسِ قَالَتْ فَأَجْلَسْنَاهُ فِي مِخْضَبٍ لِحَفْصَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ طَفِقْنَا نَصُبُّ عَلَيْهِ مِنْ تِلْكَ الْقِرَبِ حَتَّى جَعَلَ يُشِيرُ إِلَيْنَا أَنْ قَدْ فَعَلْتُنَّ قَالَتْ وَخَرَجَ إِلَى النَّاسِ فَصَلَّى لَهُمْ وَخَطَبَهُمْ","id":"Telah menceritakan kepada kami [Bisyr bin Muhammad] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dan [Yunus], [Az Zuhri] mengatakan; telah mengabarkan kepadaku [Ubaidullah bin Abdullah bin 'Utbah] bahwa [Aisyah] radliallahu 'anha yaitu isteri nabi shallallahu 'alaihi wasallam berkata; \"Ketika sakit Rasulullah shallallahu 'alaihi wasallam semakin parah, beliau meminta izin kepada para isterinya supaya di rawat di rumahku, setelah para isterinya mengizinkan beliau (tinggal di rumahku), beliau keluar dengan dibopong dua orang yaitu beliau berada di antara Abbas dan laki-laki lain, sementara kaki beliau tertatih-tatih di tanah.\" Lalu kuberitahukan hal itu kepada [Ibnu Abbas], dia berkata; \"Tahukah kamu siapakah yang dimaksud Aisyah dengan laki-laki lain itu?\" aku menjawab; \"Tidak.\" Ibnu Abbas berkata; \"Dia adalah Ali.\" Aisyah berkata lagi; Setelah Nabi shallallahu 'alaihi wasallam masuk ke rumahnya sementara sakitnya semakin parah, beliau bersabda: \"Tolong guyurlah aku dari tujuh geriba yang belum dibuka ikatannya, siapa tahu aku masih bisa menyampaikan pesan kepada orang-orang.\" Lantas kami dudukkan beliau di sebuah ember besar milik Hafsah isteri Nabi shallallahu 'alaihi wasallam. Kemudian kami mengguyur beliau dari geriba-geriba itu hingga nabi memberi isyarat \"Cukup, telah kalian lakukan!\" Nabi pun keluar menemui orang-orang dan mengimami mereka serta menyampaikan pidatonya."},"4971":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ أَنَّ أُمَّ قَيْسٍ بِنْتَ مِحْصَنٍ الْأَسَدِيَّةَ أَسَدَ خُزَيْمَةَوَكَانَتْ مِنْ الْمُهَاجِرَاتِ الْأُوَلِ اللَّاتِي بَايَعْنَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ أُخْتُ عُكَاشَةَ أَخْبَرَتْهُ أَنَّهَا أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِابْنٍ لَهَا قَدْ أَعْلَقَتْ عَلَيْهِ مِنْ الْعُذْرَةِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَا تَدْغَرْنَ أَوْلَادَكُنَّ بِهَذَا الْعِلَاقِ عَلَيْكُمْ بِهَذَا الْعُودِ الْهِنْدِيِّ فَإِنَّ فِيهِ سَبْعَةَ أَشْفِيَةٍ مِنْهَا ذَاتُ الْجَنْبِ يُرِيدُ الْكُسْتَ وَهُوَ الْعُودُ الْهِنْدِيُّوَقَالَ يُونُسُ وَإِسْحَاقُ بْنُ رَاشِدٍ عَنْ الزُّهْرِيِّ عَلَّقَتْ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Ubaidullah bin Abdullah] bahwa [Ummu Qais binti Mihshan Al Asadiyah] -yaitu singa Bani Khuzaimah- dia termasuk dari wanita yang ikut berhijrah pertama kali dan yang berbai'at kepada Nabi shallallahu 'alaihi wasallam, dia adalah saudara perempuannya Ukasah, dia mengabarkan bahwa dirinya pernah mengunjungi Rasulullah shallallahu 'alaihi wasallam bersama anaknya yang baru saja diobati dengan memasukkan jari-jari ke kerongkongannya, lalu beliau bersabda: \"Dengan maksud apa kamu mengobati penyakit tenggorokan anakmu dengan memasukkan jemari tangan? Gunakanlah kayu India, karena padanya terdapat tujuh ragam penyembuhan, di antaranya dapat menjadi penyembuh dari penyakit radang selaput dada.\" Yang di maksud adalah dahan yaitu (dahan) kayu India.\" [Yunus] dan [Ishaq bin Rasyid] mengatakan dari [Az Zuhri] dengan lafazh; \"Dia memasukan sesuatu pada kerongkongan.\""},"4972":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أَخِي اسْتَطْلَقَ بَطْنُهُ فَقَالَ اسْقِهِ عَسَلًا فَسَقَاهُ فَقَالَ إِنِّي سَقَيْتُهُ فَلَمْ يَزِدْهُ إِلَّا اسْتِطْلَاقًا فَقَالَ صَدَقَ اللَّهُ وَكَذَبَ بَطْنُ أَخِيكَتَابَعَهُ النَّضْرُ عَنْ شُعْبَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Abu Al Mutawakkil] dari [Abu Sa'id] dia berkata; seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam sambil berkata; \"Sesungguhnya saudaraku menderita diare.\" Beliau bersabda: \"Minumilah madu.\" Lalu laki-laki itu meminuminya madu, kemudian dia berkata lagi; \"Sesungguhnya aku telah meminuminya madu, ternyata sakitnya tambah parah.\" Maka beliau bersabda: \"Maha benar Allah, dan perut saudaramulah yang berdusta.\" Hadits ini juga diperkuat oleh riwayat [Nadlr] dari [Syu'bah]."},"4973":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ وَغَيْرُهُ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا عَدْوَى وَلَا صَفَرَ وَلَا هَامَةَ فَقَالَ أَعْرَابِيٌّ يَا رَسُولَ اللَّهِ فَمَا بَالُ إِبِلِي تَكُونُ فِي الرَّمْلِ كَأَنَّهَا الظِّبَاءُ فَيَأْتِي الْبَعِيرُ الْأَجْرَبُ فَيَدْخُلُ بَيْنَهَا فَيُجْرِبُهَا فَقَالَ فَمَنْ أَعْدَى الْأَوَّلَرَوَاهُ الزُّهْرِيُّ عَنْ أَبِي سَلَمَةَ وَسِنَانِ بْنِ أَبِي سِنَانٍ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Shalih] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] dan yang lain, bahwa [Abu Hurairah] radliallahu 'anhu berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada 'adwa (meyakini bahwa penyakit tersebar dengan sendirinya, bukan karena takdir Allah), dan tidak ada shafar (menjadikan bulan shafar sebagai bulan haram atau keramat) dan tidak pula hammah (rengkarnasi atau ruh seseorang yang sudah meninggal menitis pada hewan).\" Lalu seorang arab Badui berkata; \"Wahai Rasulullah, lalu bagimana dengan unta yang ada dipasir, seakan-akan (bersih) bagaikan gerombolan kijang kemudian datang padanya unta berkudis dan bercampur baur dengannya sehingga ia menularinya?\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Siapakah yang menulari yang pertama.\" Hadits ini juga di riwayatkan oleh [Az Zuhri] dari [Abu Salamah] dan [Sinan bin Abu Sinan]."},"4974":{"ar":"حَدَّثَنِي مُحَمَّدٌ أَخْبَرَنَا عَتَّابُ بْنُ بَشِيرٍ عَنْ إِسْحَاقَ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ أَنَّ أُمَّ قَيْسٍ بِنْتَ مِحْصَنٍوَكَانَتْ مِنْ الْمُهَاجِرَاتِ الْأُوَلِ اللَّاتِي بَايَعْنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ أُخْتُ عُكَاشَةَ بْنِ مِحْصَنٍ أَخْبَرَتْهُ أَنَّهَا أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِابْنٍ لَهَا قَدْ عَلَّقَتْ عَلَيْهِ مِنْ الْعُذْرَةِ فَقَالَ اتَّقُوا اللَّهَ عَلَى مَا تَدْغَرُونَ أَوْلَادَكُمْ بِهَذِهِ الْأَعْلَاقِ عَلَيْكُمْ بِهَذَا الْعُودِ الْهِنْدِيِّ فَإِنَّ فِيهِ سَبْعَةَ أَشْفِيَةٍ مِنْهَا ذَاتُ الْجَنْبِ يُرِيدُ الْكُسْتَيَعْنِي الْقُسْطَ قَالَ وَهِيَ لُغَةٌ","id":"Telah menceritakan kepadaku [Muhammad] telah mengabarkan kepada kami ['Attab bin Basyir] dari [Ishaq] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Ubaidullah bin Abdullah] bahwa [Ummu Qais binti Mihshan] -dia termasuk dari wanita yang ikut hijrah pertama kali dan yang pernah berbai'at kepada Rasulullah shallallahu 'alaihi wasallam, dia juga termasuk saudara perempuannya 'Ukasah bin Mihshan- telah mengabarkan kepadanya, bahwa dirinya pernah mengunjungi Rasulullah shallallahu 'alaihi wasallam bersama anaknya yang baru saja diobati dengan cara memasukkan jari-jari ke kerongkongannya, lalu beliau bersabda: \"Bertaqwalah kepada Allah, dengan maksud apa kamu mengobati penyakit tenggorokan anakmu dengan memasukkan jemari tangan? Gunakanlah kayu India ini, karena padanya terdapat tujuh ragam penyembuhan, di antaranya adalah penyembuh penyakit radang selaput dada.\" Yang dimaksud adalah Al Kust (dahan) atau Al Kusth (dahan), yaitu secara bahasa.\""},"4975":{"ar":"حَدَّثَنَا عَارِمٌ حَدَّثَنَا حَمَّادٌ قَالَ قُرِيءَ عَلَى أَيُّوبَ مِنْ كُتُبِ أَبِي قِلَابَةَ مِنْهُ مَا حَدَّثَ بِهِ وَمِنْهُ مَا قُرِئَ عَلَيْهِ وَكَانَ هَذَا فِي الْكِتَابِ عَنْ أَنَسٍ أَنَّ أَبَا طَلْحَةَ وَأَنَسَ بْنَ النَّضْرِ كَوَيَاهُ وَكَوَاهُ أَبُو طَلْحَةَ بِيَدِهِ وَقَالَ عَبَّادُ بْنُ مَنْصُورٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأَذِنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَهْلِ بَيْتٍ مِنْ الْأَنْصَارِ أَنْ يَرْقُوا مِنْ الْحُمَةِ وَالْأُذُنِقَالَ أَنَسٌ كُوِيتُ مِنْ ذَاتِ الْجَنْبِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيٌّ وَشَهِدَنِي أَبُو طَلْحَةَ وَأَنَسُ بْنُ النَّضْرِ وَزَيْدُ بْنُ ثَابِتٍ وَأَبُو طَلْحَةَ كَوَانِي","id":"Telah menceritakan kepada kami ['Arim] telah menceritakan kepada kami [Hammad] dia berkata; dibacakan di hadapan [Ayyub] dari kitabnya [Abu Qilabah], di antaranya ada sesuatu yang dibacakan dan ada sesuatu yang di dengar, sementara hal ini terdapat dalam kitabnya dari [Anas] bahwa Abu Thalhah dan Anas bin Nadlr pernah melakukan terapi kay (menempelkan besi panas pada daerah yang luka atau sakit) sementara Abu Thalhah juga pernah melakukan terapi kay (menempelkan besi panas pada daerah yang luka atau sakit) dengan tangannya sendiri.\" ['Abbad bin Manshur] mengatakan dari [Abu Qilabah] dari [Anas bin Malik] dia berkata; Rasulullah shallallahu 'alaihi wasallam memberi izin kepada keluarga beliau dari Anshar untuk meruqyah dari penyakit demam dan sakit telinga. Anas mengatakan; \"Aku juga pernah melakukan kay (menempelkan besi panas pada daerah yang luka atau sakit) pada penyakit radang selaput dada, sedangkan Rasulullah shallallahu 'alaihi wasallam masih hidup. Abu Thalhah, Anas bin Nadlr, Zaid bin Tsabit juga pernah menyaksikanku ketika aku diterapi dengan kay (menempelkan besi panas pada daerah yang sakit) oleh Abu Thalhah.\""},"4976":{"ar":"حَدَّثَنِي سَعِيدُ بْنُ عُفَيْرٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ الْقَارِيُّ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَلَمَّا كُسِرَتْ عَلَى رَأْسِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيْضَةُ وَأُدْمِيَ وَجْهُهُ وَكُسِرَتْ رَبَاعِيَتُهُ وَكَانَ عَلِيٌّ يَخْتَلِفُ بِالْمَاءِ فِي الْمِجَنِّ وَجَاءَتْ فَاطِمَةُ تَغْسِلُ عَنْ وَجْهِهِ الدَّمَ فَلَمَّا رَأَتْ فَاطِمَةُ عَلَيْهَا السَّلَام الدَّمَ يَزِيدُ عَلَى الْمَاءِ كَثْرَةً عَمَدَتْ إِلَى حَصِيرٍ فَأَحْرَقَتْهَا وَأَلْصَقَتْهَا عَلَى جُرْحِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَقَأَ الدَّمُ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] telah menceritakan kepada kami [Ya'qub bin Abdurrahman Al Qari] dari [Abu Hazim] dari [Sahl bin Sa'd As Sa'idi] dia berkata; Ketika topi baja yang dikenakan Rasulullah shallallahu 'alaihi wasallam pecah hingga menyebabkan wajah beliau mengalirkan darah dan gigi geraham beliau pecah, maka Ali menyiramkan air dari perisai sedangkan Fathimah datang membersihkan wajah beliau dari darah dengan air, ketika Fathimah 'alaihas salam melihat darah semakin bertambah banyak keluar, dia mengambil potongan pelepah kurma lalu dibakarnya sampai menjadi abu, kemudian abu tersebut diletakkan pada luka Rasulullah shallallahu 'alaihi wasallam hingga darahnya berhenti keluar.\""},"4977":{"ar":"حَدَّثَنِي يَحْيَى بْنُ سُلَيْمَانَ حَدَّثَنِي ابْنُ وَهْبٍ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْحُمَّى مِنْ فَيْحِ جَهَنَّمَ فَأَطْفِئُوهَا بِالْمَاءِقَالَ نَافِعٌ وَكَانَ عَبْدُ اللَّهِ يَقُولُ اكْشِفْ عَنَّا الرِّجْزَ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] telah menceritakan kepadaku [Ibnu Wahb] dia berkata; telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Demam itu berasal dari tiupan neraka jahannam, maka redakanlah dengan air.\" Nafi' berkata; sedangkan Abdullah pernah mengatakan; \"Hindarkanlah kami dari adzab.\""},"4978":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ هِشَامٍ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ أَنَّ أَسْمَاءَ بِنْتَ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَاكَانَتْ إِذَا أُتِيَتْ بِالْمَرْأَةِ قَدْ حُمَّتْ تَدْعُو لَهَا أَخَذَتْ الْمَاءَ فَصَبَّتْهُ بَيْنَهَا وَبَيْنَ جَيْبِهَا قَالَتْ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا أَنْ نَبْرُدَهَا بِالْمَاءِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Hisyam] dari [Fathimah binti Mundzir] bahwa [Asma` binti Abu Bakar] radliallahu 'anhuma bahwa apabila didatangkan kepadanya seorang wanita yang menderita sakit demam, maka ia akan mengambil air, lalu ia menyemburkan pada bagian saku (dadanya). Kemudian dia berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam memerintahkan kami supaya mendinginkan dengan air.\""},"4979":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى حَدَّثَنَا هِشَامٌ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْحُمَّى مِنْ فَيْحِ جَهَنَّمَ فَابْرُدُوهَا بِالْمَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Hisyam] telah mengabarkan kepadaku [Ayahku] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Demam berasal dari hembusan nerakan Jahannam maka dinginkanlah ia dengan air.\""},"4980":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا سَعِيدُ بْنُ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْحُمَّى مِنْ فَوْحِ جَهَنَّمَ فَابْرُدُوهَا بِالْمَاءِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu Al Ahwash] telah menceritakan kepada kami [Sa'id bin Masruq] dari ['Abayah bin Rifa'ah] dari kakeknya [Rafi' bin Khadij] dia berkata; saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Demam berasal dari hembusan nerakan Jahannam maka dinginkanlah ia dengan air.\""},"4981":{"ar":"حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ حَدَّثَنَا قَتَادَةُ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُمْأَنَّ نَاسًا أَوْ رِجَالًا مِنْ عُكْلٍ وَعُرَيْنَةَ قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَكَلَّمُوا بِالْإِسْلَامِ وَقَالُوا يَا نَبِيَّ اللَّهِ إِنَّا كُنَّا أَهْلَ ضَرْعٍ وَلَمْ نَكُنْ أَهْلَ رِيفٍ وَاسْتَوْخَمُوا الْمَدِينَةَ فَأَمَرَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَوْدٍ وَبِرَاعٍ وَأَمَرَهُمْ أَنْ يَخْرُجُوا فِيهِ فَيَشْرَبُوا مِنْ أَلْبَانِهَا وَأَبْوَالِهَا فَانْطَلَقُوا حَتَّى كَانُوا نَاحِيَةَ الْحَرَّةِ كَفَرُوا بَعْدَ إِسْلَامِهِمْ وَقَتَلُوا رَاعِيَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْتَاقُوا الذَّوْدَ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَ الطَّلَبَ فِي آثَارِهِمْ وَأَمَرَ بِهِمْ فَسَمَرُوا أَعْيُنَهُمْ وَقَطَعُوا أَيْدِيَهُمْ وَتُرِكُوا فِي نَاحِيَةِ الْحَرَّةِ حَتَّى مَاتُوا عَلَى حَالِهِمْ","id":"Telah menceritakan kepada kami [Abdul A'la bin Hammad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] telah menceritakan kepada kami [Qatadah] bahwa [Anas bin Malik] telah menceritakan kepada mereka bahwa sekelompok orang atau pemuda dari kabilah 'Ukl dan 'Urainah datang kepada Rasulullah shallallahu 'alaihi wasallam, mereka menyatakan masuk Islam. Lalu mereka berkata, \"Wahai Nabiyullah, kami orang yang hidup dari hasil ternak, bukan dari hasil pertanian.\" Lalu mereka menderita sakit di Madinah karena iklim yang tidak cocok, maka Rasulullah Shallallahu'alihi wasallam memerintahkan mereka supaya keluar menemui penggembala yang sedang menggembalakan unta, lalu beliau menyuruh mereka keluar dari Madinah. Mereka pun minum susu unta tersebut dan minum air kencingnya. Tatkala mereka berada di perbatasan Madinah, mereka keluar dari Islam (kufur), kemudian membunuh pengembala unta Rasulullah Shallallahu'alihi wasallam, dan menggiring untanya. Berita tersebut sampai kepada Rasulullah Shallallahu'alihi wasallam, maka beliau menyuruh untuk mencari jejak mereka, dan akhirnya mereka dapat dibawa kepada Rasulullah Shallallahu'laihi wasallam. Mereka dihukum dengan cara ditusuk matanya dengan paku (di congkel dengan paku panas), tangan dan kaki mereka dipotong, lalu mereka dibiarkan dalam keadaan seperti itu dibawah terik matahari hingga mereka mati.\""},"4982":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي حَبِيبُ بْنُ أَبِي ثَابِتٍ قَالَ سَمِعْتُ إِبْرَاهِيمَ بْنَ سَعْدٍ قَالَ سَمِعْتُ أُسَامَةَ بْنَ زَيْدٍ يُحَدِّثُ سَعْدًا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهُ قَالَ إِذَا سَمِعْتُمْ بِالطَّاعُونِ بِأَرْضٍ فَلَا تَدْخُلُوهَا وَإِذَا وَقَعَ بِأَرْضٍ وَأَنْتُمْ بِهَا فَلَا تَخْرُجُوا مِنْهَافَقُلْتُ أَنْتَ سَمِعْتَهُ يُحَدِّثُ سَعْدًا وَلَا يُنْكِرُهُ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dia berkata; telah mengabarkan kepadaku [Habib bin Abu Tsabit] dia berkata; saya mendengar [Ibrahim bin Sa'd] berkata; saya mendengar [Usamah bin Zaid] bercerita kepada Sa'd dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Apabila kalian mendengar wabah lepra di suatu negeri, maka janganlah kalian masuk ke dalamnya, namun jika ia menjangkiti suatu negeri, sementara kalian berada di dalamnya, maka janganlah kalian keluar dari negeri tersebut.\" Lalu aku berkata; \"Apakah kamu mendengar Usamah menceritakan hal itu kepada Sa'd, sementara [Sa'd] tidak mengingkari perkataannya Usamah?\" Ibrahim bin Sa'd berkata; \"Benar.\""},"4983":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ زَيْدِ بْنِ الْخَطَّابِ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ الحَارِثِ بْنِ نَوْفَلٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ خَرَجَ إِلَى الشَّأْمِ حَتَّى إِذَا كَانَ بِسَرْغَ لَقِيَهُ أُمَرَاءُ الْأَجْنَادِ أَبُو عُبَيْدَةَ بْنُ الْجَرَّاحِ وَأَصْحَابُهُ فَأَخْبَرُوهُ أَنَّ الْوَبَاءَ قَدْ وَقَعَ بِأَرْضِ الشَّأْمِ قَالَ ابْنُ عَبَّاسٍ فَقَالَ عُمَرُ ادْعُ لِي الْمُهَاجِرِينَ الْأَوَّلِينَ فَدَعَاهُمْ فَاسْتَشَارَهُمْ وَأَخْبَرَهُمْ أَنَّ الْوَبَاءَ قَدْ وَقَعَ بِالشَّأْمِ فَاخْتَلَفُوا فَقَالَ بَعْضُهُمْ قَدْ خَرَجْتَ لِأَمْرٍ وَلَا نَرَى أَنْ تَرْجِعَ عَنْهُ وَقَالَ بَعْضُهُمْ مَعَكَ بَقِيَّةُ النَّاسِ وَأَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا نَرَى أَنْ تُقْدِمَهُمْ عَلَى هَذَا الْوَبَاءِ فَقَالَ ارْتَفِعُوا عَنِّي ثُمَّ قَالَ ادْعُوا لِي الْأَنْصَارَ فَدَعَوْتُهُمْ فَاسْتَشَارَهُمْ فَسَلَكُوا سَبِيلَ الْمُهَاجِرِينَ وَاخْتَلَفُوا كَاخْتِلَافِهِمْ فَقَالَ ارْتَفِعُوا عَنِّي ثُمَّ قَالَ ادْعُ لِي مَنْ كَانَ هَا هُنَا مِنْ مَشْيَخَةِ قُرَيْشٍ مِنْ مُهَاجِرَةِ الْفَتْحِ فَدَعَوْتُهُمْ فَلَمْ يَخْتَلِفْ مِنْهُمْ عَلَيْهِ رَجُلَانِ فَقَالُوا نَرَى أَنْ تَرْجِعَ بِالنَّاسِ وَلَا تُقْدِمَهُمْ عَلَى هَذَا الْوَبَاءِ فَنَادَى عُمَرُ فِي النَّاسِ إِنِّي مُصَبِّحٌ عَلَى ظَهْرٍ فَأَصْبِحُوا عَلَيْهِ قَالَ أَبُو عُبَيْدَةَ بْنُ الْجَرَّاحِ أَفِرَارًا مِنْ قَدَرِ اللَّهِ فَقَالَ عُمَرُ لَوْ غَيْرُكَ قَالَهَا يَا أَبَا عُبَيْدَةَ نَعَمْ نَفِرُّ مِنْ قَدَرِ اللَّهِ إِلَى قَدَرِ اللَّهِ أَرَأَيْتَ لَوْ كَانَ لَكَ إِبِلٌ هَبَطَتْ وَادِيًا لَهُ عُدْوَتَانِ إِحْدَاهُمَا خَصِبَةٌ وَالْأُخْرَى جَدْبَةٌ أَلَيْسَ إِنْ رَعَيْتَ الْخَصْبَةَ رَعَيْتَهَا بِقَدَرِ اللَّهِ وَإِنْ رَعَيْتَ الْجَدْبَةَ رَعَيْتَهَا بِقَدَرِ اللَّهِ قَالَ فَجَاءَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ وَكَانَ مُتَغَيِّبًا فِي بَعْضِ حَاجَتِهِ فَقَالَ إِنَّ عِنْدِي فِي هَذَا عِلْمًا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا سَمِعْتُمْ بِهِ بِأَرْضٍ فَلَا تَقْدَمُوا عَلَيْهِ وَإِذَا وَقَعَ بِأَرْضٍ وَأَنْتُمْ بِهَا فَلَا تَخْرُجُوا فِرَارًا مِنْهُ قَالَ فَحَمِدَ اللَّهَ عُمَرُ ثُمَّ انْصَرَفَ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Abdul Hamid bin Abdurrahman bin Zaid bin Al Khatthab] dari [Abdullah bin Abdullah bin Al Harits bin Naufal] dari [Abdullah bin Abbas] bahwa Umar bin Khatthab pernah bepergian menuju Syam, ketika ia sampai di daerah Sargha, dia bertemu dengan panglima pasukan yaitu Abu 'Ubaidah bersama sahabat-sahabatnya, mereka mengabarkan bahwa negeri Syam sedang terserang wabah. Ibnu Abbas berkata; \"Lalu Umar bin Khattab berkata; 'Panggilkan untukku orang-orang muhajirin yang pertama kali (hijrah), ' kemudian mereka dipanggil, lalu dia bermusyawarah dengan mereka dan memberitahukan bahwa negeri Syam sedang terserang wabah, merekapun berselisih pendapat. Sebagian dari mereka berkata; 'Engkau telah keluar untuk suatu keperluan, kami berpendapat bahwa engkau tidak perlu menarik diri.' Sebagian lain berkata; 'Engkau bersama sebagian manusia dan beberapa sahabat Rasulullah Shalla Allahu 'alaihi wa sallam. Kami berpendapat agar engkau tidak menghadapkan mereka dengan wabah ini, ' Umar berkata; 'Keluarlah kalian, ' dia berkata; 'Panggilkan untukku orang-orang Anshar'. Lalu mereka pun dipanggil, setelah itu dia bermusyawarah dengan mereka, sedangkan mereka sama seperti halnya orang-orang Muhajirin dan berbeda pendapat seperti halnya mereka berbeda pendapat. Umar berkata; 'keluarlah kalian, ' dia berkata; 'Panggilkan untukku siapa saja di sini yang dulu menjadi tokoh Quraisy dan telah berhijrah ketika Fathul Makkah.' Mereka pun dipanggil dan tidak ada yang berselisih dari mereka kecuali dua orang. Mereka berkata; 'Kami berpendapat agar engkau kembali membawa orang-orang dan tidak menghadapkan mereka kepada wabah ini.' Umar menyeru kepada manusia; 'Sesungguhnya aku akan bangun pagi di atas pelana (maksudnya hendak berangkat pulang di pagi hari), bagunlah kalian pagi hari, ' Abu Ubaidah bin Jarrah bertanya; 'Apakah engkau akan lari dari takdir Allah? ' maka Umar menjawab; 'Kalau saja yang berkata bukan kamu, wahai Abu 'Ubaidah! Ya, kami lari dari takdir Allah menuju takdir Allah yang lain. Bagaimana pendapatmu, jika kamu memiliki unta kemudian tiba di suatu lembah yang mempunyai dua daerah, yang satu subur dan yang lainnya kering, tahukah kamu jika kamu membawanya ke tempat yang subur, niscaya kamu telah membawanya dengan takdir Allah. Apabila kamu membawanya ke tempat yang kering, maka kamu membawanya dengan takdir Allah juga.' Ibnu Abbas berkata; \"Kemudian datanglah [Abdurrahman bin 'Auf], dia tidak ikut hadir (dalam musyawarah) karena ada keperluan. Dia berkata; \"Saya memiliki kabar tentang ini dari Rasulullah Shalla Allahu 'alaihi wa sallam beliau bersabda: \"Jika kalian mendengar suatu negeri terjangkit wabah, maka janganlah kalian menuju ke sana, namun jika dia menjangkiti suatu negeri dan kalian berada di dalamnya, maka janganlah kalian keluar dan lari darinya.\" Ibnu 'Abbas berkata; \"Lalu Umar memuji Allah kemudian pergi.\""},"4984":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرٍ أَنَّ عُمَرَ خَرَجَ إِلَى الشَّأْمِ فَلَمَّا كَانَ بِسَرْغَ بَلَغَهُ أَنَّ الْوَبَاءَ قَدْ وَقَعَ بِالشَّأْمِ فَأَخْبَرَهُ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَمِعْتُمْ بِهِ بِأَرْضٍ فَلَا تَقْدَمُوا عَلَيْهِ وَإِذَا وَقَعَ بِأَرْضٍ وَأَنْتُمْ بِهَا فَلَا تَخْرُجُوا فِرَارًا مِنْهُ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Abdullah bin 'Amir] bahwa Umar pernah bepergian menuju Syam, ketika dia sampai di daerah Sargha, diberitahukan kepadanya bahwa negeri Syam sedang terjangkiti wabah penyakit menular, lantas [Abdurrahman bin 'Auf] memberitahukan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian mendengar wabah tersebut menjangkiti suatu negeri, maka janganlah kalian menuju ke sana, namun jika dia menjangkiti suatu negeri dan kalian berada di dalamnya, maka janganlah kalian keluar dan lari darinya.\""},"4985":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نُعَيْمٍ الْمُجْمِرِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدْخُلُ الْمَدِينَةَ المَسِيحُ وَلَا الطَّاعُونُ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nu'aim Al Mujmir] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Al Masih (Dajjal) dan penyakit lepra tidak akan bisa masuk Madinah.\""},"4986":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا عَاصِمٌ حَدَّثَتْنِي حَفْصَةُ بِنْتُ سِيرِينَ قَالَتْ قَالَ لِي أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ يَحْيَى بِمَ مَاتَ قُلْتُ مِنْ الطَّاعُونِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الطَّاعُونُ شَهَادَةٌ لِكُلِّ مُسْلِمٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami ['Ashim] telah menceritakan kepadaku [Hafshah binti Sirin] dia berkata; [Anas bin Malik] radliallahu 'anhu bertanya kepadaku; \"Sebab apakah Yahya meninggal dunia?\" Jawabku; \"Karena menderita lepra.\" Anas berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"(mati) karena menderita lepra adalah syahid bagi setiap Muslim.\""},"4987":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ مَالِكٍ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَبْطُونُ شَهِيدٌ وَالْمَطْعُونُ شَهِيدٌ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Malik] dari [Sumayy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"(meninggal) karena sakit perut adalah syahid, dan (meninggal) karena lepra juga syahid.\""},"4988":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا حَبَّانُ حَدَّثَنَا دَاوُدُ بْنُ أَبِي الْفُرَاتِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهَا أَخْبَرَتْنَا أَنَّهَا سَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الطَّاعُونِ فَأَخْبَرَهَا نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ عَذَابًا يَبْعَثُهُ اللَّهُ عَلَى مَنْ يَشَاءُ فَجَعَلَهُ اللَّهُ رَحْمَةً لِلْمُؤْمِنِينَ فَلَيْسَ مِنْ عَبْدٍ يَقَعُ الطَّاعُونُ فَيَمْكُثُ فِي بَلَدِهِ صَابِرًا يَعْلَمُ أَنَّهُ لَنْ يُصِيبَهُ إِلَّا مَا كَتَبَ اللَّهُ لَهُ إِلَّا كَانَ لَهُ مِثْلُ أَجْرِ الشَّهِيدِتَابَعَهُ النَّضْرُ عَنْ دَاوُدَ","id":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Habban] telah menceritakan kepada kami [Daud bin Abu Al Furat] telah menceritakan kepada kami [Abdullah bin Buraidah] dari [Yahya bin Ya'mar] dari ['Aisyah isteri Nabi] shallallahu 'alaihi wasallam bahwa dia pernah mengabarkan kepada kami, bahwa dia pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai penyakit lepra, lantas Nabiyullah shallallahu 'alaihi wasallam memberitahukan kepadanya; \"Bahwa penyakit lepra merupakan azab yang Allah timpakan terhadap siapa yang dikehendaki-Nya, dan menjadikannya sebagai rahmat bagi orang-orang yang beriman. Tidaklah seseorang yang berada di wilayah yang terjangkit penyakit lepra, kemudian ia tetap tinggal di negerinya dan selalu bersabar, ia mengetahui bahwa penyakit tersebut tidak akan mengjangkitinya kecuali apa yang Allah tetapkan kepadanya, maka baginya seperti pahalanya orang yang mati syahid.\" Hadits ini juga di perkuat oleh riwayat [An Nadlr] dari [Daud]."},"4989":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْفُثُ عَلَى نَفْسِهِ فِي الْمَرَضِ الَّذِي مَاتَ فِيهِ بِالْمُعَوِّذَاتِ فَلَمَّا ثَقُلَ كُنْتُ أَنْفِثُ عَلَيْهِ بِهِنَّ وَأَمْسَحُ بِيَدِ نَفْسِهِ لِبَرَكَتِهَا فَسَأَلْتُ الزُّهْرِيَّ كَيْفَ يَنْفِثُ قَالَ كَانَ يَنْفِثُ عَلَى يَدَيْهِ ثُمَّ يَمْسَحُ بِهِمَا وَجْهَهُ","id":"Telah menceritakan kepadaku [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam] dari [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] radliallahu 'anha bahwa Nabi shallallahu 'alaihi wasallam meniupkan kepada diri beliau sendiri dengan Mu'awwidzat (surat An nas dan Al falaq) ketika beliau sakit menjelang wafatnya, dan tatkala sakit beliau semakin parah, sayalah yang meniup dengan kedua surat tersebut dan saya megusapnya dengan tangan beliau sendiri karena berharap untuk mendapat berkahnya.\" Aku bertanya kepada Az Zuhri; \"Bagaimana cara meniupnya?\" dia menjawab; \"Beliau meniup kedua tangannya, kemudian beliau mengusapkan ke wajah dengan kedua tangannya.\""},"4990":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ نَاسًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَوْا عَلَى حَيٍّ مِنْ أَحْيَاءِ الْعَرَبِ فَلَمْ يَقْرُوهُمْ فَبَيْنَمَا هُمْ كَذَلِكَ إِذْ لُدِغَ سَيِّدُ أُولَئِكَ فَقَالُوا هَلْ مَعَكُمْ مِنْ دَوَاءٍ أَوْ رَاقٍ فَقَالُوا إِنَّكُمْ لَمْ تَقْرُونَا وَلَا نَفْعَلُ حَتَّى تَجْعَلُوا لَنَا جُعْلًا فَجَعَلُوا لَهُمْ قَطِيعًا مِنْ الشَّاءِ فَجَعَلَ يَقْرَأُ بِأُمِّ الْقُرْآنِ وَيَجْمَعُ بُزَاقَهُ وَيَتْفِلُ فَبَرَأَ فَأَتَوْا بِالشَّاءِ فَقَالُوا لَا نَأْخُذُهُ حَتَّى نَسْأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلُوهُ فَضَحِكَ وَقَالَ وَمَا أَدْرَاكَ أَنَّهَا رُقْيَةٌ خُذُوهَا وَاضْرِبُوا لِي بِسَهْمٍ","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Abu Al Mutawakkil] dari [Abu Sa'id Al Khudri] radliallahu 'anhu bahwa beberapa orang sahabat Nabi shallallahu 'alaihi wasallam mengadakan suatu perjalanan, ketika mereka melewati salah satu perkampungan dari perkampungan Arab, orang-orang kampung tersebut tidak menerima mereka, ketika sikap mereka masih seperti itu seorang pemimpin mereka terkena sengatan kalajengking, lalu mereka pun berkata; \"Apakah diantara kalian ada yang mempunyai obat, atau seorang yang bisa meruqyah?\" lalu para sahabat Nabi pun berkata; \"Sesungguhnya kalian tidak mau menerima kami, maka kamipun tidak akan melakukannya sehingga kalian memberikan imbalan kepada kami, \" akhirnya mereka pun berjanji akan memberikan beberapa ekor kambing.\"Lalu seorang sahabat Nabi membaca Ummul Qur`an dan mengumpulkan ludahnya seraya meludahkan kepadanya hingga laki-laki itu sembuh, kemudian orang-orang kampung itu memberikan kepada para sahabat Nabi beberapa ekor kambing.\" Namun para sahabat Nabi berkata; \"Kita tidak akan mengambilnya hingga kita bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang hal ini, \" lalu mereka bertanya kepada Nabi shallallahu 'alaihi wasallam tentang pemberian itu hingga membuat beliau tertawa. Beliau bersabda: \"Tidak tahukah bahwa itu ruqyah, ambillah pemberian tersebut dan berilah bagiannya untukku.\""},"4991":{"ar":"حَدَّثَنِي سِيدَانُ بْنُ مُضَارِبٍ أَبُو مُحَمَّدٍ الْبَاهِلِيُّ حَدَّثَنَا أَبُو مَعْشَرٍ الْبَصْرِيُّ هُوَ صَدُوقٌ يُوسُفُ بْنُ يَزِيدَ الْبَرَّاءُ قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ الْأَخْنَسِ أَبُو مَالِكٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ نَفَرًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرُّوا بِمَاءٍ فِيهِمْ لَدِيغٌ أَوْ سَلِيمٌ فَعَرَضَ لَهُمْ رَجُلٌ مِنْ أَهْلِ الْمَاءِ فَقَالَ هَلْ فِيكُمْ مِنْ رَاقٍ إِنَّ فِي الْمَاءِ رَجُلًا لَدِيغًا أَوْ سَلِيمًا فَانْطَلَقَ رَجُلٌ مِنْهُمْ فَقَرَأَ بِفَاتِحَةِ الْكِتَابِ عَلَى شَاءٍ فَبَرَأَ فَجَاءَ بِالشَّاءِ إِلَى أَصْحَابِهِ فَكَرِهُوا ذَلِكَ وَقَالُوا أَخَذْتَ عَلَى كِتَابِ اللَّهِ أَجْرًا حَتَّى قَدِمُوا الْمَدِينَةَ فَقَالُوا يَا رَسُولَ اللَّهِ أَخَذَ عَلَى كِتَابِ اللَّهِ أَجْرًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَحَقَّ مَا أَخَذْتُمْ عَلَيْهِ أَجْرًا كِتَابُ اللَّهِ","id":"Telah menceritakan kepada kami [Sidan bin Muddzarib Abu Muhammad Al Bahili] telah menceritakan kepada kami Abu Ma'syar Al Bashri dia adalah seorang yang jujur yaitu [Yusuf bin Yazid Al Barra`] dia berkata; telah menceritakan kepadaku ['Ubaidullah bin Al Ahnas Abu Malik] dari [Ibnu Abu Mulaikah] dari [Ibnu Abbas] bahwa beberapa sahabat Nabi shallallahu 'alaihi wasallam melewati sumber mata air dimana terdapat orang yang tersengat binatang berbisa, lalu salah seorang yang bertempat tinggal di sumber mata air tersebut datang dan berkata; \"Adakah di antara kalian seseorang yang pandai menjampi? Karena di tempat tinggal dekat sumber mata air ada seseorang yang tersengat binatang berbisa.\" Lalu salah seorang sahabat Nabi pergi ke tempat tersebut dan membacakan al fatihah dengan upah seekor kambing. Ternyata orang yang tersengat tadi sembuh, maka sahabat tersebut membawa kambing itu kepada teman-temannya. Namun teman-temannya tidak suka dengan hal itu, mereka berkata; \"Kamu mengambil upah atas kitabullah?\" setelah mereka tiba di Madinah, mereka berkata; \"Wahai Rasulullah, ia ini mengambil upah atas kitabullah.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya upah yang paling berhak kalian ambil adalah upah karena (mengajarkan) kitabullah.\" "},"4992":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ قَالَ حَدَّثَنِي مَعْبَدُ بْنُ خَالِدٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ شَدَّادٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ أَمَرَ أَنْ يُسْتَرْقَى مِنْ الْعَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dia berkata; telah menceritakan kepadaku [Ma'bad bin Khalid] dia berkata; saya mendengar [Abdullah bin Syaddad] dari [Aisyah] radliallahu 'anha dia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kami supaya meruqyah orang yang terkena penyakit 'ain (gangguan sihir).\""},"4993":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ وَهْبِ بْنِ عَطِيَّةَ الدِّمَشْقِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ حَدَّثَنَا مُحَمَّدُ بْنُ الْوَلِيدِ الزُّبَيْدِيُّ أَخْبَرَنَا الزُّهْرِيُّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ زَيْنَبَ ابْنَةِ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى فِي بَيْتِهَا جَارِيَةً فِي وَجْهِهَا سَفْعَةٌ فَقَالَ اسْتَرْقُوا لَهَا فَإِنَّ بِهَا النَّظْرَةَتَابَعَهُ عَبْدُ اللَّهِ بْنُ سَالِمٍ عَنْ الزُّبَيْدِيِّ وَقَالَ عُقَيْلٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُرْوَةُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Khalid] telah menceritakan kepada kami [Muhammad bin Wahb bin 'Athiyah Ad Dimasyqi] telah menceritakan kepada kami [Muhammad bin Harb] telah menceritakan kepada kami [Muhammad bin Al Walid Az Zubaidi] telah mengabarkan kepada kami [Az Zuhri] dari ['Urwah bin Zubair] dari [Zainab puteri Ummu Salamah] dari [Ummu Salamah] radliallahu 'anha bahwa Nabi shallallahu 'alaihi wasallam melihat budak wanita di rumahnya, ketika beliau melihat bekas hitam pada wajah budak wanita itu, beliau bersabda: \"Ruqyahlah dia, karena padanya terdapat nadlrah (sisa sakit yang disebabkan karena sorotan mata jahat).\" Hadits ini diperkuat oleh riwayat [Abdullah bin Salim] dari [Az Zubaidi], dan berkata [Uqail] dari [Az Zuhri] telah mengabarkan kepadaku [Urwah] dari Nabi shallallahu 'alaihi wasallam."},"4994":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ نَصْرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعَيْنُ حَقٌّ وَنَهَى عَنْ الْوَشْمِ","id":"Telah menceritakan kepada kami [Ishaq bin Nashr] telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Hammam] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Penyakit 'ain (yang disebabkan oleh sorotan mata yang dengki) adalah haq (benar).\" Dan beliau melarang tato.\""},"4995":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا سُلَيْمَانُ الشَّيْبَانِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْأَسْوَدِ عَنْ أَبِيهِ قَالَ سَأَلْتُ عَائِشَةَعَنْ الرُّقْيَةِ مِنْ الْحُمَةِ فَقَالَتْ رَخَّصَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرُّقْيَةَ مِنْ كُلِّ ذِي حُمَةٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami [Sulaiman As Syaibani] telah menceritakan kepada kami [Abdurrahman bin Al Aswad] dari [Ayahnya] dia berkata; saya bertanya kepada ['Aisyah] tentang ruqyah (jampi-jampi dari al Qur'an dan As Sunnah) dari penyakit demam, dia menjawab; \"Nabi shallallahu 'alaihi wasallam mengizinkan ruqyah dari setiap penderita sakit demam.\""},"4996":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ قَالَدَخَلْتُ أَنَا وَثَابِتٌ عَلَى أَنَسِ بْنِ مَالِكٍ فَقَالَ ثَابِتٌ يَا أَبَا حَمْزَةَ اشْتَكَيْتُ فَقَالَ أَنَسٌ أَلَا أَرْقِيكَ بِرُقْيَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَلَى قَالَ اللَّهُمَّ رَبَّ النَّاسِ مُذْهِبَ الْبَاسِ اشْفِ أَنْتَ الشَّافِي لَا شَافِيَ إِلَّا أَنْتَ شِفَاءً لَا يُغَادِرُ سَقَمًا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdul Warits] dari [Abdul Aziz] dia berkata; \"Aku dan Tsabit pernah mengunjungi Anas bin Malik, lalu Tsabit berkata; \"Wahai Abu Hamzah, aku sedang menderita suatu penyakit.\" Maka [Anas] berkata; \"Maukah kamu aku ruqyah dengan ruqyah Rasulullah shallallahu 'alaihi wasallam?\" dia menjawab; \"Tentu.\" Anas berkata; \"ALLAHUMMA RABBAN NAASI MUDZHIBIL BA`SA ISYFII ANTA SYAAFI LAA SYAAFIYA ILLA ANTA SYIFAA`AN LAA YUGHAADIRU SAQAMA (Ya Allah Rabb manusia, dzat yang menghilangkan rasa sakit, sembuhkanlah sesungguhnya Engkau Maha Penyembuh, tidak ada yang dapat menyembuhkan melainkan Engkau, yaitu kesembuhan yang tidak menyisakan rasa sakit).\""},"4997":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى حَدَّثَنَا سُفْيَانُ حَدَّثَنِي سُلَيْمَانُ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُعَوِّذُ بَعْضَ أَهْلِهِ يَمْسَحُ بِيَدِهِ الْيُمْنَى وَيَقُولُ اللَّهُمَّ رَبَّ النَّاسِ أَذْهِبْ الْبَاسَ اشْفِهِ وَأَنْتَ الشَّافِي لَا شِفَاءَ إِلَّا شِفَاؤُكَ شِفَاءً لَا يُغَادِرُ سَقَمًاقَالَ سُفْيَانُ حَدَّثْتُ بِهِ مَنْصُورًا فَحَدَّثَنِي عَنْ إِبْرَاهِيمَ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ نَحْوَهُ","id":"Telah menceritakan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Sufyan] telah menceritakan kepadaku [Sulaiman] dari [Muslim] dari [Masruq] dari ['Aisyah] radliallahu 'anha bahwa Nabi shallallahu 'alaihi wasallam selalu meminta perlindungan terhadap sebagian keluarganya, beliau mengusap dengan tangan kanannya sambil berdo'a; \"ALLAHUMMA RABBAN NAASI ADZHIBIL BA`SA ISYFIHI ANTA SYAAFI LAA SYIFAA`A ILLA SYIFAA`UKA SYIFAA`AN LAA YUGHAADIRU SAQAMA (Ya Allah Rabb manusia, dzat yang menghilangkan rasa sakit, sembuhkanlah sesungguhnya Engkau Dzat yang Maha menyembuhkan, tidak ada kesembuhan melainkan dari kesembuhan-Mu, yaitu kesembuhan yang tidak menyisakan rasa sakit).\" [Sufyan] berkata; Aku menceritakan hal ini kepada [Manshur], maka dia menceritakan kepadaku dari [Ibrahim] dari [Masruq] dari [Aisyah] seperti hadits di atas."},"4998":{"ar":"حَدَّثَنِي أَحْمَدُ ابْنُ أَبِي رَجَاءٍ حَدَّثَنَا النَّضْرُ عَنْ هِشَامِ بْنِ عُرْوَةَ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَرْقِي يَقُولُ امْسَحْ الْبَاسَ رَبَّ النَّاسِ بِيَدِكَ الشِّفَاءُ لَا كَاشِفَ لَهُ إِلَّا أَنْتَ","id":"Telah menceritakan kepadaku [Ahmad bin Abu Raja`] telah menceritakan kepada kami [An Nadlr] dari [Hisyam bin 'Urwah] dia berkata; telah mengabarkan kepadaku [Ayahku] dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam ketika meruqyah beliau berdo'a: \"Hilangkanlah rasa sakit wahai Rabb manusia, di tangan-Mu lah segala kesembuhan, dan tidak ada yang dapat menyingkap penyakit tersebut melainkan Engkau.\""},"4999":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي عَبْدُ رَبِّهِ بْنُ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ لِلْمَرِيضِ بِسْمِ اللَّهِ تُرْبَةُ أَرْضِنَا بِرِيقَةِ بَعْضِنَا يُشْفَى سَقِيمُنَا بِإِذْنِ رَبِّنَا","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepadaku [Abdurrabbihi bin Sa'id] dari ['Amrah] dari ['Aisyah] radliallahu 'anha bahwa apabila Nabi shallallahu 'alaihi wasallam mendo'akan orang sakit, beliau membaca: \"BISMILLAHI TURBATU ARDLINA BI RIIQATI BA'DLINA YUSYFAA SAQIIMUNA BI IDZNI RABBINA (\"Dengan nama Allah, Debu tanah kami dengan ludah sebagian kami semoga sembuh orang yang sakit dari kami dengan izin Rabb kami.\""},"5000":{"ar":"حَدَّثَنِي صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا ابْنُ عُيَيْنَةَ عَنْ عَبْدِ رَبِّهِ بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي الرُّقْيَةِ تُرْبَةُ أَرْضِنَا وَرِيقَةُ بَعْضِنَا يُشْفَى سَقِيمُنَا بِإِذْنِ رَبِّنَا","id":"Telah menceritakan kepadaku [Shadaqah bin Al Fadl] telah mengabarkan kepada kami [Ibnu 'Uyainah] dari ['Abdurrabbihi bin Sa'id] dari ['Amrah] dari ['Aisyah] dia berkata; \"Biasanya dalam meruqyah, beliau membaca: \"BISMILLAHI TURBATU ARDLINA BI RIIQATI BA'DLINA YUSYFAA SAQIIMUNA BI IDZNI RABBINA (\"Dengan nama Allah, Debu tanah kami dengan ludah sebagian kami semoga sembuh orang yang sakit dari kami dengan izin Rabb kami.\""}};
